INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('1. Place water into bowl of Rye Wheat Sourdough', 'Breads & Yeast Doughs', 'Module 2', 'Course 3', 'Breads & Yeast Doughs', 32, NULL, NULL, '["5 quart mixer"]', '[{"name":"water (80°F)","amounts":[["455","grams"]],"bakers_pct":null,"component":null},{"name":"high gluten flour","amounts":[["510","grams"]],"bakers_pct":null,"component":null},{"name":"dark rye flour (pumpernickel","amounts":[["115","grams"]],"bakers_pct":null,"component":null},{"name":"whole wheat flour","amounts":[["115","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["14","grams"]],"bakers_pct":null,"component":null},{"name":"starter","amounts":[["255","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Mix together on low speed using the hook attachment for 6 minutes.","Turn dough onto a lightly floured surface and gently knead the dough (dough will be very wet)","Lightly oil bowl and place dough in and cover with plastic. Place in proof box. Let rest for 30 minutes. Turn the dough. Let rest another 30 minutes and turn again."]', '[]', 'Pastry_Module_2_Course_3.pdf', 100);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Bagel Dough', 'Breads & Yeast Doughs', 'Module 2', 'Course 3', 'Breads & Yeast Doughs', 32, NULL, NULL, '[]', '[{"name":"water","amounts":[["570","grams"]],"bakers_pct":"62.64","component":null},{"name":"malt syrup","amounts":[["14","grams"]],"bakers_pct":"1.54","component":null},{"name":"SAF dry yeast","amounts":[["14","grams"]],"bakers_pct":"1.54","component":null},{"name":"high gluten flour","amounts":[["795","grams"]],"bakers_pct":"87.36","component":null},{"name":"all purpose flour","amounts":[["115","grams"]],"bakers_pct":"12.64","component":null},{"name":"salt","amounts":[["14","grams"]],"bakers_pct":"1.54","component":null},{"name":"water","amounts":[["570","grams"]],"bakers_pct":"62.64","component":null},{"name":"malt syrup","amounts":[["14","grams"]],"bakers_pct":"1.54","component":null},{"name":"SAF yeast","amounts":[["14","grams"]],"bakers_pct":"1.54","component":null},{"name":"high gluten flour","amounts":[["795","grams"]],"bakers_pct":"87.36","component":null},{"name":"whole wheat flour","amounts":[["115","grams"]],"bakers_pct":"12.64","component":null},{"name":"salt","amounts":[["14","grams"]],"bakers_pct":"1.54","component":null}]', NULL, '["Add water and malt syrup to mixing bowl.","Whisk in yeast.","Add flours and salt on top.","Mix on low speed using the hook attachment for 6 minutes. Transfer dough onto a lightly floured surface and knead briefly by hand until dough is smooth.","Place in oiled bowl and cover to let proof for about an hour. Whole Wheat Bagel Total 1522 grams","Place water and malt syrup to mixing bowl.","Whisk in yeast.","Add flours and salt on top.","Mix on low speed using the hook attachment for about 6 minutes. Transfer to a lightly floured surface and knead briefly by hand until dough is smooth.","Place in oiled bowl and cover to let proof until double in size for about an hour."]', '[]', 'Pastry_Module_2_Course_3.pdf', 105);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Baguette Dough', 'Breads & Yeast Doughs', 'Module 2', 'Course 3', 'Breads & Yeast Doughs', 29, NULL, NULL, '["LARGE BATCH","SMALL BATCH"]', '[{"name":"water 85° F","amounts":[["3570","grams"],["595","grams"]],"bakers_pct":null,"component":null},{"name":"SAF yeast","amounts":[["86","grams"],["13","grams"]],"bakers_pct":null,"component":null},{"name":"high gluten flour","amounts":[["6618","grams"],["1100","grams"]],"bakers_pct":null,"component":null},{"name":"white rye flour","amounts":[["732","grams"],["120","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["204","grams"],["34","grams"]],"bakers_pct":null,"component":null},{"name":"Large Batch Poolish","amounts":[["7150","grams"],["1190","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Stir in the yeast.","Put the salt on top of the flours and add the flours to the mixing bowl.","Add the poolish. (If poolish has been refrigerated over night, increase the water temperature to approximately 90° F to warm the dough)","Mix using the hook attachment on 1st speed for 3 minutes.","Increase to 2nd speed and mix for an additional 4 minutes.","Take temperature of dough, dough should be approximately 76° F.","Lightly oil a bin and place the dough in the bin. Cover with plastic wrap.","Allow the dough to rest for 30 minutes and then turn the dough. Re-cover with plastic wrap and let rest for another 30 minutes, then turn again","Cover and rest the dough another 30 to 45 minutes until it is ready to shape","Line sheet pans with couche and generously flour couche.","Transfer the dough onto a lightly floured surface. Sprinkle the top of the dough","Divide dough into 340 gram (12 ounce) pieces; try to keep a rectangular shape","Place a piece, smooth side face down and stretch it into a rectangle. Try not to","Turn ends in slightly, about ½-inch.","Working from the top (the long end that is farthest away), fold in, tucking","Roll dough tucking everything in (3 times) and seal it (like an empanada).","Place seam side face down. Elongate the dough by rolling with hands starting in","Place on couche lined pans and sprinkle with flour 2 ½ feet above.","Cover with cloth and place in proof box for approximately 15 minutes**","Preheat oven to 515° F","Lift up baguettes carefully by placing hands at 2/3 intervals on the dough so it","Using a lame or razor blade, slice 6 straight cuts to baguette. They will overlap","Make sure dampers are closed, steam for 1 second. Open oven, place board all the","Bake for 15 minutes, then open the damper and let steam out. Bake for a few","Remove from the oven and cool on the rack."]', '[]', 'Pastry_Module_2_Course_3.pdf', 65);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Baker''s Percentage for Pizza Dough', 'Breads & Yeast Doughs', 'Module 2', 'Course 3', 'Breads & Yeast Doughs', 31, NULL, NULL, '[]', '[{"name":"water 76°F","amounts":[["340","grams"],["1590","grams"],["1930","grams"]],"bakers_pct":"73.94","component":null},{"name":"fresh Yeast","amounts":[["7","grams"],["14","grams"],["21","grams"]],"bakers_pct":"0.80","component":null},{"name":"all purpose flour","amounts":[["230","grams"],["230","grams"]],"bakers_pct":"8.81","component":null},{"name":"high gluten flour","amounts":[["570","grams"],["1810","grams"],["2380","grams"]],"bakers_pct":"91.19","component":null},{"name":"salt","amounts":[["42","grams"],["42","grams"]],"bakers_pct":"1.61","component":null},{"name":"olive oil","amounts":[["114","grams"],["114","grams"]],"bakers_pct":"4.36","component":null}]', NULL, '["Dissolve the fresh yeast in the water.","Combine the all-purpose flour, high gluten flour, and salt in the bowl of a mixer fitted with the dough hook.","Add the yeast water and olive oil.","Mix on low speed until the ingredients come together, then knead on medium speed until the dough is smooth, elastic, and clears the sides of the bowl.","Round the dough into a ball, place in a lightly oiled covered container, and bulk ferment at room temperature until nearly doubled.","Divide the dough into portions and round each tightly into a ball.","Place the balled dough in lightly oiled, covered containers and retard under refrigeration, or hold at room temperature until ready to use.","Bring the dough to room temperature before shaping.","Stretch each ball by hand into a round, working from the center out and leaving a slightly thicker rim for the crust.","Top as desired and bake in a very hot oven until the crust is browned and blistered and any cheese is melted and bubbling."]', '[]', 'Pastry_Module_2_Course_3.pdf', 96);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Biga for Pizza', 'Breads & Yeast Doughs', 'Module 2', 'Course 3', 'Breads & Yeast Doughs', 30, NULL, NULL, '["SMALL BATCH","LARGE BATCH"]', '[{"name":"high gluten flour","amounts":[["285","grams"],["570","grams"]],"bakers_pct":"100.00","component":null},{"name":"water","amounts":[["170","grams"],["340","grams"]],"bakers_pct":"60.00","component":null},{"name":"yeast","amounts":[["4","grams"],["2","grams"],["7","grams"]],"bakers_pct":"0.63","component":null}]', NULL, '["Mix all the ingredients together, cover and set aside.","Leave at room temperature overnight or refrigerate for up to 5 days."]', '[]', 'Pastry_Module_2_Course_3.pdf', 87);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Boston Cream Doughnuts', 'Breads & Yeast Doughs', 'Module 2', 'Course 3', 'Breads & Yeast Doughs', 33, NULL, NULL, '["Baker''s %"]', '[{"name":"milk (100°F)","amounts":[["375","grams"]],"bakers_pct":"54.35","component":null},{"name":"SAF yeast, dry","amounts":[["14","grams"]],"bakers_pct":"2.03","component":null},{"name":"all purpose flour","amounts":[["575","grams"]],"bakers_pct":"83.33","component":null},{"name":"cake flour","amounts":[["115","grams"]],"bakers_pct":"16.67","component":null},{"name":"granulated sugar","amounts":[["145","grams"]],"bakers_pct":"21.01","component":null},{"name":"eggs 2","amounts":[["100","grams"]],"bakers_pct":"14.49","component":null},{"name":"salt","amounts":[["14","grams"]],"bakers_pct":"2.03","component":null},{"name":"butter, melted","amounts":[["72","grams"]],"bakers_pct":"10.43","component":null},{"name":"milk","amounts":[["975","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["200","grams"]],"bakers_pct":null,"component":null},{"name":"cornstarch","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"egg yolk","amounts":[["135","grams"]],"bakers_pct":null,"component":null},{"name":"butter","amounts":[["150","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Warm milk to 100 °F and whisk yeast into milk.","Add flours, sugars, eggs, salt, and butter.","Mix on low speed using the hook attachment for about 10 minutes. (Dough will be very soft).","Cover, refrigerate and let rise 1 hour, until double in size. Pastry Cream Filling vanilla bean 1 bean split","In a medium saucepan, heat 3/4 of the milk, vanilla bean and half the sugar over medium heat and bring to a boil.","Sift together the remaining sugar and cornstarch. Whisk in the remaining milk and yolks. Once the milk has boiled, temper with the cornstarch yolk mixture.","Pour all the liquid back into the pan whisking continuously. Return to medium heat while mixing and bring back to a boil.","Cook for about two minutes after it boils.","Place the cream in a bowl of a standing mixer fitted with the paddle attachment. Add the butter and continue to mix until the pastry cream reaches room temperature. Set in the refrigerator to cool until ready to use."]', '[]', 'Pastry_Module_2_Course_3.pdf', 114);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Brioche Dough', 'Breads & Yeast Doughs', 'Module 2', 'Course 3', 'Breads & Yeast Doughs', 33, NULL, NULL, '[]', '[{"name":"milk","amounts":[["155","grams"]],"bakers_pct":null,"component":null},{"name":"SAF yeast","amounts":[["14","grams"]],"bakers_pct":null,"component":null},{"name":"eggs","amounts":[["450","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["14","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["55","grams"]],"bakers_pct":null,"component":null},{"name":"all purpose flour","amounts":[["910","grams"]],"bakers_pct":null,"component":null},{"name":"butter","amounts":[["225","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Pour milk into a mixing bowl. Add yeast, eggs, salt, sugar, and flour.","Mix together on 1st speed for 3 minutes with dough hook attachment.","Mix together on 2nd speed for 3 minutes.","Place butter between parchment paper and beat down to flatten. Break into small pieces and add to dough while mixing.","Continue to mix for 12-15 minutes. Near the end, scrape down the sides.","Scrape into bowl and cover with plastic wrap.","Allow the dough to sit for 1 hour at room temperature and then transfer to the refrigerator and store overnight."]', '["NOTE: all ingredients must be cold."]', 'Pastry_Module_2_Course_3.pdf', 119);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Bun Dough', 'Breads & Yeast Doughs', 'Module 2', 'Course 3', 'Breads & Yeast Doughs', 29, NULL, NULL, '["Small Batch","Large Batch"]', '[{"name":"high gluten flour","amounts":[["765","grams"],["1815","grams"]],"bakers_pct":null,"component":null},{"name":"butter, cut and softened","amounts":[["200","grams"],["455","grams"]],"bakers_pct":null,"component":null},{"name":"granulated sugar","amounts":[["130","grams"],["285","grams"]],"bakers_pct":null,"component":null},{"name":"salt 1 pinch","amounts":[["14","grams"]],"bakers_pct":null,"component":null},{"name":"milk","amounts":[["355","grams"],["850","grams"]],"bakers_pct":null,"component":null},{"name":"SAF yeast","amounts":[["14","grams"],["42","grams"]],"bakers_pct":null,"component":null},{"name":"large eggs","amounts":[["140","grams"],["340","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Add flour and nutmeg to mixing bowl with paddle attachment","Add butter, sugar and salt to mixing bowl and mix for 3 minutes on low speed. Continue to mix until dough is sandy.","Warm milk to 100°F and whisk in yeast.","Whisk eggs in a separate bowl to break them, and then whisk into yeast mixture.","Add the yeast/milk mixture, eggs and lemon zest to the mixing bowl. Switch to a dough hook and mix for 3 minutes on low speed. Increase to second speed and mix for an additional 3 minutes.","Mix for 3 additional minutes on high speed.","Place in bowl and cover with plastic wrap. Let rest until doubled in size."]', '[]', 'Pastry_Module_2_Course_3.pdf', 72);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Cecini (Flatbread)', 'Breads & Yeast Doughs', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 47, NULL, NULL, '[]', '[{"name":"water","amounts":[["950","grams"]],"bakers_pct":null,"component":null},{"name":"extra virgin olive oil","amounts":[["110","grams"]],"bakers_pct":null,"component":null},{"name":"chick pea flour","amounts":[["455","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["18","grams"]],"bakers_pct":null,"component":null},{"name":"freshly ground black pepper","amounts":[["7","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Place two sheet pans in a pre-heated 450 ° F oven. Allow them to get hot.","Combine all the ingredients together in the bowl of a standing mixer. Beat using a paddle until the batter is smooth. The batter will be extremely wet.","Pour enough oil on each pan to grease it generously.","Divide the batter between the two pans and smooth it evenly with a spatula.","Bake for 10 to 15 minutes until golden brown and set.","Serve warm."]', '[]', 'Pastry_Module_2_Course_4.pdf', 137);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Chelsea Buns', 'Breads & Yeast Doughs', 'Module 2', 'Course 3', 'Breads & Yeast Doughs', 29, NULL, NULL, '["small batch"]', '[{"name":"melted butter","amounts":[["115","grams"]],"bakers_pct":null,"component":null},{"name":"cinnamon","amounts":[["8","grams"]],"bakers_pct":null,"component":null},{"name":"brown sugar","amounts":[["170","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Place dough in slightly oiled bowl and cover with plastic wrap. Let dough rest until doubled in size. Preheat oven to 400 °F","Brush melted butter over the remainder of the dough, generously.","Mix cinnamon and brown sugar together; make sure there are no lumps. Sprinkle it generously over dough but not where the egg/water wash is.","Sprinkle drained soaked currants over dough on top of cinnamon sugar.","Roll top over towards the egg washed end, and tuck under and keep rolling. Seal at end. Elongate slightly to make sure roll is even but don''t stretch dough. Roll should be about 2 ½ inches in diameter","Cut slices about 1 ½ inches apart and place on parchment lined sheet pan, arranged 4 X 5 close together.","Brush tops generously with melted butter.","Place in proof box for until doubled in size.","Bake in oven for 30 to 35 minutes.","As soon as buns come out of the oven finish either by:"]', '[]', 'Pastry_Module_2_Course_3.pdf', 75);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Chocolate Brioche', 'Breads & Yeast Doughs', 'Module 2', 'Course 3', 'Breads & Yeast Doughs', 33, NULL, NULL, '[]', '[{"name":"water","amounts":[["85","grams"]],"bakers_pct":null,"component":null},{"name":"SAF instant yeast","amounts":[["12","grams"]],"bakers_pct":null,"component":null},{"name":"cocoa powder","amounts":[["42","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["6","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["56","grams"]],"bakers_pct":null,"component":null},{"name":"high gluten flour","amounts":[["510","grams"]],"bakers_pct":null,"component":null},{"name":"eggs 5","amounts":[["250","grams"]],"bakers_pct":null,"component":null},{"name":"butter","amounts":[["255","grams"]],"bakers_pct":null,"component":null},{"name":"semi sweet chocolate","amounts":[["85","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Pour water into a mixing bowl. Add yeast, cocoa powder, salt, sugar, flour, and eggs.","Mix together on low speed for 3 minutes with dough hook attachment.","Mix together on medium speed for 3 minutes.","Turn the mixer off and scrape down the bowl. Continue mixing to develop gluten and until dough forms a ball around the hook attachment.","Place butter between parchment paper and beat down to flatten. This will soften the butter and enable it to incorporate into the dough more easily. Break the butter into small pieces and add it quickly to the dough while the machine is mixing.","While the dough is mixing, roughly chop the chocolate into 1/2-inch pieces.","Continue to mix the dough for 12-15 minutes. Towards the end of mixing, turn off the machine and scrape down the sides of the bowl again. The dough is ready when it is smooth and shiny and comes away from sides of the mixer.","Add the chocolate chunks until just combined.","Scrape into bowl and cover with plastic wrap.","Allow the dough to sit for 1 hour at room temperature and then transfer to the refrigerator and store overnight.","When ready to bake, preheat the oven to 350°F","Divide dough into eight 140 gram (5-ounce) pieces, rounding each piece to form a smooth surface.","Place four rolls evenly spaced in each pan as follows:","Cover and allow the dough to proof in until double in size, about one hour.","Egg wash tops and sprinkle with half granulated and half light brown sugar","Bake for about 25 to 35 minutes, until well colored. Remove from pan"]', '[]', 'Pastry_Module_2_Course_3.pdf', 120);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Ciabatta Bread Biga', 'Breads & Yeast Doughs', 'Module 2', 'Course 3', 'Breads & Yeast Doughs', 29, NULL, NULL, '["Small Batch","Large Batch"]', '[{"name":"high gluten flour","amounts":[["300","grams"],["2500","grams"]],"bakers_pct":"100.00","component":null},{"name":"water","amounts":[["170","grams"],["1500","grams"]],"bakers_pct":"60.00","component":null},{"name":"SAF yeast","amounts":[["1","grams"],["2","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Mix all ingredients together with a dough hook and allow it to develop for 10-17 hours. is too dry, but after it sits for 10 to 17 hours, it is very bubbly and easy to work into dough."]', '["NOTE – Biga is very dry. When it is first mixed the impression may be that it"]', 'Pastry_Module_2_Course_3.pdf', 79);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Ciabatta Dough', 'Breads & Yeast Doughs', 'Module 2', 'Course 3', 'Breads & Yeast Doughs', 30, NULL, NULL, '["Small Batch","Large Batch"]', '[{"name":"Water (76 °F)","amounts":[["650","grams"],["7500","grams"]],"bakers_pct":"75.00","component":null},{"name":"SAF yeast","amounts":[["14","grams"],["70","grams"]],"bakers_pct":"0.70","component":null},{"name":"High gluten flour","amounts":[["865","grams"],["10000","grams"]],"bakers_pct":"100.00","component":null},{"name":"Salt","amounts":[["28","grams"],["250","grams"]],"bakers_pct":"2.50","component":null},{"name":"sour dough starter (optional)","amounts":[["140","grams"],["750","grams"]],"bakers_pct":"7.50","component":null},{"name":"fresh rosemary, chopped","amounts":[["45","grams"]],"bakers_pct":"0.45","component":null}]', NULL, '["Place water into bowl of a standing mixer and whisk yeast into water.","Add the flour and then the salt.","Add all of the biga and the sourdough starter if being used.","Mix using a hook attachment for 3 minutes on the 1st speed (or low speed). The dough will be wet. Continue to mix for 5 minutes on the second (or medium) speed.","Place it in an oiled bowl, cover and allow it to rest for 30 minutes.","After 30 minutes, turn dough. Proceed to “Shaping Focaccia” instructions continued on page 4. oiled bin and cover with plastic wrap. Let rest for 30 minutes. rosemary on low speed until incorporated. *Do Not Over Mix (the rosemary will cut the gluten). After it is mixed, also place this dough in a lightly oiled bin covered with plastic wrap. Let rest for 30 minutes.","After 30 minutes, turn each piece of dough. Wait another 30 minutes and turn again and proceed as instructed below.","Flour surface (this is very wet dough so flour a lot).","Flip dough out of the bin onto the floured surface","Fold dough in half without knocking the air out.","Divide dough into 565 gram (1 1/4 pound) pieces. Try to cut in large","Form the 565 gram (1 1/4 pound) pieces into a rough rectangle with the","Divide dough into 565 gram (1 1/4 pound) pieces (about 12 for 1/2 large","Shape into a boule using the 1-2-3-4 dough shaping method (see attached","Push the dough right to left and up and down to tighten boule slightly, do","Place 4 on a tray sprinkled with flour.","Place in proof box for about 30 minutes","Shape into large rings as follows:"]', '[]', 'Pastry_Module_2_Course_3.pdf', 82);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Cinnamon Coffee Doughnuts', 'Breads & Yeast Doughs', 'Module 2', 'Course 3', 'Breads & Yeast Doughs', 33, NULL, NULL, '["Baker''s %"]', '[{"name":"milk (100°F)","amounts":[["375","grams"]],"bakers_pct":"54.35","component":null},{"name":"SAF yeast, dry","amounts":[["14","grams"]],"bakers_pct":"2.03","component":null},{"name":"all purpose flour","amounts":[["345","grams"]],"bakers_pct":"50.00","component":null},{"name":"high gluten flour","amounts":[["345","grams"]],"bakers_pct":"50.00","component":null},{"name":"granulated sugar","amounts":[["145","grams"]],"bakers_pct":"21.01","component":null},{"name":"eggs 2","amounts":[["100","grams"]],"bakers_pct":"14.49","component":null},{"name":"salt","amounts":[["14","grams"]],"bakers_pct":"2.03","component":null},{"name":"butter, melted","amounts":[["57","grams"]],"bakers_pct":"8.26","component":null},{"name":"cinnamon","amounts":[["1","gram"]],"bakers_pct":"0.14","component":null}]', NULL, '["Heat milk to 100 °F.","Whisk yeast into milk.","Add flours, sugar, eggs, salt, butter and cinnamon.","Mix on low speed for 10 minutes.","Cover and refrigerate to rise for about 1 hour"]', '["Note – Use very strong Coffee in the fondant glaze"]', 'Pastry_Module_2_Course_3.pdf', 116);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Cinnamon Raisin Bagel', 'Breads & Yeast Doughs', 'Module 2', 'Course 3', 'Breads & Yeast Doughs', 32, NULL, NULL, '[]', '[{"name":"water","amounts":[["570","grams"]],"bakers_pct":"62.64","component":null},{"name":"malt syrup","amounts":[["14","grams"]],"bakers_pct":"1.54","component":null},{"name":"SAF yeast","amounts":[["14","grams"]],"bakers_pct":"1.54","component":null},{"name":"high gluten flour","amounts":[["795","grams"]],"bakers_pct":"87.36","component":null},{"name":"all purpose flour","amounts":[["115","grams"]],"bakers_pct":"12.64","component":null},{"name":"salt","amounts":[["14","grams"]],"bakers_pct":"1.54","component":null},{"name":"cinnamon","amounts":[["16","grams"]],"bakers_pct":"1.76","component":null},{"name":"water","amounts":[["400","grams"]],"bakers_pct":"50.00","component":null},{"name":"malt syrup","amounts":[["14","grams"]],"bakers_pct":"1.75","component":null},{"name":"SAF yeast","amounts":[["14","grams"]],"bakers_pct":"1.75","component":null},{"name":"high gluten flour","amounts":[["685","grams"]],"bakers_pct":"85.63","component":null},{"name":"all purpose flour","amounts":[["115","grams"]],"bakers_pct":"14.37","component":null},{"name":"salt","amounts":[["14","grams"]],"bakers_pct":"1.75","component":null}]', NULL, '["Place water and malt syrup in a mixing bowl.","Whisk in yeast.","Add the flours and salt on top.","Mix on low speed using the hook attachment for about 6 minutes. Transfer the dough to a lightly floured surface and knead by hand.","Place in oiled bowl and cover to let proof until double in size, for about one hour. Bialys Total 1242 grams","Add water and malt syrup to mixing bowl.","Whisk in yeast.","Add flours and salt on top.","Mix on low speed for 6 minutes. Then take out and knead by hand.","Place in oiled bowl and cover to let proof for about an hour. Difference between bagel and bialy: bialy has no hole, floured surface and onions.","Cut into 115 gram (4 ounce) pieces.","Make rectangle.","1-2 roll into empanada. Roll out to about 10 ½ inches with thin edges","Place on cornmeal and parchment lined tray or silpat lined tray.","Place 2 at a time into boiling water for no longer than 20 seconds.","Brush with egg white and sprinkle sesame seeds and/or poppy seeds.","Place in 350 °F convection oven and bake 20 minutes.","Cut into 115 gram (4 ounce) pieces.","Make rectangle.","1-2-3 roll into empanada. Roll out to about 10 ½ inches with thin","Place on cornmeal and parchment lined tray or silpat lined tray.","Place 2 at a time into boiling water for no longer than 20 seconds.","Brush with egg white and sprinkle sesame seeds and/or poppy seeds.","Place in 350 °F convection oven and bake for 20 minutes.","Cut into 115 gram (4 ounce) pieces.","Make rectangle.","Brush with water","Sprinkle with raisins (drained) and cinnamon.","1-2 roll into empanada. Roll out to about 10½ inches with thin edges","Place on cornmeal and parchment lined tray or silpat lined tray.","Place 2 at a time into boiling water for no longer than 20 seconds.","Egg white wash tops and bake in convection oven at 350°F for"]', '["For Shaping:"]', 'Pastry_Module_2_Course_3.pdf', 106);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Crispy Pizza Dough', 'Breads & Yeast Doughs', 'Module 2', 'Course 3', 'Breads & Yeast Doughs', 30, NULL, NULL, '[]', '[{"name":"compressed yeast","amounts":[["42","grams"]],"bakers_pct":"3.12","component":null},{"name":"water","amounts":[["737","grams"]],"bakers_pct":"54.17","component":null},{"name":"olive oil","amounts":[["170","grams"]],"bakers_pct":"12.5","component":null},{"name":"honey","amounts":[["28","grams"]],"bakers_pct":"2.08","component":null},{"name":"high-gluten flour","amounts":[["1360","grams"]],"bakers_pct":"100.00","component":null},{"name":"salt","amounts":[["28","grams"]],"bakers_pct":"2.08","component":null}]', NULL, '["Mix the first 4 ingredients and allow it to sit for 10 minutes.","Add flour and salt and knead dough with a dough hook for 5 to 7 minutes.","Bench proof covered for 10 minutes and 5 ounce pieces for individual pizzas.","Round perfectly and make sure the seam is on the bottom. Place in an oiled cake pan and cover dough with additional oil. Wrap well, making sure the wrap is touching the surface of the dough.","For best results refrigerate for a minimum of one hour, or ideally overnight."]', '[]', 'Pastry_Module_2_Course_3.pdf', 88);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Dead Dough', 'Breads & Yeast Doughs', 'Module 2', 'Course 3', 'Breads & Yeast Doughs', 29, NULL, NULL, '[]', '[{"name":"sugar","amounts":[["420","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["410","grams"]],"bakers_pct":null,"component":null},{"name":"glucose or corn syrup","amounts":[["150","grams"]],"bakers_pct":null,"component":null},{"name":"syrup","amounts":[["400","grams"]],"bakers_pct":null,"component":null},{"name":"dark molasses","amounts":[["25","grams"]],"bakers_pct":null,"component":null},{"name":"beet powder","amounts":[["25","grams"]],"bakers_pct":null,"component":null},{"name":"dark chili powder","amounts":[["50","grams"]],"bakers_pct":null,"component":null},{"name":"White Rye","amounts":[["325","grams"]],"bakers_pct":null,"component":null},{"name":"dark buckwheat flour","amounts":[["125","grams"]],"bakers_pct":null,"component":null},{"name":"syrup","amounts":[["400","grams"]],"bakers_pct":null,"component":null},{"name":"molasses","amounts":[["25","grams"]],"bakers_pct":null,"component":null},{"name":"turmeric powder","amounts":[["12.5","grams"]],"bakers_pct":null,"component":null},{"name":"white rye flour","amounts":[["350","grams"]],"bakers_pct":null,"component":null},{"name":"dark buckwheat flour","amounts":[["145","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine all ingredients in saucepan and bring to a rolling boil for about 2 minutes.","Pour into a bowl over an ice bath and let cool. Red Brown Dead Dough","Sift beet powder over syrup.","Whisk in chili powder.","Using a dough hook add flours and mix on low speed until all incorporated. The dough will be crumbly.","Turn onto the bench and knead wearing rubber gloves until it comes together and color is evenly distributed.","Form dough into a disk and triple wrap in plastic, store at room temperature up to 3 days. For longer storage refrigerate. Yellow Dead Dough and whisk.","Add flours to mixture. Mix on low speed using the paddle attachment until incorporated.","Put on rubber gloves to prevent hands from turning yellow and work dough together on surface until smooth and color is evenly distributed.","Form dough into a disk and triple wrap in plastic, store at room temperature up to 3 days. For longer storage refrigerate."]', '[]', 'Pastry_Module_2_Course_3.pdf', 69);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Farm House White', 'Breads & Yeast Doughs', 'Module 2', 'Course 3', 'Breads & Yeast Doughs', 28, NULL, NULL, '["LARGE BATCH"]', '[{"name":"water (78° F)","amounts":[["3740","grams"],["3885","grams"],["7625","grams"]],"bakers_pct":"69.60","component":null},{"name":"SAF yeast","amounts":[["14","grams"],["71","grams"],["85","grams"]],"bakers_pct":"0.78","component":null},{"name":"high gluten flour","amounts":[["4960","grams"],["4905","grams"],["9865","grams"]],"bakers_pct":"90.05","component":null},{"name":"whole wheat flour","amounts":[["1090","grams"],["1090","grams"]],"bakers_pct":"9.95","component":null},{"name":"salt","amounts":[["49","grams"],["121","grams"],["170","grams"]],"bakers_pct":"1.55","component":null}]', NULL, '["Place the pre-ferment and water in the bowl of a mixer and break up the pre-ferment until loosened.","Add the high gluten flour, whole wheat flour, SAF yeast, and salt.","Mix on low speed with the dough hook until the ingredients come together, then knead on medium speed until the dough is smooth, elastic, and clears the sides of the bowl.","Round into a ball, place in a lightly oiled covered container, and bulk ferment until doubled, folding the dough once or twice during fermentation to build strength.","Divide the dough into loaf-sized portions, pre-shape into rounds, and let rest.","Shape each piece into a loaf and place seam-side down in greased loaf pans.","Proof, covered, until the dough crowns above the rim of the pan.","Bake until deep golden brown and the loaves sound hollow when tapped.","Turn out onto racks and cool completely before slicing."]', '[]', 'Pastry_Module_2_Course_3.pdf', 55);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Gluten Free Bread Sticks', 'Breads & Yeast Doughs', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 47, NULL, NULL, '[]', '[{"name":"Teff flour","amounts":[["77","grams"]],"bakers_pct":null,"component":null},{"name":"brown rice flour","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"tapioca flour","amounts":[["76","grams"]],"bakers_pct":null,"component":null},{"name":"potato starch","amounts":[["116","grams"]],"bakers_pct":null,"component":null},{"name":"ground flax meal","amounts":[["24","grams"]],"bakers_pct":null,"component":null},{"name":"potato flour","amounts":[["46","grams"]],"bakers_pct":null,"component":null},{"name":"xanthan gum","amounts":[["7","grams"]],"bakers_pct":null,"component":null},{"name":"SAF yeast","amounts":[["17","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["6","grams"]],"bakers_pct":null,"component":null},{"name":"granulated sugar","amounts":[["12","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["250","grams"]],"bakers_pct":null,"component":null},{"name":"cider vinegar","amounts":[["5","grams"]],"bakers_pct":null,"component":null},{"name":"eggs(2)","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"olive oil","amounts":[["55","grams"]],"bakers_pct":null,"component":null},{"name":"egg whites lightly beaten","amounts":[["66","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Mix all dry ingredients in the bowl of a standing mixer fitted with a paddle attachment and beat to combine well.","Place all the liquid ingredients in another bowl and add them all at once to the dry ingredients. Mix on low speed until batter is dough is uniform for about 5- 7 minutes.","Divide dough into approximately 24 pieces (or more for thinner breadsticks) Roll into a thin cylinder on the bench to elongate. Place on a parchment","Cover loosely with oiled plastic wrap and allow to proof 20 to 30 minutes.","Brush with beaten egg white or water and strew with salt and/or seeds.","Bake in a preheated 375°F oven until firm."]', '[]', 'Pastry_Module_2_Course_4.pdf', 136);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Hot Cross Buns', 'Breads & Yeast Doughs', 'Module 2', 'Course 3', 'Breads & Yeast Doughs', 29, NULL, NULL, '["small batch"]', '[{"name":"candied orange peel","amounts":[["56","grams"]],"bakers_pct":null,"component":null},{"name":"currants","amounts":[["170","grams"]],"bakers_pct":null,"component":null},{"name":"cinnamon","amounts":[["8","grams"]],"bakers_pct":null,"component":null},{"name":"allspice","amounts":[["6","grams"]],"bakers_pct":null,"component":null},{"name":"all purpose flour","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"oil","amounts":[["70","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["225","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Preheat oven to 400 °F.","Mix all ingredients into bun dough by machine or by hand. Place dough in a bowl and cover with plastic wrap. Let rest until doubled in size.","Once doubled, cut dough into about 24 70 gram pieces.","Perform the 1-2-3-4 dough shaping method on each piece. Line the pieces on a parchment paper lined pan. Ideal is to have 4x6.","Proof in proof box for about 10 minutes.","While buns are proofing prepare Hot Cross Bun Paste. Mix the flour and oil together in a bowl of a standing mixer fitted with the paddle attachment. Add the water and mix on low speed until well combined. Adjust if necessary.","Remove buns from the proof box.","Place a number 801 tip in a pastry bag and fill it with Hot Cross Bun Paste.","Draw horizontal and vertical lines across pan in center of buns to make a cross on each bun.","Bake for about 35 minutes until golden and well risen.","While baking, prepare the simple syrup: 500 grams water and 500 grams sugar in a saucepan. Bring to a boil and cook for 3 minutes to thicken slightly. Brush tops of buns with simple syrup. bowl.","Preheat oven to 400 °F","After bun dough is finished being mixed, add the cherries and knead by","Cut the dough into about 20 70 gram pieces.","Shape each piece using the 1-2-3-4 dough shaping method. Place the","Put in proof box until doubled in size.","Egg wash the tops of the buns.","Place in oven and bake for about 35 minutes.","Brush with melted fondant and sprinkle with coconut."]', '["*** Cinnamon and allspice can be mixed in with fruit by hand or with dough in mixing"]', 'Pastry_Module_2_Course_3.pdf', 73);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Lemon Doughnuts', 'Breads & Yeast Doughs', 'Module 2', 'Course 3', 'Breads & Yeast Doughs', 33, NULL, NULL, '["Baker''s %"]', '[{"name":"milk (100°F)","amounts":[["345","grams"]],"bakers_pct":"50.00","component":null},{"name":"SAF yeast, dry","amounts":[["14","grams"]],"bakers_pct":"2.03","component":null},{"name":"high gluten flour","amounts":[["460","grams"]],"bakers_pct":"66.67","component":null},{"name":"all purpose flour","amounts":[["230","grams"]],"bakers_pct":"33.33","component":null},{"name":"granulated sugar","amounts":[["57","grams"]],"bakers_pct":"8.26","component":null},{"name":"light brown sugar","amounts":[["86","grams"]],"bakers_pct":"12.46","component":null},{"name":"eggs 2","amounts":[["100","grams"]],"bakers_pct":"14.49","component":null},{"name":"salt","amounts":[["14","grams"]],"bakers_pct":"2.03","component":null},{"name":"butter, melted","amounts":[["57","grams"]],"bakers_pct":"8.26","component":null},{"name":"lemon extract","amounts":[["14","grams"]],"bakers_pct":"2.03","component":null}]', NULL, '["Heat milk to 100 °F.","Whisk yeast into milk.","Add flours, sugar, eggs, salt, butter, lemon extract and lemon zest.","Mix on low speed for 10 minutes.","Cover, refrigerate and let rise 1 hour, until double in size."]', '[]', 'Pastry_Module_2_Course_3.pdf', 115);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Pizza Dough', 'Breads & Yeast Doughs', 'Module 2', 'Course 3', 'Breads & Yeast Doughs', 31, NULL, NULL, '["SMALL BATCH","LARGE BATCH"]', '[{"name":"water 76°F","amounts":[["795","ounces"],["1590","grams"]],"bakers_pct":"77.94","component":null},{"name":"fresh Yeast","amounts":[["7","grams"],["14","grams"]],"bakers_pct":"0.69","component":null},{"name":"all purpose flour","amounts":[["115","grams"],["230","grams"]],"bakers_pct":"11.27","component":null},{"name":"high gluten flour","amounts":[["905","grams"],["1810","grams"]],"bakers_pct":"88.73","component":null},{"name":"salt","amounts":[["21","grams"],["42","grams"]],"bakers_pct":"2.06","component":null},{"name":"olive oil","amounts":[["57","grams"],["114","grams"]],"bakers_pct":"5.59","component":null}]', NULL, '["Sprinkle the peel with cornmeal","Flour your work surface.","Use fingers to push out dough leaving a mound in the center, pushing it as","Ladle sauce on dough (don''t use too much) and leave an edge","Place slices of mozzarella around the outside, then cheddar then","Salt and pepper the pizza and sprinkle with some olive oil. Rub additional","Place in 515°F oven. Place board in oven and pull out quickly. Bake for"]', '[]', 'Pastry_Module_2_Course_3.pdf', 93);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Pizza Variations: Calzone Base', 'Breads & Yeast Doughs', 'Module 2', 'Course 3', 'Breads & Yeast Doughs', 31, 'yield 2 calzone', NULL, '[]', '[{"name":"ricotta","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"parmesan","amounts":[["60","grams"]],"bakers_pct":null,"component":null},{"name":"mozzarella","amounts":[["60","grams"]],"bakers_pct":null,"component":null},{"name":"fresh herbs","amounts":[["","as needed"]],"bakers_pct":null,"component":null},{"name":"salt and pepper","amounts":[["","as needed"]],"bakers_pct":null,"component":null}]', NULL, '["Combine the ricotta, grated parmesan, and shredded mozzarella in a bowl.","Chop the fresh herbs and fold into the cheese mixture; season with salt and pepper.","Divide the prepared pizza dough into rounds and stretch each into a circle.","Place half of the cheese filling on one half of each round, leaving a border for sealing.","Fold the dough over the filling to form a half-moon and press the edges together to seal.","Crimp or fold the sealed edge to lock it, then dock the top a few times to vent steam.","Transfer to a parchment-lined sheet pan.","Bake in a hot oven until the crust is golden brown and the filling is heated through and molten."]', '[]', 'Pastry_Module_2_Course_3.pdf', 95);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Pizzeria-Style Pizza Sauce', 'Breads & Yeast Doughs', 'Module 2', 'Course 3', 'Breads & Yeast Doughs', 31, NULL, NULL, '[]', '[{"name":"olive oil","amounts":[["27","grams"]],"bakers_pct":null,"component":null},{"name":"can tomatoes, strained","amounts":[["2720","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Heat oil in a large saucepan and add onion.","Sauté until transparent, about 15 minutes. Add garlic and cook briefly.","Add tomatoes and bouquet. Bring to a boil, stirring occasionally. Reduce heat and simmer about 1 hour, or until reduced by one quarter."]', '[]', 'Pastry_Module_2_Course_3.pdf', 92);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Plain White Sourdough', 'Breads & Yeast Doughs', 'Module 2', 'Course 3', 'Breads & Yeast Doughs', 32, NULL, NULL, '[]', '[{"name":"high gluten flour","amounts":[["795","grams"]],"bakers_pct":null,"component":null},{"name":"water (80°F)","amounts":[["455","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["14","grams"]],"bakers_pct":null,"component":null},{"name":"starter","amounts":[["255","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine the high gluten flour and water and let autolyse, covered, until fully hydrated.","Add the active starter and salt and mix by hand or on low speed until incorporated.","Knead or slap-and-fold until the dough is smooth and elastic and passes the windowpane test.","Bulk ferment, covered, performing a series of stretch and folds at intervals during the first hours of fermentation.","Continue bulk fermentation until the dough has increased noticeably in volume and shows surface bubbles.","Turn the dough onto a lightly floured surface, divide if needed, pre-shape into a round, and let rest.","Shape into a boule or batard and place seam-side up in a floured banneton.","Proof at room temperature until nearly doubled, or retard under refrigeration overnight for flavor development.","Turn the dough out onto parchment and score the top.","Bake with steam in a preheated hot oven, then reduce heat and continue baking until the crust is deep golden brown.","Cool completely on a rack before slicing."]', '[]', 'Pastry_Module_2_Course_3.pdf', 101);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Poolish for Baguettes', 'Breads & Yeast Doughs', 'Module 2', 'Course 3', 'Breads & Yeast Doughs', 28, NULL, NULL, '["LARGE BATCH","SMALL BATCH"]', '[{"name":"cold water (60° F)","amounts":[["3570","grams"],["595","grams"]],"bakers_pct":"100.00","component":null},{"name":"SAF yeast","amounts":[["10","grams"],["1.5","grams"]],"bakers_pct":"0.28","component":null},{"name":"high gluten flour","amounts":[["3570","grams"],["595","grams"]],"bakers_pct":"100.00","component":null}]', NULL, '["Place water in the bowl of a 60 quart or smaller mixer depending on batch size.","Sprinkle yeast on top. Allow it to stand for 2 to 3 minutes and whisk to combine.","Add the flour to the water.","Beat with the paddle attachment until all the flour is absorbed.","Cover and set aside for 12 to 24 hours.","For longer storage, refrigerate the poolish immediately."]', '[]', 'Pastry_Module_2_Course_3.pdf', 61);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Pre-Ferment for Farm House White', 'Breads & Yeast Doughs', 'Module 2', 'Course 3', 'Breads & Yeast Doughs', 28, NULL, NULL, '["Large Batch"]', '[{"name":"cold water (60° F)","amounts":[["3740","grams"]],"bakers_pct":"75.40","component":null},{"name":"SAF yeast","amounts":[["14","grams"]],"bakers_pct":"0.28","component":null},{"name":"salt","amounts":[["49","grams"]],"bakers_pct":"1.00","component":null},{"name":"high gluten flour","amounts":[["4960","grams"]],"bakers_pct":"100.00","component":null}]', NULL, '["Sprinkle yeast on top. Allow it to stand for 2 to 3 minutes and whisk to combine.","Mix the salt into the flour and add it to the water.","Beat with the paddle attachment until all the flour is absorbed.","Cover and set aside for 12 to 24 hours (ideal time 17 hours).","For longer storage, refrigerate the pre-ferment immediately."]', '[]', 'Pastry_Module_2_Course_3.pdf', 53);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Pre-ferment', 'Breads & Yeast Doughs', 'Module 2', 'Course 3', 'Breads & Yeast Doughs', 31, NULL, NULL, '[]', '[{"name":"cold water","amounts":[["1715","grams"]],"bakers_pct":"75.55","component":null},{"name":"SAF yeast","amounts":[["7","grams"]],"bakers_pct":"0.31","component":null},{"name":"salt","amounts":[["21","grams"]],"bakers_pct":"0.93","component":null},{"name":"high gluten flour","amounts":[["2270","grams"]],"bakers_pct":"100.00","component":null},{"name":"water","amounts":[["900","grams"]],"bakers_pct":null,"component":null},{"name":"sesame seeds","amounts":[["450","grams"]],"bakers_pct":null,"component":null},{"name":"millet","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"flax seeds","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"sunflower seeds","amounts":[["450","grams"]],"bakers_pct":null,"component":null},{"name":"oats","amounts":[["450","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Mix all ingredients together on low speed.","Cover with plastic and let rest overnight. Grains & Seeds","Boil water*.","Combine all grains and seeds in a bowl. Pour boiling water on top.","Cover and let rest overnight. Combine all grains and seeds in a bowl and pour cold measured water on top. Leave at room temperature until ready to use, up to 1 week."]', '["*If soaking grains and seeds for more than one day, do NOT boil water."]', 'Pastry_Module_2_Course_3.pdf', 97);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Pretzel Dough', 'Breads & Yeast Doughs', 'Module 2', 'Course 3', 'Breads & Yeast Doughs', 32, NULL, NULL, '[]', '[{"name":"water","amounts":[["455","grams"]],"bakers_pct":"61.49","component":null},{"name":"light olive oil","amounts":[["43","grams"]],"bakers_pct":"5.81","component":null},{"name":"SAF yeast","amounts":[["6","grams"]],"bakers_pct":"0.81","component":null},{"name":"high gluten flour","amounts":[["740","grams"]],"bakers_pct":"100.00","component":null},{"name":"salt","amounts":[["14","grams"]],"bakers_pct":"1.89","component":null}]', NULL, '["Add water and olive oil to mixing bowl.","Whisk in yeast.","Add flour and salt on top.","Mix on low speed using a hook attachment for about 5 minutes. Transfer to a lightly floured surface and then take out and knead by hand for 2-3 minutes.","Place in oiled bowl and cover to let proof until double in size for about an hour. Shaping Pretzels:","Cut dough into 140 grams (5 ounce) pieces. Put a little flour on top and 1- 2 roll into empanada shape. Roll out on non floured surface to","Shape into double dutch (see diagram below – with two twists in the middle) and place on silpat or oiled pan.","Poach pretzels in simmering water for 15-20 seconds. Place on oiled pan.","Sprinkle with coarse salt.","Place in 350°F oven for about 20 minutes."]', '[]', 'Pastry_Module_2_Course_3.pdf', 109);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Shaping Doughnuts: No Filling with Filling Frying the Doughnuts: Toppings: Sugar Glaze', 'Breads & Yeast Doughs', 'Module 2', 'Course 3', 'Breads & Yeast Doughs', 33, NULL, NULL, '["1 inch thick"]', '[{"name":"confectioners sugar","amounts":[["450","grams"]],"bakers_pct":null,"component":null},{"name":"pouring fondant","amounts":[["450","grams"]],"bakers_pct":null,"component":null},{"name":"light cornsyrup","amounts":[["85","grams"]],"bakers_pct":null,"component":null},{"name":"flavoring","amounts":[["30","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Pour confectioner''s sugar in bowl. Squeeze lemon juice through strainer and whisk together. Fondant Glaze"]', '[]', 'Pastry_Module_2_Course_3.pdf', 117);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Soft Roll Dough', 'Breads & Yeast Doughs', 'Module 2', 'Course 3', 'Breads & Yeast Doughs', 29, NULL, NULL, '["Baker''s %"]', '[{"name":"water","amounts":[["354","grams"]],"bakers_pct":"39.03","component":null},{"name":"SAF yeast","amounts":[["14","grams"]],"bakers_pct":"1.54","component":null},{"name":"high gluten flour","amounts":[["907","grams"]],"bakers_pct":"100.00","component":null},{"name":"sugar","amounts":[["57","grams"]],"bakers_pct":"6.28","component":null},{"name":"salt","amounts":[["14","grams"]],"bakers_pct":"1.54","component":null},{"name":"oil","amounts":[["57","grams"]],"bakers_pct":"6.28","component":null},{"name":"eggs","amounts":[["150","grams"]],"bakers_pct":"16.54","component":null}]', NULL, '["Whisk yeast into water. Add all ingredients into mixing bowl and mix on low speed for 5 minutes.","Knead to ball on table. Place in an oiled bowl and cover with plastic wrap. Let rest for about 1 hour. Soft Roll Dough Shaping braid) For hamburger buns, divide dough into 55 gram pieces Shaping Braids:","Put a tiny bit of flour on the bench under the dough. Make a rectangle with the dough and roll into itself 3 times, sealing the end to make empanada. Elongate like baguette but thicker in the middle and tapered on the ends","Make a simple French braid, left to right always over the middle keeping it tight. Squeeze the ends and turn underneath.","Place on parchment lined sheet pan. Very lightly dust with flour. Transfer to proof box to proof until double in size.","Brush completely with egg wash.","Bake in convection oven with low fan at 350 °F for about 25 minutes, until loaves are golden. Shaping Hamburger Rolls","Cut 55 gram pieces and shape using the 1-2-3-4 dough shaping method. Round under the palm of hand with no flour.","Lightly flour top and form a disk with a rolling pin, or press flat with palm of hand.","Cover and bench proof for 5 minutes. Transfer to proof box and finish proofing until double in size.","Brush egg wash on buns and sprinkle with a few sesame seeds.","Place in convection oven at 350 °F. Must turn and rotate halfway through Bake for approximately 20 minutes, until buns are golden.","Cut 1/3 of the red dead dough and start kneading it by hand.","Roll with a pin to form an oval about ¼-inch thick.","Shape round with knife, trimming off edges to make a smooth oval.","Run a string along the edge and go about 5 inches longer. This will be the","Take a smaller piece of dough and work it pressing down onto itself. It","Roll 2 pieces about ½ inch in diameter the length of the string. Twist these","Make roses and leafs with yellow dough-same procedure as you would","Make an epi sheath with yellow dough.","Attach all decorations with water (the water acts like glue).","Place in preheated 325°F oven and bake for about an hour."]', '["For braids, divide dough into 225 gram pieces (3 per","Note – always keep dough covered"]', 'Pastry_Module_2_Course_3.pdf', 77);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('White French Bread', 'Breads & Yeast Doughs', 'Module 2', 'Course 3', 'Breads & Yeast Doughs', 26, NULL, NULL, '["Small Batch"]', '[{"name":"*water (75 °F)","amounts":[["567","grams"]],"bakers_pct":"62.50","component":null},{"name":"SAF yeast","amounts":[["11","grams"]],"bakers_pct":"1.25","component":null},{"name":"high gluten flour","amounts":[["822","grams"]],"bakers_pct":"90.63","component":null},{"name":"whole wheat flour","amounts":[["85","grams"]],"bakers_pct":"9.37","component":null},{"name":"fine sea salt","amounts":[["20","grams"]],"bakers_pct":"2.19","component":null}]', NULL, '["Place water in a mixing bowl.","Sprinkle the yeast on top and allow it to stand for approximately 3 minutes.","Whisk water until the yeast is dissolved.","Add the flours and sprinkle the salt on top of the flour.","Stir until all the flour is absorbed.","Transfer the dough to a lightly floured surface and begin kneading the dough by hand. The kneading process is -- stretch, fold, rotate and repeat, until you have a smooth, elastic dough. Or knead dough using the hook attachment of the mixer on low speed, mixing until smooth and elastic.","Lightly oil a mixing bowl, place dough in the bowl, cover with plastic wrap and let rest.","After thirty minutes turn the dough. Cover and allow to rest again until double in size.","Place the rolls evenly spaced on a sheet pan that has been sprinkled with","Allow rolls to proof until doubled in size.","Preheat the oven to 485F","When dough is ready to bake, slash tops with a deep smile face cut, cutting 2 to","Steam oven, loading rolls into a damp environment is essential.","After rolls are loaded, steam oven again for a full 5 seconds. Wait 1 1/2","Bake rolls for approximately 10 minutes until they are well colored, have risen"]', '[]', 'Pastry_Module_2_Course_3.pdf', 33);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Whole Grain Bread', 'Breads & Yeast Doughs', 'Module 2', 'Course 3', 'Breads & Yeast Doughs', 32, NULL, NULL, '["Baker''s %"]', '[{"name":"water","amounts":[["1615","grams"]],"bakers_pct":"45.95","component":null},{"name":"SAF yeast","amounts":[["28","grams"]],"bakers_pct":"0.80","component":null},{"name":"high gluten flour","amounts":[["3060","grams"]],"bakers_pct":"87.56","component":null},{"name":"whole wheat flour","amounts":[["455","grams"]],"bakers_pct":"12.94","component":null},{"name":"salt","amounts":[["50","grams"]],"bakers_pct":"1.42","component":null},{"name":"Pre-ferment","amounts":[["3655","grams"]],"bakers_pct":"103.98","component":null},{"name":"soaked grains/seeds","amounts":[["1815","grams"]],"bakers_pct":"51.64","component":null}]', NULL, '["Add water to the 60 quart mixing bowl and whisk in yeast.","Add flours and salt. Cut up and add pre-ferment.","Mix on low speed for 3 minutes. Then mix on 2nd speed for 5 minutes.","Add soaked grains and seeds. Mix to incorporate on 1st speed for about 5 to 10 minutes.","Pour into oiled bin or leave in 60 quart bowl. Turn the dough. Cover and let proof. 30 minutes later turn the dough. After another 30 minutes start shaping.","1-2-3-4 dough shaping method with 450 gram (1 pound) pieces of dough","Roll top on wet cloth and roll in oats. Place on cornmeal lined pans.","Cover and proof 80%.","Steam the oven. Place in preheated oven 515°F and steam after loaded.","1-2-3-4 dough shaping method with 85 to 115 gram (3 to 4 ounce) pieces","Round, roll top on wet cloth and then roll in oats.","Place 4 in oiled and cornmeal lined loaf pan","Cover and proof 80%. Cut diagonal cuts across each roll","Steam the oven. Place in preheated oven 515°F and steam after loaded.","1-2-3-4 dough shaping method with 70 grams (2 1/2 ounce) pieces of","Round, roll top on wet cloth and then roll in oats.","Place on a cornmeal lined pan. Proof.","Cut “x” in the center of each roll or leave plain","Steam the oven. Place in preheated oven 515°F and steam after loaded."]', '[]', 'Pastry_Module_2_Course_3.pdf', 103);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Whole Wheat Sourdough', 'Breads & Yeast Doughs', 'Module 2', 'Course 3', 'Breads & Yeast Doughs', 32, NULL, NULL, '[]', '[{"name":"water at 80° F","amounts":[["425","grams"]],"bakers_pct":null,"component":null},{"name":"high gluten flour","amounts":[["625","grams"]],"bakers_pct":null,"component":null},{"name":"whole wheat flour","amounts":[["115","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["14","grams"]],"bakers_pct":null,"component":null},{"name":"starter","amounts":[["255","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine the high gluten flour, whole wheat flour, and water and autolyse, covered, allowing extra time for the bran to fully hydrate.","Add the active starter and salt and mix by hand or on low speed until incorporated.","Knead or slap-and-fold until the dough is smooth and moderately elastic.","Bulk ferment, covered, performing stretch and folds at intervals to build strength.","Continue bulk fermentation until the dough feels airy and has risen visibly.","Turn the dough onto a lightly floured surface, divide if needed, pre-shape into a round, and let rest.","Shape gently into a boule or batard to preserve gas and place seam-side up in a floured banneton.","Proof at room temperature until nearly doubled, or retard under refrigeration overnight.","Turn the dough out onto parchment and score the top.","Bake with steam in a preheated hot oven, then reduce heat and continue baking until deeply colored and hollow-sounding.","Cool completely on a rack before slicing."]', '[]', 'Pastry_Module_2_Course_3.pdf', 100);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Zeppole Doughnuts', 'Breads & Yeast Doughs', 'Module 2', 'Course 3', 'Breads & Yeast Doughs', 33, NULL, NULL, '["Baker''s %"]', '[{"name":"milk","amounts":[["690","grams"]],"bakers_pct":"100.00","component":null},{"name":"SAF yeast, dry","amounts":[["10","grams"]],"bakers_pct":"1.45","component":null},{"name":"all purpose flour","amounts":[["460","grams"]],"bakers_pct":"66.67","component":null},{"name":"high gluten flour","amounts":[["230","grams"]],"bakers_pct":"33.33","component":null},{"name":"light brown sugar","amounts":[["29","grams"]],"bakers_pct":"4.20","component":null},{"name":"salt","amounts":[["6","grams"]],"bakers_pct":"0.87","component":null}]', NULL, '["Warm milk to 100 °F.","Whisk yeast into milk.","Add flours, sugar, and salt.","Mix on low speed using the hook attachment for about 10 minutes. (Dough will be very soft).","Cover and let rise at room temperature for about 1 hour, until double in size. Shaping Doughnuts","Heat the canola oil to 375° F","Carefully dip two metal tablespoons in the hot oil.","Take a large spoonful of the dough and use the other spoon to gently push it into the oil.","Repeat until there are several zeppoles in the hot oil. Flip them during the frying process to make sure both sides are colored evenly.","Drain on towel lined pans and while they have cooled but still slightly warm, toss them into a bowl of confectioners sugar."]', '[]', 'Pastry_Module_2_Course_3.pdf', 113);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Apricot Glaze', 'Buttercreams & Icings', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 37, NULL, NULL, '[]', '[{"name":"Apricot Preserves","amounts":[["450","grams"]],"bakers_pct":null,"component":null},{"name":"Water","amounts":[["115","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine apricot preserves, and water in a heavy saucepan;","Bring to a boil over medium heat, stirring.","Strain mixture into another saucepan. Reduce mixture until it coats the back of a metal spoon."]', '[]', 'Pastry_Module_2_Course_4.pdf', 42);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Brown Sugar Icing or Glaze', 'Buttercreams & Icings', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 52, NULL, NULL, '[]', '[{"name":"butter","amounts":[["115","grams"]],"bakers_pct":null,"component":null},{"name":"brown sugar","amounts":[["200","grams"]],"bakers_pct":null,"component":null},{"name":"milk","amounts":[["50","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["2","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla extract or bourbon","amounts":[["5","grams"]],"bakers_pct":null,"component":null},{"name":"confectioner''s sugar","amounts":[["","as needed"]],"bakers_pct":null,"component":null}]', NULL, '["Heat the butter and brown sugar to dissolve the brown sugar.","Add the milk and salt and bring to a boil.","Allow to cool. Add in the extract or bourbon. Add and mix in confectioners'' sugar to create a glaze or about 225 grams to make a frosting."]', '[]', 'Pastry_Module_3_Course_5.pdf', 52);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Chocolate Glaze', 'Buttercreams & Icings', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 65, 'Yield 1,350 grams', '1,350 grams', '["10” cardboard"]', '[{"name":"sugar","amounts":[["450","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["180","grams"]],"bakers_pct":null,"component":null},{"name":"light corn syrup","amounts":[["270","grams"]],"bakers_pct":null,"component":null},{"name":"semisweet chocolate","amounts":[["450","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Bring the sugar, water, and corn syrup to a boil making sure that all the sugar crystals are dissolved. Pour the boiled mixture over the chocolate. Whisk until smooth making sure not to get too many bubbles in the glaze.","With a cornet, write “Gustav Klimt” on the cake."]', '[]', 'Pastry_Module_3_Course_6.pdf', 49);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Chocolate Glaze for Eclairs', 'Buttercreams & Icings', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 21, NULL, NULL, '[]', '[{"name":"water","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"light corn syrup","amounts":[["170","grams"]],"bakers_pct":null,"component":null},{"name":"semisweet chocolate (finely cut)","amounts":[["570","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Bring water and corn syrup to a boil","Pour over chopped chocolate. Whisk until smooth being careful not to incorporate too many air bubbles. Strain if necessary."]', '[]', 'PA_Mod_01_Instructor.pdf', 340);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Coffee Buttercream', 'Buttercreams & Icings', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 67, 'Yield: 1,350 grams', '1,350 grams', '[]', '[{"name":"egg whites","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"granulated sugar","amounts":[["450","grams"]],"bakers_pct":null,"component":null},{"name":"butter","amounts":[["675","grams"]],"bakers_pct":null,"component":null},{"name":"Trablit coffee extract","amounts":[["10","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine egg whites and sugar in mixing bowl. Stir well with whisk and then place over simmering water.","Heat, beating with whisk, until egg whites are hot to the touch (approximately 140 ºF) and all the sugar is dissolved.","Remove from the heat and place bowl on mixer. Whisk until cool and stiff.","Switch to the paddle attachment of the mixer if desired.","Add the butter gradually and continue beating until there are no lumps of butter and the mixture is completely smooth. Add flavoring."]', '[]', 'Pastry_Module_3_Course_6.pdf', 70);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Cream Cheese Icing', 'Buttercreams & Icings', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 58, 'Yield 3,060 grams', '3,060 grams', '[]', '[{"name":"butter","amounts":[["510","grams"]],"bakers_pct":null,"component":null},{"name":"cream cheese","amounts":[["1530","grams"]],"bakers_pct":null,"component":null},{"name":"10x","amounts":[["1020","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Beat butter with paddle on medium speed until soft and light making sure there are absolutely no lumps. Beat in cream cheese and continue beating just until smooth. Add 10x (sifted if necessary) and beat just until smooth. Make sure not to overbeat. Use immediately."]', '[]', 'Pastry_Module_3_Course_5.pdf', 156);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Decorator''S Buttercream', 'Buttercreams & Icings', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 53, 'Yield 2,211 grams', '2,211 grams', '[]', '[{"name":"butter","amounts":[["340","grams"]],"bakers_pct":null,"component":null},{"name":"shortening","amounts":[["340","grams"]],"bakers_pct":null,"component":null},{"name":"10X , sifted","amounts":[["1360","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["6","grams"]],"bakers_pct":null,"component":null},{"name":"water or milk","amounts":[["130","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla or almond extract","amounts":[["10","grams"]],"bakers_pct":null,"component":null},{"name":"meringue powder","amounts":[["25","grams"]],"bakers_pct":null,"component":null}]', NULL, '["In a KitchenAid, beat the butter and shortening to remove any lumps.","Gradually add the sifted 10X and salt. Once incorporated, add the liquids.","Add the meringue powder and mix for several minutes until light and fluffy. Keep bowl covered at all times to reduce any crust forming from the meringue powder."]', '[]', 'Pastry_Module_3_Course_5.pdf', 68);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Decorator''S Buttercream', 'Buttercreams & Icings', 'Module 4', 'Course 8', 'Cake Decorating', 89, 'Yield 1,663.5 grams', '1,663.5 grams', '[]', '[{"name":"butter","amounts":[["255","grams"]],"bakers_pct":null,"component":null},{"name":"Crisco or high ratio shortening","amounts":[["255","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["4.5","grams"]],"bakers_pct":null,"component":null},{"name":"desired extract","amounts":[["11","grams"]],"bakers_pct":null,"component":null},{"name":"10X, sifted","amounts":[["1020","grams"]],"bakers_pct":null,"component":null},{"name":"meringue powder","amounts":[["16","grams"]],"bakers_pct":null,"component":null},{"name":"milk","amounts":[["100","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine butter, shortening and salt and beat with a paddle until smooth.","Add extract and beat until smooth.","Gradually add the sifted confectioner''s sugar making sure to scrape down completely.","Beat in the meringue powder, then the milk, and continue to mix for several minutes until the mixture is light and fluffy. crust from forming. and green for leaves and stems. Roses, ruffles, violets, suggested tips 103, 104 Assorted flowers with Russian tips Assorted cupped flowers, daisies, sunflowers, suggested tip #6"]', '["*Note: Always keep icings with meringue powder covered on the surface to avoid a","**Note: Each team will make one color with different shades as assigned by the Chef","Utilize the Decorator''s Buttercream for the following suggested skills:"]', 'Pastry_Module_4_Course_8.pdf', 35);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Glaze', 'Buttercreams & Icings', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 62, '(two 6” round cakes 2” high) Yield 1,638 grams', '1,638 grams', '[]', '[{"name":"powdered gelatin","amounts":[["9","grams"]],"bakers_pct":null,"component":null},{"name":"water (1)","amounts":[["45","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["120","grams"]],"bakers_pct":null,"component":null},{"name":"water (1)","amounts":[["75","grams"]],"bakers_pct":null,"component":null},{"name":"glucose","amounts":[["150","grams"]],"bakers_pct":null,"component":null},{"name":"white chocolate","amounts":[["150","grams"]],"bakers_pct":null,"component":null},{"name":"sweetened condensed milk","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"neutral glaze","amounts":[["45","grams"]],"bakers_pct":null,"component":null},{"name":"orange food color","amounts":[["","as needed"]],"bakers_pct":null,"component":null}]', NULL, '["Whip the cream to soft peak; set aside refrigerated.","Soak the gelatin in cold water.","Place chocolate into a bowl with the 90 grams of orange juice. Place over a bain marie to melt. Whisk to combine and set aside.","In a mixer, whip the yolks and orange zest to ribbon."]', '["Utilize the Pate a Bombe Method"]', 'Pastry_Module_3_Course_5.pdf', 185);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Glaze', 'Buttercreams & Icings', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 62, '(two 6” round cakes 2” high) Yield 1,270 grams', '1,270 grams', '[]', '[{"name":"powdered gelatin","amounts":[["9","grams"]],"bakers_pct":null,"component":null},{"name":"water (1)","amounts":[["45","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["120","grams"]],"bakers_pct":null,"component":null},{"name":"water (1)","amounts":[["75","grams"]],"bakers_pct":null,"component":null},{"name":"glucose","amounts":[["150","grams"]],"bakers_pct":null,"component":null},{"name":"white chocolate","amounts":[["150","grams"]],"bakers_pct":null,"component":null},{"name":"sweetened condensed milk","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"neutral glaze","amounts":[["45","grams"]],"bakers_pct":null,"component":null},{"name":"red food color","amounts":[["","as needed"]],"bakers_pct":null,"component":null}]', NULL, '["Whip the cream until soft peak; set aside refrigerated.","Soak the gelatin in cold water.","Place the chocolate and 90 grams of water (2) in a bowl. Place over a bain marie to melt and whisk to combine. Set aside.","In a mixer, whip the yolks to ribbon."]', '["Utilize the Pate a Bombe Method"]', 'Pastry_Module_3_Course_5.pdf', 187);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Glaze', 'Buttercreams & Icings', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 62, '(two 6” round cakes 2” high) Yield 993 grams', '993 grams', '[]', '[{"name":"powdered gelatin","amounts":[["9","grams"]],"bakers_pct":null,"component":null},{"name":"water (1)","amounts":[["45","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["120","grams"]],"bakers_pct":null,"component":null},{"name":"water (1)","amounts":[["75","grams"]],"bakers_pct":null,"component":null},{"name":"glucose","amounts":[["150","grams"]],"bakers_pct":null,"component":null},{"name":"white chocolate","amounts":[["150","grams"]],"bakers_pct":null,"component":null},{"name":"sweetened condensed milk","amounts":[["100","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Whip heavy cream (1) to medium peak and set aside.","Bloom gelatin sheets in cold water.","Bring milk and heavy cream (2) to a simmer, set aside.","In a large sauce pot caramelize the sugar (1) until very dark amber.","Carefully deglaze the caramel with the hot cream/milk.","Mix until the caramelized sugar is completely dissolved in the milk and return to a boil.","Meanwhile, whisk yolks and sugar (2) together, then temper with some of the boiling caramel mixture.","Return the remaining caramel mixture to the heat and whisk in the yolk mixture. Stir mixture constantly, until thickened to nappé or 180° F. Strain and cool.","Immediately add bloomed gelatin and Maldon salt to warm caramel mixture.","Fold in whipped cream.","Place entremet ring on top of an 8” cake board. Place one layer of cake in the center, making","Bloom gelatin in cold water (1) and set aside.","Bring the water (2), sugar and glucose to a boil and cook to 217 F. At 217 F., pour over the"]', '[]', 'Pastry_Module_3_Course_5.pdf', 196);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Glaze', 'Buttercreams & Icings', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 62, '(two 6” round cakes 2” high) Yield 1,081 grams', '1,081 grams', '[]', '[{"name":"powdered gelatin","amounts":[["9","grams"]],"bakers_pct":null,"component":null},{"name":"water (1)","amounts":[["45","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["120","grams"]],"bakers_pct":null,"component":null},{"name":"water (1)","amounts":[["75","grams"]],"bakers_pct":null,"component":null},{"name":"glucose","amounts":[["150","grams"]],"bakers_pct":null,"component":null},{"name":"white chocolate","amounts":[["150","grams"]],"bakers_pct":null,"component":null},{"name":"sweetened condensed milk","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"green food color","amounts":[["","as needed"]],"bakers_pct":null,"component":null}]', NULL, '["Whip heavy cream to medium peak and set aside.","Bloom gelatin sheets in cold water, then place in a small bowl over a bain marie until melted.","Mix pistachio paste and Kirsch into crème Anglaise and whisk until smooth.","Temper bloomed and melted gelatin with crème Anglaise mixture.","Fold into whipped cream. Cake Assembly","Bloom gelatin in cold water (1) and set aside.","Bring the water (2), sugar and glucose to a boil and cook to 217 F. At 217 F., pour over the"]', '[]', 'Pastry_Module_3_Course_5.pdf', 192);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Glaze', 'Buttercreams & Icings', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 62, '(two 6” round cakes 2” high) Yield 1,178 grams', '1,178 grams', '[]', '[{"name":"powdered gelatin","amounts":[["9","grams"]],"bakers_pct":null,"component":null},{"name":"water (1)","amounts":[["45","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["120","grams"]],"bakers_pct":null,"component":null},{"name":"water (1)","amounts":[["75","grams"]],"bakers_pct":null,"component":null},{"name":"glucose","amounts":[["150","grams"]],"bakers_pct":null,"component":null},{"name":"white chocolate","amounts":[["150","grams"]],"bakers_pct":null,"component":null},{"name":"sweetened condensed milk","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"purple food color","amounts":[["","as needed"]],"bakers_pct":null,"component":null}]', NULL, '["Whip heavy cream to medium peak and set aside.","Bloom gelatin sheets in cold water, then place in a small bowl over a bain marie until melted.","Mix unsweetened peanut butter into crème Anglaise and whisk until smooth.","Temper bloomed and melted gelatin with crème Anglaise mixture.","Fold into whipped cream. Cake Assembly sure there is a space around the edge between cake and ring mold. Spread 60 grams of jelly on the cake layer. Top cake with 160 grams of mousse, top with layer of cake making sure to press the second layer down slightly. Spread second cake layer with 60 grams of jelly and top","Bloom gelatin in cold water (1) and set aside.","Bring the water (2), sugar and glucose to a boil and cook to 217 F. At 217 F., pour over the"]', '[]', 'Pastry_Module_3_Course_5.pdf', 194);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Raspberry Glaze', 'Buttercreams & Icings', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 37, NULL, NULL, '[]', '[{"name":"Seedless Raspberry Preserves","amounts":[["450","grams"]],"bakers_pct":null,"component":null},{"name":"Water","amounts":[["115","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine raspberry preserves, and water in a heavy saucepan;","Bring to a boil over medium heat, stirring.","Strain mixture into another saucepan. Reduce mixture until it coats the back of a metal spoon."]', '[]', 'Pastry_Module_2_Course_4.pdf', 42);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Vanilla Buttercream', 'Buttercreams & Icings', 'Module 4', 'Course 8', 'Cake Decorating', 96, 'Yield 2,313 grams 9,252 grams', '2,313 grams', '["quart mixer","quart mixer"]', '[{"name":"milk","amounts":[["340","grams"],["1360","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["680","grams"],["2720","grams"]],"bakers_pct":null,"component":null},{"name":"AP flour","amounts":[["25","grams"],["100","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["3","grams"],["12","grams"]],"bakers_pct":null,"component":null},{"name":"butter","amounts":[["1135","grams"],["4450","grams"]],"bakers_pct":null,"component":null},{"name":"heavy cream","amounts":[["100","grams"],["400","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla","amounts":[["30","grams"],["120","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Heat milk and sugar until sugar is dissolved.","Remove from heat and add the flour and salt whisking until smooth.","Place over ice bath to cool or place in the freezer in a hotel pan.","While the mixture is cooling, beat the butter with a paddle until there are no lumps.","Gradually add the vanilla and the heavy cream.","Once the vanilla and heavy cream are incorporated, gradually add the cooled milk mixture.","Mix on low speed to incorporate ingredients. Increase speed as mixture begins to thicken. Continue to beat for 7 to 10 minutes or until butter is fully incorporated and the mixture is smooth."]', '[]', 'Pastry_Module_4_Course_8.pdf', 63);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Biscuit Cuillere Marzipan', 'Cake Decorating', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 66, NULL, NULL, '[]', '[{"name":"almond paste","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"10X","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"light corn syrup","amounts":[["65","grams"]],"bakers_pct":null,"component":null},{"name":"fondant","amounts":[["35","grams"]],"bakers_pct":null,"component":null},{"name":"food coloring","amounts":[["","as needed"]],"bakers_pct":null,"component":null}]', NULL, '["Combine almond paste and sugar with a paddle. The mixture will","Add corn syrup and fondant and mix. If the marzipan is dry,","Remove marzipan from the bowl and knead the marzipan","Unmold biscuit onto parchment paper that has been slightly sprinkled","Combine syrup and flavoring and brush on cake. Spread very thinly with","Roll up tightly from long end, using paper. Refrigerate or freeze until firm.","Spread or pipe buttercream with a thin straight tip, covering the buche (except","With a warm knife, trim the edges of the cake diagonally cutting off as little","Optionally, cut out one end of the cake diagonally and position the cut end on","Chill the cake again and decorate with decorations and finish with"]', '[]', 'Pastry_Module_3_Course_6.pdf', 58);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Buche De Noel Roulade Biscuit Swiss Meringue Buttercream Marzipan Roulade Biscuit', 'Cake Decorating', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 66, '( one half sheet pan)Yield 569 grams', '569 grams', '[]', '[{"name":"egg yolks","amounts":[["120","grams"]],"bakers_pct":null,"component":null},{"name":"whole eggs","amounts":[["200","grams"]],"bakers_pct":null,"component":null},{"name":"sugar (1)","amounts":[["55","grams"]],"bakers_pct":null,"component":null},{"name":"extract","amounts":[["5","grams"]],"bakers_pct":null,"component":null},{"name":"cake flour","amounts":[["46","grams"]],"bakers_pct":null,"component":null},{"name":"cornstarch","amounts":[["28","grams"]],"bakers_pct":null,"component":null},{"name":"egg whites","amounts":[["85","grams"]],"bakers_pct":null,"component":null},{"name":"sugar (2)","amounts":[["25","grams"]],"bakers_pct":null,"component":null},{"name":"cream of tarter","amounts":[["5","grams"]],"bakers_pct":null,"component":null}]', NULL, '["In a KitchenAid bowl combine yolks, eggs and the sugar (1).","Warm over double boiler until the sugar is dissolved and mixture is warm.","Whip until ribbon stage. Add the extract.","Then, add the sifted flour and corn starch and whip until light and fluffy.","In a separate bowl, make an ordinary meringue with the egg whites, sugar (2) and cream of tartar.","Fold together both mixtures.","Spread evenly on a flat parchment lined half sheet pan.","Bake in a 375 F. convection oven for 8-10 minutes. Suggested flavorings: vanilla extract, almond extract, coffee extract, lemon oil, orange"]', '[]', 'Pastry_Module_3_Course_6.pdf', 57);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Chocolate Plastiq', 'Cake Decorating', 'Module 4', 'Course 8', 'Cake Decorating', 89, 'Yield 665 grams', '665 grams', '[]', '[{"name":"semisweet chocolate","amounts":[["455","grams"]],"bakers_pct":null,"component":null},{"name":"light corn syrup","amounts":[["210","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Over a hot water bath, melt the chocolate just to the point where it is completely melted. Make sure not to get the chocolate too hot.","Off the heat, add the light corn syrup and mix until thoroughly combined.","Set aside to cool and store for future use."]', '[]', 'Pastry_Module_4_Course_8.pdf', 36);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Cookie Flood Icing', 'Cake Decorating', 'Module 4', 'Course 8', 'Cake Decorating', 90, 'Yield 675 grams', '675 grams', '[]', '[{"name":"10X, sifted","amounts":[["460","grams"]],"bakers_pct":null,"component":null},{"name":"whole milk or water","amounts":[["90","grams"]],"bakers_pct":null,"component":null},{"name":"light corn syrup","amounts":[["125","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine all of the ingredients and mix until completely smooth. Keep the bowl covered with a moist towel or place plastic wrap on the surface of the icing. Color deeply as colors may fade slightly. Butterfly stencil for Royal Icing flooding:"]', '["Note: This alternative flood icing can be used for cookies only, as it has a much longer"]', 'Pastry_Module_4_Course_8.pdf', 40);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Fondant', 'Cake Decorating', 'Module 4', 'Course 7', 'Chocolate & Confections', 76, NULL, NULL, '[]', '[{"name":"sucrose","amounts":[["750","grams"]],"bakers_pct":null,"component":null},{"name":"glucose syrup","amounts":[["150","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["75","grams"]],"bakers_pct":null,"component":null},{"name":"fondant *","amounts":[["75","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine sucrose, glucose and water in a small pot. Cook to 117˚C/243˚F making sure to wash down the sides of the pot and to minimize stirring as to avoid recrystallization.","Sprinkle some cold water onto marble slab; carefully pour syrup onto marble and sprinkle with additional water. Allow syrup to cool to approximately 66˚C/150˚F folding the outside inwards as to cool the syrup evenly.","Transfer the syrup to the bowl of an electric stand mixer fitted with the paddle attachment. Add the fondant and blend the syrup on medium speed until a thick, white crystallized paste has developed and continue to blend until cool enough to handle. Wrap and store for future use. sugar crystals."]', '["*The process is accelerated by using previously made fondant to initiate seeding of"]', 'Pastry_Module_4_Course_7.pdf', 28);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Fondant Icing', 'Cake Decorating', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 22, NULL, NULL, '[]', '[{"name":"fondant","amounts":[["455","grams"]],"bakers_pct":null,"component":null},{"name":"light corn syrup or glucose","amounts":[["45","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Place the fondant in a bowl. Using a metal spoon, work the corn syrup into the fondant.","Gently heat the fondant over simmering water to warm it slightly, Do not allow it to get too hot or it will lose its sheen. The ideal temperature for the fondant during heating is 100° F. During the heating, work the fondant continuously."]', '[]', 'PA_Mod_01_Instructor.pdf', 345);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Marzipan', 'Cake Decorating', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 67, NULL, NULL, '[]', '[{"name":"almond paste","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"10 X","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"light corn syrup","amounts":[["65","grams"]],"bakers_pct":null,"component":null},{"name":"fondant","amounts":[["35","grams"]],"bakers_pct":null,"component":null},{"name":"food coloring","amounts":[["","as needed"]],"bakers_pct":null,"component":null}]', NULL, '["Combine almond paste and 10 X with a paddle. The mixture will appear crumbly.","Add corn syrup and fondant and mix to combine. If the marzipan is dry, continue adding small amounts of corn syrup to slightly moisten.","Remove marzipan from the bowl and knead the marzipan smooth by hand and double wrap it in plastic. Fraisier Assembly:","Pipe crème mousseline in between the strawberries and a thin layer across the","Hull and halve the remaining strawberries and place them upright in the middle","Place the second cake layer, slightly smaller than the ring, on top, press gently","Spread top with a thin layer of vanilla buttercream or nappage.","Cover with plastic wrap and refrigerate for at least 4 hours or overnight. Place","Cover the top of the cake with textured green marzipan, or optionally,","To serve, unmold from ring mold and peel away the acetate."]', '[]', 'Pastry_Module_3_Course_6.pdf', 74);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Mint Fondant - Dark Chocolate Bonbon Mint Fondant', 'Cake Decorating', 'Module 4', 'Course 7', 'Chocolate & Confections', 83, 'Total Yield: 215 grams', '215 grams', '[]', '[{"name":"fondant","amounts":[["200","grams"]],"bakers_pct":null,"component":null},{"name":"mint compound","amounts":[["3","grams"]],"bakers_pct":null,"component":null},{"name":"egg white powder","amounts":[["1","grams"]],"bakers_pct":null,"component":null},{"name":"fine sea salt","amounts":[["0.2","grams"]],"bakers_pct":null,"component":null},{"name":"mint, fresh, finely chopped","amounts":[["2","grams"]],"bakers_pct":null,"component":null},{"name":"citric acid","amounts":[["1","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["10","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Gently heat the fondant to soften; combine with the compound, egg white powder, salt, mint, citric acid and enough water to create a smooth semi liquid paste (typically 10-15g).","Allow mixture to cool to 32˚C/90˚F and deposit the mint fondant directly into the pre- cast molds - roughly one-fourth full - either with a pastry bag or a pastry funnel with a minimum of air pockets and a flat surface. Allow the centers to set at room temperature."]', '["For the pre-cast shells:"]', 'Pastry_Module_4_Course_7.pdf', 124);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Quick Gumpaste', 'Cake Decorating', 'Module 4', 'Course 8', 'Cake Decorating', 91, NULL, NULL, '[]', '[{"name":"rolled fondant","amounts":[["455","grams"]],"bakers_pct":null,"component":null},{"name":"Tylose CMC","amounts":[["4","grams"]],"bakers_pct":null,"component":null},{"name":"white vegetable shortening (Crisco)","amounts":[["6","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Add the Tylose CMC to the rolled fondant. Rub the vegetable shortening into your palms and begin kneading the paste for a full 3 to 5 minutes to help activate the chemical.","Store airtight when not in use, and well covered while in use. eat. This chemical is white in color and thus produces a snow-white paste. When added to rolled fondant it creates a strong, pliable, and flexible gumpaste that can be rolled petal-thin and can be used immediately. Some Cake Decorators choose to make their own gumpaste and will typically use another chemical, Gum Tragacanth. Gum Tragacanth is beige in color and thus produces a slightly off-white paste. Although both chemicals perform the same function, gumpaste made with Gum Tragacanth typically needs to be aged for several hours or overnight to work properly. As a little gumpaste can go a long way, particularly when making items petal thin, it is best not to make too much gumpaste in advance as it can harden and develop an unusable crust over several days. in very humid days."]', '["Note: Tylose CMC - This is a natural chemical and is found in some of the foods we","Note: Gumpaste items can be placed in a proof box with no humidity to assist in drying"]', 'Pastry_Module_4_Course_8.pdf', 46);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Royal Icing', 'Cake Decorating', 'Module 4', 'Course 8', 'Cake Decorating', 90, 'Yield 869 grams', '869 grams', '[]', '[{"name":"(pasteurized if available) egg whites","amounts":[["135","grams"]],"bakers_pct":null,"component":null},{"name":"10x (sifted if necessary)","amounts":[["730","grams"]],"bakers_pct":null,"component":null},{"name":"lemon juice","amounts":[["4","grams"]],"bakers_pct":null,"component":null}]', NULL, '["In a Kitchen Aid bowl with a paddle, combine the ingredients and beat until the mixture is very white and holds its shape completely.","Keep covered with a damp towel. embroidery, cornelli lace, marbling, Swiss dots, etc."]', '["Note: Use this icing for flood work, outlining, (butterfly etc.), monograms, brush","For flooding, dilute the icing with additional egg whites, water, or as instructed."]', 'Pastry_Module_4_Course_8.pdf', 40);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Smoked Almond Financier, Goat Cheese Fondant, Red Wine Caramel, Caramelized Cherry Smoked Almond Financier', 'Cake Decorating', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 71, NULL, NULL, '[]', '[{"name":"almond flour","amounts":[["63","grams"]],"bakers_pct":null,"component":null},{"name":"AP flour","amounts":[["63","grams"]],"bakers_pct":null,"component":null},{"name":"smoking brick","amounts":[["10","grams"]],"bakers_pct":null,"component":null},{"name":"butter, unsalted","amounts":[["150","grams"]],"bakers_pct":null,"component":null},{"name":"10X sugar","amounts":[["190","grams"]],"bakers_pct":null,"component":null},{"name":"smoked salt","amounts":[["1","gram"]],"bakers_pct":null,"component":null},{"name":"egg whites","amounts":[["160","grams"]],"bakers_pct":null,"component":null}]', '[["627","grams"]]', '["Combine the flours and gently smoke in a covered container for one hour, relighting the brick every 15 minutes.","Meanwhile, cook the butter over medium heat to a medium brown color, whisking occasionally to avoid scorching. Reserve warm.","Combine smoked flours with the 10X sugar. In a large mixing bowl, manually whip egg whites just until frothy and yellow color dissipates. Whisk in the flour mixture.","Slowly whisk in warm brown butter, ensuring complete emulsification. Allow to rest, chilled, at least one hour."]', '[]', 'Pastry_Module_3_Course_6.pdf', 161);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('White Chocolate Plastiq', 'Cake Decorating', 'Module 4', 'Course 8', 'Cake Decorating', 87, 'Yield 1,165 grams', '1,165 grams', '[]', '[{"name":"white chocolate","amounts":[["910","grams"]],"bakers_pct":null,"component":null},{"name":"light corn syrup","amounts":[["255","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Over a hot water bath, melt the chocolate just to the point where it is completely melted. Alternatively, melt the chocolate in a microwave. Place the chocolate in a large bowl. Make absolutely sure not to get the chocolate too hot!","Off the heat, add warmed light corn syrup by drizzling it over the white chocolate. Mix for a maximum of 25-30 strokes.","Set aside to cool and store for future use. time to begin to cool. cooled and kneaded pliable. Compound chocolate can be substituted for white chocolate in this preparation."]', '["Note: To use white chocolate plastiq the same day, it can be refrigerated for a short","Optional: Add 400-450 grams of rolled fondant to white chocolate plastiq once it is"]', 'Pastry_Module_4_Course_8.pdf', 24);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('‘Black-And-White'' Bonbon Chocolate Fondant', 'Cake Decorating', 'Module 4', 'Course 7', 'Chocolate & Confections', 83, 'Total Yield: 200.5 grams', '200.5 grams', '[]', '[{"name":"fondant","amounts":[["150","grams"]],"bakers_pct":null,"component":null},{"name":"fine sea salt","amounts":[["0.5","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["20","grams"]],"bakers_pct":null,"component":null},{"name":"unsweetened chocolate, melted","amounts":[["20","grams"]],"bakers_pct":null,"component":null},{"name":"butter, room temperature","amounts":[["10","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Gently heat the fondant, salt and water to soften over a bain marie. Add the melted chocolate to create a smooth semi liquid paste.","Allow mixture to cool to 35˚C/95˚F and stir in the butter. Deposit the fondant directly into the pre-cast molds - roughly one-fourth full - either with a pastry bag or a pastry funnel with a minimum of air pockets and a flat surface. Allow the centers to set at room temperature."]', '["For the pre-cast shells:"]', 'Pastry_Module_4_Course_7.pdf', 118);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Almond Pear Cake', 'Cakes & Sponges', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 69, '(two 10” cakes) Yield 2,286 grams', '2,286 grams', '[]', '[{"name":"almond paste","amounts":[["450","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["400","grams"]],"bakers_pct":null,"component":null},{"name":"butter, softened","amounts":[["450","grams"]],"bakers_pct":null,"component":null},{"name":"eggs","amounts":[["500","grams"]],"bakers_pct":null,"component":null},{"name":"lemon zest","amounts":[["2","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla","amounts":[["24","grams"]],"bakers_pct":null,"component":null},{"name":"cake flour","amounts":[["460","grams"]],"bakers_pct":null,"component":null},{"name":"poached pears","amounts":[["8","each"]],"bakers_pct":null,"component":null}]', NULL, '["Utilizing a paddle, cream the almond paste with sugar and butter making sure there are absolutely no lumps.","Add eggs and vanilla gradually to combine. Add flour and mix just until smooth.","Place the batter in two (10”) parchment lined round cake pans.","Dry the pears. Cut the pears to fan them and place them evenly, 8 halves for each cake, rounded side up in the batter. Place the pears evenly in the batter making sure to give space in between to allow the cake to bake properly. Bake at 350 F.","Once unmolded and cooled, slice the cakes in two layers and spread the bottom layer with desired jam and reassemble. Brush only the pears with nappage and sprinkle the cake heavily with 10X."]', '["Utilize the Pain de Gene mixing method","**Important: Prepare poached pear recipe below, first, before preparing cake"]', 'Pastry_Module_3_Course_6.pdf', 126);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Almond Sponge', 'Cakes & Sponges', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 71, NULL, NULL, '[]', '[{"name":"almond flour","amounts":[["125","grams"]],"bakers_pct":null,"component":null},{"name":"10X sugar","amounts":[["125","grams"]],"bakers_pct":null,"component":null},{"name":"AP flour","amounts":[["30","grams"]],"bakers_pct":null,"component":null},{"name":"heavy cream","amounts":[["40","grams"]],"bakers_pct":null,"component":null},{"name":"whole milk","amounts":[["40","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose","amounts":[["50","grams"]],"bakers_pct":null,"component":null},{"name":"egg white powder","amounts":[["2","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["1","grams"]],"bakers_pct":null,"component":null},{"name":"egg whites","amounts":[["115","grams"]],"bakers_pct":null,"component":null}]', '[["558","grams"]]', '["In a large bowl, combine almond flour, 10X and flour.","Meanwhile, combine cream and milk in a small saucepan. Bring just to a boil","Stir the cream and milk mixture into dry ingredients to create a thick paste.","Combine sucrose, dry egg whites, and salt. Begin whipping egg whites and slowly add the sucrose mixture. Continue to whip to a firm peak.","Fold a small amount of meringue into the sponge base to lighten. Add the lightened base to the egg whites and gently fold until thoroughly combined.","Transfer to a pastry bag fitted with a plain tip and pipe appropriate sized circles onto parchment, or spread evenly into a prepared half sheet pan. Dust surface with confectioner''s sugar. Bake in a convection oven at 180˚C/350˚F for five minutes, and then reduce heat to 150°C/300°F and bake an additional ten minutes or until golden brown. Remove circles with parchment from sheet pan and allow to cool on a rack. Trim the circles slightly smaller than the base of the large hemisphere molds."]', '[]', 'Pastry_Module_3_Course_6.pdf', 150);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Angel Food Cake', 'Cakes & Sponges', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 53, 'Yield 830 grams', '830 grams', '[]', '[{"name":"egg whites","amounts":[["350","grams"]],"bakers_pct":null,"component":null},{"name":"lemon juice","amounts":[["3","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["3","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla extract","amounts":[["4","grams"]],"bakers_pct":null,"component":null},{"name":"sugar, granulated, processed in a Robot Coupe","amounts":[["115","grams"]],"bakers_pct":null,"component":null},{"name":"sugar, granulated, processed in a Robot Coupe","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"cake flour, sifted","amounts":[["130","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Begin whipping the egg whites with the lemon juice, salt and vanilla extract and make an ordinary meringue with the sugar (1). Whip until soft peaks, being careful not to over whip the whites.","Combine the sugar (2) with the flour and fold in, in several additions just until incorporated.","Place in a tube pan with a removable bottom that has ONLY the bottom greased and lined with parchment paper. Do not grease the sides of the pan.","Bake at 350 F.","Remove from oven and carefully turn upside down to cool. Variations: Citrus: Add 8 grams of citrus zest when folding flour into meringue Green tea: Add 5 grams green tea powder to flour/sugar mixture when folding into meringue Cocoa: Add 9 grams of cocoa powder to flour/sugar mixture when folding into meringue"]', '[]', 'Pastry_Module_3_Course_5.pdf', 63);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Basic Chocolate Cupcake', 'Cakes & Sponges', 'Module 4', 'Course 8', 'Cake Decorating', 88, '(approximately 24)Yield 1,845 grams', '1,845 grams', '[]', '[{"name":"sugar","amounts":[["476","grams"]],"bakers_pct":null,"component":null},{"name":"cocoa powder","amounts":[["125","grams"]],"bakers_pct":null,"component":null},{"name":"butter, softened and cubed","amounts":[["250","grams"]],"bakers_pct":null,"component":null},{"name":"AP flour","amounts":[["370","grams"]],"bakers_pct":null,"component":null},{"name":"baking powder","amounts":[["10","grams"]],"bakers_pct":null,"component":null},{"name":"baking soda","amounts":[["5","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["6","grams"]],"bakers_pct":null,"component":null},{"name":"milk","amounts":[["408","grams"]],"bakers_pct":null,"component":null},{"name":"whole eggs","amounts":[["187","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla","amounts":[["6","grams"]],"bakers_pct":null,"component":null}]', NULL, '["With a paddle, combine the first 6 ingredients.","Add half of the combined liquid ingredients and mix until there is no butter visible. Mix for two additional minutes.","With the mixer on, add remaining liquid in a slow steady stream. Mix for an additional two minutes.","Place in muffin pans and bake at 350 F."]', '["Utilize the High Ratio mixing method"]', 'Pastry_Module_4_Course_8.pdf', 30);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Basic Vanilla Cake', 'Cakes & Sponges', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 70, '(three 8” round cakes) Yield 1,843 grams', '1,843 grams', '[]', '[{"name":"sugar","amounts":[["476","grams"]],"bakers_pct":null,"component":null},{"name":"cake flour","amounts":[["272","grams"]],"bakers_pct":null,"component":null},{"name":"butter, softened and cubed","amounts":[["250","grams"]],"bakers_pct":null,"component":null},{"name":"AP flour","amounts":[["221","grams"]],"bakers_pct":null,"component":null},{"name":"baking powder","amounts":[["17","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["6","grams"]],"bakers_pct":null,"component":null},{"name":"milk","amounts":[["408","grams"]],"bakers_pct":null,"component":null},{"name":"eggs","amounts":[["187","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla","amounts":[["6","grams"]],"bakers_pct":null,"component":null}]', NULL, '["With a paddle, combine the first 6 ingredients.","Add half of the combined liquid ingredients and mix until there is no butter visible. Mix for two additional minutes.","With the mixer on, add remaining liquid in a slow steady dream. Mix for an additional two minutes."]', '["Utilize the High Ratio mixing method"]', 'Pastry_Module_3_Course_6.pdf', 133);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Basic White Cupcake', 'Cakes & Sponges', 'Module 4', 'Course 8', 'Cake Decorating', 88, '(approximately 24)Yield 1,843 grams', '1,843 grams', '[]', '[{"name":"sugar","amounts":[["476","grams"]],"bakers_pct":null,"component":null},{"name":"cake flour","amounts":[["272","grams"]],"bakers_pct":null,"component":null},{"name":"butter, softened and cubed","amounts":[["250","grams"]],"bakers_pct":null,"component":null},{"name":"AP flour","amounts":[["221","grams"]],"bakers_pct":null,"component":null},{"name":"baking powder","amounts":[["17","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["6","grams"]],"bakers_pct":null,"component":null},{"name":"milk","amounts":[["408","grams"]],"bakers_pct":null,"component":null},{"name":"egg whites","amounts":[["187","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla","amounts":[["6","grams"]],"bakers_pct":null,"component":null}]', NULL, '["With a paddle, combine the first 6 ingredients.","Add half of the combined liquid ingredients and mix until there is no butter visible. Mix for two additional minutes.","With the mixer on, add remaining liquid in a slow steady stream. Mix for an additional two minutes.","Place in muffin pans and bake at 350 F."]', '["Utilize the High Ratio mixing method"]', 'Pastry_Module_4_Course_8.pdf', 29);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Basic Yellow Cake', 'Cakes & Sponges', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 61, '(two 1/2 sheets) Yield 2,717 grams', '2,717 grams', '[]', '[{"name":"butter","amounts":[["450","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["800","grams"]],"bakers_pct":null,"component":null},{"name":"eggs","amounts":[["400","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla extract","amounts":[["20","grams"]],"bakers_pct":null,"component":null},{"name":"AP flour","amounts":[["570","grams"]],"bakers_pct":null,"component":null},{"name":"baking powder","amounts":[["27","grams"]],"bakers_pct":null,"component":null},{"name":"milk","amounts":[["450","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Cream the butter and sugar.","Add the eggs and vanilla gradually.","Alternate the combined flour and baking powder and the milk in several additions.","Spread on parchment lined sheet pan and bake at 350 F.","Ice as instructed utilizing flavored buttercream and jam as a striping layer if desired.","Finish with buttercream piping. Variations: Add 60 grams of colored sprinkles to batter to create a confetti cake."]', '["Utilize the Creaming mixing method"]', 'Pastry_Module_3_Course_5.pdf', 180);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Biscuit Cuillere Espresso Syrup Zabaione Filling Biscuit Cuillere', 'Cakes & Sponges', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 67, '( two 1/2 sheets) Yield 810 grams', '810 grams', '[]', '[{"name":"egg yolks","amounts":[["270","grams"]],"bakers_pct":null,"component":null},{"name":"sugar (1)","amounts":[["75","grams"]],"bakers_pct":null,"component":null},{"name":"egg whites","amounts":[["270","grams"]],"bakers_pct":null,"component":null},{"name":"sugar (2)","amounts":[["75","grams"]],"bakers_pct":null,"component":null},{"name":"AP flour","amounts":[["120","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Whip yolks and sugar (1) until ribboned, set aside.","Make an ordinary meringue with the whites and sugar (2).","Gently fold meringue and ribboned yolks together three quarters of the way. Complete the folding by folding in sifted AP flour.","Using a piping bag, pipe sticks of biscuit (lady fingers) next to each other onto two (1/2) sheet pans lined with parchment paper.","Dust with confectioner''s sugar 2 times.","Cook at 400 degrees for 5 minutes. Be careful not to overbake."]', '["Utilize the Biscuit mixing method"]', 'Pastry_Module_3_Course_6.pdf', 76);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Bourbon Pecan Pound Cake', 'Cakes & Sponges', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 52, '(approximately 3 metal loaf pans) Yield 1,690 grams', '1,690 grams', '[]', '[{"name":"AP flour","amounts":[["280","grams"]],"bakers_pct":null,"component":null},{"name":"light brown sugar","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"baking powder","amounts":[["7","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["3","grams"]],"bakers_pct":null,"component":null},{"name":"softened unsalted butter","amounts":[["450","grams"]],"bakers_pct":null,"component":null},{"name":"eggs","amounts":[["200","grams"]],"bakers_pct":null,"component":null},{"name":"egg yolks","amounts":[["60","grams"]],"bakers_pct":null,"component":null},{"name":"Kentucky Bourbon","amounts":[["55","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla extract","amounts":[["9","grams"]],"bakers_pct":null,"component":null},{"name":"finely chopped pecan pieces","amounts":[["170","grams"]],"bakers_pct":null,"component":null},{"name":"AP flour","amounts":[["6","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine the dry ingredients and butter. Beat with a paddle until well combined.","While the dry ingredients and butter are mixing, combine all the remaining batter ingredients together in a mixing bowl until well combined.","Add approximately one third of the liquid. Mix for several minutes making sure to scrape the bowl well. Repeat this process with the other thirds of the liquid mixture.","Toss the pecans with the 6g of flour and fold into the mixture.","Place in metal pans (which have been buttered or sprayed and lined with parchment) or paper loaf pans.","Bake at 325 F.","Cool the cake in the pan on a rack for 10 minutes, and then remove from the pan to finish cooling the cake before glazing."]', '["Utilize the High Ratio Mixing Method"]', 'Pastry_Module_3_Course_5.pdf', 46);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Brown Butter Madeleines', 'Cakes & Sponges', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 56, 'Yield 1,522.5 grams', '1,522.5 grams', '[]', '[{"name":"butter","amounts":[["340","grams"]],"bakers_pct":null,"component":null},{"name":"eggs","amounts":[["400","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["200","grams"]],"bakers_pct":null,"component":null},{"name":"dark brown sugar","amounts":[["90","grams"]],"bakers_pct":null,"component":null},{"name":"honey","amounts":[["90","grams"]],"bakers_pct":null,"component":null},{"name":"AP flour","amounts":[["257","grams"]],"bakers_pct":null,"component":null},{"name":"cake flour","amounts":[["120","grams"]],"bakers_pct":null,"component":null},{"name":"baking powder","amounts":[["22.5","grams"]],"bakers_pct":null,"component":null},{"name":"fine sea salt","amounts":[["3","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Brown the butter with the scraped vanilla bean and cool until room temp, but still liquid. Strain.","Whip eggs, sugar, brown sugar, and honey to heavy ribbon.","Sift the dry ingredients and fold into ribboned mixture.","Fold in butter.","Chill batter overnight.","Pipe two-thirds full into small, sprayed madeleine molds.","Bake 375F."]', '[]', 'Pastry_Module_3_Course_5.pdf', 81);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Carrot Cake Layer', 'Cakes & Sponges', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 57, 'Yield', NULL, '[]', '[{"name":"whole eggs","amounts":[["200","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["450","grams"]],"bakers_pct":null,"component":null},{"name":"vegetable or canola oil","amounts":[["320","grams"]],"bakers_pct":null,"component":null},{"name":"AP flour","amounts":[["320","grams"]],"bakers_pct":null,"component":null},{"name":"baking powder","amounts":[["8.5","grams"]],"bakers_pct":null,"component":null},{"name":"cinnamon","amounts":[["5.5","grams"]],"bakers_pct":null,"component":null},{"name":"baking soda","amounts":[["5.8","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["6.4","grams"]],"bakers_pct":null,"component":null},{"name":"carrots, peeled and grated","amounts":[["455","grams"]],"bakers_pct":null,"component":null},{"name":"walnuts, chopped","amounts":[["115","grams"]],"bakers_pct":null,"component":null}]', NULL, '["In a KitchenAid bowl, whisk together the first 3 ingredients.","Sift together the next 5 (dry) ingredients and add to the KitchenAid bowl. Mix until just combined.","Add the grated carrots and chopped walnuts and mix until incorporated.","Spread the batter on a half sheet pan lined with parchment and bake at 350 ºF.","Cool and wrap for use in the next lesson."]', '["Utilize the One Step mixing method."]', 'Pastry_Module_3_Course_5.pdf', 147);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Chocolate Biscuit', 'Cakes & Sponges', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 63, '(one half sheet pan) Yield 646 grams', '646 grams', '[]', '[{"name":"egg yolks","amounts":[["150","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"egg whites","amounts":[["140","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["24","grams"]],"bakers_pct":null,"component":null},{"name":"cake flour","amounts":[["89","grams"]],"bakers_pct":null,"component":null},{"name":"cocoa powder","amounts":[["20","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Whip egg yolks and sugar until thick and ribbon stage. Transfer to a wide bowl and set aside.","Meanwhile, sift dry ingredients and set aside.","Whip egg whites and gradually add the sugar. Whip until stiff peak.","Fold the whipped egg whites into the ribboned yolks by first folding 1/3 of the whites to lighten the mixture before folding in the remaining whites.","Fold in the sifted dry ingredients.","Spread batter evenly onto a very flat parchment-lined half sheet pan, making sure to get enough in the corners.","Bake for approximately 10 minutes in a 375 ºF. convection oven, rotating the sheet pans half- way through baking."]', '["Utilize the Biscuit mixing method."]', 'Pastry_Module_3_Course_6.pdf', 21);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Chocolate Biscuit', 'Cakes & Sponges', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 71, NULL, NULL, '[]', '[{"name":"almond flour","amounts":[["150","grams"]],"bakers_pct":null,"component":null},{"name":"rice flour","amounts":[["150","grams"]],"bakers_pct":null,"component":null},{"name":"dark chocolate (aprox.70%), melted","amounts":[["420","grams"]],"bakers_pct":null,"component":null},{"name":"unsalted butter, softened","amounts":[["190","grams"]],"bakers_pct":null,"component":null},{"name":"egg yolk","amounts":[["120","grams"]],"bakers_pct":null,"component":null},{"name":"egg white","amounts":[["280","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose","amounts":[["340","grams"]],"bakers_pct":null,"component":null}]', '[["825","grams"]]', '["Thoroughly combine the almond and rice flours and reserve.","Combine the melted chocolate and softened butter, followed by the egg yolks.","Meanwhile, begin a French-style meringue with the egg whites, adding the sucrose in stages to achieve firm peaks. Fold the flours into the chocolate mixture, followed by the meringue. arranged on a Silpat-lined sheet pan. Insert the frozen ganache centers and top with an additional 15g of the base. *Freeze.","Bake the cakes from the frozen state on a double Silpat-lined sheet pan at with low or no fan, for approximately 13 minutes, turning the pan halfway during the baking process. Allow to cool slightly before unmolding."]', '["*Or alternatively, bake the cakes fresh and reheat for service."]', 'Pastry_Module_3_Course_6.pdf', 158);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Chocolate Cake', 'Cakes & Sponges', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 62, '(one ½ sheet pan) Yield 729 grams', '729 grams', '["6” entremet","2” high"]', '[{"name":"butter","amounts":[["90","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["190","grams"]],"bakers_pct":null,"component":null},{"name":"eggs","amounts":[["75","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["180","grams"]],"bakers_pct":null,"component":null},{"name":"AP flour","amounts":[["150","grams"]],"bakers_pct":null,"component":null},{"name":"cocoa powder","amounts":[["36","grams"]],"bakers_pct":null,"component":null},{"name":"baking soda","amounts":[["4","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["2","grams"]],"bakers_pct":null,"component":null},{"name":"baking powder","amounts":[["2","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Cream butter and sugar.","Gradually add liquid until incorporated. The mixture will appear broken.","Add dry ingredients.","Bake on a parchment-lined half sheet pan at 350ºF. When cool, cut out four 5 ½” discs per sheet. Reserve the remaining cake to assemble individual mousses if needed."]', '["Utilize the Creaming Mixing Method"]', 'Pastry_Module_3_Course_5.pdf', 184);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Chocolate Cinnamon Chiffon Cake', 'Cakes & Sponges', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 52, '(approximately 3 metal loaf pans) Yield 1,279 grams', '1,279 grams', '[]', '[{"name":"cocoa powder","amounts":[["56","grams"]],"bakers_pct":null,"component":null},{"name":"boiling water","amounts":[["180","grams"]],"bakers_pct":null,"component":null},{"name":"cake flour","amounts":[["210","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["280","grams"]],"bakers_pct":null,"component":null},{"name":"baking powder","amounts":[["11","grams"]],"bakers_pct":null,"component":null},{"name":"cinnamon","amounts":[["5","grams"]],"bakers_pct":null,"component":null},{"name":"vegetable oil","amounts":[["110","grams"]],"bakers_pct":null,"component":null},{"name":"yolks","amounts":[["120","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla extract","amounts":[["4","grams"]],"bakers_pct":null,"component":null},{"name":"egg whites","amounts":[["240","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["60","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["3","grams"]],"bakers_pct":null,"component":null},{"name":"heavy cream","amounts":[["175","grams"]],"bakers_pct":null,"component":null},{"name":"light corn syrup","amounts":[["20","grams"]],"bakers_pct":null,"component":null},{"name":"butter","amounts":[["30","grams"]],"bakers_pct":null,"component":null},{"name":"semisweet chocolate","amounts":[["280","grams"]],"bakers_pct":null,"component":null},{"name":"instant espresso powder or Trablit extract","amounts":[["","as needed"]],"bakers_pct":null,"component":null}]', NULL, '["Sift the cocoa into a small mixing bowl and stir in the boiling water until. Whisk until cocoa is smooth. Set aside to cool.","Separately, combine the next 4 dry ingredients and stir well to mix.","In another bowl stir together the oil, egg yolks and vanilla. Stir the liquid ingredients and the cooled cocoa mixture into the dry ingredients and mix until smooth.","In a KitchenAid bowl, make an ordinary meringue with the egg whites, sugar and salt and whip to a soft peak.","Fold the combined dry/liquid batter into the meringue making sure to scrape the bottom of the bowl.","Place in metal pans (which have been buttered or sprayed and lined with parchment) or","Bake at 350 F.","While the cake is baking, prepare the ganache. Bring the cream, corn syrup and butter to a boil."]', '["Utilize the Chiffon mixing method"]', 'Pastry_Module_3_Course_5.pdf', 49);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Chocolate Cupcakes', 'Cakes & Sponges', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 52, '(approximately 21) Yield 1,914 grams', '1,914 grams', '[]', '[{"name":"cocoa powder","amounts":[["72","grams"]],"bakers_pct":null,"component":null},{"name":"hot water or coffee","amounts":[["375","grams"]],"bakers_pct":null,"component":null},{"name":"butter","amounts":[["180","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["375","grams"]],"bakers_pct":null,"component":null},{"name":"eggs","amounts":[["150","grams"]],"bakers_pct":null,"component":null},{"name":"AP Flour","amounts":[["300","grams"]],"bakers_pct":null,"component":null},{"name":"baking soda","amounts":[["5","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["4","grams"]],"bakers_pct":null,"component":null},{"name":"baking powder","amounts":[["4","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Whisk together hot liquid and cocoa powder until smooth. Let cool.","In a kitchen aid bowl with paddle attachment, cream butter and sugar together until light and fluffy.","Add the eggs gradually, scraping the bowl often.","In a separate bowl whisk together all the dry ingredients.","Alternate the liquid and dry ingredients, mixing until the batter is well emulsified.","Portion into prepared cupcake pans, 1 rounded medium scoop of approximately 65 grams each.","Bake at 350 F.","Reserve and freeze for future lessons."]', '["Utilize the Creaming mixing method"]', 'Pastry_Module_3_Course_5.pdf', 54);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Chocolate Genoise Cake (Genoise)', 'Cakes & Sponges', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 59, '(four 6” round) Yield 700 grams', '700 grams', '[]', '[{"name":"whole eggs","amounts":[["330","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["210","grams"]],"bakers_pct":null,"component":null},{"name":"AP flour","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"cocoa powder","amounts":[["33","grams"]],"bakers_pct":null,"component":null},{"name":"cooled melted butter","amounts":[["50","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Place the eggs, sugar and the salt in bowl of an electric mixer, and whisk well. Place bowl over a pot of simmering water and heat while stirring constantly with hand whisk at the bottom until mixture is lukewarm and the sugar is dissolved. Remove from heat, place on mixer and whip on high speed until cool, increased in volume and very thick (ribbon stage).","While the mixture is whipping, sift the flour and cocoa powder together. Remove egg mixture from mixer and sift flour/cocoa mixture again over the egg mixture, efficiently and quickly folding with a rubber spatula making sure to scrape the bottom. Finish by folding in cooled melted butter just until incorporated. until just firm in the center."]', '["Utilize the Genoise mixing method."]', 'Pastry_Module_3_Course_5.pdf', 161);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Coconut Cake', 'Cakes & Sponges', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 57, '(four 6” cakes) Yield 1,660 grams', '1,660 grams', '[]', '[{"name":"butter","amounts":[["230","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["480","grams"]],"bakers_pct":null,"component":null},{"name":"eggs","amounts":[["200","grams"]],"bakers_pct":null,"component":null},{"name":"AP flour","amounts":[["390","grams"]],"bakers_pct":null,"component":null},{"name":"baking powder","amounts":[["6","grams"]],"bakers_pct":null,"component":null},{"name":"milk","amounts":[["250","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla or coconut extract","amounts":[["4","grams"]],"bakers_pct":null,"component":null},{"name":"shredded coconut, sweetened","amounts":[["100","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Cream butter and sugar.","Add eggs gradually.","Alternate the dry ingredients with the wet ingredients making sure to scrape thoroughly in between additions.","Add the shredded coconut and mix until just combined.","Divide the batter into 4 (6”) buttered or sprayed cake pans lined parchment.","Bake at 350º F.","Unmold, cool and wrap for the next lesson."]', '["Utilize the Creaming Mixing Method."]', 'Pastry_Module_3_Course_5.pdf', 145);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Financier', 'Cakes & Sponges', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 65, '(two 9” cakes)Yield 2,054 grams', '2,054 grams', '[]', '[{"name":"butter, melted and cooled","amounts":[["285","grams"]],"bakers_pct":null,"component":null},{"name":"water or rum","amounts":[["55","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla extract","amounts":[["12","grams"]],"bakers_pct":null,"component":null},{"name":"egg whites","amounts":[["450","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["2","grams"]],"bakers_pct":null,"component":null},{"name":"sugar (1)","amounts":[["340","grams"]],"bakers_pct":null,"component":null},{"name":"almond flour","amounts":[["285","grams"]],"bakers_pct":null,"component":null},{"name":"sugar (2)","amounts":[["340","grams"]],"bakers_pct":null,"component":null},{"name":"AP flour","amounts":[["285","grams"]],"bakers_pct":null,"component":null},{"name":"almonds, sliced for sprinkling on top","amounts":[["","as needed"]],"bakers_pct":null,"component":null}]', NULL, '["Combine the butter, water or rum, and the vanilla extract and set aside","Make an ordinary meringue from the whites, salt and sugar (1) and whip until soft peak.","Alternately, fold the liquid ingredients and the combined dry ingredients (with the sugar (2) into the meringue just until combined."]', '[]', 'Pastry_Module_3_Course_6.pdf', 53);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Gluten Free Chocolate Cupcakes', 'Cakes & Sponges', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 52, '(2 dozen) Yield: 1,344 grams', '1,344 grams', '[]', '[{"name":"bittersweet chocolate","amounts":[["170","grams"]],"bakers_pct":null,"component":null},{"name":"vegetable oil","amounts":[["200","grams"]],"bakers_pct":null,"component":null},{"name":"GF Flour Blend","amounts":[["200","grams"]],"bakers_pct":null,"component":null},{"name":"baking powder","amounts":[["7","grams"]],"bakers_pct":null,"component":null},{"name":"xanthan gum","amounts":[["2.5","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["5","grams"]],"bakers_pct":null,"component":null},{"name":"baking soda","amounts":[["4","grams"]],"bakers_pct":null,"component":null},{"name":"cocoa powder","amounts":[["56","grams"]],"bakers_pct":null,"component":null},{"name":"eggs","amounts":[["4","each"]],"bakers_pct":null,"component":null},{"name":"vanilla extract","amounts":[["15","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["300","grams"]],"bakers_pct":null,"component":null},{"name":"whole milk","amounts":[["226","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Over a double boiler melt chocolate and then whisk in vegetable oil.","In a separate bowl, combine the cocoa powder, gluten-free flour blend, baking powder, xanthan gum, salt and baking soda.","In a KitchenAid mixing bowl with whisk attachment, whisk together the eggs, vanilla and sugar","On low speed add the cooled melted chocolate/oil and milk and mix to combine.","Gradually add the dry ingredients and mix until thoroughly combined and smooth.","Portion into cupcakes pans and bake at 325 F. in a deck oven until just set.","Reserve and freeze for future lessons."]', '[]', 'Pastry_Module_3_Course_5.pdf', 55);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Gluten-Free Vanilla Cupcakes', 'Cakes & Sponges', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 52, '(2 dozen) Yield: 1,393.5 grams', '1,393.5 grams', '[]', '[{"name":"white chocolate","amounts":[["240","grams"]],"bakers_pct":null,"component":null},{"name":"vegetable oil","amounts":[["200","grams"]],"bakers_pct":null,"component":null},{"name":"GF Flour Blend","amounts":[["370","grams"]],"bakers_pct":null,"component":null},{"name":"baking powder","amounts":[["10","grams"]],"bakers_pct":null,"component":null},{"name":"xanthan gum","amounts":[["2.5","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["5","grams"]],"bakers_pct":null,"component":null},{"name":"baking soda","amounts":[["2","grams"]],"bakers_pct":null,"component":null},{"name":"eggs","amounts":[["200","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla","amounts":[["15","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["200","grams"]],"bakers_pct":null,"component":null},{"name":"sour cream","amounts":[["150","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Over a double boiler melt white chocolate and then whisk in vegetable oil.","In a separate bowl combine the gluten-free flour blend, baking powder, xanthan gum, salt and baking soda.","In a KitchenAid mixing bowl with whisk attachment, whisk together the eggs, sugar, sour cream and vanilla until well combined and pale in color.","On low speed add the cooled melted chocolate/oil mixture and mix to combine.","Gradually add the dry ingredients and mix until thoroughly combined and smooth.","Portion into cupcakes pans and bake at 325 F. in a deck oven until just set.","Reserve and freeze for future lessons."]', '[]', 'Pastry_Module_3_Course_5.pdf', 57);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Gluten-Free Vanilla Loaf Cake', 'Cakes & Sponges', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 51, '( 1 loaf pan) Yield: 1,665 grams', '1,665 grams', '[]', '[{"name":"sugar","amounts":[["260","grams"]],"bakers_pct":null,"component":null},{"name":"sorghum flour","amounts":[["152","grams"]],"bakers_pct":null,"component":null},{"name":"potato starch","amounts":[["230","grams"]],"bakers_pct":null,"component":null},{"name":"xanthan gum","amounts":[["1","grams"]],"bakers_pct":null,"component":null},{"name":"baking powder","amounts":[["4","grams"]],"bakers_pct":null,"component":null},{"name":"water or milk","amounts":[["90","grams"]],"bakers_pct":null,"component":null},{"name":"whole eggs","amounts":[["200","grams"]],"bakers_pct":null,"component":null},{"name":"vegetable, or canola oil","amounts":[["150","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla extract","amounts":[["18","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine dry ingredients in the KitchenAid bowl with a whisk.","Whisk liquids together and add to dry ingredients with the machine running on low speed.","Stop the machine and scrape the bowl. Resume mixing for an additional 4-5 minutes.","Pour batter into a sprayed, parchment-lined metal loaf pan, and bake in a preheated 325°F oven for approximately 50 minutes or until just set."]', '["Utilize the One Step mixing method."]', 'Pastry_Module_3_Course_5.pdf', 39);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('High-Ratio Buttermilk Pound Cake', 'Cakes & Sponges', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 52, '(approximately 6 paper loaf pans) Yield 1,363 grams', '1,363 grams', '[]', '[{"name":"AP flour","amounts":[["285","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["450","grams"]],"bakers_pct":null,"component":null},{"name":"baking powder","amounts":[["7","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["3","grams"]],"bakers_pct":null,"component":null},{"name":"softened butter","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"eggs","amounts":[["200","grams"]],"bakers_pct":null,"component":null},{"name":"egg yolks","amounts":[["60","grams"]],"bakers_pct":null,"component":null},{"name":"buttermilk","amounts":[["120","grams"]],"bakers_pct":null,"component":null},{"name":"lemon zest","amounts":[["5","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla extract","amounts":[["8","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine the dry ingredients and butter. Beat with a paddle until well combined.","While the dry ingredients and butter are mixing, combine all the remaining batter ingredients together in a mixing bowl until well combined.","Add approximately one-third of the liquid. Mix for several minutes making sure to scrape the bowl well. Repeat this process with the other thirds of the liquid mixture.","Place in paper loaf pans.","Bake at 325 F."]', '["Utilize the High Ratio mixing method"]', 'Pastry_Module_3_Course_5.pdf', 44);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('High-Ratio Fresh Ginger Pound Cake with Lemon Glaze', 'Cakes & Sponges', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 52, '(approximately 3 metal loaf pans) Yield 1,839 grams', '1,839 grams', '[]', '[{"name":"AP flour","amounts":[["280","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["450","grams"]],"bakers_pct":null,"component":null},{"name":"baking powder","amounts":[["7","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["3","grams"]],"bakers_pct":null,"component":null},{"name":"butter, softened, softened","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"eggs","amounts":[["200","grams"]],"bakers_pct":null,"component":null},{"name":"egg yolks","amounts":[["60","grams"]],"bakers_pct":null,"component":null},{"name":"milk","amounts":[["120","grams"]],"bakers_pct":null,"component":null},{"name":"ginger, grated fresh","amounts":[["85","grams"]],"bakers_pct":null,"component":null},{"name":"lemon zest","amounts":[["5","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla extract","amounts":[["4","grams"]],"bakers_pct":null,"component":null},{"name":"10x sugar","amounts":[["340","grams"]],"bakers_pct":null,"component":null},{"name":"strained lemon juice","amounts":[["30","grams"]],"bakers_pct":null,"component":null},{"name":"water or milk","amounts":[["30","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine the dry ingredients and butter. Beat with the paddle until well combined.","While the dry ingredients and butter are mixing, combine all the remaining batter ingredients together in a mixing bowl until well combined.","Add approximately one third of the liquid. Mix for several minutes making sure to scrape the bowl well. Repeat this process with the other thirds of the liquid mixture.","Place in metal pans (which have been buttered or sprayed and lined with parchment) or paper loaf pans. Bake at 325 F.","Cool the cake in the pan on a rack for 10 minutes, and then remove from the pan to finish cooling the cake before glazing.","To make the glaze, combine the sugar, lemon juice, and water or milk in a saucepan and heat over a very low temperature, whisking until smooth and just lukewarm. Drizzle over cake."]', '["Optional: chopped candied ginger for top","Utilize the High Ratio Mixing Method"]', 'Pastry_Module_3_Course_5.pdf', 45);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Klimt-Torte', 'Cakes & Sponges', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 65, '( two 10” round cakes) Yield 2,562 grams', '2,562 grams', '[]', '[{"name":"butter","amounts":[["340","grams"]],"bakers_pct":null,"component":null},{"name":"sugar (1)","amounts":[["224","grams"]],"bakers_pct":null,"component":null},{"name":"yolks","amounts":[["360","grams"]],"bakers_pct":null,"component":null},{"name":"lemon zest","amounts":[["6","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla extract","amounts":[["8","grams"]],"bakers_pct":null,"component":null},{"name":"hazelnuts flour","amounts":[["400","grams"]],"bakers_pct":null,"component":null},{"name":"breadcrumbs","amounts":[["230","grams"]],"bakers_pct":null,"component":null},{"name":"egg whites","amounts":[["540","grams"]],"bakers_pct":null,"component":null},{"name":"sugar (2)","amounts":[["224","grams"]],"bakers_pct":null,"component":null},{"name":"seedless raspberry jam for filling","amounts":[["230","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Cream the butter and sugar (1).","Beat in the yolks gradually until the mixture is very light and smooth. Add the lemon zest and vanilla extract.","Fold in the hazelnut flour and bread crumbs.","Make an ordinary meringue with the egg whites and sugar (2).","Lighten the creamed butter mixture with 1/4 of the meringue, and then fold in the remaining meringue","Unmold the cake to cool."]', '["Utilize the Modified Creaming mixing method."]', 'Pastry_Module_3_Course_6.pdf', 48);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Lemon Pound Loaf Cake', 'Cakes & Sponges', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 51, '(approximately 7 paper loaf pans) Yield 1,679.6 grams', '1,679.6 grams', '[]', '[{"name":"butter","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["450","grams"]],"bakers_pct":null,"component":null},{"name":"whole eggs","amounts":[["200","grams"]],"bakers_pct":null,"component":null},{"name":"milk","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"AP flour","amounts":[["395","grams"]],"bakers_pct":null,"component":null},{"name":"baking powder","amounts":[["14.3","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["2.3","grams"]],"bakers_pct":null,"component":null},{"name":"10x sugar","amounts":[["56","grams"]],"bakers_pct":null,"component":null},{"name":"lemon juice","amounts":[["112","grams"]],"bakers_pct":null,"component":null}]', NULL, '["In a kitchen aid bowl with a paddle, cream the butter, sugar and lemon zest.","Add eggs gradually, scraping down often. Add the milk and the combined dry ingredients alternately until just combined.","Place in paper loaf pans, filling about 2/3 full. Bake at 350 F.","While baking, whisk together 10x sugar and lemon juice.","When loaves are baked and still hot, brush the 10x sugar/lemon juice mixture very liberally on top of loaves. After 5 minutes, brush liberally again. Allow loaves to cool."]', '["Utilize the Creaming Dough mixing method:"]', 'Pastry_Module_3_Course_5.pdf', 33);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Lemon Ricotta Sponge', 'Cakes & Sponges', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 68, '(two 1/2 sheet pans )Yield 1,551 grams', '1,551 grams', '[]', '[{"name":"sugar (1)","amounts":[["130","grams"]],"bakers_pct":null,"component":null},{"name":"lemon zest","amounts":[["25","grams"]],"bakers_pct":null,"component":null},{"name":"butter, room temperature","amounts":[["230","grams"]],"bakers_pct":null,"component":null},{"name":"egg yolks","amounts":[["122","grams"]],"bakers_pct":null,"component":null},{"name":"whole milk ricotta","amounts":[["290","grams"]],"bakers_pct":null,"component":null},{"name":"lemon juice","amounts":[["77","grams"]],"bakers_pct":null,"component":null},{"name":"almond flour","amounts":[["260","grams"]],"bakers_pct":null,"component":null},{"name":"cake flour","amounts":[["72","grams"]],"bakers_pct":null,"component":null},{"name":"egg whites","amounts":[["215","grams"]],"bakers_pct":null,"component":null},{"name":"sugar (2)","amounts":[["130","grams"]],"bakers_pct":null,"component":null}]', NULL, '["In a KitchenAid bowl, combine the sugar (1) and lemon zest. Mix for several minutes with a paddle to release the oils of the zest into the sugar.","Add the room temperature butter and cream on high until light and fluffy.","Slowly add the yolks into the creaming mixture, scraping down the bowl often.","In a separate bowl whisk together the ricotta and lemon juice and add to the creamed mixture and mix until incorporated.","Add the almond and cake flour, and mix and until incorporated. Set aside in a large bowl for folding.","Make an ordinary meringue from the whites and sugar (2) and whip to soft peak.","Stir about 1/3 of the meringue into the cake batter to lighten the batter, then gently fold in the remaining 2/3 of meringue.","Divide onto two flat half sheet pans lined with parchment paper and spread evenly.","Bake 15-18 minutes at 350 F."]', '["Utilize the Modified Creaming method"]', 'Pastry_Module_3_Course_6.pdf', 93);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Light or Dark Linzertorte', 'Cakes & Sponges', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 41, NULL, NULL, '[]', '[{"name":"Linzer dough, light or dark","amounts":[["1","batch"]],"bakers_pct":null,"component":null},{"name":"raspberry preserves","amounts":[["140","grams"]],"bakers_pct":null,"component":null},{"name":"sliced almonds","amounts":[["55","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Reserve about one-third of the Linzer dough for the lattice top and refrigerate.","Line a tart pan with the remaining Linzer dough.","Spread the raspberry preserves evenly over the dough.","Roll the reserved dough and cut into strips; arrange over the preserves in a lattice pattern.","Scatter the sliced almonds over the lattice.","Bake at 350 F until the crust is golden brown."]', '[]', 'Pastry_Module_2_Course_4.pdf', 87);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Pistachio Sponge', 'Cakes & Sponges', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 71, NULL, NULL, '[]', '[{"name":"pistachio paste, sweetened","amounts":[["120","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose","amounts":[["40","grams"]],"bakers_pct":null,"component":null},{"name":"Wondra or AP flour","amounts":[["50","grams"]],"bakers_pct":null,"component":null},{"name":"whole eggs","amounts":[["200","grams"]],"bakers_pct":null,"component":null}]', '[["410","grams"]]', '["Thoroughly combine all ingredients; pass through a fine mesh sieve.","Transfer the mixture to a one-pint foam siphon and load two gas chargers, per manufacturer''s instructions.","Dispense the mixture into paper cups, into which a few regularly-spaced holes are punched.","Place in microwave and cook on high power for 30-40 seconds."]', '[]', 'Pastry_Module_3_Course_6.pdf', 167);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Plain Genoise', 'Cakes & Sponges', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 60, '(four 6” round cakes) Yield 725 grams', '725 grams', '[]', '[{"name":"whole eggs","amounts":[["330","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["210","grams"]],"bakers_pct":null,"component":null},{"name":"AP flour","amounts":[["135","grams"]],"bakers_pct":null,"component":null},{"name":"cooled melted butter","amounts":[["50","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Place the eggs, sugar and the salt in bowl of an electric mixer, and whisk well. Place bowl over a pot of simmering water and heat while stirring constantly with hand whisk until mixture is lukewarm and the sugar is dissolved. Remove from heat, place on mixer and whip on high speed until cool, increased in volume and very thick (ribbon stage).","While the mixture is whipping, sift the flour. Remove egg mixture from mixer and sift flour again over the egg mixture, efficiently and quickly folding with a rubber spatula making sure to scrape the bottom. Finish by folding in cooled melted butter just until incorporated. until just firm in the center."]', '["Utilize the Genoise mixing method"]', 'Pastry_Module_3_Course_5.pdf', 168);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Red Velvet Cake', 'Cakes & Sponges', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 58, '(two 6” cakes) Yield 1,087 grams', '1,087 grams', '[]', '[{"name":"sugar","amounts":[["253","grams"]],"bakers_pct":null,"component":null},{"name":"oil","amounts":[["215","grams"]],"bakers_pct":null,"component":null},{"name":"eggs","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"red food coloring","amounts":[["90","grams"]],"bakers_pct":null,"component":null},{"name":"cake flour","amounts":[["213","grams"]],"bakers_pct":null,"component":null},{"name":"cocoa, (not Dutch processed)","amounts":[["30","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["5","grams"]],"bakers_pct":null,"component":null},{"name":"buttermilk","amounts":[["160","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla","amounts":[["5","grams"]],"bakers_pct":null,"component":null},{"name":"vinegar","amounts":[["10","grams"]],"bakers_pct":null,"component":null},{"name":"baking soda","amounts":[["6","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Place sugar and oil in a Kitchen Aid mixer and mix utilizing the whisk attachment.","Add the eggs gradually and mix well.","Add the food coloring carefully.","Add the sifted dry ingredients, alternately with the buttermilk and vanilla until just combined.","In a separate bowl, combine the vinegar with the baking soda and quickly combine it with the rest of the batter and mix for about 10 seconds to ensure that it is well distributed.","Divide the batter evenly into 2 (6”) cake pans that have been buttered or sprayed and the bottoms lined with parchment.","Bake at 350 F."]', '[]', 'Pastry_Module_3_Course_5.pdf', 153);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Sacher Torte', 'Cakes & Sponges', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 65, '(two 10” round cakes) Yields 2,567 grams', '2,567 grams', '[]', '[{"name":"bittersweet chocolate, melted","amounts":[["400","grams"]],"bakers_pct":null,"component":null},{"name":"eggs yolks","amounts":[["160","grams"]],"bakers_pct":null,"component":null},{"name":"sugar (1)","amounts":[["280","grams"]],"bakers_pct":null,"component":null},{"name":"AP flour","amounts":[["330","grams"]],"bakers_pct":null,"component":null},{"name":"baking powder","amounts":[["7","grams"]],"bakers_pct":null,"component":null},{"name":"butter, melted and cooled","amounts":[["400","grams"]],"bakers_pct":null,"component":null},{"name":"egg whites","amounts":[["240","grams"]],"bakers_pct":null,"component":null},{"name":"sugar (2)","amounts":[["300","grams"]],"bakers_pct":null,"component":null},{"name":"apricot or raspberry jam","amounts":[["450","grams"]],"bakers_pct":null,"component":null},{"name":"heavy cream","amounts":[["400","grams"]],"bakers_pct":null,"component":null},{"name":"semi-sweet chocolate","amounts":[["400","grams"]],"bakers_pct":null,"component":null},{"name":"butter","amounts":[["100","grams"]],"bakers_pct":null,"component":null}]', NULL, '["In KitchenAid mixer, whip egg yolks and sugar (1) until ribboned.","Sift together AP flour and baking powder, fold into the ribboned yolks.","Fold in melted butter and chocolate.","Make an ordinary meringue with the egg whites and sugar (2).","Fill the center with 200 grams of apricot or raspberry jam and spread the remaining jam on the","Place in the fridge or freezer to set while you prepare the ganache.","Prepare ganache, pour over the set cake.","Place in fridge to set ganache.","Using a chocolate cornet, pipe “Sacher” on top."]', '[]', 'Pastry_Module_3_Course_6.pdf', 44);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Salted Chocolate Cake', 'Cakes & Sponges', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 51, '(approximately 11 paper loaf pans) Yield 2,285.2 grams', '2,285.2 grams', '[]', '[{"name":"unsweetened chocolate","amounts":[["170","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["345","grams"]],"bakers_pct":null,"component":null},{"name":"whole eggs","amounts":[["150","grams"]],"bakers_pct":null,"component":null},{"name":"butter (melted and cooled)","amounts":[["455","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla extract","amounts":[["9.5","grams"]],"bakers_pct":null,"component":null},{"name":"sour cream","amounts":[["205","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["600","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["6.2","grams"]],"bakers_pct":null,"component":null},{"name":"baking soda","amounts":[["4.5","grams"]],"bakers_pct":null,"component":null},{"name":"AP flour","amounts":[["340","grams"]],"bakers_pct":null,"component":null}]', NULL, '["In a KitchenAid bowl over a bain marie, heat the chocolate and water until melted and warm.","Transfer the bowl to the mixer and whisk in the next 4 (wet) ingredients.","In a separate bowl, mix together the remaining 4 (dry) ingredients.","Add the dry ingredients to the wet and mix until combined.","Place in paper loaf pans filling about 2/3 full. Sprinkle lightly with Fleur de Sal.","Bake at 350 F."]', '["Utilize the One Step mixing method."]', 'Pastry_Module_3_Course_5.pdf', 32);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Strawberry Upside Down Cakes', 'Cakes & Sponges', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 69, NULL, NULL, '[]', '[{"name":"butter","amounts":[["161","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["476","grams"]],"bakers_pct":null,"component":null},{"name":"lemon zest","amounts":[["1","grams"]],"bakers_pct":null,"component":null},{"name":"lemon extract","amounts":[["3","grams"]],"bakers_pct":null,"component":null},{"name":"cake flour","amounts":[["400","grams"]],"bakers_pct":null,"component":null},{"name":"baking powder","amounts":[["16","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["3","grams"]],"bakers_pct":null,"component":null},{"name":"egg whites","amounts":[["160","grams"]],"bakers_pct":null,"component":null},{"name":"whole milk","amounts":[["390","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Melt a portion of the butter in the bottom of the cake pans and sprinkle with a portion of the sugar to form a caramel layer.","Arrange sliced strawberries over the caramel in the pans.","Cream the remaining butter and sugar with the lemon zest and lemon extract until light.","Add the egg whites gradually, beating well after each addition.","Alternate the sifted cake flour, baking powder, and salt with the milk, adding in several additions.","Spread the batter evenly over the strawberries in the pans.","Bake at 350 F until a tester inserted in the center comes out clean.","Cool briefly in the pans, then invert onto plates while still warm."]', '[]', 'Pastry_Module_3_Course_6.pdf', 124);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Torta Caprese', 'Cakes & Sponges', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 65, '(two 10” round cakes) Yield 2,350 grams', '2,350 grams', '[]', '[{"name":"butter","amounts":[["340","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["170","grams"]],"bakers_pct":null,"component":null},{"name":"chocolate, semisweet","amounts":[["365","grams"]],"bakers_pct":null,"component":null},{"name":"yolks","amounts":[["320","grams"]],"bakers_pct":null,"component":null},{"name":"walnuts, ground","amounts":[["340","grams"]],"bakers_pct":null,"component":null},{"name":"AP flour","amounts":[["170","grams"]],"bakers_pct":null,"component":null},{"name":"egg whites","amounts":[["480","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["170","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Cream the butter and sugar.","Meanwhile, melt the chocolate over a bain marie. Remove the chocolate from the heat before it is all completely melted and allow the residual heat to melt the rest of the chocolate so the mixture does not get too hot.","Add the melted chocolate to the creamed butter and sugar. Gradually add the yolks and mix until emulsified.","Add the ground walnuts and flour and mix until just combined.","Separately, make an ordinary meringue from the whites and sugar and whip to a soft peak.","Lighten the batter with some of the meringue and then fold in the remaining meringue."]', '[]', 'Pastry_Module_3_Course_6.pdf', 50);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Tres Leches Syrup', 'Cakes & Sponges', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 65, 'cake pans)Yield 1,430 grams', '1,430 grams', '[]', '[{"name":"milk","amounts":[["520","grams"]],"bakers_pct":null,"component":null},{"name":"milk","amounts":[["450","grams"]],"bakers_pct":null,"component":null},{"name":"evaporated milk","amounts":[["380","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla","amounts":[["65","grams"]],"bakers_pct":null,"component":null},{"name":"rum or brandy","amounts":[["15","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine all of the ingredients.","Poke holes into the cooled unmolded cakes that have been put in a larger container such as a","Cover the cake and refrigerate it overnight to allow enough time for the syrup to soak in."]', '[]', 'Pastry_Module_3_Course_6.pdf', 47);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Vanilla Biscuit', 'Cakes & Sponges', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 63, '(one half sheet pan) Yield 646 grams', '646 grams', '[]', '[{"name":"egg yolks","amounts":[["150","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"egg whites","amounts":[["140","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["24","grams"]],"bakers_pct":null,"component":null},{"name":"cake flour","amounts":[["108","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Whip the egg yolks with the sugar on high speed until pale and thick, ribbon stage.","In a separate bowl, whip the egg whites, gradually adding the remaining sugar, to soft to medium peaks.","Fold one third of the meringue into the yolk mixture to lighten, then fold in the rest.","Sift the cake flour over the mixture and fold in gently until just combined.","Spread evenly onto a parchment-lined half sheet pan.","Bake at 425 F until light gold and springs back to the touch, 8 to 10 minutes."]', '[]', 'Pastry_Module_3_Course_6.pdf', 21);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Vanilla Chiffon Cake', 'Cakes & Sponges', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 52, '(approximately 3 metal loaf pans) Yield 1,257 grams', '1,257 grams', '[]', '[{"name":"cake flour","amounts":[["285","grams"]],"bakers_pct":null,"component":null},{"name":"sugar (1)","amounts":[["280","grams"]],"bakers_pct":null,"component":null},{"name":"baking powder","amounts":[["11","grams"]],"bakers_pct":null,"component":null},{"name":"vegetable oil, such as corn or canola","amounts":[["110","grams"]],"bakers_pct":null,"component":null},{"name":"egg yolks","amounts":[["80","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["180","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla extract","amounts":[["9","grams"]],"bakers_pct":null,"component":null},{"name":"egg whites","amounts":[["240","grams"]],"bakers_pct":null,"component":null},{"name":"sugar (2)","amounts":[["60","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["2","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine the first 3 dry ingredients and stir well to mix.","In another bowl stir together the oil, egg yolks, water and vanilla. Add the liquid ingredients into the dry ingredients and whisk until smooth.","In a KitchenAid bowl, make an ordinary meringue with the egg whites, sugar (2) and salt and whip to a soft peak.","Fold the combined dry/liquid batter into the meringue making sure to scrape the bottom of the bowl.","Place in metal pans (which have been buttered or sprayed and lined with parchment) or paper loaf pans.","Bake at 350 F. for about 55 to 60 minutes."]', '["Utilize the Chiffon mixing method"]', 'Pastry_Module_3_Course_5.pdf', 48);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Vanilla Cupcakes', 'Cakes & Sponges', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 52, '(approximately 18) Yield 1,158 grams', '1,158 grams', '[]', '[{"name":"egg yolks s","amounts":[["114","grams"]],"bakers_pct":null,"component":null},{"name":"milk (1)","amounts":[["60","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla","amounts":[["9","grams"]],"bakers_pct":null,"component":null},{"name":"cake flour","amounts":[["300","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["300","grams"]],"bakers_pct":null,"component":null},{"name":"baking powder","amounts":[["10","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["5","grams"]],"bakers_pct":null,"component":null},{"name":"butter, softened","amounts":[["170","grams"]],"bakers_pct":null,"component":null},{"name":"milk (2)","amounts":[["182","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine egg yolks, first measurement of milk and vanilla. Set aside.","In a KitchenAid bowl with paddle attachment, combine the cake flour, sugar, baking powder and salt.","Add the softened butter and the second measurement of milk into the dry ingredients. Mix on low speed until combined.","Add the egg yolk mixture in 3 additions, making sure to mix on high speed for 1 minute in between each addition to develop structure.","Portion into prepared cupcake pans: 1 level large scoop or 50 grams each.","Bake 15-20 minutes at 350 F.","Reserve and freeze for future lessons."]', '["Utilize the High Ratio mixing method"]', 'Pastry_Module_3_Course_5.pdf', 53);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Walnut Chiffon Cake', 'Cakes & Sponges', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 52, '(approximately 3 metal loaf pans) Yield 1,371 grams', '1,371 grams', '[]', '[{"name":"cake flour","amounts":[["285","grams"]],"bakers_pct":null,"component":null},{"name":"light brown sugar","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["60","grams"]],"bakers_pct":null,"component":null},{"name":"baking powder","amounts":[["11","grams"]],"bakers_pct":null,"component":null},{"name":"walnut oil","amounts":[["110","grams"]],"bakers_pct":null,"component":null},{"name":"egg yolks","amounts":[["80","grams"]],"bakers_pct":null,"component":null},{"name":"cold tap water","amounts":[["180","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla","amounts":[["9","grams"]],"bakers_pct":null,"component":null},{"name":"egg whites","amounts":[["240","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["55","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["1","grams"]],"bakers_pct":null,"component":null},{"name":"walnut pieces, finely chopped","amounts":[["115","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine the first 4 dry ingredients and stir well to mix.","In another bowl stir together the oil, egg yolks, water and vanilla. Add the liquid ingredients into the dry ingredients and mix until smooth.","In a KitchenAid bowl, make an ordinary meringue with the egg whites, sugar and salt and whip to a soft peak.","Fold the combined dry/liquid batter into the meringue making sure you scrape the bottom of the bowl.","Fold in the walnut pieces.","Place in metal loaf pans (which have been buttered or sprayed and lined with parchment) or paper loaf pans.","Bake at 350 F. Cool and drizzle with Brown Sugar Glaze"]', '["Utilize the Chiffon mixing method"]', 'Pastry_Module_3_Course_5.pdf', 51);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Yellow Buttermilk Cake', 'Cakes & Sponges', 'Module 4', 'Course 8', 'Cake Decorating', 95, 'Yield 2,372 grams 9,488 grams 37,952 grams', '2,372 grams', '["quart mixer","quart mixer","quart mixer"]', '[{"name":"sugar","amounts":[["570","grams"],["2280","grams"],["9120","grams"]],"bakers_pct":null,"component":null},{"name":"soft butter","amounts":[["340","grams"],["1360","grams"],["4080","grams"]],"bakers_pct":null,"component":null},{"name":"AP flour","amounts":[["570","grams"],["2280","grams"],["9120","grams"]],"bakers_pct":null,"component":null},{"name":"baking powder","amounts":[["21","grams"],["84","grams"],["336","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["7","grams"],["28","grams"],["112","grams"]],"bakers_pct":null,"component":null},{"name":"whole eggs","amounts":[["400","grams"],["1600","grams"],["6400","grams"]],"bakers_pct":null,"component":null},{"name":"buttermilk","amounts":[["340","grams"],["1360","grams"],["5440","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla extract","amounts":[["14","grams"],["56","grams"],["224","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Cream the butter and the sugar.","Combine the dry ingredients.","Combine the liquid ingredients.","Alternately add the liquid and the dry ingredients to the creamed butter and sugar.","Portion into the prepared pans lined with parchment two thirds full.","Bake at 350 F."]', '["Utilize the Creaming Mixing Method"]', 'Pastry_Module_4_Course_8.pdf', 60);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Crumb Mixture for Cheesecake', 'Cheesecakes', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 17, '2 (8”) cheesecakes Yield 270 grams', '270 grams', '[]', '[{"name":"Graham cracker crumbs","amounts":[["200","grams"]],"bakers_pct":null,"component":null},{"name":"butter, melted","amounts":[["70","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Mix the ingredients to combine well.","Use this crumb mixture for the New York and Sour Cream Cheesecake recipes."]', '[]', 'PA_Mod_01_Instructor.pdf', 252);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Mascarpone Cheesecakes', 'Cheesecakes', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 17, 'Yield 2,269 grams', '2,269 grams', '[]', '[{"name":"cream cheese, at room temperature","amounts":[["955","grams"]],"bakers_pct":null,"component":null},{"name":"granulated sugar","amounts":[["480","grams"]],"bakers_pct":null,"component":null},{"name":"Mascarpone, at room temperature","amounts":[["450","grams"]],"bakers_pct":null,"component":null},{"name":"eggs","amounts":[["350","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla","amounts":[["4","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Butter and line 16 aluminum mise en place cups with a disk of buttered parchment on the bottom.","Beat room temperature cream cheese and sugar until smooth. Do not over mix. Gently beat in mascarpone. Add eggs and vanilla until incorporated making sure to scrape down to the bottom.","Fill aluminum cups with batter. Place in bain marie. Bake at 325° F for approximately 30 minutes or until set.","While batter is baking, roll out Pate Sable dough on the following page and cut out to the size of the base of the cheesecakes. Bake until very lightly golden on the edges. Reserve until the cheesecakes are ready to be unmolded and can be used for the base when unmolded.","Chill cheesecakes overnight before unmolding."]', '[]', 'PA_Mod_01_Instructor.pdf', 255);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('New York Cheesecake', 'Cheesecakes', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 17, '2 (8”) pans Yield 2,298 grams', '2,298 grams', '[]', '[{"name":"Crumb mixture","amounts":[["1","batch"]],"bakers_pct":null,"component":null},{"name":"cream cheese (room temperature if possible)","amounts":[["1360","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["340","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla extract","amounts":[["13","grams"]],"bakers_pct":null,"component":null},{"name":"lemon juice (strained)","amounts":[["15","grams"]],"bakers_pct":null,"component":null},{"name":"eggs","amounts":[["300","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Press the crumb mixture into the pan(s).","Beat the cream cheese on low speed until smooth and free of lumps.","Add the sugar and beat until combined, scraping down the bowl.","Add the vanilla extract and lemon juice; mix until smooth.","Add the eggs gradually on low speed, mixing just until incorporated; do not overmix or incorporate excess air.","Pour the batter over the crumb crust in the pans.","Bake in a water bath at 325 F until the edges are set and the center still wobbles slightly.","Cool gradually at room temperature, then refrigerate until fully chilled before unmolding."]', '[]', 'PA_Mod_01_Instructor.pdf', 253);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Pate Sablee Crust for Mascarpone Cheesecake Bases', 'Cheesecakes', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 17, 'Yield 632 grams', '632 grams', '[]', '[{"name":"butter","amounts":[["200","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["1","gram"]],"bakers_pct":null,"component":null},{"name":"confectioners'' sugar","amounts":[["85","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla extract","amounts":[["2","grams"]],"bakers_pct":null,"component":null},{"name":"egg yolks","amounts":[["35","grams"]],"bakers_pct":null,"component":null},{"name":"all-purpose flour","amounts":[["310","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Cream butter, salt, confectioners'' sugar, and vanilla in mixer with paddle and mix until well combined and smooth.","Beat in yolks, until incorporated.","Add all the flour, mixing to combine.","Remove bowl from mixer and empty dough onto floured work surface and roll to cut out bases.","Bake at 350 until just golden around the edges."]', '[]', 'PA_Mod_01_Instructor.pdf', 256);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Sour Cream Cheesecake', 'Cheesecakes', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 17, '2 (8”) pans Yield 2,210 grams', '2,210 grams', '[]', '[{"name":"Crumb mixture","amounts":[["1","batch"]],"bakers_pct":null,"component":null},{"name":"cream cheese (room temperature if possible)","amounts":[["680","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["340","grams"]],"bakers_pct":null,"component":null},{"name":"sour cream","amounts":[["690","grams"]],"bakers_pct":null,"component":null},{"name":"eggs","amounts":[["200","grams"]],"bakers_pct":null,"component":null},{"name":"yolks","amounts":[["17","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla extract","amounts":[["13","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Press the crumb mixture into the pans.","Beat the cream cheese on low speed until smooth.","Add the sugar and beat until combined.","Add the sour cream and vanilla extract; mix until smooth.","Add the eggs and yolks gradually on low speed, mixing just until incorporated.","Pour the batter over the crumb crust in the pans.","Bake in a water bath at 325 F until set around the edges but still slightly wobbly in the center.","Cool gradually at room temperature, then chill thoroughly before unmolding."]', '[]', 'PA_Mod_01_Instructor.pdf', 254);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Tarte Au Fromage Blanc', 'Cheesecakes', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 39, NULL, NULL, '["9-inch pan"]', '[{"name":"Pasta Frolla","amounts":[["340","grams"]],"bakers_pct":null,"component":null},{"name":"yellow raisins","amounts":[["55","grams"]],"bakers_pct":null,"component":null},{"name":"farmer cheese","amounts":[["900","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["270","grams"]],"bakers_pct":null,"component":null},{"name":"eggs(3)","amounts":[["150","grams"]],"bakers_pct":null,"component":null},{"name":"yolks(2)","amounts":[["35","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla extract","amounts":[["4","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Line the tart pan with the rolled Pasta Frolla.","Soak the raisins in warm water to plump, then drain well.","Beat the farmer cheese until smooth.","Add the sugar and beat until combined.","Add the eggs, yolks, and vanilla extract; mix until smooth.","Fold in the raisins.","Pour the filling into the lined shell.","Bake at 350 F until set and lightly golden."]', '[]', 'Pastry_Module_2_Course_4.pdf', 66);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Torta Di Ricotta', 'Cheesecakes', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 39, NULL, NULL, '["10-inch pan"]', '[{"name":"Pasta Frolla","amounts":[["450","grams"]],"bakers_pct":null,"component":null},{"name":"whole milk ricotta","amounts":[["900","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"eggs(5)","amounts":[["250","grams"]],"bakers_pct":null,"component":null},{"name":"egg yolks(1)","amounts":[["17","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla extract","amounts":[["5","grams"]],"bakers_pct":null,"component":null},{"name":"anisette","amounts":[["21","grams"]],"bakers_pct":null,"component":null},{"name":"ground cinnamon","amounts":[["3","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Line the tart pan with the rolled Pasta Frolla.","Beat the ricotta until smooth.","Add the sugar and beat until combined.","Add the eggs and yolk gradually, mixing until smooth.","Add the vanilla extract, anisette, and ground cinnamon; mix to combine.","Pour the filling into the lined shell.","Bake at 350 F until set and golden."]', '[]', 'Pastry_Module_2_Course_4.pdf', 65);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Armagnac Truffles', 'Chocolate & Bonbons', 'Module 4', 'Course 7', 'Chocolate & Confections', 80, 'Total Yield: approx. 100 10g pieces 1,080 grams', '1,080 grams', '[]', '[{"name":"heavy cream (35% fat)","amounts":[["300","grams"]],"bakers_pct":null,"component":null},{"name":"invert sugar","amounts":[["80","grams"]],"bakers_pct":null,"component":null},{"name":"dark chocolate, very finely chopped or slightly melted","amounts":[["500","grams"]],"bakers_pct":null,"component":null},{"name":"butter, room temperature","amounts":[["120","grams"]],"bakers_pct":null,"component":null},{"name":"Armagnac","amounts":[["80","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Place the cream in a saucepan and bring to a boil","Meanwhile, place the chocolate and invert sugar in a large bowl. Remove the cream from heat and gradually add to the chocolate in three additions; with each addition, stir the mixture with a rubber spatula in tight circles, working from the inside of the mass toward the outside, until each addition is incorporated. The resulting ganache should be smooth, supple, and slightly elastic with glossy shine.","Allow the ganache to cool to 35˚C/95ºF. Stir in the butter and Armagnac. Transfer the ganache to a shallow third pan and allow to crystallize at room temperature.","Transfer the crystallized ganache to a pastry bag fitted with a large, plain tip (# 804 or 806) and pipe uniform mounds onto a parchment-lined half sheet pan; the individual mounds should weigh approximately 10-15g each and piped into evenly spaced in rows.","Briefly chill the pan of piped ganache until slightly firm. Quickly roll each mound into a spherical shape if necessary and arrange on a fresh parchment-lined half sheet pan."]', '["For enrobing truffles in the next lesson:"]', 'Pastry_Module_4_Course_7.pdf', 95);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Banana Ganache', 'Chocolate & Bonbons', 'Module 4', 'Course 7', 'Chocolate & Confections', 82, 'Total Yield: approx. 2 molds or 80 pc 530 grams', '530 grams', '[]', '[{"name":"heavy cream","amounts":[["150","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla bean, split and scraped","amounts":[["1","each"]],"bakers_pct":null,"component":null},{"name":"invert sugar","amounts":[["30","grams"]],"bakers_pct":null,"component":null},{"name":"white chocolate, finely chopped or slightly melted","amounts":[["260","grams"]],"bakers_pct":null,"component":null},{"name":"banana, ripe, puréed","amounts":[["40","grams"]],"bakers_pct":null,"component":null},{"name":"butter, room temperature","amounts":[["40","grams"]],"bakers_pct":null,"component":null},{"name":"dark rum","amounts":[["10","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Place the cream and vanilla bean in a saucepan and bring to a boil","Meanwhile, place the invert sugar and the white chocolate in a large bowl. Remove the cream from heat and discard the vanilla bean; gradually add to the chocolate in three additions; with each addition, stir the mixture with a rubber spatula in tight circles, working from the inside of the mass toward the outside, until each addition is incorporated. The resulting ganache should be smooth, supple, and slightly elastic with glossy shine.","Allow the ganache to cool to 35˚C/95ºF. Stir in the banana, butter, and rum. Deposit the ganache directly into the pre-cast molds, either with a pastry bag or pastry funnel with a minimum of air pockets and a flat surface, with no portion exceeding the top of the cavity. Allow a small gap to provide a sealing base and allow the centers to crystallize at room temperature.","When the centers have fully crystallized, seal the mold with additional tempered white or milk chocolate: fill the remaining space of each cavity and scrape away the excess to produce a clean, smooth base and allow to crystallize undisturbed.","Using a lined half sheet pan, carefully invert the mold to release the finished bonbons; this may require a slight tap or in some cases, the molds may require a"]', '["For the pre-cast shells:"]', 'Pastry_Module_4_Course_7.pdf', 110);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Biscuit Jaconde Coffee Syrup Coffee Buttercream Chocolate Ganache Biscuit Jaconde', 'Chocolate & Bonbons', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 67, 'Yield', NULL, '[]', '[{"name":"10X","amounts":[["315","grams"]],"bakers_pct":null,"component":null},{"name":"almond flour","amounts":[["315","grams"]],"bakers_pct":null,"component":null},{"name":"AP flour","amounts":[["84","grams"]],"bakers_pct":null,"component":null},{"name":"eggs","amounts":[["421","grams"]],"bakers_pct":null,"component":null},{"name":"whites","amounts":[["275","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["42","grams"]],"bakers_pct":null,"component":null},{"name":"butter, melted and cooled","amounts":[["63","grams"]],"bakers_pct":null,"component":null},{"name":"(three half sheet pans)","amounts":[["1515","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine the 10X, almond flour, and the AP flour in a KitchenAid bowl with the paddle attachment. Mix just to combine.","While mixing, add the eggs gradually, occasionally scraping down the sides of the bowl with a rubber spatula. It is important that before adding more eggs the mixture is beaten for a couple of minutes in between additions until it is completely emulsified. After all of the eggs have been added, beat for several minutes longer to ensure that as much air as possible has been incorporated. Transfer to a large clean bowl.","In a clean KitchenAid bowl, make a French meringue with the whites and sugar. Whip to soft peak being very careful not to over whip.","Fold the meringue quickly and gently into the egg mixture. When the mixture is about 9/10ths folded, pour in the cooled melted butter as you complete the folding."]', '["Utilize the Biscuit mixing method"]', 'Pastry_Module_3_Course_6.pdf', 69);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Caramel Truffles', 'Chocolate & Bonbons', 'Module 4', 'Course 7', 'Chocolate & Confections', 80, 'Total Yield: approx. 100 10g pieces 1,085 grams', '1,085 grams', '[]', '[{"name":"sucrose","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["50","grams"]],"bakers_pct":null,"component":null},{"name":"heavy cream (35% fat)","amounts":[["325","grams"]],"bakers_pct":null,"component":null},{"name":"glucose syrup","amounts":[["40","grams"]],"bakers_pct":null,"component":null},{"name":"butter, room temperature","amounts":[["120","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Place the sucrose in a large saucepan and dry-cook to medium dark caramel. Remove from heat and deglaze with water, and then add the cream. Bring to a boil","Meanwhile, place the chocolate and glucose syrup in a large bowl. Remove the cream mixture from heat and gradually add to the chocolate in three additions; with each addition, stir the mixture with a rubber spatula in tight circles, working from the inside of the mass toward the outside, until each addition is incorporated. The resulting ganache should be smooth, supple, and slightly elastic with glossy shine.","Allow the ganache to cool to 35˚C/95ºF. Stir in the butter. Transfer the ganache to a shallow third pan and allow to crystallize at room temperature.","Transfer the crystallized ganache to a pastry bag fitted with a large, plain tip (# 804 or 806) and pipe uniform mounds onto a parchment-lined half sheet pan; the individual mounds should weigh approximately 10-15g each and piped into evenly spaced in rows.","Briefly chill the pan of piped ganache until slightly firm. Quickly roll each mound into a spherical shape if necessary and arrange on a fresh parchment-lined half sheet pan."]', '["For enrobing truffles in the next lesson:"]', 'Pastry_Module_4_Course_7.pdf', 89);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Chocolate Clusters', 'Chocolate & Bonbons', 'Module 4', 'Course 7', 'Chocolate & Confections', 78, NULL, NULL, '[]', '[{"name":"tempered chocolate, dark or milk","amounts":[["500","grams"]],"bakers_pct":null,"component":null},{"name":"lightly toasted nuts, cooled, or other","amounts":[["350","grams"]],"bakers_pct":null,"component":null}]', NULL, '["In a bowl, combine inclusions, and stirring with a rubber spatula, quickly add tempered chocolate silpat lined sheet pan and allow to set.","As a variation, deposit the clusters directly into paper cases."]', '[]', 'Pastry_Module_4_Course_7.pdf', 64);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Chocolate Ganache', 'Chocolate & Bonbons', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 67, 'Yield: 500 grams', '500 grams', '[]', '[{"name":"heavy cream","amounts":[["250","grams"]],"bakers_pct":null,"component":null},{"name":"semi-sweet chocolate","amounts":[["250","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Make ganache and allow to cool for use as a filling."]', '[]', 'Pastry_Module_3_Course_6.pdf', 70);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Cinnamon Pistachio Ganache', 'Chocolate & Bonbons', 'Module 4', 'Course 7', 'Chocolate & Confections', 82, 'Total Yield: approx. 2 molds or 80 pc 561 grams', '561 grams', '[]', '[{"name":"heavy cream","amounts":[["160","grams"]],"bakers_pct":null,"component":null},{"name":"cinnamon, ground","amounts":[["1","grams"]],"bakers_pct":null,"component":null},{"name":"invert sugar","amounts":[["15","grams"]],"bakers_pct":null,"component":null},{"name":"pistachio paste","amounts":[["45","grams"]],"bakers_pct":null,"component":null},{"name":"white chocolate, finely chopped or slightly melted","amounts":[["280","grams"]],"bakers_pct":null,"component":null},{"name":"butter, room temperature","amounts":[["60","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Place the cream and cinnamon in a saucepan and bring to a boil.","Meanwhile, place the invert sugar, pistachio paste and the white chocolate in a large bowl. Remove the cream from heat and gradually add to the chocolate in three additions; with each addition, stir the mixture with a rubber spatula in tight circles, working from the inside of the mass toward the outside, until each addition is incorporated. The resulting ganache should be smooth, supple, and slightly elastic with glossy shine.","Allow the ganache to cool to 35˚C/95ºF. Stir in the butter. Deposit the ganache directly into the pre-cast molds, either with a pastry bag or pastry funnel with a minimum of air pockets and a flat surface, with no portion exceeding the top of the cavity. Allow a small gap to provide a sealing base and allow the centers to crystallize at room temperature.","When the centers have fully crystallized, seal the mold with additional tempered chocolate: fill the remaining space of each cavity and scrape away the excess to produce a clean, smooth base and allow to crystallize undisturbed.","Using a lined half sheet pan, carefully invert the mold to release the finished bonbons; this may require a slight tap or in some cases, the molds may require a brief chill in order achieve full contraction and release. Take care to avoid damage due to excessive force or prolonged refrigeration when releasing the chocolates"]', '["For the pre-cast shells:"]', 'Pastry_Module_4_Course_7.pdf', 109);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Dark Chocolate Ganache', 'Chocolate & Bonbons', 'Module 4', 'Course 7', 'Chocolate & Confections', 83, 'Total Yield: approx. 2 molds or 80pc 540 grams', '540 grams', '[]', '[{"name":"heavy cream","amounts":[["210","grams"]],"bakers_pct":null,"component":null},{"name":"invert sugar","amounts":[["40","grams"]],"bakers_pct":null,"component":null},{"name":"dark chocolate, finely chopped or slightly melted","amounts":[["240","grams"]],"bakers_pct":null,"component":null},{"name":"butter, room temperature","amounts":[["50","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Place the cream in a saucepan and bring to a boil.","Meanwhile, place the invert sugar and the dark chocolate in a large bowl. Remove the cream from heat and gradually add to the chocolate in three additions; with each addition, stir the mixture with a rubber spatula in tight circles, working from the inside of the mass toward the outside, until each addition is incorporated. The resulting ganache should be smooth, supple, and slightly elastic with glossy shine.","Allow the ganache to cool to 35˚C/95ºF. Stir in the butter. Deposit the ganache directly into the pre-cast molds on top of the mint fondant, either with a pastry bag or pastry funnel with a minimum of air pockets and a flat surface, with no portion exceeding the top of the cavity. Allow a small gap to provide a sealing base and allow the centers to crystallize at room temperature.","When the centers have fully crystallized, seal the mold with additional tempered dark chocolate: fill the remaining space of each cavity and scrape away the excess to produce a clean, smooth base and allow to crystallize undisturbed.","Using a lined half-sheet pan, carefully invert the mold to release the finished bonbons; this may require a slight tap or in some cases, the molds may require a brief chill in order achieve full contraction and release."]', '[]', 'Pastry_Module_4_Course_7.pdf', 125);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Dark Chocolate Spray', 'Chocolate & Bonbons', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 73, NULL, NULL, '[]', '[{"name":"cocoa butter, melted","amounts":[["300","grams"]],"bakers_pct":null,"component":null},{"name":"dark chocolate (60%), melted","amounts":[["150","grams"]],"bakers_pct":null,"component":null}]', '[["450","grams"]]', '["Combine the melted cocoa butter and dark chocolate and transfer to a chocolate spray gun, according to manufacturer''s instructions. Remove the unmolded gianduja parfait from the freezer and apply a light coat of the spray. Reserve for assembly."]', '[]', 'Pastry_Module_3_Course_6.pdf', 230);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Ganache Center', 'Chocolate & Bonbons', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 71, NULL, NULL, '[]', '[{"name":"heavy cream","amounts":[["385","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose","amounts":[["25","grams"]],"bakers_pct":null,"component":null},{"name":"fine sea salt","amounts":[["2","grams"]],"bakers_pct":null,"component":null},{"name":"invert sugar","amounts":[["15","grams"]],"bakers_pct":null,"component":null},{"name":"dark chocolate (approx.60%), chopped","amounts":[["230","grams"]],"bakers_pct":null,"component":null}]', '[["657","grams"]]', '["Combine the cream, sucrose, salt and invert sugar and bring to a boil. Remove from heat and gradually incorporate into the chocolate and homogenize with an immersion blender.","Transfer the ganache center to mini silicon dome forms and freeze.","When frozen, place two half spheres together for use."]', '[]', 'Pastry_Module_3_Course_6.pdf', 157);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Ganache Filling', 'Chocolate & Bonbons', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 73, NULL, NULL, '[]', '[{"name":"heavy cream","amounts":[["375","grams"]],"bakers_pct":null,"component":null},{"name":"glucose syrup","amounts":[["60","grams"]],"bakers_pct":null,"component":null},{"name":"chocolate (approx. 60%), melted","amounts":[["400","grams"]],"bakers_pct":null,"component":null},{"name":"butter, softened","amounts":[["45","grams"]],"bakers_pct":null,"component":null},{"name":"crushed, salted peanuts, for assembly","amounts":[["200","grams"]],"bakers_pct":null,"component":null}]', '[["880","grams"]]', '["Combine the combine cream and glucose in a small saucepan. Bring to a boil.","Place the melted chocolate in a large bowl and gradually pour hot cream over it in small additions, stirring until smooth.","Allow to cool to 35˚C/95ºF and add the butter.","Arrange tart shells on a clean baking sheet and line the bottom of each shell with crushed peanuts, about half full; reserve additional peanuts for final presentation.","Warming, if necessary, spoon the caramel filling into each shell, just to cover the peanuts. The shells at this stage should only be half to two thirds full, allowing ample space for the ganache layer. Reserve any leftover caramel in a plastic squeeze bottle.","Briefly freeze the partially filled tarts for up to 30 minutes to set the caramel. Fill the remainder of each tart with the chocolate ganache, warming if necessary. Allow tarts to stand an additional 30 minutes to one hour, at room temperature, to fully set the ganache."]', '[]', 'Pastry_Module_3_Course_6.pdf', 212);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Ganache Filling for Bon Bons', 'Chocolate & Bonbons', 'Module 4', 'Course 7', 'Chocolate & Confections', 80, 'Yield 408 grams', '408 grams', '[]', '[{"name":"heavy cream","amounts":[["56","grams"]],"bakers_pct":null,"component":null},{"name":"milk","amounts":[["56","grams"]],"bakers_pct":null,"component":null},{"name":"light corn syrup","amounts":[["30","grams"]],"bakers_pct":null,"component":null},{"name":"semisweet chocolate, finely chopped or slightly melted","amounts":[["170","grams"]],"bakers_pct":null,"component":null},{"name":"milk chocolate","amounts":[["56","grams"]],"bakers_pct":null,"component":null},{"name":"butter, very soft","amounts":[["20","grams"]],"bakers_pct":null,"component":null},{"name":"alcohol","amounts":[["25","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Place the cream and milk in a saucepan and bring to a boil.","Meanwhile, place the light corn syrup and the semisweet and milk chocolate in a large bowl. Remove the cream/milk from heat and gradually add to the chocolate in three additions; with each addition, stir the mixture with a rubber spatula in tight circles, working from the inside of the mass toward the outside, until each addition is incorporated. The resulting ganache should be smooth, supple, and slightly elastic with glossy shine.","Allow the ganache to cool to 35˚C/95ºF. Stir in the butter. Deposit the ganache directly into the pre-cast molds, either with a pastry bag or pastry funnel with a minimum of air pockets and a flat surface, with no portion exceeding the top of the cavity. Allow a small gap to provide a sealing base and allow the centers to crystallize at room temperature."]', '[]', 'Pastry_Module_4_Course_7.pdf', 102);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Ganache Glaze', 'Chocolate & Bonbons', 'Module 2', 'Course 3', 'Breads & Yeast Doughs', 33, NULL, NULL, '[]', '[{"name":"heavy cream","amounts":[["455","grams"]],"bakers_pct":null,"component":null},{"name":"semi sweet chocolate","amounts":[["340","grams"]],"bakers_pct":null,"component":null},{"name":"milk chocolate","amounts":[["115","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Heat cream to a rolling boil. Pour over chocolate.","Let sit for 3 minutes then whisk together to form ganache. Finished Doughnuts • Boston Cream - Filled with pastry cream and topped with chocolate ganache • Zeppole - Tossed in confectioners sugar or cinnamon sugar • Lemon - Covered in lemon sugar glaze and white sprinkles or rainbow. Or dipped in very light loose fondant and sprinkled with toasted shredded coconut • Cinnamon and Coffee - Instant coffee mixed with white fondant and white sprinkles or dipped in chocolate ganache glaze (Boston cream), (Lemon) and (Cinnamon Coffee)"]', '["Notes:"]', 'Pastry_Module_2_Course_3.pdf', 118);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('German Chocolate Filling Fffff Fill Fil Cake (Genoise)', 'Chocolate & Bonbons', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 59, '(four 6” round) Yield 1,528 grams', '1,528 grams', '[]', '[{"name":"cream","amounts":[["340","grams"]],"bakers_pct":null,"component":null},{"name":"butter","amounts":[["170","grams"]],"bakers_pct":null,"component":null},{"name":"sugar (1)","amounts":[["150","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["2","grams"]],"bakers_pct":null,"component":null},{"name":"pecans, finely chopped","amounts":[["300","grams"]],"bakers_pct":null,"component":null},{"name":"coconut, shredded, sweetened","amounts":[["300","grams"]],"bakers_pct":null,"component":null},{"name":"sugar (2)","amounts":[["150","grams"]],"bakers_pct":null,"component":null},{"name":"yolks","amounts":[["110","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla extract","amounts":[["6","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine the heavy cream, butter, sugar (1) and salt in a sauce pan and bring to a boil. Over medium heat, simmer for 15 minutes to reduce and thicken the mixture.","After the 15 minutes, stir in the pecans and coconut.","In a bowl, whisk together sugar (2), yolks and vanilla.","Temper the hot cream mixture into the yolk mixture. Return everything to the sauce pan and simmer for 3 minutes.","Refrigerate the mixture for use."]', '[]', 'Pastry_Module_3_Course_5.pdf', 163);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Gianduja Parfait', 'Chocolate & Bonbons', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 73, NULL, NULL, '[]', '[{"name":"water","amounts":[["55","grams"]],"bakers_pct":null,"component":null},{"name":"nonfat dry milk","amounts":[["15","grams"]],"bakers_pct":null,"component":null},{"name":"egg yolk","amounts":[["50","grams"]],"bakers_pct":null,"component":null},{"name":"glucose syrup","amounts":[["20","grams"]],"bakers_pct":null,"component":null},{"name":"hazelnut gianduja, melted","amounts":[["180","grams"]],"bakers_pct":null,"component":null},{"name":"milk chocolate, melted","amounts":[["170","grams"]],"bakers_pct":null,"component":null},{"name":"gelatin sheets, bloomed and dissolved","amounts":[["5","each"]],"bakers_pct":null,"component":null},{"name":"heavy cream (35% fat), whipped","amounts":[["400","grams"]],"bakers_pct":null,"component":null}]', '[["900","grams"]]', '["Combine the water, nonfat dry milk, egg yolk and glucose in a small saucepan and cook over low heat, stirring constantly, until mixture begins to thicken slightly. Remove from heat.","Transfer this mixture to the bowl of an electric mixer fitted with the whip attachment. Whip the mixture on high speed until cool.","Fold in the dissolved gelatin, followed by the melted chocolates.","Fold in the whipped cream.","Transfer the mixture to pastry bags and dispense into the silicon forms. Apply a previously baked pâte sucrée base onto each, and freeze."]', '[]', 'Pastry_Module_3_Course_6.pdf', 229);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Gianduja Parfait Vanilla Ice Cream', 'Chocolate & Bonbons', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 73, NULL, NULL, '[]', '[{"name":"whole milk","amounts":[["970","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla bean, split and scraped","amounts":[["2","each"]],"bakers_pct":null,"component":null},{"name":"dry nonfat milk","amounts":[["97","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose (1)","amounts":[["200","grams"]],"bakers_pct":null,"component":null},{"name":"glucose powder","amounts":[["85","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose (2)","amounts":[["80","grams"]],"bakers_pct":null,"component":null},{"name":"ice cream stabilizer","amounts":[["8","grams"]],"bakers_pct":null,"component":null},{"name":"egg yolk","amounts":[["150","grams"]],"bakers_pct":null,"component":null},{"name":"heavy cream","amounts":[["360","grams"]],"bakers_pct":null,"component":null}]', '[["1950","grams"]]', '["Place the milk and vanilla in a sauce pot. Whisk in the dry milk to rehydrate and add the first measurement of sucrose (1) and glucose. Bring to a boil.","Meanwhile, combine sucrose (2) and stabilizer. Whisk into egg yolks.","Temper hot milk into yolk mixture. Return to low heat and cook, stirring, to"]', '[]', 'Pastry_Module_3_Course_6.pdf', 227);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Ginger Truffles', 'Chocolate & Bonbons', 'Module 4', 'Course 7', 'Chocolate & Confections', 80, 'Total Yield: approx. 100 10g pieces 1,040 grams', '1,040 grams', '[]', '[{"name":"ginger, peeled and finely sliced","amounts":[["80","grams"]],"bakers_pct":null,"component":null},{"name":"heavy cream (35% fat)","amounts":[["320","grams"]],"bakers_pct":null,"component":null},{"name":"invert sugar","amounts":[["60","grams"]],"bakers_pct":null,"component":null},{"name":"milk chocolate, very finely chopped or slightly melted","amounts":[["500","grams"]],"bakers_pct":null,"component":null},{"name":"butter, room temperature","amounts":[["120","grams"]],"bakers_pct":null,"component":null},{"name":"Domain de Canton (ginger liqueur)","amounts":[["40","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Place the ginger in a saucepan and cover with cold water; bring to a boil and drain.","Combine the blanched ginger and cream in a saucepan and bring to a boil. Remove from heat, cover, and allow to infuse for 15 minutes.","Meanwhile, place the chocolate and invert sugar in a large bowl. Strain the cream and return to a boil. Remove the cream from heat and gradually add to the chocolate in three additions; with each addition, stir the mixture with a rubber spatula in tight circles, working from the inside of the mass toward the outside, until each addition is incorporated. The resulting ganache should be smooth, supple, and slightly elastic with glossy shine.","Allow the ganache to cool to 35˚C/95ºF. Stir in the butter and ginger liqueur. Transfer the ganache to a shallow third pan and allow to crystallize at room temperature.","Transfer the crystallized ganache to a pastry bag fitted with a large, plain tip (#804 or 806) and pipe uniform mounds onto a parchment-lined half sheet pan;","Briefly chill the pan of piped ganache until slightly firm. Quickly roll each mound","To enrobe, coat each truffle with a thin layer of tempered dark chocolate, allow to"]', '["For enrobing truffles in the next lesson:"]', 'Pastry_Module_4_Course_7.pdf', 93);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Green Tea Truffles', 'Chocolate & Bonbons', 'Module 4', 'Course 7', 'Chocolate & Confections', 80, 'Total Yield: approx. 100 10g pieces 1,052 grams', '1,052 grams', '[]', '[{"name":"heavy cream (35% fat)","amounts":[["350","grams"]],"bakers_pct":null,"component":null},{"name":"matcha green tea powder","amounts":[["2","grams"]],"bakers_pct":null,"component":null},{"name":"invert sugar","amounts":[["80","grams"]],"bakers_pct":null,"component":null},{"name":"dark chocolate, very finely chopped or slightly melted","amounts":[["500","grams"]],"bakers_pct":null,"component":null},{"name":"butter, room temperature","amounts":[["120","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Place the cream and matcha in a saucepan and bring to a boil","Meanwhile, place the chocolate and invert sugar in a large bowl. Remove the cream mixture from heat and gradually add to the chocolate in three additions; with each addition, stir the mixture with a rubber spatula in tight circles, working from the inside of the mass toward the outside, until each addition is incorporated. The resulting ganache should be smooth, supple, and slightly elastic with glossy shine.","Allow the ganache to cool to 35˚C/95ºF. Stir in the butter. Transfer the ganache to a shallow third pan and allow to crystallize at room temperature.","Transfer the crystallized ganache to a pastry bag fitted with a large, plain tip (#804 or 806) and pipe uniform mounds onto a parchment-lined half sheet pan; the individual mounds should weigh approximately 10-15g each and piped into evenly spaced in rows.","Briefly chill the pan of piped ganache until slightly firm. Quickly roll each mound into a spherical shape if necessary and arrange on a fresh parchment-lined half sheet pan.","To enrobe, coat each truffle with a thin layer of tempered dark chocolate and immediately drop each truffle in an ample-sized hotel pan of confectioner''s sugar"]', '["For enrobing the truffles in the next lesson:"]', 'Pastry_Module_4_Course_7.pdf', 87);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Hazelnut Praline Bar', 'Chocolate & Bonbons', 'Module 4', 'Course 7', 'Chocolate & Confections', 76, NULL, NULL, '[]', '[{"name":"cocoa butter, melted","amounts":[["50","grams"]],"bakers_pct":null,"component":null},{"name":"dark chocolate, melted","amounts":[["20","grams"]],"bakers_pct":null,"component":null},{"name":"hazelnut praline paste","amounts":[["300","grams"]],"bakers_pct":null,"component":null},{"name":"fine sea salt","amounts":[["1","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Add the melted cocoa butter and chocolate to the praline paste. Heat the whole mixture to 45°C/113°F.","Pour mixture onto a marble, working briefly with an offset spatula to cool to 30°C/ 86°F.","Transfer mixture to a plastic lined 12cm frame and allow to crystallize overnight before enrobing."]', '[]', 'Pastry_Module_4_Course_7.pdf', 34);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Honey Lavender Ganache', 'Chocolate & Bonbons', 'Module 4', 'Course 7', 'Chocolate & Confections', 82, 'Total Yield: approx. 2 molds or 80pc 510 grams', '510 grams', '[]', '[{"name":"heavy cream","amounts":[["145","grams"]],"bakers_pct":null,"component":null},{"name":"lavender, dried","amounts":[["2","grams"]],"bakers_pct":null,"component":null},{"name":"honey","amounts":[["50","grams"]],"bakers_pct":null,"component":null},{"name":"dark chocolate, finely chopped or slightly melted","amounts":[["260","grams"]],"bakers_pct":null,"component":null},{"name":"butter, room temperature","amounts":[["50","grams"]],"bakers_pct":null,"component":null},{"name":"orange flower water","amounts":[["5","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Place the cream and lavender in a saucepan and bring to a boil. Remove from heat, cover, and allow to infuse for 10 minutes.","Strain the infused cream and add water to bring the amount of liquid back up to 145g and bring to a boil.","Meanwhile, place the honey and the dark chocolate in a large bowl. Remove the infused cream from heat and gradually add to the chocolate in three additions; with each addition, stir the mixture with a rubber spatula in tight circles, working from the inside of the mass toward the outside, until each addition is incorporated. The resulting ganache should be smooth, supple, and slightly elastic with glossy shine.","Allow the ganache to cool to 35˚C/95ºF. Stir in the butter and orange flower water. Deposit the ganache directly into the pre-cast molds, either with a pastry bag or pastry funnel with a minimum of air pockets and a flat surface, with no portion exceeding the top of the cavity. Allow a small gap to provide a sealing base and allow the centers to crystallize at room temperature.","When the centers have fully crystallized, seal the mold with additional dark chocolate: fill the remaining space of each cavity and scrape away the excess to produce a clean, smooth base and allow to crystallize undisturbed.","Using a lined half sheet pan, carefully invert the mold to release the finished bonbons; this may require a slight tap or in some cases, the molds may require a"]', '["For the pre-cast shells:"]', 'Pastry_Module_4_Course_7.pdf', 114);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Lemon - Praline Bonbon Praline Cream', 'Chocolate & Bonbons', 'Module 4', 'Course 7', 'Chocolate & Confections', 83, 'Total Yield: 575 grams', '575 grams', '[]', '[{"name":"sheet gelatin","amounts":[["1","sheet"]],"bakers_pct":null,"component":null},{"name":"heavy cream","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"hazelnut praline paste","amounts":[["350","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Bloom gelatin in water and reserve.","Place the cream in a sauce pan and heat to 50ºC/120ºF. Remove from heat and add the gelatin, stirring to dissolve.","Place the praline paste in a mixer bowl fitted with paddle attachment; slowly incorporate cream while beating on low speed, scraping the sides of the bowl after each addition. The mixture may ‘break'', but will properly emulsify with the addition of all the cream.","Allow to cool to 35˚C/95˚F and deposit the praline cream directly into the pre-cast molds - roughly one-third full - either with a pastry bag or pastry funnel with a minimum of air pockets and a flat surface. Allow the centers to set slightly at room temperature. Excess praline cream should be stored under refrigeration."]', '["For the pre-cast shells:"]', 'Pastry_Module_4_Course_7.pdf', 120);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Lemon Ganache', 'Chocolate & Bonbons', 'Module 4', 'Course 7', 'Chocolate & Confections', 83, 'Total Yield: approx. 2 molds or 80pc. 485 grams', '485 grams', '[]', '[{"name":"heavy cream","amounts":[["135","grams"]],"bakers_pct":null,"component":null},{"name":"lemon zest","amounts":[["7","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla bean, split and scraped","amounts":[["1","each"]],"bakers_pct":null,"component":null},{"name":"invert sugar","amounts":[["30","grams"]],"bakers_pct":null,"component":null},{"name":"white chocolate finely chopped or slightly melted","amounts":[["260","grams"]],"bakers_pct":null,"component":null},{"name":"lemon juice, freshly squeezed","amounts":[["30","grams"]],"bakers_pct":null,"component":null},{"name":"butter, room temperature","amounts":[["30","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Place the cream, lemon zest, and vanilla bean in a saucepan and bring to a boil and allow to steep for 5 minutes.","Meanwhile, place the invert sugar and the white chocolate in a large bowl. Remove the cream from heat, strain, and discard the vanilla bean; gradually add to the chocolate in three additions; with each addition, stir the mixture with a rubber spatula in tight circles, working from the inside of the mass toward the outside, until each addition is incorporated. The resulting ganache should be smooth, supple, and slightly elastic with glossy shine.","Allow the ganache to cool to 35˚C/95ºF. Stir in the lemon juice and butter. Deposit the ganache directly into the pre-cast molds on top of the praline cream, either with a pastry bag or pastry funnel with a minimum of air pockets and a flat surface, with no portion exceeding the top of the cavity. Allow a small gap to provide a sealing base and allow the centers to crystallize at room temperature.","When the centers have fully crystallized, seal the mold with additional tempered white chocolate: fill the remaining space of each cavity and scrape away the excess to produce a clean, smooth base and allow to crystallize undisturbed.","Using a lined half-sheet pan, carefully invert the mold to release the finished bonbons; this may require a slight tap or in some cases, the molds may require a brief chill in order achieve full contraction and release."]', '[]', 'Pastry_Module_4_Course_7.pdf', 121);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Mandarin - Pistachio Bonbon Mandarin Gelee', 'Chocolate & Bonbons', 'Module 4', 'Course 7', 'Chocolate & Confections', 83, 'Total Yield: 210 grams', '210 grams', '[]', '[{"name":"lemon juice, freshly squeezed","amounts":[["10","grams"]],"bakers_pct":null,"component":null},{"name":"mandarin purée","amounts":[["65","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose","amounts":[["15","grams"]],"bakers_pct":null,"component":null},{"name":"apple pectin","amounts":[["1.5","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose","amounts":[["40","grams"]],"bakers_pct":null,"component":null},{"name":"isomalt","amounts":[["48","grams"]],"bakers_pct":null,"component":null},{"name":"glucose syrup","amounts":[["30","grams"]],"bakers_pct":null,"component":null},{"name":"citric acid","amounts":[["1.5","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine lemon juice and mandarin purée in a sauce pan and heat to"]', '["For the pre-cast shells:"]', 'Pastry_Module_4_Course_7.pdf', 126);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Maple Bourbon Truffles', 'Chocolate & Bonbons', 'Module 4', 'Course 7', 'Chocolate & Confections', 80, 'Total Yield: approx. 100 10g pieces 1,080 grams', '1,080 grams', '[]', '[{"name":"heavy cream (35% fat)","amounts":[["300","grams"]],"bakers_pct":null,"component":null},{"name":"maple syrup","amounts":[["40","grams"]],"bakers_pct":null,"component":null},{"name":"invert sugar","amounts":[["40","grams"]],"bakers_pct":null,"component":null},{"name":"butter, room temperature","amounts":[["120","grams"]],"bakers_pct":null,"component":null},{"name":"bourbon whiskey","amounts":[["80","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Place the cream and maple syrup in a saucepan and bring to a boil","Meanwhile, place the chocolate and invert sugar in a large bowl. Remove the cream mixture from heat and gradually add to the chocolate in three additions; with each addition, stir the mixture with a rubber spatula in tight circles, working from the inside of the mass toward the outside, until each addition is incorporated. The resulting ganache should be smooth, supple, and slightly elastic with glossy shine.","Allow the ganache to cool to 35˚C/95ºF. Stir in the butter and bourbon. Transfer the ganache to a shallow third pan and allow to crystallize at room temperature.","Transfer the crystallized ganache to a pastry bag fitted with a large, plain tip (# 804 or 806) and pipe uniform mounds onto a parchment-lined half sheet pan; the individual mounds should weigh approximately 10-15g each and piped into evenly spaced in rows.","Briefly chill the pan of piped ganache until slightly firm. Quickly roll each mound into a spherical shape if necessary and arrange on a fresh parchment-lined half sheet pan.","To enrobe, coat each truffle with a thin layer of tempered dark chocolate and immediately drop each truffle in an ample-sized hotel pan of the chopped pecans to coat."]', '["For enrobing the truffles in the next lesson:"]', 'Pastry_Module_4_Course_7.pdf', 86);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Mendiant', 'Chocolate & Bonbons', 'Module 4', 'Course 7', 'Chocolate & Confections', 78, NULL, NULL, '[]', '[{"name":"dark chocolate, tempered","amounts":[["200","grams"]],"bakers_pct":null,"component":null},{"name":"hazelnuts, blanched and roasted","amounts":[["80","grams"]],"bakers_pct":null,"component":null},{"name":"pistachios, shelled","amounts":[["45","grams"]],"bakers_pct":null,"component":null},{"name":"dried cherries","amounts":[["90","grams"]],"bakers_pct":null,"component":null},{"name":"candied orange peel, cut to 15mm","amounts":[["20","grams"]],"bakers_pct":null,"component":null},{"name":"Total: approx.","amounts":[["40","pieces"]],"bakers_pct":null,"component":null}]', NULL, '["Line half sheet pan with parchment paper and stencil guideline or use Silpat.","Transfer 200g tempered chocolate to a cornet or disposable pastry bag and deposit onto disc template, approximately 5g per piece.","Working quickly, affix one piece each hazelnut, pistachio, dried cherry, and orange peel to each disc before it sets.","Allow mendiants to set completely before removal and wrapping."]', '[]', 'Pastry_Module_4_Course_7.pdf', 62);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Milk Chocolate Filling for Bon', 'Chocolate & Bonbons', 'Module 4', 'Course 7', 'Chocolate & Confections', 81, 'Yield 432 grams', '432 grams', '[]', '[{"name":"heavy cream","amounts":[["112","grams"]],"bakers_pct":null,"component":null},{"name":"light corn syrup","amounts":[["20","grams"]],"bakers_pct":null,"component":null},{"name":"milk chocolate, finely chopped","amounts":[["250","grams"]],"bakers_pct":null,"component":null},{"name":"butter, very soft","amounts":[["40","grams"]],"bakers_pct":null,"component":null},{"name":"alcohol","amounts":[["10","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Place the cream in a saucepan and bring to a boil.","Meanwhile, place the light corn syrup and milk chocolate in a large bowl. Remove the cream from heat and gradually add to the chocolate in three additions; with each addition, stir the mixture with a rubber spatula in tight circles, working from the inside of the mass toward the outside, until each addition is incorporated. The resulting ganache should be smooth, supple, and slightly elastic with glossy shine.","Allow the ganache to cool to 35˚C/95ºF. Stir in the butter. Deposit the ganache directly into the pre-cast molds, either with a pastry bag or pastry funnel with a minimum of air pockets and a flat surface, with no portion exceeding the top of the cavity. Allow a small gap to provide a sealing base and allow the centers to crystallize at room temperature."]', '[]', 'Pastry_Module_4_Course_7.pdf', 105);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Milk Chocolate Ganache', 'Chocolate & Bonbons', 'Module 4', 'Course 7', 'Chocolate & Confections', 83, 'Total Yield: approx. 2 molds or 80pc 550 grams', '550 grams', '[]', '[{"name":"heavy cream","amounts":[["200","grams"]],"bakers_pct":null,"component":null},{"name":"invert sugar","amounts":[["20","grams"]],"bakers_pct":null,"component":null},{"name":"milk chocolate, finely chopped or slightly melted","amounts":[["300","grams"]],"bakers_pct":null,"component":null},{"name":"butter, room temperature","amounts":[["50","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Place the cream in a saucepan and bring to a boil.","Meanwhile, place the glucose and the milk chocolate in a large bowl. Remove the cream from heat and gradually add to the chocolate in three additions; with each addition, stir the mixture with a rubber spatula in tight circles, working from the inside of the mass toward the outside, until each addition is incorporated. The resulting ganache should be smooth, supple, and slightly elastic with glossy shine.","Allow the ganache to cool to 35˚C/95ºF. Stir in the butter. Deposit the ganache directly into the pre-cast molds on top of the salted caramel cream, either with a pastry bag or a pastry funnel with a minimum of air pockets and a flat surface, with no portion exceeding the top of the cavity. Allow a small gap to provide a sealing base and allow the centers to crystallize at room temperature.","When the centers have fully crystallized, seal the mold with additional tempered milk chocolate: fill the remaining space of each cavity and scrape away the excess to produce a clean, smooth base and allow to crystallize undisturbed.","Using a lined half-sheet pan, carefully invert the mold to release the finished bonbons; this may require a slight tap or in some cases, the molds may require a brief chill in order achieve full contraction and release."]', '[]', 'Pastry_Module_4_Course_7.pdf', 123);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Muscadine', 'Chocolate & Bonbons', 'Module 4', 'Course 7', 'Chocolate & Confections', 80, 'Total Yield: approx. 100 10g pieces 960 grams', '960 grams', '[]', '[{"name":"heavy cream (35%fat)","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"milk chocolate, very finely chopped or slightly melted","amounts":[["580","grams"]],"bakers_pct":null,"component":null},{"name":"butter, room temperature","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"Grand Marnier","amounts":[["40","grams"]],"bakers_pct":null,"component":null},{"name":"Kirschwasser","amounts":[["15","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Place the cream in a saucepan and bring to a boil","Meanwhile, place the chocolate in a large bowl. Remove the cream from heat and gradually add to the chocolate in three additions; with each addition, stir the mixture with a rubber spatula in tight circles, working from the inside of the mass toward the outside, until each addition is incorporated. The resulting ganache should be smooth, supple, and slightly elastic with glossy shine.","Allow the ganache to cool to 35˚C/95ºF. Stir in the butter, Grand Marnier, and kirshwasser. Transfer the ganache to a shallow third pan and allow to crystallize at room temperature.","Transfer the crystallized ganache to a pastry bag fitted with a large, plain tip (# 804 or 806) and pipe straight, uniform cylinders onto a parchment-lined half sheet pan.","Briefly chill the pan of piped ganache until slightly firm. Cut the cylinder into individual 4cm lengths (approximately 10g each) and arrange on a fresh parchment-lined half sheet pan.","To enrobe, coat each truffle with a thin layer of tempered dark chocolate and immediately drop each truffle in an ample-sized hotel pan of confectioner''s sugar to coat and briefly chill to set before sifting away the excess sugar."]', '["For enrobing the muscadine in the"]', 'Pastry_Module_4_Course_7.pdf', 85);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Ordinary Ganache', 'Chocolate & Bonbons', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 40, NULL, NULL, '[]', '[{"name":"semisweet chocolate","amounts":[["450","grams"]],"bakers_pct":null,"component":null},{"name":"cream","amounts":[["450","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Cut chocolate finely.","Bring cream to a boil over medium heat; remove from heat.","Add chocolate and set aside 5 minutes.","Whisk until smooth; strain into a clean, dry bowl.","Cool to room temperature or cool quickly over cold water.","Cool to room temperature and use for glazing cakes or pastries."]', '[]', 'Pastry_Module_2_Course_4.pdf', 83);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Passion Fruit Ganache', 'Chocolate & Bonbons', 'Module 4', 'Course 7', 'Chocolate & Confections', 82, 'Total Yield: approx. 2 molds or 80pc 505 grams', '505 grams', '[]', '[{"name":"heavy cream","amounts":[["45","grams"]],"bakers_pct":null,"component":null},{"name":"passion fruit purée","amounts":[["125","grams"]],"bakers_pct":null,"component":null},{"name":"glucose syrup","amounts":[["15","grams"]],"bakers_pct":null,"component":null},{"name":"white chocolate, finely chopped or slightly melted","amounts":[["275","grams"]],"bakers_pct":null,"component":null},{"name":"butter, room temperature","amounts":[["15","grams"]],"bakers_pct":null,"component":null},{"name":"apricot liqueur","amounts":[["30","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Place the cream and passion fruit purée in a saucepan and bring to a boil","Meanwhile, place the glucose and the white chocolate in a large bowl. Remove the cream mixture from heat and gradually add to the chocolate in three additions; with each addition, stir the mixture with a rubber spatula in tight circles, working from the inside of the mass toward the outside, until each addition is incorporated. The resulting ganache should be smooth, supple, and slightly elastic with glossy shine.","Allow the ganache to cool to 35˚C/95ºF. Stir in the butter and liqueur. Deposit the ganache directly into the pre-cast molds, either with a pastry bag or pastry funnel with a minimum of air pockets and a flat surface, with no portion exceeding the top of the cavity. Allow a small gap to provide a sealing base and allow the centers to crystallize at room temperature.","When the centers have fully crystallized, seal the mold with additional tempered dark chocolate: fill the remaining space of each cavity and scrape away the excess to produce a clean, smooth base and allow to crystallize undisturbed.","Using a lined half sheet pan, carefully invert the mold to release the finished bonbons; this may require a slight tap or in some cases, the molds may require a brief chill in order achieve full contraction and release. Take care to avoid damage due to excessive force or prolonged refrigeration when releasing the chocolates."]', '["For the pre-cast shells:"]', 'Pastry_Module_4_Course_7.pdf', 112);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Pistachio Ganache', 'Chocolate & Bonbons', 'Module 4', 'Course 7', 'Chocolate & Confections', 83, 'Total Yield: approx. 2 molds or 80 pc 560 grams', '560 grams', '[]', '[{"name":"heavy cream","amounts":[["160","grams"]],"bakers_pct":null,"component":null},{"name":"invert sugar","amounts":[["15","grams"]],"bakers_pct":null,"component":null},{"name":"pistachio paste","amounts":[["45","grams"]],"bakers_pct":null,"component":null},{"name":"white chocolate, finely chopped or slightly melted","amounts":[["280","grams"]],"bakers_pct":null,"component":null},{"name":"butter, room temperature","amounts":[["60","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Place the cream in a saucepan and bring to a boil","Meanwhile, place the invert sugar, pistachio paste and the white chocolate in a large bowl. Remove the cream from heat and gradually add to the chocolate in three additions; with each addition, stir the mixture with a rubber spatula in tight circles, working from the inside of the mass toward the outside, until each addition is incorporated. The resulting ganache should be smooth, supple, and slightly elastic with glossy shine.","Allow the ganache to cool to 35˚C/95ºF. Stir in the butter. Deposit the ganache directly into the pre-cast molds on top of the mandarin gelée, either with a pastry bag or pastry funnel with a minimum of air pockets and a flat surface, with no portion exceeding the top of the cavity. Allow a small gap to provide a sealing base and allow the centers to crystallize at room temperature.","When the centers have fully crystallized, seal the mold with additional tempered dark chocolate: fill the remaining space of each cavity and scrape away the excess to produce a clean, smooth base and allow to crystallize undisturbed.","Using a lined half sheet pan, carefully invert the mold to release the finished bonbons; this may require a slight tap or in some cases, the molds may require a brief chill in order achieve full contraction and release. Take care to avoid damage due to excessive force or prolonged refrigeration when releasing the chocolates."]', '[]', 'Pastry_Module_4_Course_7.pdf', 127);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Praline Cream', 'Chocolate & Bonbons', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 73, NULL, NULL, '[]', '[{"name":"heavy cream (35% fat)","amounts":[["150","grams"]],"bakers_pct":null,"component":null},{"name":"hazelnut praline paste","amounts":[["240","grams"]],"bakers_pct":null,"component":null}]', '[["390","grams"]]', '["Place the cream in a sauce pan and heat to 49˚C/120˚F. Remove from heat and add the bloomed gelatin.","Place the praline paste in mixer bowl fitted with paddle attachment; slowly incorporate cream. Mixture may ‘break'', but will emulsify with the addition of all the cream.","Transfer to a squeeze bottle and chill."]', '[]', 'Pastry_Module_3_Course_6.pdf', 229);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Rich Ganache', 'Chocolate & Bonbons', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 40, NULL, NULL, '[]', '[{"name":"semisweet chocolate","amounts":[["675","grams"]],"bakers_pct":null,"component":null},{"name":"cream","amounts":[["450","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Cut chocolate finely.","Bring cream to a boil over medium heat; remove from heat.","Add chocolate and set aside 5 minutes.","Whisk until smooth; strain into a clean, dry bowl.","Cool to room temperature or cool quickly over cold water.","Once the ganache has set, beat with a paddle on medium speed briefly to lighten."]', '[]', 'Pastry_Module_2_Course_4.pdf', 83);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Salted Caramel - Milk Chocolate Bonbon Salted Caramel Cream', 'Chocolate & Bonbons', 'Module 4', 'Course 7', 'Chocolate & Confections', 83, 'Total Yield: 516 grams', '516 grams', '[]', '[{"name":"sucrose","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["50","grams"]],"bakers_pct":null,"component":null},{"name":"glucose syrup","amounts":[["15","grams"]],"bakers_pct":null,"component":null},{"name":"lemon juice","amounts":[["3","grams"]],"bakers_pct":null,"component":null},{"name":"heavy cream","amounts":[["180","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["3","grams"]],"bakers_pct":null,"component":null},{"name":"cocoa butter","amounts":[["10","grams"]],"bakers_pct":null,"component":null},{"name":"butter, room temperature","amounts":[["30","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Into a heavy sauce pan, combine sucrose, water, glucose, and lemon juice. Cook to a medium amber caramel. Meanwhile, gently heat the cream until warm.","Remove caramelized sugar from heat and deglaze with the cream. Return to low heat to completely dissolve sugar. Continue to cook until the mixture reaches"]', '["For the pre-cast shells:"]', 'Pastry_Module_4_Course_7.pdf', 122);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Star Anise Ganache', 'Chocolate & Bonbons', 'Module 4', 'Course 7', 'Chocolate & Confections', 82, 'Total Yield: approx. 2 molds or 80pc 550 grams', '550 grams', '[]', '[{"name":"heavy cream","amounts":[["210","grams"]],"bakers_pct":null,"component":null},{"name":"star anise","amounts":[["7","grams"]],"bakers_pct":null,"component":null},{"name":"invert sugar","amounts":[["40","grams"]],"bakers_pct":null,"component":null},{"name":"milk chocolate, finely chopped or slightly melted","amounts":[["250","grams"]],"bakers_pct":null,"component":null},{"name":"butter, room temperature","amounts":[["50","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Place the cream and star anise in a saucepan and bring to a boil. Remove from heat, cover and allow to infuse for 10 minutes.","Meanwhile, place the glucose and the milk chocolate in a large bowl. Strain the cream and return to a boil. Remove the cream from heat and gradually add to the chocolate in three additions; with each addition, stir the mixture with a rubber spatula in tight circles, working from the inside of the mass toward the outside, until each addition is incorporated. The resulting ganache should be smooth, supple, and slightly elastic with glossy shine.","Allow the ganache to cool to 35˚C/95ºF. Stir in the butter. Deposit the ganache directly into the pre-cast molds, either with a pastry bag or pastry funnel with a minimum of air pockets and a flat surface, with no portion exceeding the top of the cavity. Allow a small gap to provide a sealing base and allow the centers to crystallize at room temperature.","When the centers have fully crystallized, seal the mold with additional tempered dark or milk chocolate: fill the remaining space of each cavity and scrape away the excess to produce a clean, smooth base and allow to crystallize undisturbed.","Using a lined half sheet pan, carefully invert the mold to release the finished bonbons; this may require a slight tap or in some cases, the molds may require a brief chill in order achieve full contraction and release. Take care to avoid damage due to excessive force or prolonged refrigeration when releasing the chocolates."]', '["For the pre-cast shells:"]', 'Pastry_Module_4_Course_7.pdf', 113);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Strawberry Truffles', 'Chocolate & Bonbons', 'Module 4', 'Course 7', 'Chocolate & Confections', 80, 'Total Yield: approx. 100 15g pieces 1,085 grams', '1,085 grams', '[]', '[{"name":"strawberry purée","amounts":[["275","grams"]],"bakers_pct":null,"component":null},{"name":"sorbitol","amounts":[["35","grams"]],"bakers_pct":null,"component":null},{"name":"glucose syrup","amounts":[["30","grams"]],"bakers_pct":null,"component":null},{"name":"invert sugar","amounts":[["20","grams"]],"bakers_pct":null,"component":null},{"name":"white chocolate, very finely chopped or slightly melted","amounts":[["625","grams"]],"bakers_pct":null,"component":null},{"name":"butter, unsalted, room temperature","amounts":[["100","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Place the strawberry purée, sorbitol, glucose, and invert sugar in a saucepan and bring to a boil.","Meanwhile, place the white chocolate in a large bowl. Remove the strawberry mixture from heat and gradually add to the chocolate in three additions; with each addition, stir the mixture with a rubber spatula in tight circles, working from the inside of the mass toward the outside, until each addition is incorporated. The resulting ganache should be smooth, supple, and slightly elastic with glossy shine.","Allow the ganache to cool to 35˚C/95ºF. Stir in the butter.","Transfer the ganache to a pastry bag or sauce funnel and immediately deposit the ganache into the hollow shells, allowing a small gap for sealing; allow to crystallize at room temperature.","Using a cornet or a pastry bag, apply a small amount of tempered white chocolate to the hollow shells to adequately seal. Allow to crystallize.","To enrobe, coat each truffle with a thin layer of tempered white chocolate, and","Allow the truffles to set and garnish with a dusting of freeze-dried strawberry"]', '["For enrobing the truffles in the next lesson:"]', 'Pastry_Module_4_Course_7.pdf', 97);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Sucettes', 'Chocolate & Bonbons', 'Module 4', 'Course 7', 'Chocolate & Confections', 78, NULL, NULL, '[]', '[{"name":"dark, milk, or white chocolate, tempered","amounts":[["200","grams"]],"bakers_pct":null,"component":null},{"name":"Total: approx.","amounts":[["8","pieces"]],"bakers_pct":null,"component":null}]', NULL, '["Line marble with parchment, acetate or silpat and arrange 8 lollipop sticks.","Transfer tempered chocolate to a cornet and pipe abstract, but tight concentric circles or similar design over the end of each stick.","Working quickly, garnish each sucette with desired inclusions.","Allow the fragile sucettes to set completely before removal from the work surface.","To remove, once set, pull the parchment, acetate or silpat away from the lollipops to avoid breakage."]', '[]', 'Pastry_Module_4_Course_7.pdf', 63);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Traditional Chocolate', 'Chocolate & Bonbons', 'Module 4', 'Course 7', 'Chocolate & Confections', 78, NULL, NULL, '[]', '[{"name":"cocoa nibs, roasted","amounts":[["750","grams"]],"bakers_pct":null,"component":null},{"name":"panela or piloncillo, grated","amounts":[["250","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla bean, split and scraped","amounts":[["2","each"]],"bakers_pct":null,"component":null},{"name":"cinnamon, ground","amounts":[["5","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Gently heat cocoa nibs in a large sauté pan for 3-4 minutes. The cocoa nibs must be very warm.","Transfer nibs to a metate, mortar and pestle, or food processor. Begin to grind the beans.","Once a coarse powder has developed, add the sugar, vanilla, and cinnamon. Continue to grind the mixture to a sticky paste.","Portion and roll the cocoa paste into approximately 40 25g balls. Allow several hours or overnight for the cocoa paste to dry and set.","To make hot chocolate, dissolve two balls of cocoa paste into 250g hot water or milk and forth using a traditional molinillo or immersion blender."]', '[]', 'Pastry_Module_4_Course_7.pdf', 61);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Truffle Ganache', 'Chocolate & Bonbons', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 40, NULL, NULL, '[]', '[{"name":"semisweet chocolate","amounts":[["900","grams"]],"bakers_pct":null,"component":null},{"name":"cream","amounts":[["450","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Cut chocolate finely.","Bring cream to a boil over medium heat; remove from heat.","Add chocolate and set aside 5 minutes.","Whisk until smooth; strain into a clean, dry bowl.","Cool to room temperature or cool quickly over cold water.","Add any flavorings","Once the ganache has set, beat with a paddle on medium speed briefly lighten. Variation: Ganache Praline - Beat 170 grams praline paste into ganache."]', '[]', 'Pastry_Module_2_Course_4.pdf', 83);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('White Chocolate Filling for Bon', 'Chocolate & Bonbons', 'Module 4', 'Course 7', 'Chocolate & Confections', 81, 'Yield 482 grams', '482 grams', '[]', '[{"name":"heavy cream","amounts":[["112","grams"]],"bakers_pct":null,"component":null},{"name":"light corn syrup","amounts":[["20","grams"]],"bakers_pct":null,"component":null},{"name":"white chocolate, finely chopped","amounts":[["300","grams"]],"bakers_pct":null,"component":null},{"name":"butter, very soft","amounts":[["40","grams"]],"bakers_pct":null,"component":null},{"name":"alcohol","amounts":[["10","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Place the cream in a saucepan and bring to a boil.","Meanwhile, place the light corn syrup and white chocolate in a large bowl. Remove the cream from heat and gradually add to the chocolate in three additions; with each addition, stir the mixture with a rubber spatula in tight circles, working from the inside of the mass toward the outside, until each addition is incorporated. The resulting ganache should be smooth, supple, and slightly elastic with glossy shine.","Allow the ganache to cool to 35˚C/95ºF. Stir in the butter. Deposit the ganache directly into the pre-cast molds, either with a pastry bag or pastry funnel with a minimum of air pockets and a flat surface, with no portion exceeding the top of the cavity. Allow a small gap to provide a sealing base and allow the centers to crystallize at room temperature."]', '[]', 'Pastry_Module_4_Course_7.pdf', 106);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('White Chocolate Ganache', 'Chocolate & Bonbons', 'Module 4', 'Course 7', 'Chocolate & Confections', 83, 'Total Yield: approx. 2 molds or 80pc. 470 grams', '470 grams', '[]', '[{"name":"heavy cream","amounts":[["135","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla bean, split and scraped","amounts":[["1","each"]],"bakers_pct":null,"component":null},{"name":"invert sugar","amounts":[["30","grams"]],"bakers_pct":null,"component":null},{"name":"white chocolate finely chopped or slightly melted","amounts":[["260","grams"]],"bakers_pct":null,"component":null},{"name":"dark rum","amounts":[["15","grams"]],"bakers_pct":null,"component":null},{"name":"butter, room temperature","amounts":[["30","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Place the cream and vanilla in a saucepan and bring to a boil.","Meanwhile, place the invert sugar and the white chocolate in a large bowl. Remove the cream from heat, strain, and discard the vanilla bean; gradually add to the chocolate in three additions; with each addition, stir the mixture with a rubber spatula in tight circles, working from the inside of the mass toward the outside, until each addition is incorporated. The resulting ganache should be smooth, supple, and slightly elastic with glossy shine.","Allow the ganache to cool to 35˚C/95ºF. Stir in the butter, then rum. Deposit the ganache directly into the pre-cast molds on top of the chocolate fondant, either with a pastry bag or pastry funnel with a minimum of air pockets and a flat surface, with no portion exceeding the top of the cavity. Allow a small gap to provide a sealing base and allow the centers to crystallize at room temperature.","When the centers have fully crystallized, seal the mold with additional tempered chocolate: fill the remaining space of each cavity and scrape away the excess to produce a clean, smooth base and allow to crystallize undisturbed.","Using a lined half-sheet pan, carefully invert the mold to release the finished bonbons; this may require a slight tap or in some cases, the molds may require a brief chill in order achieve full contraction and release."]', '[]', 'Pastry_Module_4_Course_7.pdf', 119);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('White Chocolate Spray', 'Chocolate & Bonbons', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 71, NULL, NULL, '[]', '[{"name":"cocoa butter, melted to 95 degrees","amounts":[["300","grams"]],"bakers_pct":null,"component":null},{"name":"white chocolate, melted to 95 degrees","amounts":[["450","grams"]],"bakers_pct":null,"component":null}]', '[["750","grams"]]', '["Combine the melted cocoa butter and white chocolate, strain through a fine strainer and transfer to a chocolate spray gun. Remove the yuzu parfait from the freezer and apply a light coat of the spray. Reserve for assembly.","Assemble each parfait onto the sucrée base and allow to temper. Place each onto a plate and garnish with the sorbet, sponge (dusted with 10X sugar), ground pistachio, and décor. Finish with the mandarin coulis."]', '[]', 'Pastry_Module_3_Course_6.pdf', 168);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('White/ Milk Chocolate Spray', 'Chocolate & Bonbons', 'Module 4', 'Course 7', 'Chocolate & Confections', 85, NULL, NULL, '[]', '[{"name":"white/milk chocolate","amounts":[["450","grams"]],"bakers_pct":null,"component":null},{"name":"cocoa butter","amounts":[["180","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Melt the desired chocolate and the cocoa butter separately over bain marie to approximately 95 F.","Combine the chocolate and cocoa butter, being careful that no water gets into the mixture.","Strain through a fine strainer and store or place in a spray gun for use. Keep mixture/spray gun at approximately 95F for optimal use.","Test spray before spraying on final piece and spray at a distance to ensure an even coat. for at least 10-15 minutes before spraying."]', '["Note: A velvet like texture can be achieved by placing the finished piece in the freezer"]', 'Pastry_Module_4_Course_7.pdf', 135);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('‘Quatre Epice'' Truffles', 'Chocolate & Bonbons', 'Module 4', 'Course 7', 'Chocolate & Confections', 80, 'Total Yield: approx. 100 g pieces 1,000 grams', '1,000 grams', '[]', '[{"name":"heavy cream (35% fat)","amounts":[["280","grams"]],"bakers_pct":null,"component":null},{"name":"quatre épice spice blend, ground","amounts":[["3","grams"]],"bakers_pct":null,"component":null},{"name":"honey","amounts":[["50","grams"]],"bakers_pct":null,"component":null},{"name":"white chocolate, very finely chopped or slightly melted","amounts":[["510","grams"]],"bakers_pct":null,"component":null},{"name":"butter, room temperature","amounts":[["120","grams"]],"bakers_pct":null,"component":null},{"name":"dark rum","amounts":[["40","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Place the cream and spice blend in a saucepan and bring to a boil","Meanwhile, place the chocolate and honey in a large bowl. Remove the cream from heat and gradually add to the chocolate in three additions; with each addition, stir the mixture with a rubber spatula in tight circles, working from the inside of the mass toward the outside, until each addition is incorporated. The resulting ganache should be smooth, supple, and slightly elastic with glossy shine.","Allow the ganache to cool to 35˚C/95ºF. Stir in the butter and rum. Transfer the ganache to a shallow third pan and allow to crystallize at room temperature.","Transfer the crystallized ganache to a pastry bag fitted with a large, plain tip (# 804 or 806) and pipe uniform mounds onto a parchment-lined half sheet pan; the individual mounds should weigh approximately 10-15g each and piped into evenly spaced in rows.","Briefly chill the pan of piped ganache until slightly firm. Quickly roll each mound into a spherical shape if necessary and arrange on a fresh parchment-lined half sheet pan."]', '["For enrobing truffles in the next lesson:"]', 'Pastry_Module_4_Course_7.pdf', 91);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Apricot Pate De Fruit', 'Confections & Sugar Work', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 8, NULL, NULL, '[]', '[{"name":"apricot purée","amounts":[["500","grams"]],"bakers_pct":null,"component":null},{"name":"sugar (1)","amounts":[["55","grams"]],"bakers_pct":null,"component":null},{"name":"apple pectin","amounts":[["13","grams"]],"bakers_pct":null,"component":null},{"name":"sugar (2)","amounts":[["375","grams"]],"bakers_pct":null,"component":null},{"name":"glucose syrup","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"citric acid","amounts":[["8","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["8","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Place the apricot purée in a medium, heavy saucepan, and heat to104˚F.","Combine the first measurement of sugar (1) and the pectin and whisk into the purée. Bring to a boil while stirring continually.","Add the remaining sugar (2) and glucose syrup in three additions. Continue stirring the mixture and cook to 223˚F. while on low heat.","Remove the mixture from the heat and stir in citric acid, previously dissolved in the water.","Immediately pour the mixture into a plastic-lined frame or silicon forms and allow to set at room temperature.","To finish the pate de fruit, cut or unmold as necessary and toss the individual pieces in sucrose*. weight of the sucrose used for coating."]', '["*To add acidity to the coating of the finished pieces, combine 2% citric acid to the"]', 'PA_Mod_01_Instructor.pdf', 96);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Black Currant Pate De Fruit', 'Confections & Sugar Work', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 8, NULL, NULL, '[]', '[{"name":"black currant purée","amounts":[["265","grams"]],"bakers_pct":null,"component":null},{"name":"pear purée","amounts":[["265","grams"]],"bakers_pct":null,"component":null},{"name":"sugar (1)","amounts":[["65","grams"]],"bakers_pct":null,"component":null},{"name":"apple pectin","amounts":[["12","grams"]],"bakers_pct":null,"component":null},{"name":"sugar (2)","amounts":[["555","grams"]],"bakers_pct":null,"component":null},{"name":"glucose syrup","amounts":[["112","grams"]],"bakers_pct":null,"component":null},{"name":"invert sugar","amounts":[["75","grams"]],"bakers_pct":null,"component":null},{"name":"citric acid","amounts":[["11","grams"]],"bakers_pct":null,"component":null},{"name":"cassis liqueur","amounts":[["11","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Place the black currant and pear purées in a medium, heavy saucepan, and heat to 104˚F.","Combine the first measurement of sugar (1) and the pectin and whisk into the purées. Bring to a boil while stirring continually.","Add the remaining sugar (2), glucose syrup and invert sugar in three additions. Continue stirring the mixture and cook to 223˚F. while on low heat.","Remove the mixture from the heat and stir in citric acid, previously dissolved in the liqueur.","Immediately pour the mixture into a plastic-lined frame or silicon forms and allow to set at room temperature.","To finish the pate de fruit, cut or unmold as necessary and toss the individual pieces in sugar*. weight of the sugar used for coating."]', '["* To add acidity to the coating of the finished pieces, combine 2% citric acid to the"]', 'PA_Mod_01_Instructor.pdf', 98);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Butter Crunch', 'Confections & Sugar Work', 'Module 4', 'Course 7', 'Chocolate & Confections', 76, NULL, NULL, '[]', '[{"name":"butter","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose","amounts":[["340","grams"]],"bakers_pct":null,"component":null},{"name":"glucose syrup","amounts":[["45","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["45","grams"]],"bakers_pct":null,"component":null},{"name":"slivered almonds, roasted and chopped","amounts":[["140","grams"]],"bakers_pct":null,"component":null},{"name":"dark chocolate, tempered","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"toasted chopped almonds","amounts":[["140","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Melt the butter in a saucepan. Remove from heat and stir in sucrose, glucose, and water. Cook, stirring occasionally, until the mixture reaches 150˚C/300˚F. Remove from heat, stir in almonds, and pour out on a half sheet pan lined with silpat and spread evenly with an offset spatula coated with pam if needed.","For the coating, melt and temper the chocolate. Spread or brush on one side of butter crunch and sprinkle with half the chopped almonds. Allow it to set, and repeat coating on other side. After both coatings have set, break into coarse piece"]', '[]', 'Pastry_Module_4_Course_7.pdf', 32);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Chocolate Walnut Fudge', 'Confections & Sugar Work', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 10, NULL, NULL, '[]', '[{"name":"cocoa powder","amounts":[["28","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["790","grams"]],"bakers_pct":null,"component":null},{"name":"whole milk","amounts":[["155","grams"]],"bakers_pct":null,"component":null},{"name":"semisweet chocolate","amounts":[["200","grams"]],"bakers_pct":null,"component":null},{"name":"butter","amounts":[["65","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["57","grams"]],"bakers_pct":null,"component":null},{"name":"corn syrup","amounts":[["70","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla","amounts":[["14","grams"]],"bakers_pct":null,"component":null},{"name":"walnuts, chopped","amounts":[["170","grams"]],"bakers_pct":null,"component":null}]', NULL, '["In a small saucepan, combine the cocoa powder, sugar and milk and mix until very well combined. Add water, chocolate, butter and corn syrup. Cook on medium heat stirring occasionally until the sugar has completely dissolved. Bring mixture to a simmer using the lowest heat setting possible that will maintain the simmer. Make sure not to stir any further. Occasionally, wash down sides of pan with water. Cook to 238° F.","Remove pan from heat and pour fudge onto marble that has been sprinkled with a little bit of water. Let stand. When the fudge can be touched in the center without sticking to your finger, add the vanilla gradually and stir the fudge with bench scrapers until the fudge begins to lose its sheen and starts to maintain its shape. The mixing can take approximately 15-20 minutes.","When the fudge I ready, quickly, stir in the nuts and even quicker, place the fudge in paper on the bottom and up two sides past the top so the fudge can be removed easily once it sets. Make sure to smooth the top of the fudge with a spatula."]', '[]', 'PA_Mod_01_Instructor.pdf', 185);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Citrus Caramel', 'Confections & Sugar Work', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 71, NULL, NULL, '[]', '[{"name":"sucrose","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"mandarin purée","amounts":[["250","grams"]],"bakers_pct":null,"component":null},{"name":"lemon juice","amounts":[["15","grams"]],"bakers_pct":null,"component":null}]', '[["365","grams"]]', '["Combine sucrose and water to moisten in a saucepan. Cook to a very light amber color.","Remove from heat, and slowly add mandarin and lemon juices. Return to heat and cook to dissolve any hardened bits of sugar. Continue to cook to 105˚C/221˚F. Allow to cool and transfer to a squeeze bottle."]', '[]', 'Pastry_Module_3_Course_6.pdf', 152);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Coconut Caramel', 'Confections & Sugar Work', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 68, 'Yield: 1,206 grams', '1,206 grams', '[]', '[{"name":"coconut milk","amounts":[["300","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["600","grams"]],"bakers_pct":null,"component":null},{"name":"corn syrup","amounts":[["120","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["11","grams"]],"bakers_pct":null,"component":null},{"name":"spiced rum","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["75","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine the first 4 ingredients in a large pot and bring to a boil.","Reduce heat to medium low; simmer for about 30 minutes (or longer if necessary), stirring occasionally until mixture becomes caramel in color.","Stir in rum and water. If caramel thickens too much upon cooling, thin with more coconut milk."]', '[]', 'Pastry_Module_3_Course_6.pdf', 86);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Lollipops', 'Confections & Sugar Work', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 9, NULL, NULL, '[]', '[{"name":"corn syrup","amounts":[["315","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["400","grams"]],"bakers_pct":null,"component":null},{"name":"(approximately","amounts":[["36","pieces"],["940","grams"]],"bakers_pct":null,"component":null}]', NULL, '["In a medium saucepan combine the corn syrup, water and sugar. Place over medium heat and stir occasionally until it comes to a boil. If necessary, wash down the sides of the pan with a clean pastry brush. Once the mixture comes to a boil, cook without stirring until the mixture reaches 300° F","When the mixture reaches 300° F, immediately remove it from the heat and add vanilla and additional flavoring and color.","Pour small circles onto a Silpat sheet and immediately press a stick into each lollipop or pour into supplied lollipop molds. Flavor options  Vanilla: add additional seeds of 1 vanilla bean when the mixture is removed from the heat.  Lemon: add 4 grams of lemon oil, 1.25 grams of citric acid and yellow food color if desired.  Herb or herb flowers: place herbs such as lilac or mint inside the molds before pouring or flowers such as basil flowers onto the lollipops after they have been poured."]', '[]', 'PA_Mod_01_Instructor.pdf', 176);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Lychee Pate De Fruit', 'Confections & Sugar Work', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 8, NULL, NULL, '[]', '[{"name":"lychee purée","amounts":[["500","grams"]],"bakers_pct":null,"component":null},{"name":"sugar(1)","amounts":[["50","grams"]],"bakers_pct":null,"component":null},{"name":"apple pectin","amounts":[["13","grams"]],"bakers_pct":null,"component":null},{"name":"sugar (2)","amounts":[["500","grams"]],"bakers_pct":null,"component":null},{"name":"glucose syrup","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"citric acid","amounts":[["8","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["8","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Place the lychee purée in a large, heavy saucepan, and heat to 104˚F.","Combine the first measurement of sugar (1) and the pectin and whisk into the purée. Bring to a boil while stirring continually.","Add the remaining sugar (2), and glucose in three additions. Continue stirring the mixture and cook to 223˚F. at low heat to make sure the mixture is sufficiently reduced.","Remove the mixture from the heat and stir in citric acid, previously dissolved in the water.","Immediately pour the mixture into a Silpat-lined frame or silicon forms and allow to set at room temperature.","To finish the pate de fruit, cut or unmold as necessary and toss the individual pieces in sugar. weight of the sugar used for coating."]', '["*To add acidity to the coating of the finished pieces, combine 2% citric acid to the"]', 'PA_Mod_01_Instructor.pdf', 100);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Marshmallow', 'Confections & Sugar Work', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 5, NULL, NULL, '[]', '[{"name":"water, cold (1)","amounts":[["85","grams"]],"bakers_pct":null,"component":null},{"name":"gelatin powder","amounts":[["18","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["265","grams"]],"bakers_pct":null,"component":null},{"name":"corn syrup (1)","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"water (2)","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"corn syrup (2)","amounts":[["90","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Place the first measurement of water (1) in a Kitchen Aid bowl; sprinkle the gelatin over the water and let stand about 5 minutes to bloom and soften.","Separately, combine the sugar, corn syrup, and water (2) in a saucepan and begin to heat to 230˚F.","Meanwhile, add the second measurement of corn syrup to the already bloomed gelatin.","Once the cooked sugar mixture reaches 230˚F, pour the mixture into the Kitchen Aid bowl and whip at medium speed until lightened or to a temperature of 86˚F, about 5-7 minutes. Immediately transfer the mixture to a sprayed and plastic-lined quarter sheet pan. Make sure to also spray the plastic wrap on the surface. Gently smooth the surface of the marshmallows and cover with sprayed plastic wrap. Set for 1 hour at room temperature.","Remove the marshmallow slab from the pan by inverting the pan onto a cutting board dusted with dextrose or a mixture of cornstarch and 10X. Cut the slab into 3cm/1in squares and toss in additional dextrose or 10X mixture. Store in a sealed container.","Vanilla: Add the seeds of one split and scraped vanilla bean to mixture before whipping.","Coffee: Add 6g instant espresso to the mixture before whipping.","Lemon: Instead of 85 grams of the first measurement of water, replace it with 90g of lemon juice for blooming the gelatin; add yellow food coloring as needed."]', '["Optional flavorings:"]', 'PA_Mod_01_Instructor.pdf', 169);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('New Orleans Pralines', 'Confections & Sugar Work', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 9, NULL, NULL, '[]', '[{"name":"sugar","amounts":[["300","grams"]],"bakers_pct":null,"component":null},{"name":"brown sugar","amounts":[["125","grams"]],"bakers_pct":null,"component":null},{"name":"milk","amounts":[["130","grams"]],"bakers_pct":null,"component":null},{"name":"pecan halves","amounts":[["150","grams"]],"bakers_pct":null,"component":null},{"name":"butter","amounts":[["85","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine all ingredients and cook to the soft ball stage (240 F), making sure not to stir once the mixture begins to boil.","Remove from heat and stir until mixture begins to thicken and turns cloudy. Quickly, spoon out on parchment paper and allow to cool."]', '[]', 'PA_Mod_01_Instructor.pdf', 178);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Nougatine', 'Confections & Sugar Work', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 9, NULL, NULL, '[]', '[{"name":"sugar","amounts":[["680","grams"]],"bakers_pct":null,"component":null},{"name":"lemon juice","amounts":[["3","grams"]],"bakers_pct":null,"component":null},{"name":"sliced almonds, slightly toasted or warmed","amounts":[["525","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine the sugar and lemon juice in a saucepan and stir until thoroughly mixed - the resulting mixture should have an appearance like wet sand.","Place the pan over medium heat and make a dry caramel. When the sugar is caramelized to a light amber color, while still on the heat, immediately stir in the almonds to coat with the caramel completely.","Immediately pour the nougatine onto a lightly oiled marble surface. Press it flat rapidly with an oiled spatula and roll it into a thin sheet, using an oiled rolling pin. (Do not oil the ends of the rolling pin where your hands are going to be placed)."]', '[]', 'PA_Mod_01_Instructor.pdf', 179);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Nougatine', 'Confections & Sugar Work', 'Module 4', 'Course 7', 'Chocolate & Confections', 76, NULL, NULL, '[]', '[{"name":"sucrose","amounts":[["455","grams"]],"bakers_pct":null,"component":null},{"name":"lemon juice","amounts":[["3","grams"]],"bakers_pct":null,"component":null},{"name":"sliced almonds, lightly toasted","amounts":[["300","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine sucrose and lemon juice in a saucepan and stir until thoroughly mixed. The resulting mixture should have an appearance like wet sand.","Place the pan over medium heat and make a dry caramel. When the sucrose is caramelized to a light amber color, while still on the heat, immediately stir in the almonds to coat with the caramel completely.","Immediately pour the nougatine onto an oiled marble surface. Press it flat with an oiled spatula and roll it into a thin sheet, using an oiled rolling pin. (Do not oil the ends of the rolling pin where your hands are going to be placed)","Cut out desired forms and rapidly shape as needed, or alternatively, shape the nougatine into a bowl for display. Allow nougatine to cool and harden. together. Scraps of nougatine can be further ground and used to add texture and flavor to other confections."]', '["For complex constructions of several pieces, prepare more caramel to adhere pieces"]', 'Pastry_Module_4_Course_7.pdf', 31);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Orange Salt Water Taffy', 'Confections & Sugar Work', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 10, NULL, NULL, '[]', '[{"name":"sugar","amounts":[["200","grams"]],"bakers_pct":null,"component":null},{"name":"corn starch","amounts":[["9","grams"]],"bakers_pct":null,"component":null},{"name":"light corn syrup","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"butter","amounts":[["22","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["115","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["6","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla","amounts":[["2.5","grams"]],"bakers_pct":null,"component":null},{"name":"orange oil","amounts":[["1","gram"]],"bakers_pct":null,"component":null}]', NULL, '["Mix the sugar and cornstarch together in a small pan. Stir in the light corn syrup, butter, water and salt. Cook over medium heat, without stirring to 250 F. while occasionally washing down the sides of the pan with water.","When the mixture reaches 250 F. remove the pot from the heat and stir in the vanilla and orange oil. Pour the mixture onto a very slightly sprayed marble.","After a minute, utilizing a sprayed bench scraper or spatula bring the outside of the taffy in towards the center continuously to cool the taffy evenly.","When the taffy is cool enough to handle, pull and fold the taffy continuously to aerate and cool.","Once shiny and cool enough to hold its shape, roll into thin or twisted cylinders and cut with a sprayed scissor into desired size pieces. Wrap in candy wrappers for storage."]', '[]', 'PA_Mod_01_Instructor.pdf', 182);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Passion Fruit Caramel', 'Confections & Sugar Work', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 73, NULL, NULL, '[]', '[{"name":"sucrose","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"passion fruit purée","amounts":[["250","grams"]],"bakers_pct":null,"component":null}]', '[["350","grams"]]', '["Combine sucrose and water to moisten in a saucepan. Cook to a very light amber color.","Remove from heat, and slowly add the passion fruit purée. Return to heat and cook to dissolve any hardened bits of sugar. Continue to cook to 105˚C/221˚F. Allow to cool and transfer to a squeeze bottle."]', '[]', 'Pastry_Module_3_Course_6.pdf', 225);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Peanut Brittle', 'Confections & Sugar Work', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 10, NULL, NULL, '[]', '[{"name":"sugar","amounts":[["340","grams"]],"bakers_pct":null,"component":null},{"name":"dark corn syrup","amounts":[["245","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["120","grams"]],"bakers_pct":null,"component":null},{"name":"butter","amounts":[["28","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["1","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla","amounts":[["2","grams"]],"bakers_pct":null,"component":null},{"name":"honey roasted salted peanuts","amounts":[["255","grams"]],"bakers_pct":null,"component":null},{"name":"baking soda","amounts":[["4","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Place sugar, corn syrup, water, butter and salt in saucepan, mix to combine.","Over medium heat bring syrup to a boil. Wash sides of pan with a pastry brush dipped in water.","Insert candy thermometer and cook without stirring.","When temperature reaches 300° F, remove from heat.","Stir in vanilla and peanuts, and allow to stand for about 15 to 20 seconds.","Stir in baking soda.","Pour onto silpat lined sheet pan and spread with a sprayed off-set spatula as thin as possible.","After cooled, break into pieces."]', '["Note: Baking soda is added to aerate the brittle and makes it a delicate candy"]', 'PA_Mod_01_Instructor.pdf', 184);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Pear Pate De Fruit', 'Confections & Sugar Work', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 8, NULL, NULL, '[]', '[{"name":"pear purée","amounts":[["500","grams"]],"bakers_pct":null,"component":null},{"name":"sugar (1)","amounts":[["60","grams"]],"bakers_pct":null,"component":null},{"name":"apple pectin","amounts":[["13","grams"]],"bakers_pct":null,"component":null},{"name":"sugar (2)","amounts":[["500","grams"]],"bakers_pct":null,"component":null},{"name":"glucose syrup","amounts":[["110","grams"]],"bakers_pct":null,"component":null},{"name":"citric acid","amounts":[["7","grams"]],"bakers_pct":null,"component":null},{"name":"Poire Williams liqueur","amounts":[["7","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Place the pear purée in a medium, heavy saucepan, and heat to 104˚F.","Combine the first measurement of sugar (1) and the pectin and whisk into the purée. Bring to a boil while stirring continually.","Add the remaining sugar (2) and glucose syrup in three additions. Continue stirring the mixture and cook to 223˚F. while on low heat.","Remove the mixture from the heat and stir in citric acid, previously dissolved in the liqueur.","Immediately pour the mixture into a plastic-lined frame or silicon forms and allow to set at room temperature.","To finish the pate de fruit, cut or unmold as necessary and toss the individual pieces in sugar*. weight of the sugar used for coating."]', '["*To add acidity to the coating of the finished pieces, combine 2% citric acid to the"]', 'PA_Mod_01_Instructor.pdf', 97);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Pecan Caramel', 'Confections & Sugar Work', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 68, '(one 1/2 sheet pan)Yield 1,030 grams', '1,030 grams', '[]', '[{"name":"gelatin powder","amounts":[["5","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["25","grams"]],"bakers_pct":null,"component":null},{"name":"sugar (1)","amounts":[["150","grams"]],"bakers_pct":null,"component":null},{"name":"warmed, toasted pecans","amounts":[["250","grams"]],"bakers_pct":null,"component":null},{"name":"heavy cream","amounts":[["300","grams"]],"bakers_pct":null,"component":null},{"name":"sugar (2)","amounts":[["150","grams"]],"bakers_pct":null,"component":null},{"name":"butter","amounts":[["150","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Bloom powdered gelatin with the 25 grams of water.","Caramelize sugar (1) and stir in warm pecans.","Cool on a silpat, then robot coupe to make a praline paste.","Combine sugar (2) and heavy cream in a small sauce pan. Cook until 218","Remove from heat and stir in praline paste and bloomed gelatin.","Allow to cool to 100 F. Add butter and blend with an immersion blender until smooth.","Spread onto dacquoise and refrigerate."]', '[]', 'Pastry_Module_3_Course_6.pdf', 103);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Raspberry Soft Caramel', 'Confections & Sugar Work', 'Module 4', 'Course 7', 'Chocolate & Confections', 76, NULL, NULL, '[]', '[{"name":"heavy cream (36% fat)","amounts":[["210","grams"]],"bakers_pct":null,"component":null},{"name":"glucose syrup","amounts":[["125","grams"]],"bakers_pct":null,"component":null},{"name":"invert sugar","amounts":[["15","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["1","grams"]],"bakers_pct":null,"component":null},{"name":"raspberry purée","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose","amounts":[["115","grams"]],"bakers_pct":null,"component":null},{"name":"cocoa butter","amounts":[["10","grams"]],"bakers_pct":null,"component":null},{"name":"citric acid","amounts":[["2","grams"]],"bakers_pct":null,"component":null}]', NULL, '["In a heavy saucepan, combine the cream, glucose, invert sugar, salt, raspberry purée, and sucrose; gently heat to a simmer to dissolve the sugars.","Increase the heat and cook, stirring, to 119°C/246°F.","Remove from heat and quickly stir in the cocoa butter and citric acid. Pour the caramel into a 12cm frame lined with plastic film; cool several hours or overnight, before cutting and wrapping, or enrobing. The purée may be substituted for a variety of other flavors for endless variations, when available, including apricot, black currant, peach, etc."]', '[]', 'Pastry_Module_4_Course_7.pdf', 33);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Red Wine Caramel', 'Confections & Sugar Work', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 20, NULL, NULL, '[]', '[{"name":"sucrose","amounts":[["250","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["","as needed"]],"bakers_pct":null,"component":null},{"name":"red wine","amounts":[["375","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine sucrose and water to moisten in a saucepan. Cook to a light amber color.","Remove from heat, and slowly add wine. Return to heat and cook to dissolve any hardened bits of sugar. Continue to cook to 105˚C/221˚F. Allow to cool and transfer to a squeeze bottle."]', '[]', 'PA_Mod_01_Instructor.pdf', 292);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Red Wine Caramel', 'Confections & Sugar Work', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 71, NULL, NULL, '[]', '[{"name":"sucrose","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"red wine","amounts":[["250","grams"]],"bakers_pct":null,"component":null}]', '[["350","grams"]]', '["Combine sucrose and water to moisten in a saucepan. Cook to very light caramel, just until the sugar begins to turn color.","Remove from heat, and slowly add the red wine. Return to heat and cook to dissolve any hardened bits of sugar. Continue to cook to 105˚C/221˚F. Allow to cool and transfer to a squeeze bottle."]', '[]', 'Pastry_Module_3_Course_6.pdf', 162);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Roasted Pears and Dried Figs in Caramel', 'Confections & Sugar Work', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 7, NULL, NULL, '[]', '[{"name":"dried figs, soaked, stemmed and halved","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["115","grams"]],"bakers_pct":null,"component":null},{"name":"dark rum","amounts":[["55","grams"]],"bakers_pct":null,"component":null},{"name":"ground ginger","amounts":[["1","gram"]],"bakers_pct":null,"component":null},{"name":"grated fresh ginger","amounts":[["2","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["2","grams"]],"bakers_pct":null,"component":null},{"name":"grated lemon zest","amounts":[["2","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla extract","amounts":[["4","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Place all ingredients in roasting pan and toss to mix.","Roast at 500 degrees for about 30 minutes.","Toss regularly during baking to ensure even caramelization.","Serve, garnished with pear chips."]', '[]', 'PA_Mod_01_Instructor.pdf', 157);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Salted Cashew Brittle', 'Confections & Sugar Work', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 9, NULL, NULL, '[]', '[{"name":"butter","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"corn syrup","amounts":[["315","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["400","grams"]],"bakers_pct":null,"component":null},{"name":"salted cashews","amounts":[["170","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine the first 4 ingredients in a medium sized pot.","Over medium heat, cook the combined ingredients to 295 F. Do not stir once the mixture comes to a boil.","At 295 F. remove the mixture from the heat and quickly stir in the cashews.","Pour the entire mixture onto a silpat sheet or on a sheet pan lined with parchment that has been sprayed."]', '[]', 'PA_Mod_01_Instructor.pdf', 177);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Strawberry Pate De Fruit', 'Confections & Sugar Work', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 8, NULL, NULL, '[]', '[{"name":"strawberry purée","amounts":[["500","grams"]],"bakers_pct":null,"component":null},{"name":"sugar(1)","amounts":[["50","grams"]],"bakers_pct":null,"component":null},{"name":"apple pectin","amounts":[["13","grams"]],"bakers_pct":null,"component":null},{"name":"sugar (2)","amounts":[["500","grams"]],"bakers_pct":null,"component":null},{"name":"glucose syrup","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"citric acid","amounts":[["8","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["8","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Place the strawberry purée in a medium, heavy saucepan, and heat to 104˚F.","Combine the first measurement of sugar (1) and the pectin and whisk into the purée. Bring to a boil while stirring continually.","Add the remaining sugar (2) and glucose in three additions. Continue stirring the mixture and cook to 223˚F. while on low heat.","Remove the mixture from the heat and stir in citric acid, previously dissolved in the water.","Immediately pour the mixture into a plastic-lined frame or silicon forms and allow to set at room temperature.","To finish the pate de fruit, cut or unmold as necessary and toss the individual pieces in sugar*. weight of the sugar used for coating."]', '["*To add acidity to the coating of the finished pieces, combine 2% citric acid to the"]', 'PA_Mod_01_Instructor.pdf', 99);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Tart Tatin Caramel', 'Confections & Sugar Work', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 7, NULL, NULL, '[]', '[{"name":"sugar","amounts":[["65","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["25","grams"]],"bakers_pct":null,"component":null},{"name":"butter","amounts":[["5","grams"]],"bakers_pct":null,"component":null},{"name":"warm water","amounts":[["20","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Place sugar and water in a small pot. Place on heat to cook and caramelize.","Combine the butter with the warm water and set aside.","When sugar/water mixture begins to caramelize and turns golden, add butter/water mixture to stop the caramel from darkening. Combine until bottom of the pan is covered."]', '[]', 'PA_Mod_01_Instructor.pdf', 155);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Torrone', 'Confections & Sugar Work', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 10, NULL, NULL, '[]', '[{"name":"edible wafer paper","amounts":[["2","sheets"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["60","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["300","grams"]],"bakers_pct":null,"component":null},{"name":"honey","amounts":[["390","grams"]],"bakers_pct":null,"component":null},{"name":"egg white","amounts":[["60","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla","amounts":[["13","grams"]],"bakers_pct":null,"component":null},{"name":"toasted slivered almonds","amounts":[["285","grams"]],"bakers_pct":null,"component":null},{"name":"toasted pistachios","amounts":[["285","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Butter and line quarter sheet pan with parchment, allowing parchment to cover sides and bottom. Place one sheet of edible wafer paper on top of parchment and set aside.","Place water, sugar, and honey in a sauce pan, mix to combine.","Place on medium heat and bring to a boil. Insert candy thermometer and cook without stirring.","When syrup reaches the soft ball stage, begin whipping the egg whites until soft peaks.","Continue cooking syrup until it reaches 286°F.","Remove from heat. While mixing, gradually pour syrup down side of bowl.","Whip until stiff peaks. While meringue is still very warm quickly fold in vanilla and warm nuts.","Press into prepared pan and place sheet of edible wafer paper on top. Press to flatten. If Torrone is firm, you can remove it from the pan and flatten with a rolling pin. If Torrone is too soft to remove from the pan, use the back of another quarter sheet pan to flatten it.","Once set use chef knife to cut into desired size pieces."]', '[]', 'PA_Mod_01_Instructor.pdf', 183);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Almond Paste Cookies Macaroons', 'Cookies & Bars', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 56, '(approximately 1 sheet pan)Yield 966 grams', '966 grams', '[]', '[{"name":"almond paste","amounts":[["450","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["340","grams"]],"bakers_pct":null,"component":null},{"name":"10x","amounts":[["56","grams"]],"bakers_pct":null,"component":null},{"name":"egg whites","amounts":[["120","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine almond paste with sugar and 10x in the bowl of a mixer with the paddle. Mix until crumbly. Pour in egg whites very gradually scraping down the bowl frequently, making sure there are no lumps of almond paste. macaroon.","Sprinkle macaroons with granulated or 10x. Bake at 375 ºF about 10 minutes until slightly golden. The macaroons should be crisp on the outside and soft on the inside.","Allow macaroons to fully cool before removing from tray."]', '[]', 'Pastry_Module_3_Course_5.pdf', 77);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Apricot Almond Rugelach', 'Cookies & Bars', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 56, '(48) Yield 1,238 grams', '1,238 grams', '[]', '[{"name":"AP flour","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"butter","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"cream cheese","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"strained apricot preserves","amounts":[["115","grams"]],"bakers_pct":null,"component":null},{"name":"chopped, toasted almonds","amounts":[["115","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["115","grams"]],"bakers_pct":null,"component":null},{"name":"finely grated lemon zest","amounts":[["6","grams"]],"bakers_pct":null,"component":null},{"name":"egg","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"almond flour","amounts":[["100","grams"]],"bakers_pct":null,"component":null}]', NULL, '["For the cream cheese pastry: In a food processor pulse the flour, butter and cream cheese until there are no lumps and the dough forms a ball. Remove the dough from the bowl and divide into","For the filling: Stir the preserves to loosen and in a separate bowl combine the almonds, sugar and zest and set aside. the almond mixture. Using a pizza wheel, cut the circle into 12 equal wedges. Roll each piece and shape into small crescents.","For the topping: Beat the egg in a bowl to use an egg wash. In another bowl, mix the sugar and almond flour. Brush the tops of each rugelach with egg wash and then sprinkle with almond sugar.","Bake at 325 ºF on silpat sheets until golden."]', '[]', 'Pastry_Module_3_Course_5.pdf', 87);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Basic Sugar Cookie', 'Cookies & Bars', 'Module 4', 'Course 8', 'Cake Decorating', 90, 'Yield 986.5 grams', '986.5 grams', '[]', '[{"name":"butter","amounts":[["255","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["170","grams"]],"bakers_pct":null,"component":null},{"name":"eggs","amounts":[["75","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla extract","amounts":[["5","grams"]],"bakers_pct":null,"component":null},{"name":"AP flour","amounts":[["465","grams"]],"bakers_pct":null,"component":null},{"name":"baking powder","amounts":[["7.5","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["9","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Cream the butter and sugar.","Add the eggs and vanilla.","Add the combined dry ingredients until just incorporated.","Chill before rolling.","Roll, cut as instructed. Freeze before baking to maintain the best shape.","Bake at 350 F."]', '["Utilize the Creaming mixing method"]', 'Pastry_Module_4_Course_8.pdf', 39);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Biscotti alla Mandorla', 'Cookies & Bars', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 3, NULL, NULL, '[]', '[{"name":"whole almonds","amounts":[["115","grams"]],"bakers_pct":null,"component":null},{"name":"all-purpose flour","amounts":[["255","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["170","grams"]],"bakers_pct":null,"component":null},{"name":"baking powder","amounts":[["4","grams"]],"bakers_pct":null,"component":null},{"name":"ground cinnamon","amounts":[["1","gram"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["1","gram"]],"bakers_pct":null,"component":null},{"name":"unsalted butter","amounts":[["55","grams"]],"bakers_pct":null,"component":null},{"name":"egg","amounts":[["50","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla extract","amounts":[["8","grams"]],"bakers_pct":null,"component":null},{"name":"milk or water","amounts":[["44","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Place the almonds on a baking pan and toast them at 350 degrees about 10 minutes, until they are very lightly colored. Cool the almonds.","Combine the flour, sugar, baking powder, cinnamon and salt in a mixing bowl and stir to mix well. Rub in the butter by hand until the mixture is very fine and powdery and no pieces of butter remain visible. Add the cooled almonds.","Combine the egg, vanilla and milk in a bowl and whisk to mix. Stir the liquid into the dough with a fork, continuing to stir until the dough holds together. Turn the dough out on the work surface and knead lightly until smooth. Slide the logs onto a cookie sheet lined with a sheet of parchment and bake at 350 degrees about 20 minutes, until well risen and firm. Remove from oven and cool."]', '[]', 'PA_Mod_01_Instructor.pdf', 51);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Cantucci Di Prato', 'Cookies & Bars', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 56, 'Yield 1,000 grams', '1,000 grams', '[]', '[{"name":"sugar","amounts":[["250","grams"]],"bakers_pct":null,"component":null},{"name":"eggs","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"yolks","amounts":[["70","grams"]],"bakers_pct":null,"component":null},{"name":"orange zest","amounts":[["8","grams"]],"bakers_pct":null,"component":null},{"name":"AP flour","amounts":[["400","grams"]],"bakers_pct":null,"component":null},{"name":"baking powder","amounts":[["14","grams"]],"bakers_pct":null,"component":null},{"name":"almonds, lightly toasted","amounts":[["150","grams"]],"bakers_pct":null,"component":null},{"name":"egg whites for brushing the tops of the logs","amounts":[["8","grams"]],"bakers_pct":null,"component":null}]', NULL, '["In a bowl, by hand or machine, whisk together the sugar, whole eggs, yolks, and orange zest.","In a separate bowl, sift the flour and baking powder.","Add the flour to the egg mixture, stirring until completely incorporated. Add the almonds.","Scrape the dough onto a lightly floured surface. Divide the dough into 4 equal pieces. Shape","Bake at 350ºF until firm and golden brown.","Cool on the pan for 10 minutes. Using a serrated knife, cut on the diagonal into ¾ inch slices. Bake again at 350ºF until crisp."]', '[]', 'Pastry_Module_3_Course_5.pdf', 101);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Chef Dalia''S Coconut Macaroons', 'Cookies & Bars', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 56, 'Yield 1,063 grams', '1,063 grams', '[]', '[{"name":"sugar","amounts":[["350","grams"]],"bakers_pct":null,"component":null},{"name":"desiccated, unsweetened coconut","amounts":[["350","grams"]],"bakers_pct":null,"component":null},{"name":"AP flour","amounts":[["30","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["3","grams"]],"bakers_pct":null,"component":null},{"name":"egg whites","amounts":[["160","grams"]],"bakers_pct":null,"component":null},{"name":"butter","amounts":[["120","grams"]],"bakers_pct":null,"component":null},{"name":"honey","amounts":[["50","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine the sugar, coconut, flour and salt with a paddle.","Add the egg whites and mix until combined.","Melt together the butter, honey and scraped vanilla bean and add to the mixture to combine.","Store in hotel pan and refrigerate overnight.","Scoop and bake at 350ºF."]', '[]', 'Pastry_Module_3_Course_5.pdf', 86);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Chef Jenny''S Sprinkle Doodles', 'Cookies & Bars', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 56, 'Yield 1,053 grams', '1,053 grams', '[]', '[{"name":"butter","amounts":[["224","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["200","grams"]],"bakers_pct":null,"component":null},{"name":"eggs","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"AP flour","amounts":[["360","grams"]],"bakers_pct":null,"component":null},{"name":"cream of tartar","amounts":[["10","grams"]],"bakers_pct":null,"component":null},{"name":"baking soda","amounts":[["5","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["4","grams"]],"bakers_pct":null,"component":null},{"name":"multi-colored sprinkles","amounts":[["150","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Cream the butter and sugar.","Add eggs and mix until combined.","Add dry ingredients making sure to scrape from the bottom just until combined. Add the sprinkles and mix until just combined.","Scoop cookies with a 1-ounce scoop. Roll balls into granulated sugar.","Bake at 350º F."]', '["Utilize the Creaming mixing method."]', 'Pastry_Module_3_Course_5.pdf', 105);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Chef Scott''S Crinkle Cookies', 'Cookies & Bars', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 56, '(75 cookies) Yield 1,134.5 grams', '75 cookies', '[]', '[{"name":"eggs","amounts":[["200","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["145","grams"]],"bakers_pct":null,"component":null},{"name":"bittersweet chocolate","amounts":[["450","grams"]],"bakers_pct":null,"component":null},{"name":"butter","amounts":[["75","grams"]],"bakers_pct":null,"component":null},{"name":"liqueur (Crème de Menthe, Grand Marnier, rum, or brandy)","amounts":[["53","grams"]],"bakers_pct":null,"component":null},{"name":"almond flour","amounts":[["130","grams"]],"bakers_pct":null,"component":null},{"name":"AP flour","amounts":[["75","grams"]],"bakers_pct":null,"component":null},{"name":"baking powder","amounts":[["6.5","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Whip eggs and sugar on high speed until heavy ribbon stage.","Melt chocolate with butter. Off the heat, whisk the liqueur into the chocolate mixture.","Stir the chocolate mixture into the whipped eggs.","Combine the dry ingredients and fold them into the chocolate mixture. Place in a hotel pan and refrigerate until firm.","Place sugar and 10x in separate bowls. With a half-ounce ice cream scoop, scoop chilled cookie batter and roll first in granulated sugar, then roll again 10x. (Make sure they are heavily coated with the 10x!)","Bake at 325F for about 20 minutes. The cookies should remain soft in the center."]', '[]', 'Pastry_Module_3_Course_5.pdf', 83);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Chocolate Cherry Biscotti', 'Cookies & Bars', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 56, 'Yield 1,425 grams', '1,425 grams', '[]', '[{"name":"AP flour","amounts":[["300","grams"]],"bakers_pct":null,"component":null},{"name":"cocoa","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"baking soda","amounts":[["6","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["1","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["400","grams"]],"bakers_pct":null,"component":null},{"name":"dried cherries (coarsely chopped)","amounts":[["250","grams"]],"bakers_pct":null,"component":null},{"name":"semisweet chocolate (coarsely chopped)","amounts":[["110","grams"]],"bakers_pct":null,"component":null},{"name":"eggs","amounts":[["250","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla extract","amounts":[["8","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Sift together the flour, cocoa, baking soda and salt into a bowl. Whisk in the sugar. Add the chocolate and cherries and stir to combine.","Beat the eggs lightly with the vanilla extract and add to the flour mixture. Mix the dough using a spatula or paddle attachment of a mixer. The dough will come together as you continue to mix it.","Turn the dough onto the table and divide into 4 equal pieces. By hand, mold and roll each each log.","Brush the tops of each log with beaten egg white. Sprinkle a little granulated sugar over the tops.","Bake at 325ºF degrees. Cool 10 minutes. Using a serrated knife slice the logs on the degrees until crisp."]', '[]', 'Pastry_Module_3_Course_5.pdf', 100);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Chocolate Chip Cookies', 'Cookies & Bars', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 56, 'Yield 2,043.25 grams', '2,043.25 grams', '[]', '[{"name":"butter","amounts":[["285","grams"]],"bakers_pct":null,"component":null},{"name":"light brown sugar","amounts":[["285","grams"]],"bakers_pct":null,"component":null},{"name":"granulated sugar","amounts":[["228","grams"]],"bakers_pct":null,"component":null},{"name":"eggs","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla extract","amounts":[["9","grams"]],"bakers_pct":null,"component":null},{"name":"AP flour","amounts":[["485","grams"]],"bakers_pct":null,"component":null},{"name":"oat flour","amounts":[["60","grams"]],"bakers_pct":null,"component":null},{"name":"baking soda","amounts":[["6.25","grams"]],"bakers_pct":null,"component":null},{"name":"baking powder","amounts":[["6","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["9","grams"]],"bakers_pct":null,"component":null},{"name":"bittersweet chocolate, coarsely chopped","amounts":[["285","grams"]],"bakers_pct":null,"component":null},{"name":"milk chocolate, coarsely chopped","amounts":[["285","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Cream butter and sugars together until very light, about 5 minutes. Add eggs and vanilla gradually. Scrape down bowl.","Combine flours, baking soda, baking powder and salt into a bowl. Reduce speed to low, add dry ingredients and mix until just combined. Add chopped chocolates.","Scoop onto parchment-lined baking sheet in desired size. Sprinkle lightly with sea salt. Bake at 350 ºF until golden brown but still soft."]', '["Utilize the Creaming method"]', 'Pastry_Module_3_Course_5.pdf', 78);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Chocolate Sables', 'Cookies & Bars', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 56, 'Yield 1,428.5 grams', '1,428.5 grams', '[]', '[{"name":"butter","amounts":[["400","grams"]],"bakers_pct":null,"component":null},{"name":"10x","amounts":[["300","grams"]],"bakers_pct":null,"component":null},{"name":"whole egg","amounts":[["25","grams"]],"bakers_pct":null,"component":null},{"name":"egg yolks","amounts":[["70","grams"]],"bakers_pct":null,"component":null},{"name":"baking powder","amounts":[["2.5","grams"]],"bakers_pct":null,"component":null},{"name":"cake flour","amounts":[["600","grams"]],"bakers_pct":null,"component":null},{"name":"cocoa powder","amounts":[["30","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["1","gram"]],"bakers_pct":null,"component":null}]', NULL, '["Cream butter and sugar.","Beat in egg and yolks gradually.","Add dry ingredients and mix until just combined, being careful not to over mix.","Divide dough and shape each into logs or as instructed. Chill until firm."]', '["Utilize the Creaming mixing method."]', 'Pastry_Module_3_Course_5.pdf', 90);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Clove Scented Pecan Snowballs', 'Cookies & Bars', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 56, 'Yield 2,017 grams', '2,017 grams', '[]', '[{"name":"butter","amounts":[["565","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["170","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["8","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["15","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla extract","amounts":[["14","grams"]],"bakers_pct":null,"component":null},{"name":"AP flour","amounts":[["680","grams"]],"bakers_pct":null,"component":null},{"name":"pecans, very finely chopped","amounts":[["565","grams"]],"bakers_pct":null,"component":null},{"name":"10x","amounts":[["500","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Cream the butter with the sugar and salt. Add vanilla and water. Add flour and mix to incorporate and then add pecans. Do not over mix.","Scoop dough with a small ice cream scoop. Place on parchment-lined sheet pan and bake at 350 ºF for about 15 minutes until firm. Remove from oven and immediately and carefully place in a hotel pan filled with the 10x (and cloves, if desired) and make sure to completely cover. Allow to cool in 10x overnight if possible. After completely cooled, remove from 10x and roll in fresh 10x."]', '[]', 'Pastry_Module_3_Course_5.pdf', 80);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Cocoa Tuile Cup', 'Cookies & Bars', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 19, NULL, NULL, '[]', '[{"name":"butter, unsalted, softened","amounts":[["170","grams"]],"bakers_pct":null,"component":null},{"name":"confectioner''s sugar","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla extract","amounts":[["8","grams"]],"bakers_pct":null,"component":null},{"name":"egg whites","amounts":[["180","grams"]],"bakers_pct":null,"component":null},{"name":"all-purpose flour","amounts":[["140","grams"]],"bakers_pct":null,"component":null},{"name":"cocoa powder","amounts":[["28","grams"]],"bakers_pct":null,"component":null},{"name":"heavy cream (36% fat)","amounts":[["30","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Beat the butter on medium speed with the paddle attachment until soft and light.","Sift the confectioners'' sugar into a bowl and beat it into the butter mixture. Continue beating until light.","Add the vanilla, followed by half of the egg whites.","Combine the cocoa powder and flour together and beat half into the butter-sugar mixture. Beat in the remaining egg whites and cream. Add the remaining flour-cocoa mixture.","Apply a thin layer of the batter onto Silpat-lined sheet pans using a stencil.","Bake at 205°C/400°F for about 6 minutes, or until just golden around the edges. Immediately remove the tuile from the pans and place each one in a small bowl or"]', '[]', 'PA_Mod_01_Instructor.pdf', 323);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Florentines', 'Cookies & Bars', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 56, '(60 cookies) Yield 1,343 grams', '60 cookies', '[]', '[{"name":"AP flour","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"candied orange peel, finely chopped","amounts":[["240","grams"]],"bakers_pct":null,"component":null},{"name":"dried figs, finely chopped","amounts":[["180","grams"]],"bakers_pct":null,"component":null},{"name":"pistachios, finely chopped","amounts":[["80","grams"]],"bakers_pct":null,"component":null},{"name":"slivered almonds, finely chopped","amounts":[["240","grams"]],"bakers_pct":null,"component":null},{"name":"butter","amounts":[["200","grams"]],"bakers_pct":null,"component":null},{"name":"Demerara (or light brown) sugar","amounts":[["240","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["3","grams"]],"bakers_pct":null,"component":null},{"name":"heavy cream","amounts":[["60","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Sift the flour into a large bowl. Add the fruit and nuts and toss until evenly distributed.","Melt the butter and sugar over medium heat. Remove from heat and add salt and cream.. Pour into the bowl of flour, fruit and nuts and stir until completely combined.","Using a small ice cream scoop, place about a 1/2-ounce of the batter on silpats, about 3 inches apart. Using a fork, flatten the batter as much as possible without leaving holes.","Bake at 350F for about 10-12 minutes until deep golden brown all over, then allow to cool on the tray.","Melt pate a glace over double boiler and brush the underside of each Florentine with pate a glace. Leave to cool and set. separately and combine."]', '["*pate a glace, for coating","Note: To make your own pate a glace if necessary, melt 2 parts chocolate and 1 part shortening"]', 'Pastry_Module_3_Course_5.pdf', 82);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Nick Malgieri''S Supernatural Brownies', 'Cookies & Bars', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 56, 'Approximately 50 2”x2”(1/2 sheet pan) Yield 3,142 grams', '3,142 grams', '[]', '[{"name":"butter","amounts":[["450","grams"]],"bakers_pct":null,"component":null},{"name":"bittersweet or semisweet chocolate","amounts":[["450","grams"]],"bakers_pct":null,"component":null},{"name":"eggs","amounts":[["400","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["3","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["450","grams"]],"bakers_pct":null,"component":null},{"name":"dark brown sugar","amounts":[["450","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla extract","amounts":[["14","grams"]],"bakers_pct":null,"component":null},{"name":"AP flour","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"(optional) walnuts, chopped large","amounts":[["700","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Melt butter and chocolate over a double boiler.","Whisk eggs in a large bowl and whisk in salt, sugar, brown sugar and vanilla. Temper with the melted chocolate and butter mixture, then stir in flour.","Pour batter onto a buttered and parchment-lined half sheet pan and spread evenly. Bake for about 1 hour at 350ºF, until batter is moderately firm in the center. Chill before cutting. Cut"]', '[]', 'Pastry_Module_3_Course_5.pdf', 91);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Oatmeal Cookies', 'Cookies & Bars', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 56, 'Yield 1,777 grams', '1,777 grams', '[]', '[{"name":"butter, softened","amounts":[["228","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["228","grams"]],"bakers_pct":null,"component":null},{"name":"dark brown sugar","amounts":[["228","grams"]],"bakers_pct":null,"component":null},{"name":"eggs","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla extract","amounts":[["4","grams"]],"bakers_pct":null,"component":null},{"name":"AP flour","amounts":[["256","grams"]],"bakers_pct":null,"component":null},{"name":"rolled oats","amounts":[["185","grams"]],"bakers_pct":null,"component":null},{"name":"baking powder","amounts":[["4","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["4","grams"]],"bakers_pct":null,"component":null},{"name":"raisins","amounts":[["255","grams"]],"bakers_pct":null,"component":null},{"name":"semisweet chocolate, coarsely chopped","amounts":[["170","grams"]],"bakers_pct":null,"component":null},{"name":"walnuts, coarsely chopped","amounts":[["115","grams"]],"bakers_pct":null,"component":null}]', NULL, '["On medium speed beat together butter, granulated sugar, and brown sugar until well mixed. Add eggs gradually. Beat in vanilla.","Combine the flour, baking powder, salt, and rolled oats.","Add the flour and oat mixture to the creamed mixture and combine well. Add raisins, walnuts, and chocolate.","Using a small ice cream scoop, drop batter, well-spaced, onto parchment-lined sheet pans.","Flatten with the back of a fork. Chill if possible.","Bake at 350 ºF until well colored and firm."]', '["Utilize the Creaming mixing method."]', 'Pastry_Module_3_Course_5.pdf', 88);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Pizzele', 'Cookies & Bars', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 19, NULL, NULL, '[]', '[{"name":"all-purpose flour","amounts":[["228","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose","amounts":[["172","grams"]],"bakers_pct":null,"component":null},{"name":"almond flour","amounts":[["58","grams"]],"bakers_pct":null,"component":null},{"name":"baking powder","amounts":[["7","grams"]],"bakers_pct":null,"component":null},{"name":"whole eggs","amounts":[["150","grams"]],"bakers_pct":null,"component":null},{"name":"clarified butter, melted","amounts":[["110","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla extract","amounts":[["5","grams"]],"bakers_pct":null,"component":null},{"name":"almond extract","amounts":[["3","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine half of the flour with remaining dry ingredients.","In a bowl whip the eggs by hand and beat in the butter and vanilla.","Add dry mixture to the egg mixture. Fold in the remaining flour.","Heat a pizzelle iron and place approximately one heaping tablespoon of batter on it. Close iron and cook 30 seconds to one minute."]', '[]', 'PA_Mod_01_Instructor.pdf', 322);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Raspberry or Apricot Crumb Bars', 'Cookies & Bars', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 56, '(one half sheet pan) Yield', NULL, '[]', '[{"name":"BAKED SHORTBREAD BASE","amounts":[["1","recipe"]],"bakers_pct":null,"component":null},{"name":"seedless raspberry jam or apricot preserves","amounts":[["450","grams"]],"bakers_pct":null,"component":null},{"name":"CRUMB TOPPING FOR BAR COOKIES","amounts":[["1","recipe"]],"bakers_pct":null,"component":null}]', NULL, '["Spread the jam or preserves evenly on the dough and within the sheet pan extender.","Distribute the crumb topping evenly. Bake at 350ºF until the crumbs are well colored."]', '[]', 'Pastry_Module_3_Course_5.pdf', 94);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Salted Peanut Butter Cookies', 'Cookies & Bars', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 56, 'Yield 1,605 grams', '1,605 grams', '[]', '[{"name":"COOKIES","amounts":[["255","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"light brown sugar","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"eggs","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla extract","amounts":[["15","grams"]],"bakers_pct":null,"component":null},{"name":"AP flour","amounts":[["340","grams"]],"bakers_pct":null,"component":null},{"name":"baking soda","amounts":[["10","grams"]],"bakers_pct":null,"component":null},{"name":"Kosher salt","amounts":[["10","grams"]],"bakers_pct":null,"component":null},{"name":"salted peanuts","amounts":[["225","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Cream together the shortening, peanut butter, sugar and brown sugar.","Add liquid ingredients, mix to combine","Add dry ingredients and mix until just combined.","Add peanuts mixed with salt.","Utilize a small ice cream scoop and bake at 350 F. until very slightly firm."]', '["Utilize the Creaming mixing method."]', 'Pastry_Module_3_Course_5.pdf', 106);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Spritz Cookies', 'Cookies & Bars', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 56, 'Yield 1,870 grams', '1,870 grams', '[]', '[{"name":"almond paste","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"10x","amounts":[["280","grams"]],"bakers_pct":null,"component":null},{"name":"eggs","amounts":[["235","grams"]],"bakers_pct":null,"component":null},{"name":"butter","amounts":[["450","grams"]],"bakers_pct":null,"component":null},{"name":"cake flour","amounts":[["680","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Mix the almond paste, butter and 10x with a paddle making sure there are absolutely no lumps. Add the eggs gradually, scraping the sides often. Cream all of these ingredients until light. Add the cake flour and mix just until combined.","Pipe as directed. Bake at 350ºF for 15 minutes or until there is color on the bottom of the cookie. These cookies should be very light in color"]', '["Utilize the Creaming method"]', 'Pastry_Module_3_Course_5.pdf', 79);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Tennessee Icebox Cookies', 'Cookies & Bars', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 56, 'Yield 1250 grams', '1250 grams', '[]', '[{"name":"butter, softened","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"light brown sugar","amounts":[["450","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla extract","amounts":[["14","grams"]],"bakers_pct":null,"component":null},{"name":"eggs","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"AP flour","amounts":[["340","grams"]],"bakers_pct":null,"component":null},{"name":"baking soda","amounts":[["4","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["2","grams"]],"bakers_pct":null,"component":null},{"name":"slivered almonds","amounts":[["115","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Cream the butter, brown sugar and vanilla.","Beat in the eggs making sure to scrape down the sides.","Combine dry ingredients and add to creamed mixture. Mix until just combined, then add the almonds.","Scrape the dough onto a lightly floured work surface and shape into logs as instructed.","Chill the dough until firm.","Slice the cookies ¼” thick and arrange the cookies on parchment-lined sheet pans and bake at 350ºF."]', '["Utilize the Creaming mixing method."]', 'Pastry_Module_3_Course_5.pdf', 98);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('The Good Cook''s Gingersnaps', 'Cookies & Bars', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 4, '(40 Cookies) Yield 250 Cookies', '40 Cookies', '[]', '[{"name":"butter","amounts":[["170","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"all purpose flour","amounts":[["255","grams"]],"bakers_pct":null,"component":null},{"name":"baking soda","amounts":[["9","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["1","gram"]],"bakers_pct":null,"component":null},{"name":"ground ginger","amounts":[["4","grams"]],"bakers_pct":null,"component":null},{"name":"ground cinnamon","amounts":[["3","grams"]],"bakers_pct":null,"component":null},{"name":"ground cloves","amounts":[["1","grams"]],"bakers_pct":null,"component":null},{"name":"egg","amounts":[["50","grams"]],"bakers_pct":null,"component":null},{"name":"molasses","amounts":[["85","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Cream the butter and sugar until light.","Beat in the egg and molasses.","Sift together the flour, baking soda, salt, ginger, cinnamon, and cloves.","Mix the dry ingredients into the creamed mixture until just combined.","Scoop and roll into balls, and place on parchment-lined sheet pans.","Bake at 350 F until cracked on top and set."]', '[]', 'PA_Mod_01_Instructor.pdf', 68);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Tuile Cup', 'Cookies & Bars', 'Module 1', 'Course 2', 'Baking Techniques & Ingredients Pt 2', 19, NULL, NULL, '[]', '[{"name":"butter, softened","amounts":[["170","grams"]],"bakers_pct":null,"component":null},{"name":"confectioner''s sugar","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla extract","amounts":[["8","grams"]],"bakers_pct":null,"component":null},{"name":"egg whites","amounts":[["180","grams"]],"bakers_pct":null,"component":null},{"name":"all-purpose flour","amounts":[["200","grams"]],"bakers_pct":null,"component":null},{"name":"heavy cream","amounts":[["30","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Beat the butter on medium speed with the paddle attachment until soft and light.","Sift the confectioners'' sugar into a bowl and beat it into the butter mixture. Continue beating until light.","Add the vanilla, followed by half of the egg whites.","Beat half of the flour into the butter-sugar mixture. Beat in the remaining egg whites and cream. Add the remaining flour.","Apply a thin layer of the batter onto Silpat-lined sheet pans using a stencil.","Bake at 205°C/400°F for about 6 minutes, or until just golden around the edges. Immediately remove the tuile from the pans and place each one in a small bowl or brioche tin. Place another mold, smaller that the first, over each tuile and press it into the bottom of the mold. Leave the tuile in the molds until cool and crisp."]', '[]', 'Pastry_Module_1_Course_2.pdf', 145);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Vanilla Sables', 'Cookies & Bars', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 56, 'Yield 1,011 grams', '1,011 grams', '[]', '[{"name":"butter","amounts":[["450","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["250","grams"]],"bakers_pct":null,"component":null},{"name":"egg yolks","amounts":[["40","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla extract","amounts":[["8","grams"]],"bakers_pct":null,"component":null},{"name":"AP flour","amounts":[["565","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Cream butter, sugar and salt.","Add the yolks and vanilla extract.","Add flour and mix until just combined, being careful not to over mix.","Shape into logs or as instructed. Chill until firm."]', '["Utilize the Creaming mixing method."]', 'Pastry_Module_3_Course_5.pdf', 89);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Venetian Rainbow Cookies', 'Cookies & Bars', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 56, '(one half sheet pan) Yield 3,040 grams', '3,040 grams', '[]', '[{"name":"almond paste","amounts":[["450","grams"]],"bakers_pct":null,"component":null},{"name":"sugar (1)","amounts":[["340","grams"]],"bakers_pct":null,"component":null},{"name":"butter, softened","amounts":[["565","grams"]],"bakers_pct":null,"component":null},{"name":"yolks","amounts":[["160","grams"]],"bakers_pct":null,"component":null},{"name":"almond extract","amounts":[["7","grams"]],"bakers_pct":null,"component":null},{"name":"AP flour","amounts":[["500","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["3","grams"]],"bakers_pct":null,"component":null},{"name":"red food coloring gel","amounts":[["","as needed"]],"bakers_pct":null,"component":null},{"name":"green food coloring gel","amounts":[["","as needed"]],"bakers_pct":null,"component":null},{"name":"egg whites","amounts":[["480","grams"]],"bakers_pct":null,"component":null},{"name":"sugar (2)","amounts":[["115","grams"]],"bakers_pct":null,"component":null},{"name":"apricot preserves, heated and strained","amounts":[["790","grams"]],"bakers_pct":null,"component":null},{"name":"pate a glace","amounts":[["450","grams"]],"bakers_pct":null,"component":null}]', NULL, '["With the paddle attachment, beat almond paste, sugar (1) and butter until light, fluffy and no lumps remain.","Add yolks and extract and beat until combined.","Add flour and salt and beat until combined.","Divide mixture into thirds in three separate bowls. Color one bowl, red. Color another green. Leave the remaining bowl uncolored. Set bowls aside.","Separately, whip egg whites, gradually adding sugar (2) to achieve a soft peak. Divide the meringue equally into each bowl of almond paste mixture, and then fold to combine. Spread each bowl of batter onto its own parchment-lined half sheet pan that has been slightly sprayed with pan spray. Make sure to use the flattest trays and to spread the batter as evenly as possible.","Bake at 350ºF until just set in the center. DO NOT OVERBAKE.","Chill layers before spreading apricot preserves in between. If possible, weigh down assembled layers and chill before covering with pate a glace. Cut as instructed."]', '[]', 'Pastry_Module_3_Course_5.pdf', 102);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Basque Cake Basque Cake Batter Pastry Cream Basque Cake Batter', 'Custards & Creams', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 65, '(two 9” cakes)Yield 2,821 grams', '2,821 grams', '[]', '[{"name":"butter","amounts":[["652","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["782","grams"]],"bakers_pct":null,"component":null},{"name":"eggs","amounts":[["345","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla","amounts":[["19","grams"]],"bakers_pct":null,"component":null},{"name":"AP flour","amounts":[["1000","grams"]],"bakers_pct":null,"component":null},{"name":"baking powder","amounts":[["18.5","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["4.5","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Cream the butter and sugar.","Add the eggs and vanilla gradually until emulsified.","Add the dry ingredients and mix until just combined.","With half the batter use a # 806 tip to pipe a continuous spiral of batter, starting from the center, to completely cover the bottom of the pan (* Do not overfill the bag as the batter is very stiff) Along the outer edge, pipe one complete ring to create a dam at the edge. (This will contain the pastry cream in the center which will be added next.)","Place the pastry cream in a pastry bag with a # 806 tip and pipe the pastry cream in the center of the dam and pipe a single continuous spiral until the dam that you have created has been filled."]', '["*Note: Prepare the pastry cream filling recipe first.","Utilize the Creaming Method"]', 'Pastry_Module_3_Course_6.pdf', 51);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Bourbon Diplomat Cream', 'Custards & Creams', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 73, NULL, NULL, '[]', '[{"name":"heavy cream (36% fat), whipped to firm peaks","amounts":[["200","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla pastry cream","amounts":[["750","grams"]],"bakers_pct":null,"component":null},{"name":"bourbon whiskey","amounts":[["20","grams"]],"bakers_pct":null,"component":null}]', '[["980","grams"]]', '["Gently fold together the whipped cream, chilled vanilla pastry cream, and bourbon. Reserve chilled."]', '[]', 'Pastry_Module_3_Course_6.pdf', 214);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Bread Pudding', 'Custards & Creams', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 16, NULL, NULL, '[]', '[{"name":"yellow raisins","amounts":[["28","grams"]],"bakers_pct":null,"component":null},{"name":"dark rum (optional)","amounts":[["14","grams"]],"bakers_pct":null,"component":null},{"name":"brioche rolls or loafs","amounts":[["170","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Bring the raisins to a boil in a small pan of water and drain. Place raisins in a container just large enough to hold them and pour the rum over them (optional).","Scatter the raisins on the bottom of individual pudding dishes. Cut the bread into 1/4-cubes. Place the cubes in the individual containers.","Pour the basic custard mixture over the bread, making sure that the bread is evenly moistened. Allow the brioche a few minutes to absorb the custard and to see if more custard mix is needed.","Bake in a pan of water at 300 degrees for approximately 45 minutes or until custard has set. Serve the Bread Pudding warm. Options: add bananas, chocolate chips or nuts to the bread pudding."]', '["Note: Serve with Caramel Sauce if desired."]', 'PA_Mod_01_Instructor.pdf', 247);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Caramel Pastry Cream', 'Custards & Creams', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 73, NULL, NULL, '[]', '[{"name":"corn starch","amounts":[["50","grams"]],"bakers_pct":null,"component":null},{"name":"whole milk (1)","amounts":[["50","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose (1)","amounts":[["25","grams"]],"bakers_pct":null,"component":null},{"name":"whole eggs","amounts":[["50","grams"]],"bakers_pct":null,"component":null},{"name":"egg yolks","amounts":[["80","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["1","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose (2)","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"whole milk (2)","amounts":[["495","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla bean, split and scraped","amounts":[["1","each"]],"bakers_pct":null,"component":null},{"name":"butter, unsalted","amounts":[["60","grams"]],"bakers_pct":null,"component":null}]', '[["911","grams"]]', '["Whisk the corn starch into the first measurement of milk (1) in a medium-sized mixing bowl, followed by the first measurement of sucrose (1), the whole eggs, egg yolks and salt.","Place the second measurement of sucrose (2) and water to cover in a medium saucepan. Cook to a medium amber caramel. Meanwhile, warm the milk and vanilla. Slowly add the warmed milk to caramel and bring to a boil.","Remove from heat and temper the warm milk mixture into the corn starch mixture. Return to heat and cook over medium heat, whisking constantly, just to a boil. Remove from heat (remove and the scraped vanilla pod) and whisk in the butter; transfer to a shallow container, cover with plastic film, and chill rapidly."]', '[]', 'Pastry_Module_3_Course_6.pdf', 232);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Chartreuse Mousseline', 'Custards & Creams', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 73, NULL, NULL, '[]', '[{"name":"vanilla pastry cream","amounts":[["500","grams"]],"bakers_pct":null,"component":null},{"name":"Swiss buttercream, whipped smooth","amounts":[["500","grams"]],"bakers_pct":null,"component":null},{"name":"green chartreuse","amounts":[["25","grams"]],"bakers_pct":null,"component":null}]', '[["1025","grams"]]', '["Beat the pastry cream smooth to loosen it.","In a separate bowl, beat the Swiss buttercream until smooth.","Combine the pastry cream and buttercream, beating until fully homogeneous.","Add the green chartreuse and beat until evenly incorporated.","Chill until ready to pipe or spread."]', '[]', 'Pastry_Module_3_Course_6.pdf', 208);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Chocolate & Summer Berry Coulis Dome Lime Dacquoise Cake Summer Berry Coulis Insert Chocolate Mousse Vanilla Mousseline Lime Dacquoise Cake', 'Custards & Creams', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 68, '(one 1/2 sheet) Yield 803 grams', '803 grams', '[]', '[{"name":"10 X","amounts":[["175","grams"]],"bakers_pct":null,"component":null},{"name":"almond flour","amounts":[["175","grams"]],"bakers_pct":null,"component":null},{"name":"limes, zested","amounts":[["3","each"]],"bakers_pct":null,"component":null},{"name":"lime juice","amounts":[["1","each"]],"bakers_pct":null,"component":null},{"name":"egg whites","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["75","grams"]],"bakers_pct":null,"component":null},{"name":"almonds, sliced and chopped","amounts":[["150","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine the 10 X, almond flour and lime zest and set aside.","In a mixer with the whip attachment, whip egg whites and lime juice. Gradually add the granulated sugar to make an ordinary meringue and whip to a firm peak.","Remove from the mixer and fold in almond flour mixture.","Spread batter on a parchment lined half sheet pan and sprinkle with chopped almonds.","Bake at 375 F. for 10-12 minutes until a light golden brown.","Allow cake to cool, invert and remove parchment paper.","Cut into discs to fit bottom of 12 flexi molds."]', '[]', 'Pastry_Module_3_Course_6.pdf', 108);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Chocolate Cremeux', 'Custards & Creams', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 64, 'Yield 2,450 grams', '2,450 grams', '[]', '[{"name":"whole milk","amounts":[["650","grams"]],"bakers_pct":null,"component":null},{"name":"heavy cream","amounts":[["650","grams"]],"bakers_pct":null,"component":null},{"name":"egg yolks","amounts":[["300","grams"]],"bakers_pct":null,"component":null},{"name":"trimoline","amounts":[["160","grams"]],"bakers_pct":null,"component":null},{"name":"gelatin, bloomed","amounts":[["13","sheets"]],"bakers_pct":null,"component":null},{"name":"semisweet chocolate","amounts":[["470","grams"]],"bakers_pct":null,"component":null},{"name":"milk chocolate","amounts":[["220","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Prepare a crème Anglaise: Boil the milk, cream and vanilla beans.","Meanwhile, whisk together yolks and trimoline.","Temper yolk mixture with hot liquid, return entire mixture to the pan and cook over medium heat, stirring constantly until mixture thickens to nappe or reaches 180F. Remove from heat and add the bloomed gelatin.","Pour hot crème anglaise through a chinoise over the chocolates and stir until combined.","Cover with plastic wrap making sure it touches surface of the custard to prevent a skin. Set aside to cool to 75F and then use."]', '[]', 'Pastry_Module_3_Course_6.pdf', 35);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Citrus Curd Tart', 'Custards & Creams', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 37, NULL, NULL, '["3-inch Tart"]', '[{"name":"pate brisee","amounts":[["250","grams"]],"bakers_pct":null,"component":null},{"name":"pastry cream, flavored Framboise or Kirsch","amounts":[["250","grams"]],"bakers_pct":null,"component":null},{"name":"Citrus Curd","amounts":[["60","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Bake at 350 degrees for about 25 minutes, or until set. Remove paper and beans and continue baking shell until very lightly colored. Cool the baked shell.","Spread a small amount of curd evenly in tart shell. Cover with meringue topping and brûlée with a propane torch."]', '[]', 'Pastry_Module_2_Course_4.pdf', 43);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Coffee Creme', 'Custards & Creams', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 68, '(one 1/2 sheet pan)Yield 1,001 grams', '1,001 grams', '[]', '[{"name":"gelatin powder","amounts":[["9","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["45","grams"]],"bakers_pct":null,"component":null},{"name":"milk","amounts":[["160","grams"]],"bakers_pct":null,"component":null},{"name":"heavy cream","amounts":[["500","grams"]],"bakers_pct":null,"component":null},{"name":"instant espresso","amounts":[["6","grams"]],"bakers_pct":null,"component":null},{"name":"Trablit coffee extract","amounts":[["6","grams"]],"bakers_pct":null,"component":null},{"name":"egg yolks","amounts":[["160","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["115","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Bloom gelatin with the 45 grams of water.","Bring the next 4 ingredients to a boil","Whisk together the egg yolks and sugar and temper with the boiled mixture.","Return to the heat and cook to 185 F., being careful not to overcook.","Add the bloomed gelatin, stir to combine, and chill over an ice bath.","When cooled, blend with an immersion blender until smooth.","Pour into the cake frame on top of the Pecan Caramel and refrigerate."]', '[]', 'Pastry_Module_3_Course_6.pdf', 104);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Coffee Creme Brulee', 'Custards & Creams', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 16, NULL, NULL, '[]', '[{"name":"heavy cream","amounts":[["475","grams"]],"bakers_pct":null,"component":null},{"name":"Trablit coffee extract","amounts":[["12","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["85","grams"]],"bakers_pct":null,"component":null},{"name":"yolks","amounts":[["100","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine cream, Trablit, sugar and vanilla bean in a pan and bring to a simmer. Whisk yolks in a bowl and temper with hot mixture. Strain through chinoise or fine strainer and skim foam from surface if necessary.","Pour the custard mixture into crème brulee dishes. Remove excess foam with torch if necessary. Bake in a water bath at 350 degrees until set. Cool and place in freezer about 1 hour or in refrigerator overnight."]', '["For the next lesson:"]', 'PA_Mod_01_Instructor.pdf', 242);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Creme Anglaise', 'Custards & Creams', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 17, NULL, NULL, '[]', '[{"name":"half and half","amounts":[["485","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["113","grams"]],"bakers_pct":null,"component":null},{"name":"egg yolks","amounts":[["100","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Bring half and half to a boil with sugar and split vanilla bean.","Whisk yolks to break them up, then temper with some of the boiling milk.","Return the remaining milk to the heat and whisk in the yolk mixture. Stir mixture constantly, until thickened to nappe or 180° F.","Strain immediately into a clean bowl over ice, and whisk to cool. Cover and refrigerate."]', '["Note: Crème Anglaise is part of your practical exam on lesson 23."]', 'PA_Mod_01_Instructor.pdf', 257);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Creme Anglaise Mousse Base', 'Custards & Creams', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 62, 'Yield 520 grams', '520 grams', '[]', '[{"name":"heavy cream","amounts":[["250","grams"]],"bakers_pct":null,"component":null},{"name":"milk","amounts":[["85","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["65","grams"]],"bakers_pct":null,"component":null},{"name":"egg yolks","amounts":[["120","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Bring the cream and milk to a boil with the sugar and split vanilla bean.","Whisk yolks in a bowl to break them up, then temper with some of the boiling cream and milk.","Return the remaining cream and milk to the heat and whisk in the yolk mixture. Stir the mixture constantly, until thickened to nappé or 180° F.","Strain immediately into a clean bowl over an ice bath.","Scale for mousse recipe as needed and proceed with instructions."]', '[]', 'Pastry_Module_3_Course_5.pdf', 189);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Creme Brulee', 'Custards & Creams', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 16, NULL, NULL, '[]', '[{"name":"heavy cream","amounts":[["475","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["85","grams"]],"bakers_pct":null,"component":null},{"name":"yolks","amounts":[["100","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine cream, sugar and vanilla bean in a pan and bring to a simmer. Whisk yolks in a bowl and temper with hot mixture. Strain through chinoise or fine strainer and skim foam from surface if necessary.","Pour the custard mixture into shallow ovenproof dishes. Remove excess foam with torch if necessary. Bake in a water bath at 350 degrees until set. Cool and place in freezer about 1 hour or in refrigerator overnight."]', '["For the next lesson:"]', 'PA_Mod_01_Instructor.pdf', 241);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Creme Mousseline', 'Custards & Creams', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 67, NULL, NULL, '[]', '[{"name":"butter","amounts":[["400","grams"]],"bakers_pct":null,"component":null},{"name":"pastry cream, cooled","amounts":[["800","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla or desired alcohol","amounts":[["20","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Beat butter on medium speed with paddle until soft and light and no lumps remain.","Beat in pastry cream, continuing to beat until smooth.","Beat in flavoring at end."]', '[]', 'Pastry_Module_3_Course_6.pdf', 73);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Creme Mousseline Pralinee', 'Custards & Creams', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 21, NULL, NULL, '["LARGE BATCH","MEDIUM BATCH","SMALL BATCH"]', '[{"name":"butter","amounts":[["450","grams"]],"bakers_pct":null,"component":null},{"name":"praline paste","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"Pastry Cream","amounts":[["775","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Proceed as for Crème Mousseline, beating butter and praline paste together until smooth, before adding pastry cream."]', '[]', 'PA_Mod_01_Instructor.pdf', 338);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Crepe Layers Pastry Cream Crepe Layers', 'Custards & Creams', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 67, 'Yield', NULL, '["8” round"]', '[{"name":"milk","amounts":[["1700","grams"]],"bakers_pct":null,"component":null},{"name":"eggs","amounts":[["500","grams"]],"bakers_pct":null,"component":null},{"name":"butter, melted","amounts":[["281","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla extract","amounts":[["10","grams"]],"bakers_pct":null,"component":null},{"name":"orange zest","amounts":[["10","grams"]],"bakers_pct":null,"component":null},{"name":"lemon zest","amounts":[["10","grams"]],"bakers_pct":null,"component":null},{"name":"AP flour","amounts":[["675","grams"]],"bakers_pct":null,"component":null},{"name":"fine sea salt","amounts":[["3.75","grams"]],"bakers_pct":null,"component":null},{"name":"clarified butter","amounts":[["","as needed"]],"bakers_pct":null,"component":null},{"name":"two 8” cakes (about 60 crepes)","amounts":[["3189.75","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Place the first 6 ingredients in a bowl and blend well to combine.","Add the flour and salt and blend until distributed evenly. Place the mixture, half at a time in a blender and blend just until smooth.","Strain the mixture with a fine strainer and place in refrigerator for a minimum of one half hour.","To cook the crepes, heat a crepe pan over medium heat and brush lightly with the clarified butter. With a 2 ounce ladle, swirl the crepe batter onto the bottom of the pan.","Cook on the first side until the crepe is set and the edges are a light brown color.","Flip the crepes and cook briefly on the other side. Slide out of the pan onto a parchment lined pan."]', '[]', 'Pastry_Module_3_Course_6.pdf', 79);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Crunchy Choux, Chartreuse Mousseline, Strawberry Pate a Choux', 'Custards & Creams', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 73, NULL, NULL, '[]', '[{"name":"whole milk","amounts":[["125","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["125","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose","amounts":[["10","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["2","grams"]],"bakers_pct":null,"component":null},{"name":"butter","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"AP flour","amounts":[["75","grams"]],"bakers_pct":null,"component":null},{"name":"bread flour","amounts":[["75","grams"]],"bakers_pct":null,"component":null},{"name":"whole eggs","amounts":[["225","grams"]],"bakers_pct":null,"component":null}]', '[["737","grams"]]', '["Place the milk, water, sucrose, salt, and butter in saucepan and bring to a rolling boil.","Remove from heat and stir in the flour until combined; return to heat and cook for 1-2 minutes until a smooth mass has formed.","Transfer to the bowl of a stand mixer fitted with the paddle attachment. Beat the mixture until slightly cooled; incorporate the eggs gradually scraping as needed.","Transfer the paste to a pastry bag and deposit into 4cm silicon hemisphere forms. Freeze."]', '[]', 'Pastry_Module_3_Course_6.pdf', 205);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Crème Fraiche Whipped Cream', 'Custards & Creams', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 5, NULL, NULL, '[]', '[{"name":"heavy cream","amounts":[["425","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["55","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla extract","amounts":[["6","grams"]],"bakers_pct":null,"component":null},{"name":"crème fraiche","amounts":[["25","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine the cream, sucrose, vanilla extract, and crème fraiche in a mixer bowl.","Whip on medium speed until mixture holds a soft peak but will hold its shape while piping.","Use immediately or refrigerate until needed."]', '[]', 'PA_Mod_01_Instructor.pdf', 172);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Cupcake Fillings Lemon Curd', 'Custards & Creams', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 53, 'Yield 505 grams', '505 grams', '[]', '[{"name":"gelatin, sheets","amounts":[["2","each"]],"bakers_pct":null,"component":null},{"name":"lemon juice","amounts":[["125","grams"]],"bakers_pct":null,"component":null},{"name":"butter","amounts":[["125","grams"]],"bakers_pct":null,"component":null},{"name":"sugar (1)","amounts":[["65","grams"]],"bakers_pct":null,"component":null},{"name":"sugar (2)","amounts":[["65","grams"]],"bakers_pct":null,"component":null},{"name":"eggs","amounts":[["125","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Bloom gelatin sheet in cold water.","Bring to a boil juice, butter, zest and sugar (1).","Whisk together sugar (2) and eggs.","Temper hot liquid into egg mixture.","Return to heat, bring to simmer and cook until thickened, stirring constantly.","Add gelatin, mix until dissolved. Strain the mixture through a chinois. Cool over ice bath or in blast freezer."]', '[]', 'Pastry_Module_3_Course_5.pdf', 64);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Dark Chocolate Cremeux', 'Custards & Creams', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 73, NULL, NULL, '[]', '[{"name":"dark chocolate (approx. 70%), chopped","amounts":[["250","grams"]],"bakers_pct":null,"component":null},{"name":"heavy cream (35% fat)","amounts":[["400","grams"]],"bakers_pct":null,"component":null},{"name":"sorbitol","amounts":[["60","grams"]],"bakers_pct":null,"component":null},{"name":"glucose syrup","amounts":[["20","grams"]],"bakers_pct":null,"component":null},{"name":"fine sea salt","amounts":[["2","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["60","grams"]],"bakers_pct":null,"component":null},{"name":"agar","amounts":[["1.5","grams"]],"bakers_pct":null,"component":null},{"name":"gelatin sheets, bloomed","amounts":[["2","each"]],"bakers_pct":null,"component":null}]', '[["800","grams"]]', '["Place the chocolate in a mixing bowl and reserve. Combine the cream with the sorbitol, glucose, and salt; bring to a boil.","Meanwhile combine water and agar in a small sauce pan and gently bring to a boil, holding a simmer for two minutes.","Once cream has boiled, remove from heat and gradually incorporate into the chocolate. Follow with the agar mixture. Add the gelatin and transfer to oval silicon forms. Freeze."]', '[]', 'Pastry_Module_3_Course_6.pdf', 218);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Diluted Caramel for Baked Custards', 'Custards & Creams', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 16, NULL, NULL, '[]', '[{"name":"sugar","amounts":[["450","grams"]],"bakers_pct":null,"component":null},{"name":"lemon juice","amounts":[["5","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["60","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Prepare a Dry Caramel with the sugar and lemon juice, to a light amber color or as instructed. When the caramel is ready, pour in the liquid. The caramel may splatter when the liquid is added if the liquid is cold or is added too quickly.","Allow the caramel to reheat if necessary to dissolve any caramel that may have cooled or solidified. Remove from the heat and pour into molds for use. Caramel sauce: To enrich the caramel and make it into a sauce for the bread pudding, substitute 175 grams of heavy cream for the water and omit the lemon juice."]', '[]', 'PA_Mod_01_Instructor.pdf', 245);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Fruit Tart with Pastry Cream', 'Custards & Creams', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 37, NULL, NULL, '["8-inch Tart"]', '[{"name":"pate brisee","amounts":[["250","grams"]],"bakers_pct":null,"component":null},{"name":"pastry cream, flavored Framboise or Kirsch","amounts":[["250","grams"]],"bakers_pct":null,"component":null},{"name":"neutral glaze","amounts":[["125","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Line tart ring(s) or pan with the pate brisee and dock the bottom.","Blind bake until golden brown and fully set; cool completely.","Beat the framboise- or kirsch-flavored pastry cream smooth.","Spread or pipe the pastry cream evenly into the baked shell.","Arrange fresh fruit decoratively over the pastry cream.","Warm the neutral glaze and brush over the fruit to finish."]', '[]', 'Pastry_Module_2_Course_4.pdf', 40);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Goat Cheese Cream', 'Custards & Creams', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 72, NULL, NULL, '[]', '[{"name":"soft goat cheese","amounts":[["250","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose","amounts":[["125","grams"]],"bakers_pct":null,"component":null},{"name":"sheet gelatin, bloomed","amounts":[["3","each"]],"bakers_pct":null,"component":null},{"name":"whole milk","amounts":[["50","grams"]],"bakers_pct":null,"component":null},{"name":"heavy cream whipped to soft peaks","amounts":[["250","grams"]],"bakers_pct":null,"component":null}]', '[["675","grams"]]', '["In the bowl of a mixer fitted with a paddle attachment, combine the goat cheese and sucrose. Cream the mixture until smooth, light, and fluffy.","Meanwhile, gently warm the milk and add the gelatin to dissolve.","Combine goat cheese and milk mixture. Fold in whipped cream. Transfer to a container and chill until set."]', '[]', 'Pastry_Module_3_Course_6.pdf', 196);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Lemon Cream', 'Custards & Creams', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 68, 'Yield 2,526 grams', '2,526 grams', '[]', '[{"name":"sugar","amounts":[["607","grams"]],"bakers_pct":null,"component":null},{"name":"lemon zest","amounts":[["5","grams"]],"bakers_pct":null,"component":null},{"name":"eggs","amounts":[["625","grams"]],"bakers_pct":null,"component":null},{"name":"lemon juice","amounts":[["407","grams"]],"bakers_pct":null,"component":null},{"name":"butter, soft","amounts":[["882","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Whisk together sugar, eggs and lemon zest in a bowl and put aside.","Bring the lemon juice to a boil and temper the eggs and sugar mix with the hot juice.","Place the entire mixture on the stove and bring to a boil, whisking constantly.","Remove from heat, strain and cool over ice bath until mixture reaches 110","At this point, using an immersion blender, add the softened butter.","When a homogenous mixture has been attained, scale 555g of lemon cream for the mousse below. Reserve the remaining cream (covered with plastic wrap to prevent a skin from forming) and set aside for the cake assembly."]', '[]', 'Pastry_Module_3_Course_6.pdf', 95);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Lemon Cream', 'Custards & Creams', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 73, NULL, NULL, '[]', '[{"name":"whole egg","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose","amounts":[["160","grams"]],"bakers_pct":null,"component":null},{"name":"lemon juice","amounts":[["85","grams"]],"bakers_pct":null,"component":null},{"name":"gelatin sheet, hydrated","amounts":[["1","each"]],"bakers_pct":null,"component":null},{"name":"unsalted butter, softened","amounts":[["85","grams"]],"bakers_pct":null,"component":null}]', '[["430","grams"]]', '["In a heavy saucepan, whisk together eggs and sucrose, and then add the lemon juice.","On medium heat, bring mixture just to a boil, stirring constantly. Remove from heat and add the gelatin.","Allow the mixture to cool 35˚C/95˚F and emulsify the butter into the mixture. Reserve chilled."]', '[]', 'Pastry_Module_3_Course_6.pdf', 214);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Lemon Curd', 'Custards & Creams', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 20, NULL, NULL, '[]', '[{"name":"whole eggs","amounts":[["150","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"lemon juice","amounts":[["127","grams"]],"bakers_pct":null,"component":null},{"name":"butter","amounts":[["127","grams"]],"bakers_pct":null,"component":null}]', NULL, '["In a heavy saucepan, whisk together the eggs and sucrose, and then add the lemon juice.","On medium heat, bring mixture just to a boil, stirring constantly. Remove from heat.","Allow the mixture to cool 35˚C/95˚F and emulsify the butter into the base."]', '[]', 'PA_Mod_01_Instructor.pdf', 292);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Lemon Curd', 'Custards & Creams', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 36, NULL, NULL, '[]', '[{"name":"lemon zest, grated","amounts":[["25","grams"],["50","grams"]],"bakers_pct":null,"component":null},{"name":"strained lemon juice","amounts":[["185","grams"],["370","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["170","grams"],["340","grams"]],"bakers_pct":null,"component":null},{"name":"egg yolks","amounts":[["135","grams"],["270","grams"]],"bakers_pct":null,"component":null},{"name":"unsalted butter, softened","amounts":[["115","grams"],["230","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine the zest, juice and sugar in a saucepan and bring to a boil over medium heat.","Whisk the yolks in a bowl until liquid. Strain out the zest and beat 1/4 of the boiling liquid into the yolks and return the remaining liquid to a boil over low heat. Whisk the yolk mixture into the boiling liquid and continue whisking until it thickens. Allow it to come to a simmer.","Add the softened butter and stir to combine.","Pour the lemon curd into a clean container, press plastic wrap against the surface and chill it."]', '[]', 'Pastry_Module_2_Course_4.pdf', 36);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Lemon Curd', 'Custards & Creams', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 57, 'Yield 505 grams', '505 grams', '[]', '[{"name":"gelatin, sheets","amounts":[["2","each"]],"bakers_pct":null,"component":null},{"name":"lemon juice","amounts":[["125","grams"]],"bakers_pct":null,"component":null},{"name":"butter","amounts":[["125","grams"]],"bakers_pct":null,"component":null},{"name":"sugar (1)","amounts":[["65","grams"]],"bakers_pct":null,"component":null},{"name":"lemon zest","amounts":[["1","each"]],"bakers_pct":null,"component":null},{"name":"sugar (2)","amounts":[["65","grams"]],"bakers_pct":null,"component":null},{"name":"eggs","amounts":[["125","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Bloom gelatin sheet in cold water.","Bring the juice, butter, zest and sugar (1) to a boil.","Whisk together sugar (2) and eggs.","Temper egg mix with hot liquid.","Return to heat and bring to simmer. Cook until thickened, stirring constantly.","Add bloomed gelatin, mix until dissolved. Strain through a chinois and cool over ice bath or in blast freezer. Reserve for next lesson."]', '[]', 'Pastry_Module_3_Course_5.pdf', 148);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Lemon Curd', 'Custards & Creams', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 58, 'Yield 505 grams', '505 grams', '[]', '[{"name":"gelatin, sheets","amounts":[["2","each"]],"bakers_pct":null,"component":null},{"name":"lemon juice","amounts":[["125","grams"]],"bakers_pct":null,"component":null},{"name":"butter","amounts":[["125","grams"]],"bakers_pct":null,"component":null},{"name":"sugar (1)","amounts":[["65","grams"]],"bakers_pct":null,"component":null},{"name":"lemon zest","amounts":[["1","each"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["65","grams"]],"bakers_pct":null,"component":null},{"name":"eggs","amounts":[["125","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Bloom gelatin sheet in cold water.","Bring juice/, butter, zest and sugar (1) to a boil.","Whisk together sugar (2) and eggs.","Temper hot liquid into eggs.","Return to heat, bring to simmer and cook until thickened, stirring constantly.","Add bloomed gelatin, mix until dissolved and strain through a chinois. Cool over ice bath."]', '[]', 'Pastry_Module_3_Course_5.pdf', 155);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Lemon Curd', 'Custards & Creams', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 66, 'Yield 755 grams', '755 grams', '[]', '[{"name":"gelatin, sheet","amounts":[["2","each"]],"bakers_pct":null,"component":null},{"name":"lemon juice","amounts":[["187","grams"]],"bakers_pct":null,"component":null},{"name":"butter","amounts":[["187","grams"]],"bakers_pct":null,"component":null},{"name":"sugar (1)","amounts":[["97","grams"]],"bakers_pct":null,"component":null},{"name":"lemon zest","amounts":[["1","each"]],"bakers_pct":null,"component":null},{"name":"sugar (2)","amounts":[["97","grams"]],"bakers_pct":null,"component":null},{"name":"eggs","amounts":[["187","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Bloom gelatin sheet in cold water.","Bring to a boil the juice, butter, sugar (1) and zest.","Whisk together sugar (2) and eggs.","Temper egg mix with the hot liquid.","Return to heat, and cook to a simmer, stirring constantly.","Add bloomed gelatin, mix until dissolved. Strain through a chinois and cool over ice bath or on a plastic lined sheet pan."]', '[]', 'Pastry_Module_3_Course_6.pdf', 64);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Lemon Raspberry Roulade Biscuit Layer Lemon Curd Buttercream Biscuit Layer', 'Custards & Creams', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 66, '(two half sheet pans)Yield 1,016 grams', '1,016 grams', '[]', '[{"name":"whole eggs","amounts":[["360","grams"]],"bakers_pct":null,"component":null},{"name":"egg yolks","amounts":[["216","grams"]],"bakers_pct":null,"component":null},{"name":"sugar (1)","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"cake flour","amounts":[["83","grams"]],"bakers_pct":null,"component":null},{"name":"cornstarch","amounts":[["50","grams"]],"bakers_pct":null,"component":null},{"name":"egg whites","amounts":[["153","grams"]],"bakers_pct":null,"component":null},{"name":"sugar (2)","amounts":[["45","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla extract","amounts":[["9","grams"]],"bakers_pct":null,"component":null}]', NULL, '["In a KitchenAid mixing bowl combine the eggs, yolks and the sugar (1).","Warm over double boiler until sugar is dissolved and mixture is warm.","Mix until ribboned.","Sift flour and corn starch together and add to ribboned eggs Add vanilla extract and whip for 1 more minute at high speed until light and fluffy.","Separately, make an ordinary meringue from the egg whites and sugar (2) and whip to a soft peak.","Fold together both mixes until just combined.","Spread evenly onto flat parchment lined half sheet pans.","Bake in a 375 F. convection oven."]', '[]', 'Pastry_Module_3_Course_6.pdf', 63);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Lemon Strawberry Pistachio Cake Pistachio Pain De Gene Lemon Ricotta Sponge Strawberry Gelee Lemon Cream Lemon Mousse Pistachio Pain De Gene', 'Custards & Creams', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 68, '(one 1/2 sheet )Yield 797 grams', '797 grams', '[]', '[{"name":"browned butter, warm","amounts":[["90","grams"]],"bakers_pct":null,"component":null},{"name":"almond paste","amounts":[["240","grams"]],"bakers_pct":null,"component":null},{"name":"pistachio paste","amounts":[["40","grams"]],"bakers_pct":null,"component":null},{"name":"eggs","amounts":[["50","grams"]],"bakers_pct":null,"component":null},{"name":"eggs","amounts":[["300","grams"]],"bakers_pct":null,"component":null},{"name":"cake flour","amounts":[["55","grams"]],"bakers_pct":null,"component":null},{"name":"baking powder","amounts":[["1","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["1","grams"]],"bakers_pct":null,"component":null},{"name":"pistachios, finely chopped","amounts":[["20","grams"]],"bakers_pct":null,"component":null}]', NULL, '["In a small sauce pan, brown the butter over medium heat making sure not to burn the butter.","In a KitchenAid bowl with the paddle attachment, soften the almond and pistachio paste with 50 grams of egg until smooth, making sure to scrape down often.","Gradually add the second eggs and whip the mixture to ribbon stage.","Meanwhile, sift together the flour, baking powder and salt and set aside.","Take a small portion of the egg/nut paste mixture and whisk into the warmed brown butter.","Fold the sifted dry ingredients into remaining egg mixture.","Continue to mix while slowly adding the brown butter mixture.","Stir in finely chopped pistachios.","Spread onto a flat parchment lined sheet pan.","Bake 10-15 minutes at 350 F."]', '["Utilize the Pain de Gene mixing method"]', 'Pastry_Module_3_Course_6.pdf', 91);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Lightened Pastry Cream', 'Custards & Creams', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 21, NULL, NULL, '["LARGE BATCH","MEDIUM BATCH","SMALL BATCH"]', '[{"name":"heavy cream","amounts":[["1900","grams"],["950","grams"],["475","grams"]],"bakers_pct":null,"component":null},{"name":"gelatin","amounts":[["18","sheets"],["9","sheets"]],"bakers_pct":null,"component":null},{"name":"Pastry Cream","amounts":[["3600","grams"],["1800","grams"],["900","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Whip heavy cream until soft peak.","Soak gelatin in cold water until softened. Squeeze gelatin to extract excess water. Melt gelatin in a bowl over gently simmering water.","Beat pastry cream with a rubber spatula to loosen slightly.","Remove some of pastry cream and temper into gelatin, make sure there are no lumps.","Add tempered gelatin mixture into the remaining pastry cream, whisking constantly. Fold in heavy cream by hand working quickly.","Cover surface with plastic wrap and refrigerate for longer storage."]', '[]', 'PA_Mod_01_Instructor.pdf', 338);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Lime Cream', 'Custards & Creams', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 73, NULL, NULL, '[]', '[{"name":"whole egg","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose","amounts":[["160","grams"]],"bakers_pct":null,"component":null},{"name":"lime juice","amounts":[["85","grams"]],"bakers_pct":null,"component":null},{"name":"butter, softened","amounts":[["85","grams"]],"bakers_pct":null,"component":null}]', '[["435","grams"]]', '["In a heavy saucepan, whisk together eggs and sucrose, and then add the lemon juice.","On medium heat, bring mixture just to a boil, stirring constantly. Remove from heat and add the gelatin.","Allow the mixture to cool 35˚C/95˚F and emulsify the butter into the mixture. Reserve chilled."]', '[]', 'Pastry_Module_3_Course_6.pdf', 218);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Lime Curd', 'Custards & Creams', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 53, 'Yield 505 grams', '505 grams', '[]', '[{"name":"gelatin, sheets","amounts":[["1","each"]],"bakers_pct":null,"component":null},{"name":"lime juice","amounts":[["125","grams"]],"bakers_pct":null,"component":null},{"name":"butter","amounts":[["125","grams"]],"bakers_pct":null,"component":null},{"name":"sugar (1)","amounts":[["65","grams"]],"bakers_pct":null,"component":null},{"name":"sugar (2)","amounts":[["65","grams"]],"bakers_pct":null,"component":null},{"name":"eggs","amounts":[["125","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Bloom gelatin sheet in cold water.","Bring to a boil juice, butter, zest and sugar (1).","Whisk together sugar (2) and eggs.","Temper hot liquid into egg mixture.","Return to heat, bring to simmer and cook until thickened, stirring constantly.","Add gelatin, mix until dissolved. Strain the mixture through a chinois. Cool over ice bath or in blast freezer."]', '[]', 'Pastry_Module_3_Course_5.pdf', 66);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Maple Panna Cotta', 'Custards & Creams', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 68, '(approximately 17 red oval flexi molds) Yield 1,110 grams', '1,110 grams', '[]', '[{"name":"gelatin sheets","amounts":[["9","sheets"]],"bakers_pct":null,"component":null},{"name":"coconut milk","amounts":[["600","grams"]],"bakers_pct":null,"component":null},{"name":"maple syrup","amounts":[["230","grams"]],"bakers_pct":null,"component":null},{"name":"bourbon","amounts":[["50","grams"]],"bakers_pct":null,"component":null},{"name":"semi-sweet chocolate","amounts":[["230","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Bloom gelatin and set aside.","Heat coconut milk, maple syrup and bourbon until just boiling. Turn off heat and add bloomed gelatin, pour mixture over the chocolate to melt. Whisk until completely smooth.","Pour into flexi molds ½ way, top with 1 oval of dacquoise.","Top with remaining panna cotta and top with pecan biscuit.","Freeze in blast freezer or place in the refrigerator overnight."]', '[]', 'Pastry_Module_3_Course_6.pdf', 100);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Maple Pecan Creme Brulee', 'Custards & Creams', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 16, NULL, NULL, '[]', '[{"name":"heavy cream","amounts":[["475","grams"]],"bakers_pct":null,"component":null},{"name":"maple syrup","amounts":[["60","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["85","grams"]],"bakers_pct":null,"component":null},{"name":"yolks","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"pecans (chopped)","amounts":[["80","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine cream, maple syrup, sugar and vanilla bean in a pan and bring to a simmer. Whisk yolks in a bowl and temper with hot mixture. Strain through a chinoise or fine strainer and skim foam from surface if necessary.","Scatter the pecans on the bottom of the crème brulee dishes","Pour the custard mixture into crème brulee dishes. Bake in a water bath at 350 degrees until set. Cool and place in freezer about 1 hour or in refrigerator overnight."]', '["For the next lesson:"]', 'PA_Mod_01_Instructor.pdf', 243);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Milk Chocolate Panna Cotta', 'Custards & Creams', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 5, NULL, NULL, '[]', '[{"name":"whole milk (1)","amounts":[["50","grams"]],"bakers_pct":null,"component":null},{"name":"gelatin powder","amounts":[["6","grams"]],"bakers_pct":null,"component":null},{"name":"whole milk (2)","amounts":[["250","grams"]],"bakers_pct":null,"component":null},{"name":"heavy cream (35% fat)","amounts":[["300","grams"]],"bakers_pct":null,"component":null},{"name":"milk chocolate, chopped","amounts":[["225","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Place the 50g of the milk into a bowl and sprinkle the gelatin powder onto the surface making sure it gets hydrated. Allow it to stand for several minutes for the gelatin to bloom and soften.","Combine the cream, the second milk, and vanilla bean; bring to a boil. Remove from heat and infuse for 5 minutes.","Remove the vanilla bean from the cream mixture and return to a boil. Remove from heat and pour over the chopped milk chocolate; combine with the bloomed gelatin.","Homogenize well with an immersion blender.","Strain and deposit the mixture approximately two thirds high into the prepared containers and refrigerate until set."]', '[]', 'PA_Mod_01_Instructor.pdf', 167);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Mixture for Baked Custards', 'Custards & Creams', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 16, NULL, NULL, '[]', '[{"name":"half and half","amounts":[["1950","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["450","grams"]],"bakers_pct":null,"component":null},{"name":"large eggs","amounts":[["400","grams"]],"bakers_pct":null,"component":null},{"name":"egg yolks","amounts":[["270","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla extract","amounts":[["25","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Bring half and half, and sugar to a boil.","Whisk eggs and yolks until liquid. Whisk in boiling milk in a thin stream. Strain into a clean bowl and skim foam from surface. Stir in vanilla extract.","Reserve and use the custard mixture for the crème renversee and bread pudding recipes."]', '[]', 'PA_Mod_01_Instructor.pdf', 244);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Panna Cotta', 'Custards & Creams', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 5, NULL, NULL, '[]', '[{"name":"whole milk (1)","amounts":[["50","grams"]],"bakers_pct":null,"component":null},{"name":"gelatin powder","amounts":[["6","grams"]],"bakers_pct":null,"component":null},{"name":"whole milk (2)","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"heavy cream (35% fat)","amounts":[["510","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["100","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Place the 50g of the milk into a bowl and sprinkle the gelatin powder onto the surface making sure it gets hydrated. Allow it to stand for several minutes for the gelatin to bloom and soften.","Combine the cream, the second milk, sugar, vanilla bean, and lemon zest; bring to a boil. Remove from heat and infuse for 5 minutes.","Remove the vanilla bean from the cream mixture and return to a boil. Remove from heat and combine with the bloomed gelatin.","Homogenize well with an immersion blender.","Strain and deposit the mixture approximately two thirds high into the prepared containers and refrigerate until set."]', '[]', 'PA_Mod_01_Instructor.pdf', 168);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Passion Fruit Curd', 'Custards & Creams', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 53, 'Yield 505 grams', '505 grams', '[]', '[{"name":"gelatin, sheets","amounts":[["2.5","each"]],"bakers_pct":null,"component":null},{"name":"passion fruit puree","amounts":[["125","grams"]],"bakers_pct":null,"component":null},{"name":"butter","amounts":[["125","grams"]],"bakers_pct":null,"component":null},{"name":"sugar (1)","amounts":[["65","grams"]],"bakers_pct":null,"component":null},{"name":"sugar (2)","amounts":[["65","grams"]],"bakers_pct":null,"component":null},{"name":"eggs","amounts":[["125","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Bloom gelatin sheet in cold water.","Bring to a boil juice, butter, zest and sugar (1).","Whisk together sugar (2) and eggs.","Temper hot liquid into egg mixture.","Return to heat, bring to simmer and cook until thickened, stirring constantly.","Add gelatin, mix until dissolved. Strain the mixture through a chinois. Cool over ice bath or in blast freezer."]', '[]', 'Pastry_Module_3_Course_5.pdf', 65);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Pastry Cream', 'Custards & Creams', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 36, NULL, NULL, '["Large Batch","Medium Batch","Small Batch"]', '[{"name":"milk","amounts":[["1960","grams"],["980","grams"],["490","grams"]],"bakers_pct":null,"component":null},{"name":"cornstarch","amounts":[["200","grams"],["100","grams"],["50","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["452","grams"],["226","grams"],["113","grams"]],"bakers_pct":null,"component":null},{"name":"eggs","amounts":[["200","grams"],["100","grams"],["50","grams"]],"bakers_pct":null,"component":null},{"name":"yolks","amounts":[["280","grams"],["140","grams"],["70","grams"]],"bakers_pct":null,"component":null},{"name":"butter","amounts":[["220","grams"],["110","grams"],["55","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla","amounts":[["24","grams"],["12","grams"],["6","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Dissolve cornstarch in 1/8 of the milk.","Combine the remaining milk with the sugar in a rondeau or saucepan; bring to a boil.","Whisk whole eggs, then the yolks into cornstarch mixture.","Pour 1/3 of the boiling milk into the egg mixture, whisking. Return the remaining milk mixture to a boil.","Whisk the egg mixture into the boiling milk, whisking until the pastry cream thickens and returns to a boil. Boil, whisking, about 1 minute.","Remove from heat and beat in the butter and vanilla.","Pour the cream into a stainless-steel pan. Press plastic wrap directly on the surface, and poke holes to vent. Chill immediately."]', '[]', 'Pastry_Module_2_Course_4.pdf', 35);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Pastry Cream', 'Custards & Creams', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 54, 'Yield 901 grams', '901 grams', '[]', '[{"name":"cornstarch","amounts":[["50","grams"]],"bakers_pct":null,"component":null},{"name":"milk","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["60","grams"]],"bakers_pct":null,"component":null},{"name":"eggs","amounts":[["55","grams"]],"bakers_pct":null,"component":null},{"name":"yolks","amounts":[["75","grams"]],"bakers_pct":null,"component":null},{"name":"milk","amounts":[["430","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["60","grams"]],"bakers_pct":null,"component":null},{"name":"butter","amounts":[["60","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla extract","amounts":[["6","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Dissolve cornstarch with the first measurement of milk. Add the sugar, eggs and yolks, and whisk to combine.","Combine the second milk with the second sugar in saucepan; bring to a boil.","Temper the corn starch mixture with some of the boiling milk mixture.","Return the remaining milk mixture to a boil. Whisk the corn starch mixture into the boiling milk. Whisking until the pastry cream thickens and returns to a boil, stirring constantly","Boil the pastry cream and continue whisking for 1 minute or as instructed. Remove from heat and whisk in the butter and vanilla. Transfer to a bowl and cool over ice. Or alternatively, spread thinly on a plastic-lined sheet pan. Press plastic wrap directly on the surface. Chill immediately. Variations: Chocolate: Add 175 grams of semisweet chocolate when adding butter. Coffee: Add 30 grams of Trablit extract (or to taste), or make a paste of water and instant espresso powder and add when adding butter. Praline or Nutella: Add 120 grams of praline or Nutella paste and 50 grams of chopped toasted hazelnuts (optional) when adding butter."]', '[]', 'Pastry_Module_3_Course_5.pdf', 72);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Pastry Cream', 'Custards & Creams', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 60, 'Yield 901 grams', '901 grams', '[]', '[{"name":"cornstarch","amounts":[["50","grams"]],"bakers_pct":null,"component":null},{"name":"milk","amounts":[["530","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["125","grams"]],"bakers_pct":null,"component":null},{"name":"eggs","amounts":[["55","grams"]],"bakers_pct":null,"component":null},{"name":"yolks","amounts":[["75","grams"]],"bakers_pct":null,"component":null},{"name":"butter","amounts":[["60","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla","amounts":[["6","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Dissolve cornstarch in some of the milk. Add approximately ½ of the sugar, all of the eggs and yolks, and whisk to combine.","Combine the remaining milk with the other half of the sugar in saucepan; bring to a boil.","Temper the corn starch mixture with some of the boiling milk mixture.","Return the remaining milk mixture to a boil. Whisk the corn starch mixture into the boiling milk, whisking constantly until the pastry cream thickens and returns to a boil.","Boil the pastry cream and continue whisking for 1 minute or as instructed. Remove from heat and whisk in the butter and vanilla. Transfer to a bowl and cool over ice. Or alternatively, spread thinly on a plastic-lined sheet pan. Press plastic wrap directly on the surface. Chill immediately."]', '[]', 'Pastry_Module_3_Course_5.pdf', 169);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Pastry Cream', 'Custards & Creams', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 67, 'Yield: 839 grams', '839 grams', '[]', '[{"name":"cornstarch","amounts":[["40","grams"]],"bakers_pct":null,"component":null},{"name":"milk","amounts":[["500","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["120","grams"]],"bakers_pct":null,"component":null},{"name":"eggs","amounts":[["50","grams"]],"bakers_pct":null,"component":null},{"name":"yolks","amounts":[["72","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla bean","amounts":[["1","each"]],"bakers_pct":null,"component":null},{"name":"butter","amounts":[["57","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine the cornstarch with approximately ½ of the sugar and ½ of the milk. Whisk to remove lumps. Add all of the eggs, yolks and vanilla and whisk to combine.","Combine the remaining milk with the remaining sugar in saucepan; bring to a boil.","Temper the corn starch mixture with some of the boiling milk mixture.","Return the remaining milk mixture to a boil. Whisk the corn starch mixture into the boiling milk, whisking constantly until the pastry cream thickens and returns to a boil.","Boil the pastry cream and continue whisking for 1 minute or as instructed. Remove from heat and whisk in the butter. Transfer to a bowl and cool over ice. Or spread thinly on a plastic lined sheet pan and press plastic wrap directly on the surface. Chill immediately."]', '[]', 'Pastry_Module_3_Course_6.pdf', 73);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Pastry Cream Large Medium Small Batch', 'Custards & Creams', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 21, NULL, NULL, '[]', '[{"name":"cornstarch 200 100","amounts":[["50","grams"]],"bakers_pct":null,"component":null},{"name":"milk 2,120 1,060","amounts":[["530","grams"]],"bakers_pct":null,"component":null},{"name":"sugar 500 250","amounts":[["125","grams"]],"bakers_pct":null,"component":null},{"name":"eggs 220 110","amounts":[["55","grams"]],"bakers_pct":null,"component":null},{"name":"yolks 300 150","amounts":[["75","grams"]],"bakers_pct":null,"component":null},{"name":"butter 240 120","amounts":[["60","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla 24 12","amounts":[["6","grams"]],"bakers_pct":null,"component":null},{"name":"Total 3,604 1,802","amounts":[["901","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Dissolve cornstarch in some of the milk. Add approximately ½ of the sugar, all of the eggs and yolks, and whisk to combine.","Combine the remaining milk with the other half of the sugar in saucepan; bring to a boil.","Temper the corn starch mixture with some of the boiling milk.","Return the remaining milk mixture to a boil. Whisk the corn starch mixture into the boiling milk, whisking until the pastry cream thickens and returns to a boil.","Boil the pastry cream and continue whisking for 1 minute or as instructed. Remove from heat and whisk in the butter and vanilla. Transfer to a bowl and cool over ice. Or spread thinly on a plastic lined sheet pan. Press plastic wrap directly on the surface. Chill immediately.","Flavoring options follow on the next page."]', '[]', 'PA_Mod_01_Instructor.pdf', 336);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Pineapple Coconut Anglaise', 'Custards & Creams', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 20, NULL, NULL, '[]', '[{"name":"coconut purée","amounts":[["200","grams"]],"bakers_pct":null,"component":null},{"name":"pineapple purée","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"heavy cream (36% fat)","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"dark rum","amounts":[["25","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose","amounts":[["70","grams"]],"bakers_pct":null,"component":null},{"name":"egg yolk","amounts":[["60","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Into a heavy saucepan, combine the coconut purée, pineapple purée, cream, and rum. Bring to a boil over medium heat. Meanwhile whisk together sucrose and egg yolks.","Remove from heat and carefully temper the egg yolks.","Continue to cook on low heat to 85˚C/185˚F. Remove from heat and strain through a chinois. Chill over an ice water bath."]', '[]', 'PA_Mod_01_Instructor.pdf', 293);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Praline Mousseline', 'Custards & Creams', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 71, NULL, NULL, '[]', '[{"name":"unsalted butter, softened","amounts":[["240","grams"]],"bakers_pct":null,"component":null},{"name":"hazelnut praline paste","amounts":[["180","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla pastry cream","amounts":[["450","grams"]],"bakers_pct":null,"component":null}]', '[["870","grams"]]', '["Combine the softened butter and praline paste in a mixer bowl and beat until thoroughly combined. Slowly add the pastry cream, scraping down the bowl to ensure the mixture is homogenous.","Transfer to a pastry bag fitted with a medium plain tip and pipe into the baked pâte croustade shells. Finish each tart with candied orange peel, caramelized hazelnuts, and chocolate garnish."]', '[]', 'Pastry_Module_3_Course_6.pdf', 148);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Raspberry Cremeux', 'Custards & Creams', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 71, NULL, NULL, '[]', '[{"name":"whole milk","amounts":[["75","grams"]],"bakers_pct":null,"component":null},{"name":"glucose syrup","amounts":[["40","grams"]],"bakers_pct":null,"component":null},{"name":"white chocolate, chopped","amounts":[["75","grams"]],"bakers_pct":null,"component":null},{"name":"gelatin sheets, bloomed","amounts":[["3","each"]],"bakers_pct":null,"component":null},{"name":"raspberry purée","amounts":[["300","grams"]],"bakers_pct":null,"component":null},{"name":"heavy cream (35% fat)","amounts":[["75","grams"]],"bakers_pct":null,"component":null}]', '[["950","grams"]]', '["Combine the milk and glucose in a sauce pan and bring to a boil. Remove from heat and stir in the bloomed gelatin.","Whisk in the white chocolate and raspberry purée.","Add the cream and emulsify thoroughly with an immersion blender. Deposit onto already set gelee and chill to fully set."]', '[]', 'Pastry_Module_3_Course_6.pdf', 154);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Raspberry Cremeux', 'Custards & Creams', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 72, NULL, NULL, '[]', '[{"name":"whole milk","amounts":[["75","grams"]],"bakers_pct":null,"component":null},{"name":"glucose syrup","amounts":[["40","grams"]],"bakers_pct":null,"component":null},{"name":"white chocolate, chopped","amounts":[["75","grams"]],"bakers_pct":null,"component":null},{"name":"gelatin sheets, bloomed","amounts":[["3","each"]],"bakers_pct":null,"component":null},{"name":"raspberry purée","amounts":[["300","grams"]],"bakers_pct":null,"component":null},{"name":"heavy cream","amounts":[["75","grams"]],"bakers_pct":null,"component":null}]', '[["950","grams"]]', '["Combine the milk and glucose in a sauce pan and bring to a boil. Remove from heat and stir in the bloomed gelatin.","Whisk in the white chocolate and raspberry purée.","Add the cream and emulsify thoroughly with an immersion blender. Deposit onto already set gelee and chill to fully set."]', '[]', 'Pastry_Module_3_Course_6.pdf', 188);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('STRAWBERY FRAISIER (two GENOISE PASTRY CREAM MOUSSELINE SIMPLE SYRUP PLAIN SPONGE CAKE (GENOISE)', 'Custards & Creams', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 67, '(four 6” round cakes)Yield 635 grams', '635 grams', '["6” rounds"]', '[{"name":"whole eggs","amounts":[["300","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["190","grams"]],"bakers_pct":null,"component":null},{"name":"AP flour","amounts":[["120","grams"]],"bakers_pct":null,"component":null},{"name":"butter, melted and cooled","amounts":[["25","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Place the eggs, sugar and the salt in bowl of an electric mixer, and whisk well. Place bowl on a pan of simmering water and heat stirring constantly with hand whip until mixture is warm and the sugar is dissolved. Do not overheat. Remove from heat, place on mixer and whip until cool and increased in volume until the mixture is very thick. (It should hold its shape once you draw your finger across the batter).","While the mixture is whipping, sift the flour. Remove egg mixture from mixer and sift flour over the egg mixture, efficiently and quickly fold with a rubber spatula making sure to scrape the bottom. Finish by folding in cooled melted butter just until incorporated. (Do not over fold to prevent the cake from rising properly) Bake at 350 ºF."]', '["Utilize the Genoise mixing method."]', 'Pastry_Module_3_Course_6.pdf', 72);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Sweetened Whipped Cream', 'Custards & Creams', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 22, NULL, NULL, '[]', '[{"name":"heavy cream","amounts":[["900","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["90","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Whip some of the heavy cream with all of the sugar until thickened.","Add the remaining heavy cream and whip to stiff peak.","Keep refrigerated until needed."]', '[]', 'PA_Mod_01_Instructor.pdf', 344);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Tres Leches Cake Tres Leches Cake Layer Tres Leches Syrup Whipped Cream Tres Leches Cake Layer', 'Custards & Creams', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 65, '(two 10” cake pans)Yield 1250.5 grams', '1250.5 grams', '[]', '[{"name":"butter","amounts":[["200","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["360","grams"]],"bakers_pct":null,"component":null},{"name":"eggs","amounts":[["280","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla extract","amounts":[["7","grams"]],"bakers_pct":null,"component":null},{"name":"AP flour","amounts":[["395","grams"]],"bakers_pct":null,"component":null},{"name":"baking powder","amounts":[["8.5","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Cream the butter and sugar.","Gradually add the eggs and vanilla, and emulsify well.","Add the dry ingredients until just combined."]', '["Utilize the Creaming method"]', 'Pastry_Module_3_Course_6.pdf', 46);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Vanilla Custard', 'Custards & Creams', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 71, NULL, NULL, '[]', '[{"name":"corn starch","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"whole milk (1)","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose (1)","amounts":[["125","grams"]],"bakers_pct":null,"component":null},{"name":"whole eggs","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"egg yolks","amounts":[["160","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["2","grams"]],"bakers_pct":null,"component":null},{"name":"whole milk (2)","amounts":[["990","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose (2)","amounts":[["125","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla bean, split and scraped","amounts":[["2","each"]],"bakers_pct":null,"component":null},{"name":"butter, unsalted","amounts":[["120","grams"]],"bakers_pct":null,"component":null}]', '[["1823","grams"]]', '["Whisk the corn starch into the first measurement of milk (1) in a medium-sized mixing bowl, followed by the first measurement of sucrose (1), the whole eggs, egg yolks and salt.","Combine the remaining milk (2), sucrose (2), and vanilla in a sauce pan; bring to a boil.","Remove from heat and temper the warm milk mixture into the corn starch mixture. Return to heat and cook over medium heat, whisking constantly, just to a boil. Remove from heat (remove the scraped vanilla pod) and whisk in the butter; transfer to a shallow container, cover with plastic film, and chill rapidly."]', '[]', 'Pastry_Module_3_Course_6.pdf', 141);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Vanilla Mousseline', 'Custards & Creams', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 68, '(12 flexi mold domes) Yields 952 grams', '952 grams', '[]', '[{"name":"gelatin","amounts":[["2","sheets"]],"bakers_pct":null,"component":null},{"name":"heavy cream","amounts":[["250","grams"]],"bakers_pct":null,"component":null},{"name":"milk","amounts":[["400","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla beans, scraped","amounts":[["2","each"]],"bakers_pct":null,"component":null},{"name":"egg yolks","amounts":[["60","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["110","each"]],"bakers_pct":null,"component":null},{"name":"cornstarch","amounts":[["40","grams"]],"bakers_pct":null,"component":null},{"name":"butter","amounts":[["90","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Bloom gelatin sheets in cold water and set aside.","Whip heavy cream to soft peak, reserve in refrigerator.","Make a pastry cream.","Add bloomed gelatin and butter to finished pastry cream off the fire.","Cool to room temperature then fold in whipped cream. Assembly:","Pipe layer of mousseline in mold, spreading evenly around sides.","Insert frozen berry coulis dome.","Top with thin layer of mousse and lime dacquoise and freeze."]', '[]', 'Pastry_Module_3_Course_6.pdf', 111);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Vanilla Pastry Cream', 'Custards & Creams', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 71, NULL, NULL, '[]', '[{"name":"corn starch","amounts":[["50","grams"]],"bakers_pct":null,"component":null},{"name":"whole milk (1)","amounts":[["50","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose (1)","amounts":[["62","grams"]],"bakers_pct":null,"component":null},{"name":"whole eggs","amounts":[["50","grams"]],"bakers_pct":null,"component":null},{"name":"egg yolks","amounts":[["80","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["1","gram"]],"bakers_pct":null,"component":null},{"name":"whole milk (2)","amounts":[["495","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose (2)","amounts":[["62","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla bean, split and scraped","amounts":[["1","each"]],"bakers_pct":null,"component":null},{"name":"butter, unsalted","amounts":[["60","grams"]],"bakers_pct":null,"component":null}]', '[["910","grams"]]', '["Whisk the corn starch into the first measurement of milk (1) in a medium-sized mixing bowl, followed by the first measurement of sucrose (1), the whole eggs, egg yolks and salt.","Combine the remaining milk (2), sucrose (2), and vanilla in a sauce pan; bring to a boil.","Remove from heat and temper the warm milk mixture into the corn starch mixture. Return to heat and cook over medium heat, whisking constantly, just to a boil. Remove from heat (remove and the scraped vanilla pod) and whisk in the butter; transfer to a shallow container, cover with plastic film, and chill rapidly."]', '[]', 'Pastry_Module_3_Course_6.pdf', 147);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Whipped Cream', 'Custards & Creams', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 46, NULL, NULL, '[]', '[{"name":"heavy cream","amounts":[["240","grams"]],"bakers_pct":null,"component":null},{"name":"crème frâiche","amounts":[["12","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["5","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla extract","amounts":[["2","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine the heavy cream, crème fraîche, sugar, and vanilla extract in a chilled bowl.","Whip on medium-high speed to soft-to-medium peaks.","Use immediately or refrigerate until needed."]', '[]', 'Pastry_Module_2_Course_4.pdf', 125);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Whipped Cream', 'Custards & Creams', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 60, 'Yield 480 grams', '480 grams', '[]', '[{"name":"heavy cream","amounts":[["425","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["55","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine the cream and sugar in a mixer bowl.","Whip until stiff peak.","Use immediately or refrigerate."]', '[]', 'Pastry_Module_3_Course_5.pdf', 170);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Whipped Cream', 'Custards & Creams', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 65, 'cakes)Yield 820 grams', '820 grams', '["12” cake"]', '[{"name":"heavy cream","amounts":[["750","grams"]],"bakers_pct":null,"component":null},{"name":"10X","amounts":[["70","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Sift the 10X sugar into the heavy cream.","Whip to soft peaks for folding or stiff peaks for piping, as the application requires.","Use immediately or refrigerate until needed."]', '[]', 'Pastry_Module_3_Course_6.pdf', 47);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Yogurt Panna Cotta Yogurt Panna Cotta', 'Custards & Creams', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 71, NULL, NULL, '[]', '[{"name":"heavy cream","amounts":[["350","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose","amounts":[["120","grams"]],"bakers_pct":null,"component":null},{"name":"orange zest","amounts":[["1","each"]],"bakers_pct":null,"component":null},{"name":"gelatin sheets, bloomed","amounts":[["4","each"]],"bakers_pct":null,"component":null},{"name":"whole milk Greek yogurt","amounts":[["240","grams"]],"bakers_pct":null,"component":null}]', '[["710","grams"]]', '["Combine the cream, sucrose, and zest in a sauce pan, gently warming over medium heat.","Remove from heat and add the gelatin, stirring to dissolve. Temper into yogurt and strain through a chinois or fine mesh sieve. Transfer to silicon molds and place into a freezer. Allow at least two hours to freeze."]', '[]', 'Pastry_Module_3_Course_6.pdf', 137);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Almond Frangipane', 'Doughs & Crusts', 'Module 2', 'Course 3', 'Breads & Yeast Doughs', 35, NULL, NULL, '[]', '[{"name":"almond paste","amounts":[["455","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["285","grams"]],"bakers_pct":null,"component":null},{"name":"butter, softened","amounts":[["455","grams"]],"bakers_pct":null,"component":null},{"name":"eggs (about 9)","amounts":[["425","grams"]],"bakers_pct":null,"component":null},{"name":"lemon zest","amounts":[["2","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla","amounts":[["13","grams"]],"bakers_pct":null,"component":null},{"name":"all-purpose flour","amounts":[["140","grams"]],"bakers_pct":null,"component":null},{"name":"baking powder","amounts":[["4","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine almond paste, sugar and softened butter in mixer with the paddle attachment. Beat on medium speed until smooth.","Beat in the eggs, a few at a time. Mix until smooth.","Add the lemon zest and vanilla, stir to combine.","Combine flour and baking powder and add to the mixing bowl beating on low speed, just until the flour is absorbed."]', '[]', 'Pastry_Module_2_Course_3.pdf', 136);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Almond Frangipane', 'Doughs & Crusts', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 44, NULL, NULL, '[]', '[{"name":"almond paste","amounts":[["455","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["285","grams"]],"bakers_pct":null,"component":null},{"name":"eggs (9)","amounts":[["450","grams"]],"bakers_pct":null,"component":null},{"name":"butter, softened","amounts":[["455","grams"]],"bakers_pct":null,"component":null},{"name":"lemon zest","amounts":[["2","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla","amounts":[["2","grams"]],"bakers_pct":null,"component":null},{"name":"all purpose flour","amounts":[["140","grams"]],"bakers_pct":null,"component":null},{"name":"baking powder","amounts":[["4","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine almond paste, sugar and 1 egg in mixer.","Beat with paddle on medium speed until smooth.","Beat in butter, lemon zest and vanilla, mixing until smooth.","Beat in the eggs, one at a time, until very smooth, scraping bowl and paddle several times.","Combine flour and baking powder.","On low speed, stir in flour until just absorbed."]', '[]', 'Pastry_Module_2_Course_4.pdf', 115);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Almond Pate Sucree', 'Doughs & Crusts', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 38, NULL, NULL, '[]', '[{"name":"butter","amounts":[["375","grams"]],"bakers_pct":null,"component":null},{"name":"confectioner''s sugar","amounts":[["130","grams"]],"bakers_pct":null,"component":null},{"name":"all purpose flour","amounts":[["520","grams"]],"bakers_pct":null,"component":null},{"name":"almond flour","amounts":[["130","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla extract","amounts":[["6","grams"]],"bakers_pct":null,"component":null},{"name":"eggs(2)","amounts":[["100","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Prepare using Creaming Dough Mixing Method. Chill until ready to use.","Beat butter and sugar in the bowl of a kitchen aid fitted with a paddle attachment.","Add flours, vanilla and eggs. Mix until just combined, making sure to scrape from the bottom.","Chill before using. Hazelnut flour can be substituted for almond flour Roll thinly for best results Fragile when cooked."]', '["Note:"]', 'Pastry_Module_2_Course_4.pdf', 46);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Choux Sablee', 'Doughs & Crusts', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 73, NULL, NULL, '[]', '[{"name":"butter, softened","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose","amounts":[["125","grams"]],"bakers_pct":null,"component":null},{"name":"AP flour","amounts":[["125","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["2","grams"]],"bakers_pct":null,"component":null}]', '[["352","grams"]]', '["Place all ingredients in the bowl of a stand mixer fitted with paddle; mix on low speed just until combined, adding a small amount of water if necessary.","Roll the dough between two sheets of acetate or parchment and cut to approximately 30cm by 40cm. Freeze. Cut into 5cm discs."]', '[]', 'Pastry_Module_3_Course_6.pdf', 206);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Cocoa Pate Sucree', 'Doughs & Crusts', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 73, NULL, NULL, '[]', '[{"name":"butter, softened","amounts":[["120","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["2","grams"]],"bakers_pct":null,"component":null},{"name":"10X sugar","amounts":[["90","grams"]],"bakers_pct":null,"component":null},{"name":"almond flour","amounts":[["30","grams"]],"bakers_pct":null,"component":null},{"name":"whole egg","amounts":[["50","grams"]],"bakers_pct":null,"component":null},{"name":"AP flour (1)","amounts":[["40","grams"]],"bakers_pct":null,"component":null},{"name":"AP flour (2)","amounts":[["155","grams"]],"bakers_pct":null,"component":null},{"name":"cocoa powder","amounts":[["40","grams"]],"bakers_pct":null,"component":null}]', '[["527","grams"]]', '["Combine and blend the butter, salt, 10X sugar, and almond flour in a food processor.","Add the whole egg and first measurement of flour (1); process just until incorporated.","Add the remaining flour (2) and cocoa powder; process just until incorporated. Wrap the dough and chill."]', '[]', 'Pastry_Module_3_Course_6.pdf', 210);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Cocoa Sablee', 'Doughs & Crusts', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 71, NULL, NULL, '[]', '[{"name":"AP flour","amounts":[["90","grams"]],"bakers_pct":null,"component":null},{"name":"cocoa powder","amounts":[["18","grams"]],"bakers_pct":null,"component":null},{"name":"baking soda","amounts":[["1","grams"]],"bakers_pct":null,"component":null},{"name":"fine sea salt","amounts":[["2","grams"]],"bakers_pct":null,"component":null},{"name":"light brown sugar","amounts":[["55","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose","amounts":[["25","grams"]],"bakers_pct":null,"component":null},{"name":"butter, softened","amounts":[["70","grams"]],"bakers_pct":null,"component":null}]', '[["261","grams"]]', '["Sift the flour, cocoa and baking soda and reserve. Place the butter in the bowl of a mixer fitted with a paddle attachment and beat at medium speed until the butter is soft and creamy. Add the sugars and salt and beat for another 1 or 2 minutes. Reduce the speed to low and slowly add the sifted dry ingredients. Mix until the dry ingredients are just incorporated.","Transfer the dough to a clean smooth work surface, divide in half and, working with one half at a time, shape the dough into a cylinder that is roughly 1 ½ inches in diameter. Wrap the cylinders in plastic wrap and chill them for at least 1 hour.","Unwrap the dough cylinders and slice the dough into individual cookies about ½ inch thick. Divide the cookies onto parchment or Silpat-lined baking sheets, allowing ample space between them. Bake at 160˚/320°F for 12-15 minutes. Remove from oven and cool completely before removing from baking sheet.","Use as cookies and also crumbled into pieces as garnish."]', '[]', 'Pastry_Module_3_Course_6.pdf', 159);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Crumb Topping', 'Doughs & Crusts', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 39, NULL, NULL, '["Small Batch","Large Batch"]', '[{"name":"butter","amounts":[["225","grams"],["450","grams"]],"bakers_pct":null,"component":null},{"name":"light brown sugar","amounts":[["115","grams"],["230","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["115","grams"],["230","grams"]],"bakers_pct":null,"component":null},{"name":"cinnamon","amounts":[["2","grams"],["4","grams"]],"bakers_pct":null,"component":null},{"name":"flour","amounts":[["340","grams"],["680","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Melt butter and cool.","Combine the remaining ingredients and stir butter in evenly.","Allow it to cool for 5 minutes.","Break into crumbs by hand."]', '[]', 'Pastry_Module_2_Course_4.pdf', 54);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Crumb Topping', 'Doughs & Crusts', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 40, NULL, NULL, '["small batch","large batch"]', '[{"name":"butter","amounts":[["450","grams"]],"bakers_pct":null,"component":null},{"name":"light brown sugar","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"cinnamon","amounts":[["3","grams"]],"bakers_pct":null,"component":null},{"name":"all-purpose flour","amounts":[["675","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Melt butter and cool.","Combine the remaining ingredients and stir butter in evenly.","Allow it to cool for 5 minutes.","Break into crumbs by hand."]', '[]', 'Pastry_Module_2_Course_4.pdf', 73);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Crumb Topping for Bars Cookies', 'Doughs & Crusts', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 56, 'Yield 911 grams', '911 grams', '[]', '[{"name":"butter (melted and cooled)","amounts":[["200","grams"]],"bakers_pct":null,"component":null},{"name":"light brown sugar","amounts":[["102","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["102","grams"]],"bakers_pct":null,"component":null},{"name":"AP flour","amounts":[["305","grams"]],"bakers_pct":null,"component":null},{"name":"cinnamon","amounts":[["1","gram"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["1","gram"]],"bakers_pct":null,"component":null},{"name":"pecans, chopped","amounts":[["70","grams"]],"bakers_pct":null,"component":null},{"name":"walnuts, chopped","amounts":[["60","grams"]],"bakers_pct":null,"component":null},{"name":"rolled oats","amounts":[["70","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine dry ingredients. Add butter and mix until crumbly.","Add nuts and oats and mix until evenly distributed."]', '[]', 'Pastry_Module_3_Course_5.pdf', 93);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Frangipane From Ground Nuts', 'Doughs & Crusts', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 38, NULL, NULL, '[]', '[{"name":"ground nuts (pistachios or other nuts)","amounts":[["170","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["170","grams"]],"bakers_pct":null,"component":null},{"name":"butter","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"almond extract (optional)","amounts":[["13","grams"]],"bakers_pct":null,"component":null},{"name":"grated lemon zest (optional)","amounts":[["2","grams"]],"bakers_pct":null,"component":null},{"name":"yolks (8)","amounts":[["135","grams"]],"bakers_pct":null,"component":null},{"name":"all-purpose flour","amounts":[["85","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Beat ground nuts, sugar, and butter by machine w/ paddle on medium speed until light.","Beat in optional flavorings, then yolks, one at a time, beating until smooth.","Beat in flour until just absorbed."]', '[]', 'Pastry_Module_2_Course_4.pdf', 50);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Muffin Crumb Topping', 'Doughs & Crusts', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 51, 'Yield 295.7 grams', '295.7 grams', '[]', '[{"name":"light brown sugar","amounts":[["35","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["35","grams"]],"bakers_pct":null,"component":null},{"name":"AP flour","amounts":[["140","grams"]],"bakers_pct":null,"component":null},{"name":"butter","amounts":[["85","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Place all of the ingredients into a mixing bowl and mix by hand or machine until a loose, crumb-like texture is achieved.","Liberally cover the surface of the muffins with the crumb topping and bake in a pre- heated 350˚F oven."]', '[]', 'Pastry_Module_3_Course_5.pdf', 35);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Pasta Frolla', 'Doughs & Crusts', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 38, NULL, NULL, '[]', '[{"name":"all purpose flour","amounts":[["920","grams"]],"bakers_pct":"100.00","component":null},{"name":"sugar","amounts":[["230","grams"]],"bakers_pct":"25.00","component":null},{"name":"baking powder","amounts":[["9","grams"]],"bakers_pct":"0.98","component":null},{"name":"salt","amounts":[["6","grams"]],"bakers_pct":"0.65","component":null},{"name":"butter","amounts":[["345","grams"]],"bakers_pct":"37.50","component":null},{"name":"eggs (7)","amounts":[["350","grams"]],"bakers_pct":"38.04","component":null}]', NULL, '["Prepare using Mealy Dough Mixing Method. Chill until ready to use."]', '[]', 'Pastry_Module_2_Course_4.pdf', 47);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Pate Brisee', 'Doughs & Crusts', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 36, NULL, NULL, '[]', '[{"name":"butter","amounts":[["450","grams"]],"bakers_pct":"66.67","component":null},{"name":"all-purpose flour","amounts":[["450","grams"]],"bakers_pct":"66.67","component":null},{"name":"cake flour","amounts":[["225","grams"]],"bakers_pct":"33.33","component":null},{"name":"salt","amounts":[["6","grams"]],"bakers_pct":"0.89","component":null},{"name":"baking powder","amounts":[["2","grams"]],"bakers_pct":"0.30","component":null},{"name":"cold water","amounts":[["175","grams"]],"bakers_pct":"25.93","component":null}]', NULL, '["Prepare using Flaky Dough Mixing Method. Chill until ready to use."]', '[]', 'Pastry_Module_2_Course_4.pdf', 26);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Pate Sablee', 'Doughs & Crusts', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 40, NULL, NULL, '[]', '[{"name":"butter","amounts":[["460","grams"]],"bakers_pct":"66.67","component":null},{"name":"sugar","amounts":[["230","grams"]],"bakers_pct":"33.33","component":null},{"name":"eggs (2)","amounts":[["100","grams"]],"bakers_pct":"14.49","component":null},{"name":"cake flour","amounts":[["690","grams"]],"bakers_pct":"100.00","component":null}]', NULL, '["Prepare using Creaming Dough Mixing Method; chill until ready to use."]', '[]', 'Pastry_Module_2_Course_4.pdf', 81);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Pate Sucree', 'Doughs & Crusts', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 38, NULL, NULL, '[]', '[{"name":"all purpose flour","amounts":[["680","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"baking powder","amounts":[["7","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["6","grams"]],"bakers_pct":null,"component":null},{"name":"butter","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"eggs (5)","amounts":[["250","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Prepare using Mealy Dough Mixing Method. Chill until ready to use."]', '[]', 'Pastry_Module_2_Course_4.pdf', 46);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Pate Sucree', 'Doughs & Crusts', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 71, NULL, NULL, '[]', '[{"name":"butter, unsalted","amounts":[["250","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose","amounts":[["175","grams"]],"bakers_pct":null,"component":null},{"name":"almond flour","amounts":[["40","grams"]],"bakers_pct":null,"component":null},{"name":"egg yolks","amounts":[["20","grams"]],"bakers_pct":null,"component":null},{"name":"whole eggs","amounts":[["50","grams"]],"bakers_pct":null,"component":null},{"name":"all-purpose flour","amounts":[["400","grams"]],"bakers_pct":null,"component":null},{"name":"baking powder","amounts":[["1","gram"]],"bakers_pct":null,"component":null}]', '[["936","grams"]]', '["Cream together the butter, sucrose, and almond flour.","Slowly add the eggs and yolks, scraping down the bowl.","Add the flour and baking powder, mixing until just combined.","Roll or sheet the dough very thinly. Transfer the dough to a half sheet pan and bake at 150°C/300°F for 10 minutes. Remove from the oven and cut the dough into 4cm squares. Return to the oven for 5-7 minutes, or until lightly browned. Remove from the oven and cool."]', '[]', 'Pastry_Module_3_Course_6.pdf', 166);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Pate Sucree', 'Doughs & Crusts', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 73, NULL, NULL, '[]', '[{"name":"butter, softened","amounts":[["125","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose","amounts":[["85","grams"]],"bakers_pct":null,"component":null},{"name":"almond flour","amounts":[["20","grams"]],"bakers_pct":null,"component":null},{"name":"baking powder","amounts":[["1","grams"]],"bakers_pct":null,"component":null},{"name":"whole egg","amounts":[["50","grams"]],"bakers_pct":null,"component":null},{"name":"all-purpose flour","amounts":[["200","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["5","grams"]],"bakers_pct":null,"component":null}]', '[["486","grams"]]', '["In an electric mixer bowl fitted with the paddle attachment, cream the butter and sugar until light. Combine the almond flour and baking powder and add all at once to the creamed butter.","While mixer is on low speed, add egg, scraping down the bowl as needed.","Add the flour, mixing until thoroughly combined. Add water. Turn dough onto a lightly floured surface. Wrap, chill and allow to rest approximately two hours.","Roll dough to a thickness of 3mm, and cut bases with an 8cm (3”) round cutter.","Place dough on a parchment lined sheet pan and bake at 150˚C/300ºF for about 12 minutes, or until golden."]', '[]', 'Pastry_Module_3_Course_6.pdf', 224);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Pate a Choux', 'Doughs & Crusts', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 21, NULL, NULL, '[]', '[{"name":"milk","amounts":[["730","grams"]],"bakers_pct":null,"component":null},{"name":"butter (cut in pieces)","amounts":[["310","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["4","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["7","grams"]],"bakers_pct":null,"component":null},{"name":"all-purpose flour","amounts":[["465","grams"]],"bakers_pct":null,"component":null},{"name":"eggs","amounts":[["730","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine milk, butter, sugar and salt in a pan over medium heat; bring to a boil, stirring occasionally.","At a full boil, remove the pan from the heat; add the flour all at once. Stir vigorously removing any lumps of flour to a smooth consistency.","Return to the heat and cook, stirring constantly, until the paste forms a ball and a skin forms on the bottom of the pot.","Transfer the paste to the bowl of an electric mixer; beat on lowest speed with the paddle to cool the paste slightly, about 20 seconds. Add eggs gradually making sure to scrape down the bowl often."]', '[]', 'PA_Mod_01_Instructor.pdf', 339);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Raspberry Sablee', 'Doughs & Crusts', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 71, NULL, NULL, '[]', '[{"name":"unsalted butter, softened","amounts":[["55","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose","amounts":[["50","grams"]],"bakers_pct":null,"component":null},{"name":"egg yolk","amounts":[["20","grams"]],"bakers_pct":null,"component":null},{"name":"raspberry compound (Pregel) or extract","amounts":[["5","grams"]],"bakers_pct":null,"component":null},{"name":"fine sea salt","amounts":[["2","grams"]],"bakers_pct":null,"component":null},{"name":"baking soda","amounts":[["3","grams"]],"bakers_pct":null,"component":null},{"name":"AP flour","amounts":[["75","grams"]],"bakers_pct":null,"component":null}]', '[["210","grams"]]', '["In a mixer bowl fitted with the paddle attachment, cream together butter and sucrose.","Slowly add egg yolk and raspberry compound, scraping down the bowl and mixing until thoroughly combined.","Add the flour, salt, baking soda and red color, mixing just until combined. Chill."]', '[]', 'Pastry_Module_3_Course_6.pdf', 154);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Shortbread Crust for Bars', 'Doughs & Crusts', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 56, '(1 half sheet pan) Yield 1,023 grams', '1,023 grams', '[]', '[{"name":"butter","amounts":[["265","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["265","grams"]],"bakers_pct":null,"component":null},{"name":"light brown sugar","amounts":[["33","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["6","grams"]],"bakers_pct":null,"component":null},{"name":"eggs","amounts":[["50","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla","amounts":[["4","grams"]],"bakers_pct":null,"component":null},{"name":"AP flour","amounts":[["400","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Cream together butter, sugar, light brown sugar and salt until smooth.","Gradually add the eggs and vanilla, scraping the bowl in between additions.","Add the flour all at once, lower speed, and mix until smooth.","Press or roll onto the bottom of a flat half sheet pan with parchment glued down with spray or butter. Use plastic wrap on top to smooth the crust, making sure it''s an even thickness.","Press a sheet pan extender into the dough and refrigerate until chilled and firm.","Pre-bake the crust in a 350ºF deck oven until baked through and very light in color. Do not remove the extender until after baked with chosen filling."]', '["Utilize the Creaming mixing method."]', 'Pastry_Module_3_Course_5.pdf', 92);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Sour Cream Dough', 'Doughs & Crusts', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 38, NULL, NULL, '[]', '[{"name":"all-purpose flour","amounts":[["540","grams"]],"bakers_pct":"100.00","component":null},{"name":"salt","amounts":[["6","grams"]],"bakers_pct":"1.11","component":null},{"name":"butter","amounts":[["240","grams"]],"bakers_pct":"44.44","component":null},{"name":"sour cream","amounts":[["360","grams"]],"bakers_pct":"66.67","component":null}]', NULL, '["Prepare using Flaky Dough Mixing Method, using sour cream as liquid."]', '[]', 'Pastry_Module_2_Course_4.pdf', 47);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Walnut Frangipane', 'Doughs & Crusts', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 38, NULL, NULL, '[]', '[{"name":"walnut pieces","amounts":[["285","grams"]],"bakers_pct":null,"component":null},{"name":"granulated sugar","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"brown sugar","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"softened butter","amounts":[["455","grams"]],"bakers_pct":null,"component":null},{"name":"dark rum","amounts":[["28","grams"]],"bakers_pct":null,"component":null},{"name":"eggs(8)","amounts":[["400","grams"]],"bakers_pct":null,"component":null},{"name":"all-purpose flour","amounts":[["140","grams"]],"bakers_pct":null,"component":null},{"name":"baking powder","amounts":[["2","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Place walnuts and granulated sugar in work bowl of robot coup. Grind finely.","In mixing bowl, cream butter and brown sugar with paddle on medium speed until light.","Beat walnut mixture into creamed butter. Add cinnamon and dark rum.","Beat in the eggs, a few at a time.","Combine flour and baking powder and add to the mixing bowl beating on low speed, just until the flour is absorbed."]', '[]', 'Pastry_Module_2_Course_4.pdf', 49);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Almond Filling', 'Fillings, Sauces & Garnishes', 'Module 2', 'Course 3', 'Breads & Yeast Doughs', 35, NULL, NULL, '[]', '[{"name":"almond paste","amounts":[["450","grams"]],"bakers_pct":null,"component":null},{"name":"egg white","amounts":[["120","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine almond paste and egg white in mixing bowl and beat with paddle on low speed until smooth."]', '[]', 'Pastry_Module_2_Course_3.pdf', 137);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Apple Filling', 'Fillings, Sauces & Garnishes', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 40, NULL, NULL, '["small batch","large batch"]', '[{"name":"apples ( 6 or 12)","amounts":[["1350","grams"],["2700","grams"]],"bakers_pct":null,"component":null},{"name":"butter","amounts":[["55","grams"],["110","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["110","grams"],["220","grams"]],"bakers_pct":null,"component":null},{"name":"lemon zest","amounts":[["2","grams"],["4","grams"]],"bakers_pct":null,"component":null},{"name":"dark rum","amounts":[["28","grams"],["56","grams"]],"bakers_pct":null,"component":null},{"name":"cinnamon","amounts":[["1","gram"],["2","grams"]],"bakers_pct":null,"component":null},{"name":"currants","amounts":[["85","grams"],["170","grams"]],"bakers_pct":null,"component":null},{"name":"chopped walnuts","amounts":[["85","grams"],["170","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Peel, core and cut apples into wedges.","Place apples and all other ingredients into a large rondeau, cooking over medium heat, covered, until apples begin to soften.","Uncover and continue to cook until liquid is evaporated.","Chill until ready to use."]', '[]', 'Pastry_Module_2_Course_4.pdf', 73);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Caramel Filling', 'Fillings, Sauces & Garnishes', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 73, NULL, NULL, '[]', '[{"name":"sucrose","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["120","grams"]],"bakers_pct":null,"component":null},{"name":"lemon juice","amounts":[["2","grams"]],"bakers_pct":null,"component":null},{"name":"glucose syrup","amounts":[["20","grams"]],"bakers_pct":null,"component":null},{"name":"heavy cream","amounts":[["180","grams"]],"bakers_pct":null,"component":null},{"name":"butter, cold","amounts":[["30","grams"]],"bakers_pct":null,"component":null}]', '[["577","grams"]]', '["Combine the sucrose, water, lemon juice, and glucose in a medium sauce pan. Cook over medium heat to a dark amber color.","While sugar is cooking, warm heavy cream slightly.","Remove caramelized sugar from heat and deglaze with the cream. Return to low heat to completely dissolve sugar and to make sure no lumps remain.","Once smooth, remove from heat, cool slightly and emulsify butter into the caramel using a hand held mixer."]', '[]', 'Pastry_Module_3_Course_6.pdf', 211);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Caramel Hazelnut Filling', 'Fillings, Sauces & Garnishes', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 56, 'Yield of filling (one half sheet pan) 1,196 grams', '1,196 grams', '[]', '[{"name":"light corn syrup","amounts":[["230","grams"]],"bakers_pct":null,"component":null},{"name":"light brown sugar","amounts":[["220","grams"]],"bakers_pct":null,"component":null},{"name":"butter","amounts":[["60","grams"]],"bakers_pct":null,"component":null},{"name":"heavy cream","amounts":[["130","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla extract","amounts":[["1","gram"]],"bakers_pct":null,"component":null},{"name":"dark rum","amounts":[["9","grams"]],"bakers_pct":null,"component":null},{"name":"hazelnuts, chopped","amounts":[["546","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine corn syrup and sugar in a sauce pan and mix well. Place on medium heat, stirring occasionally, until the syrup comes to a boil.","At the boil, add the butter and cream and return to a boil.","Simmer the mixture for about 3 minutes, stirring occasionally.","Remove from heat and stir in vanilla and rum.","Combine the syrup and hazelnuts in a bowl and mix to combine.","Pour the filling into the sheet pan extender on the pre-baked crust and spread evenly.","Bake at 350ºF until the filling bubbles across the surface, approximately 20-25 minutes. Filling will still be soft but will set up after it is chilled. Be careful not to over bake the bar or the filling with be too hard when cooled."]', '[]', 'Pastry_Module_3_Course_5.pdf', 97);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Caramel Sauce', 'Fillings, Sauces & Garnishes', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 74, NULL, NULL, '[]', '[{"name":"sucrose","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["120","grams"]],"bakers_pct":null,"component":null},{"name":"lemon juice","amounts":[["2","grams"]],"bakers_pct":null,"component":null},{"name":"glucose syrup","amounts":[["20","grams"]],"bakers_pct":null,"component":null},{"name":"heavy cream (36% fat)","amounts":[["180","grams"]],"bakers_pct":null,"component":null},{"name":"unsalted butter, cold","amounts":[["30","grams"]],"bakers_pct":null,"component":null}]', '[["577","grams"]]', '["Combine the sucrose, water, lemon juice, and glucose in a medium sauce pan. Cook over medium heat to a dark amber color.","While sugar is cooking, warm heavy cream slightly.","Remove caramelized sugar from heat and deglaze with the cream. Return to low heat to completely dissolve sugar and to make sure no lumps remain.","Once smooth, remove from heat, cool slightly and emulsify butter into the caramel using an immersion blender."]', '[]', 'Pastry_Module_3_Course_6.pdf', 253);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Cheese Filling', 'Fillings, Sauces & Garnishes', 'Module 2', 'Course 3', 'Breads & Yeast Doughs', 35, NULL, NULL, '["small batch"]', '[{"name":"farmer cheese","amounts":[["1360","grams"]],"bakers_pct":null,"component":null},{"name":"lemon zest","amounts":[["2","grams"]],"bakers_pct":null,"component":null},{"name":"golden raisins","amounts":[["225","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Mix all ingredients together until smooth.","Roll out dough like croissants. Dough should be 1/8-1/4 inch thick. Trim","Egg wash opposite corners of the dough.","Fold egg washed corners in towards center and press down to seal. Brush","Place on tray before filling.","Place a dollop of filling (farmer''s cheese or frangipane) in center. Place","Egg wash Danish and place in oven set at 350°F (actual temp is 375°F)","Let cool and brush center with heated apricot nappage.","Sprinkle tops with confectioners sugar."]', '[]', 'Pastry_Module_2_Course_3.pdf', 140);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Chocolate Almond Filling', 'Fillings, Sauces & Garnishes', 'Module 2', 'Course 3', 'Breads & Yeast Doughs', 35, NULL, NULL, '[]', '[{"name":"almond paste","amounts":[["450","grams"]],"bakers_pct":null,"component":null},{"name":"bittersweet chocolate, finely grated","amounts":[["115","grams"]],"bakers_pct":null,"component":null},{"name":"egg white","amounts":[["120","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Paddle the almond paste on low speed to break it up and soften it.","Add the egg white gradually, beating until smooth, light, and free of lumps.","Fold in the finely grated bittersweet chocolate until evenly distributed."]', '[]', 'Pastry_Module_2_Course_3.pdf', 137);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Chocolate Sauce', 'Fillings, Sauces & Garnishes', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 71, NULL, NULL, '[]', '[{"name":"whole milk","amounts":[["200","grams"]],"bakers_pct":null,"component":null},{"name":"glucose syrup","amounts":[["50","grams"]],"bakers_pct":null,"component":null},{"name":"semisweet chocolate (approx. 60%)","amounts":[["190","grams"]],"bakers_pct":null,"component":null}]', '[["440","grams"]]', '["In a small saucepan, combine milk and glucose and bring to a boil.","Remove from heat and gradually pour over chocolate, stirring to combine."]', '[]', 'Pastry_Module_3_Course_6.pdf', 160);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Coffee Syrup', 'Fillings, Sauces & Garnishes', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 67, NULL, NULL, '[]', '[{"name":"sugar","amounts":[["150","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["150","grams"]],"bakers_pct":null,"component":null},{"name":"instant espresso","amounts":[["8","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine ingredients and bring to a boil."]', '[]', 'Pastry_Module_3_Course_6.pdf', 70);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Cooked Apple Filling', 'Fillings, Sauces & Garnishes', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 48, NULL, NULL, '[]', '[{"name":"Golden Delicious apples(6)","amounts":[["1300","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["115","grams"]],"bakers_pct":null,"component":null},{"name":"butter","amounts":[["55","grams"]],"bakers_pct":null,"component":null},{"name":"lemon juice","amounts":[["15","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Peel, core, and halve the apples. Slice each half into 5 pieces.","Combine apple slices with remaining ingredients in a heavy saucepan over medium heat.","Cover and cook for 10 minutes.","Uncover; lower heat and cook until water evaporates. Cool."]', '[]', 'Pastry_Module_2_Course_4.pdf', 144);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Cooked Apple Filling Cooked Apple Filling', 'Fillings, Sauces & Garnishes', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 2, NULL, NULL, '[]', '[{"name":"Granny Smith or Golden Delicious apples","amounts":[["1360","grams"]],"bakers_pct":null,"component":null},{"name":"butter","amounts":[["55","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["115","grams"]],"bakers_pct":null,"component":null},{"name":"cinnamon, ground","amounts":[["1","gram"]],"bakers_pct":null,"component":null},{"name":"lemon juice","amounts":[["15","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Peel, halve, core, and slice the apples as for a filling, cutting each half into five or six slices from stem to blossom end.","Melt the butter in a wide pan and add the sliced apples, followed by the sucrose, cinnamon and lemon juice; stir well to combine. Cook over medium heat until the apples begin to ‘sizzle''. Lower the heat and cover the pan; steam for 10 minutes.","Remove the cover and continue cooking over low heat to evaporate the juices for an additional 10 minutes. The apples should remain tender and in distinct pieces.","Use immediately or transfer the filling to a stainless steel pan and cool to room temperature. Wrap tightly and refrigerate until needed, up to 5 days. cranberries."]', '["Optional: Substitute pears for apples for the filling. Add inclusions such as nuts or"]', 'PA_Mod_01_Instructor.pdf', 34);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Cooked Pear Filling', 'Fillings, Sauces & Garnishes', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 48, NULL, NULL, '[]', '[{"name":"ripe pears(6)","amounts":[["1350","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["115","grams"]],"bakers_pct":null,"component":null},{"name":"butter","amounts":[["55","grams"]],"bakers_pct":null,"component":null},{"name":"lemon juice","amounts":[["15","grams"]],"bakers_pct":null,"component":null},{"name":"pear eau-de-vie","amounts":[["28","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Peel, core, and halve the pears; slice each half into 1/2-inch-thick slices.","Melt butter in a sauté pan over high heat; add pears and toss to coat. Add sugar, then lemon juice.","Cook over high heat until pears are just tender. Flame with pear alcohol. Cool."]', '[]', 'Pastry_Module_2_Course_4.pdf', 144);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Espresso Simple Syrup', 'Fillings, Sauces & Garnishes', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 67, NULL, NULL, '[]', '[{"name":"sugar","amounts":[["150","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["150","grams"]],"bakers_pct":null,"component":null},{"name":"Italian brandy","amounts":[["50","grams"]],"bakers_pct":null,"component":null},{"name":"instant espresso","amounts":[["18","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Bring sugar and water to a boil. Stir in instant espresso, let cool and add brandy."]', '[]', 'Pastry_Module_3_Course_6.pdf', 77);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Lemon Confit', 'Fillings, Sauces & Garnishes', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 71, NULL, NULL, '[]', '[{"name":"sucrose","amounts":[["200","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["300","grams"]],"bakers_pct":null,"component":null}]', '[["500","grams"]]', '["In a medium saucepan, cover sliced lemons with ample cold water and gently bring to a boil. Drain and discard water. Repeat this step once more.","Meanwhile, prepare a syrup with the sucrose and water.","Combine blanched lemons and the syrup and gently cook over low heat, reducing until the lemon is slightly translucent.","Allow to cool and coarsely chop."]', '[]', 'Pastry_Module_3_Course_6.pdf', 152);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Lemon Topping', 'Fillings, Sauces & Garnishes', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 56, 'Yield of filling, (one half sheet pan) 1,494 grams', '1,494 grams', '[]', '[{"name":"eggs","amounts":[["400","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["900","grams"]],"bakers_pct":null,"component":null},{"name":"strained lemon juice","amounts":[["175","grams"]],"bakers_pct":null,"component":null},{"name":"finely grated lemon zest","amounts":[["19","grams"]],"bakers_pct":null,"component":null}]', NULL, '["While the base is baking, prepare the topping. Be careful not to over mix the topping or it will have coarse-textured foam on the top when baked. In a large mixing bowl, whisk the eggs just to break them up. Whisk in the sugar, followed by the lemon juice and zest.","As soon as the base is baked, remove it from the oven and pour the topping into the sheet pan extender. Immediately return the pan to the oven and continue baking the squares in a deck oven until the topping is completely set and firm and has darkened significantly.","Cool completely, either in the refrigerator or at room temperature (ideally overnight), before","Dust with 10x or snow sugar before serving."]', '[]', 'Pastry_Module_3_Course_5.pdf', 95);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Magic Bar Filling', 'Fillings, Sauces & Garnishes', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 56, 'Yield of filling (one half sheet pan) 1,249 grams', '1,249 grams', '[]', '[{"name":"eggs","amounts":[["150","grams"]],"bakers_pct":null,"component":null},{"name":"sweetened condensed milk","amounts":[["295","grams"]],"bakers_pct":null,"component":null},{"name":"light brown sugar","amounts":[["170","grams"]],"bakers_pct":null,"component":null},{"name":"shredded sweetened coconut","amounts":[["210","grams"]],"bakers_pct":null,"component":null},{"name":"pecans, chopped","amounts":[["170","grams"]],"bakers_pct":null,"component":null},{"name":"semisweet chocolate, pistoles or chopped","amounts":[["127","grams"]],"bakers_pct":null,"component":null},{"name":"milk chocolate, pistoles or chopped","amounts":[["127","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Whisk together the first 4 ingredients.","Stir in pecans and chocolates. Pour mixture evenly into sheet pan extender. Bake at 350ºF until filling is set and golden brown."]', '[]', 'Pastry_Module_3_Course_5.pdf', 96);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Mandarin Coulis', 'Fillings, Sauces & Garnishes', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 71, NULL, NULL, '[]', '[{"name":"mandarin purée","amounts":[["300","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose","amounts":[["60","grams"]],"bakers_pct":null,"component":null},{"name":"‘yellow'' pectin","amounts":[["5","grams"]],"bakers_pct":null,"component":null}]', '[["365","grams"]]', '["Place the mandarin purée into a small sauce pan and bring to a simmer.","Whisk together sucrose and pectin and whisk into the puree mixture. Resume a simmer remove from heat, and allow to cool."]', '[]', 'Pastry_Module_3_Course_6.pdf', 168);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Passion Fruit Coulis', 'Fillings, Sauces & Garnishes', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 20, NULL, NULL, '[]', '[{"name":"passion fruit purée","amounts":[["560","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"pectin","amounts":[["15","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Place the passion fruit purée in a sauce pan and gently bring to a boil.","Combine sucrose and pectin and whisk into the puree mixture. Resume boil, remove from heat, and cool."]', '[]', 'PA_Mod_01_Instructor.pdf', 291);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Pineapple Filling', 'Fillings, Sauces & Garnishes', 'Module 2', 'Course 3', 'Breads & Yeast Doughs', 35, NULL, NULL, '["2-inch hole"]', '[{"name":"cornstarch","amounts":[["8","grams"]],"bakers_pct":null,"component":null},{"name":"cold water","amounts":[["15","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Purée cooled poached pineapples.","Place puree in a saucepan and cook over medium heat, stirring occasionally. Cook until mixture thickens slightly, approximately 10 minutes.","Dissolve the cornstarch in the cold water.","Make a liaison between the pineapple purée and cornstarch mixture, return to saucepan and bring to a boil. Be careful not to scorch pineapple. Chill until ready to use."]', '[]', 'Pastry_Module_2_Course_3.pdf', 138);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Pineapple Filling Poached Pineapple', 'Fillings, Sauces & Garnishes', 'Module 2', 'Course 3', 'Breads & Yeast Doughs', 35, NULL, NULL, '[]', '[{"name":"water","amounts":[["2000","grams"]],"bakers_pct":null,"component":null},{"name":"lemon zest","amounts":[["4","grams"]],"bakers_pct":null,"component":null},{"name":"lemon juice","amounts":[["15","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["455","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Place in a 2-quart saucepan and add the remaining ingredients. Add more water if necessary to cover the pineapple by 1 inch.","Cut a round of parchment paper to fit inside the saucepan and make a 1 it down so that the paper is below the surface of the liquid. This will keep the fruit submerged in the syrup while it is cooking so that it cooks evenly.","Bring the pineapple to a boil over medium heat and simmer for 5 minutes. Allow it to cool in the syrup."]', '[]', 'Pastry_Module_2_Course_3.pdf', 138);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Poached Pears', 'Fillings, Sauces & Garnishes', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 7, NULL, NULL, '[]', '[{"name":"pears","amounts":[["6","each"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["4000","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["1000","grams"]],"bakers_pct":null,"component":null},{"name":"fresh herbs (optional)","amounts":[["4","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Peel, halve and core the pears. Place in a rondeaux with the sugar and water and place over heat.","Add split and scraped vanilla bean, fresh herbs if using, and position the pears so that the cut sides are up, if possible. (If any oxidation occurs, it will occur on the flat side which will eventually be positioned downward in a dessert).","Cut a round of parchment or wax paper to fit inside the saucepan and make a 1 pears submerged in the syrup so they do not develop dark spots).","Bring the pears to a boil, then immediately turn heat down and simmer until pears are knife tender. Remove from heat; cool, store pears in the syrup and refrigerate."]', '[]', 'PA_Mod_01_Instructor.pdf', 151);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Poached Pears', 'Fillings, Sauces & Garnishes', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 69, NULL, NULL, '[]', '[{"name":"pears","amounts":[["8","each"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["2000","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["500","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Peel, halve and core the pears. Place in a rondeaux with the sugar and water and place over heat.","Add split and scraped vanilla bean and position the pears so that the cut sides are up, if possible. (If any oxidation occurs, it will occur on the flat side which will eventually be positioned downward in a dessert). the center. Cover the pears with the paper, pressing it down so that the paper is below the surface of the liquid. (This will keep the pears submerged in the syrup so they do not develop dark spots.)","Bring the pears to a boil, then immediately turn heat down and simmer until pears are knife tender. Remove from heat, cool for use."]', '[]', 'Pastry_Module_3_Course_6.pdf', 127);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Poached Pears in Caramel Syrup', 'Fillings, Sauces & Garnishes', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 7, NULL, NULL, '[]', '[{"name":"sugar","amounts":[["750","grams"]],"bakers_pct":null,"component":null},{"name":"lemon juice","amounts":[["15","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["4000","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["750","grams"]],"bakers_pct":null,"component":null},{"name":"pears","amounts":[["6","each"]],"bakers_pct":null,"component":null}]', NULL, '["Combine the first sugar and lemon juice in a rondeaux or large pot stirring until the sugar resembles wet sand.","Place on medium heat; heat without stirring until the sugar starts to melt and begins to caramelize.","Begin to stir the sugar. Continue heating, stirring occasionally, until the caramel is a clear amber color creating a dry caramel","Dilute the caramel with the water. Add the remaining sugar and vanilla bean which has been cut and scraped.","Peel, halve and core the pears and place into the caramel solution.","Position the pears so that the cut sides are up, if possible (if any oxidation occurs, it will occur on the flat side which will eventually be positioned downward in a dessert).","Cut a round of parchment or wax paper to fit inside the saucepan and make a 1 pears submerged in the syrup so they do not develop dark spots).","Bring the pears to a boil and immediately turn heat down and simmer until pears are knife tender. Remove from heat; cool, store pears in the syrup and refrigerate."]', '[]', 'PA_Mod_01_Instructor.pdf', 153);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Poached Pears in Wine', 'Fillings, Sauces & Garnishes', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 7, NULL, NULL, '[]', '[{"name":"sugar","amounts":[["1000","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["3000","grams"]],"bakers_pct":null,"component":null},{"name":"red wine or port","amounts":[["1000","grams"]],"bakers_pct":null,"component":null},{"name":"pears","amounts":[["6","each"]],"bakers_pct":null,"component":null},{"name":"fresh herbs (optional)","amounts":[["4","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine the water, wine and sugar in a large saucepan. Peel, halve and core the pears and immerse into the wine liquid.","Add vanilla bean and cinnamon sticks and fresh herbs if using and position the pears so that the cut sides are up, if possible. (If any oxidation occurs, it will occur on the flat side which will eventually be positioned downward in a dessert).","Cut a round of parchment or wax paper to fit inside the saucepan and make a 1 pears submerged in the syrup so they do not develop dark spots).","Bring the pears to a boil, then immediately turn heat down and simmer until pears are knife tender. Remove from heat; cool, store pears in the syrup and refrigerate."]', '[]', 'PA_Mod_01_Instructor.pdf', 152);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Poached Pineapple', 'Fillings, Sauces & Garnishes', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 7, NULL, NULL, '[]', '[{"name":"1 fresh pineapple","amounts":[["1","each"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["750","grams"]],"bakers_pct":null,"component":null},{"name":"lemon juice","amounts":[["15","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["250","grams"]],"bakers_pct":null,"component":null},{"name":"fresh herbs (optional)","amounts":[["6","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Bring the pineapple to a boil. Reduce heat and simmer 5 to 10 minutes. Turn off the heat and allow the pineapple to cool in the syrup. The heat in the syrup will finish cooking the pineapple.","If the pineapple is to be kept more than a few hours before use, hold the pineapple in the syrup, covered, in the refrigerator."]', '[]', 'PA_Mod_01_Instructor.pdf', 154);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Port Sauteed Pear Filling', 'Fillings, Sauces & Garnishes', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 40, NULL, NULL, '[]', '[{"name":"ripe pears (6 large)","amounts":[["1350","grams"]],"bakers_pct":null,"component":null},{"name":"butter","amounts":[["55","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["115","grams"]],"bakers_pct":null,"component":null},{"name":"lemon juice","amounts":[["15","grams"]],"bakers_pct":null,"component":null},{"name":"port","amounts":[["55","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Peel, core, and halve the pears; slice each half into 1/2-inch-thick slices.","Melt butter in a sauté pan over high heat; add pears and toss to coat.","Add sugar, then lemon juice and port.","Cook over high heat until pears are just tender. Cool."]', '[]', 'Pastry_Module_2_Course_4.pdf', 70);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Prune Filling', 'Fillings, Sauces & Garnishes', 'Module 2', 'Course 3', 'Breads & Yeast Doughs', 35, NULL, NULL, '[]', '[{"name":"Pitted prunes","amounts":[["455","grams"]],"bakers_pct":null,"component":null},{"name":"Orange zest","amounts":[["6","grams"]],"bakers_pct":null,"component":null},{"name":"Lemon juice","amounts":[["60","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["115","grams"]],"bakers_pct":null,"component":null},{"name":"Softened butter","amounts":[["55","grams"]],"bakers_pct":null,"component":null}]', NULL, '["In a medium saucepan, cover prunes with water, add cinnamon sticks and simmer until tender.","Remove the cinnamon sticks, drain and purée.","Add in other ingredients and mix until smooth."]', '[]', 'Pastry_Module_2_Course_3.pdf', 139);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Raspberry Almond Filling', 'Fillings, Sauces & Garnishes', 'Module 2', 'Course 3', 'Breads & Yeast Doughs', 35, NULL, NULL, '[]', '[{"name":"seedless raspberry preserves","amounts":[["450","grams"]],"bakers_pct":null,"component":null},{"name":"almond paste","amounts":[["450","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine preserves and almond paste in mixing bowl and beat with paddle on low speed until smooth."]', '[]', 'Pastry_Module_2_Course_3.pdf', 137);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Raspberry Coulis', 'Fillings, Sauces & Garnishes', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 20, NULL, NULL, '[]', '[{"name":"raspberry purée","amounts":[["750","grams"]],"bakers_pct":null,"component":null},{"name":"raspberries","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"invert sugar","amounts":[["75","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine puree and fresh raspberries in a saucepan. Bring to a simmer.","Whisk in the invert sugar and allow to cool."]', '[]', 'PA_Mod_01_Instructor.pdf', 291);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Roasted Pears and Dried Figs', 'Fillings, Sauces & Garnishes', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 40, NULL, NULL, '[]', '[{"name":"wedged (4 large)","amounts":[["900","grams"]],"bakers_pct":null,"component":null},{"name":"dried figs, stemmed and halved","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["115","grams"]],"bakers_pct":null,"component":null},{"name":"dark rum","amounts":[["55","grams"]],"bakers_pct":null,"component":null},{"name":"ground ginger","amounts":[["1","gram"]],"bakers_pct":null,"component":null},{"name":"grated fresh ginger","amounts":[["2","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["3","grams"]],"bakers_pct":null,"component":null},{"name":"grated lemon zest","amounts":[["2","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla extract","amounts":[["4","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Place all ingredients in roasting pan and toss to mix.","Roast at 500 degrees, turning every 10 minutes (lower heat if charring, but some charring is good)."]', '[]', 'Pastry_Module_2_Course_4.pdf', 71);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Roasted Plums and Ginger', 'Fillings, Sauces & Garnishes', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 40, NULL, NULL, '[]', '[{"name":"wedged (10 plums)","amounts":[["660","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["115","grams"]],"bakers_pct":null,"component":null},{"name":"dark rum","amounts":[["55","grams"]],"bakers_pct":null,"component":null},{"name":"ground ginger","amounts":[["1","gram"]],"bakers_pct":null,"component":null},{"name":"grated fresh ginger","amounts":[["2","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["3","grams"]],"bakers_pct":null,"component":null},{"name":"grated lemon zest","amounts":[["2","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla extract","amounts":[["4","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Toss the wedged plums with the sugar, rum, ground ginger, grated ginger, salt, lemon zest, and vanilla extract.","Spread the plums in a single layer on a parchment-lined sheet pan.","Roast at 400 F until softened and caramelized at the edges.","Cool before using."]', '[]', 'Pastry_Module_2_Course_4.pdf', 71);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Simple Syrup', 'Fillings, Sauces & Garnishes', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 59, NULL, NULL, '[]', '[{"name":"granulated sugar","amounts":[["200","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["400","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine sugar and water and bring to a boil. Cool."]', '[]', 'Pastry_Module_3_Course_5.pdf', 162);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Simple Syrup', 'Fillings, Sauces & Garnishes', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 67, NULL, NULL, '[]', '[{"name":"sugar","amounts":[["150","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["150","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine ingredients and bring to a boil. Cool and add flavoring (extract or alcohol)."]', '[]', 'Pastry_Module_3_Course_6.pdf', 74);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Stock Syrup', 'Fillings, Sauces & Garnishes', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 60, NULL, NULL, '[]', '[{"name":"granulated sugar","amounts":[["200","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["400","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine sugar and water in saucepan bring to a boil. Cool."]', '[]', 'Pastry_Module_3_Course_5.pdf', 170);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Stock Syrup', 'Fillings, Sauces & Garnishes', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 63, 'Yield 225 grams', '225 grams', '[]', '[{"name":"water","amounts":[["150","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["75","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine water and sugar and bring to a boil. Cool for use."]', '[]', 'Pastry_Module_3_Course_6.pdf', 24);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Strawberry Salad', 'Fillings, Sauces & Garnishes', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 7, NULL, NULL, '[]', '[{"name":"strawberries, rinsed, stems removed and quartered","amounts":[["400","grams"]],"bakers_pct":null,"component":null},{"name":"granulated sugar","amounts":[["35","grams"]],"bakers_pct":null,"component":null},{"name":"balsamic vinegar","amounts":[["2","grams"]],"bakers_pct":null,"component":null},{"name":"herbs","amounts":[["2","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Rinse, hull and quarter strawberries.","In a bowl, toss with sugar, balsamic vinegar and herbs.","Chill for one hour, covered in refrigerator. Toss at least once while in the refrigerator to ensure the strawberries are well coated.","Serve, garnished with sprigs of fresh herbs."]', '[]', 'PA_Mod_01_Instructor.pdf', 150);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Summer Berry Coulis Insert', 'Fillings, Sauces & Garnishes', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 68, '(25 mini domes) Yield 288 grams', '288 grams', '[]', '[{"name":"sugar","amounts":[["45","grams"]],"bakers_pct":null,"component":null},{"name":"apple pectin","amounts":[["3","grams"]],"bakers_pct":null,"component":null},{"name":"raspberry puree","amounts":[["120","grams"]],"bakers_pct":null,"component":null},{"name":"strawberry puree","amounts":[["120","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla bean, scraped","amounts":[["1","each"]],"bakers_pct":null,"component":null},{"name":"limes, juiced","amounts":[["1","each"]],"bakers_pct":null,"component":null}]', NULL, '["In a small bowl, whisk to combine the sugar and pectin.","Bring purees and vanilla bean to a boil, then whisk in pectin/sugar mixture.","Cook over medium heat until well thickened.","Remove from heat and whisk in lime juice.","Portion into small dome flexi molds and freeze."]', '[]', 'Pastry_Module_3_Course_6.pdf', 109);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Walnut Filling', 'Fillings, Sauces & Garnishes', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 48, NULL, NULL, '[]', '[{"name":"light brown sugar","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"butter","amounts":[["115","grams"]],"bakers_pct":null,"component":null},{"name":"honey","amounts":[["170","grams"]],"bakers_pct":null,"component":null},{"name":"walnuts, coarsely chopped","amounts":[["455","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Bring brown sugar, butter and honey to a boil in heavy saucepan over medium heat.","Boil for 3 minutes. Remove from heat.","Stir in walnuts."]', '[]', 'Pastry_Module_2_Course_4.pdf', 144);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Zabaione Filling', 'Fillings, Sauces & Garnishes', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 67, NULL, NULL, '[]', '[{"name":"gelatin","amounts":[["8","sheets"]],"bakers_pct":null,"component":null},{"name":"heavy cream","amounts":[["475","grams"]],"bakers_pct":null,"component":null},{"name":"egg yolks","amounts":[["160","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"Marsala wine, sweet","amounts":[["120","grams"]],"bakers_pct":null,"component":null},{"name":"instant espresso powder","amounts":[["5","grams"]],"bakers_pct":null,"component":null},{"name":"coffee, strong brewed and cooled","amounts":[["120","grams"]],"bakers_pct":null,"component":null},{"name":"Mascarpone, room temperature","amounts":[["680","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Bloom the gelatin sheets in cold water until soft.","Combine the egg yolks, sugar, and Marsala in a bowl set over simmering water.","Whisk constantly until pale, thick, and ribboning (classic zabaione stage).","Whisk in the espresso powder and brewed coffee.","Remove from heat, squeeze excess water from the bloomed gelatin, and whisk it into the hot zabaione until fully melted.","Cool the zabaione to room temperature, stirring occasionally.","Fold in the mascarpone until smooth and homogeneous.","Whip the heavy cream to soft peaks and fold into the mascarpone-zabaione mixture.","Chill until set."]', '[]', 'Pastry_Module_3_Course_6.pdf', 77);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Gruyere Flavoring', 'Flavorings', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 15, NULL, NULL, '[]', '[{"name":"salt and pepper","amounts":[["","as needed"]],"bakers_pct":null,"component":null},{"name":"(such as: thyme, parsley and basil)","amounts":[["4","grams"]],"bakers_pct":null,"component":null},{"name":"grated Swiss gruyere","amounts":[["115","grams"]],"bakers_pct":null,"component":null},{"name":"grated parmesan for coating ramekins","amounts":[["55","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Add seasoning and cheese to Flour-Based Soufflé at step 5. Note: Do not add sugar to whites in Flour-Based Soufflé in step 8; use grated parmesan in place of sugar for preparing ramekins."]', '["Breadcrumbs can be used in place of grated parmesan for coating the ramekins, if preferred."]', 'PA_Mod_01_Instructor.pdf', 232);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Lemon Flavoring', 'Flavorings', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 15, NULL, NULL, '[]', '[{"name":"lemon zest","amounts":[["6","grams"]],"bakers_pct":null,"component":null},{"name":"lemon juice","amounts":[["120","grams"]],"bakers_pct":null,"component":null},{"name":"white rum","amounts":[["14","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Add zest, juice and rum to Flour-Based Soufflé at step 5."]', '[]', 'PA_Mod_01_Instructor.pdf', 232);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Lime Flavoring', 'Flavorings', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 15, NULL, NULL, '[]', '[{"name":"lime zest","amounts":[["6","grams"]],"bakers_pct":null,"component":null},{"name":"lime juice","amounts":[["120","grams"]],"bakers_pct":null,"component":null},{"name":"white rum","amounts":[["10","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Add zest, juice and rum to Flour-Based Soufflé at step 5."]', '[]', 'PA_Mod_01_Instructor.pdf', 232);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Orange Flavoring', 'Flavorings', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 15, NULL, NULL, '[]', '[{"name":"orange zest","amounts":[["6","grams"]],"bakers_pct":null,"component":null},{"name":"orange juice","amounts":[["120","grams"]],"bakers_pct":null,"component":null},{"name":"Orange liquor","amounts":[["25","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Add zest, juice and Grand Marnier to Flour-Based Soufflé at step 5."]', '[]', 'PA_Mod_01_Instructor.pdf', 232);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Banana Citrus Sorbet', 'Frozen Desserts', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 18, NULL, NULL, '[]', '[{"name":"sucrose (1)","amounts":[["50","grams"]],"bakers_pct":null,"component":null},{"name":"sorbet stabilizer","amounts":[["4","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["500","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose (2)","amounts":[["180","grams"]],"bakers_pct":null,"component":null},{"name":"dextrose","amounts":[["20","grams"]],"bakers_pct":null,"component":null},{"name":"invert sugar","amounts":[["90","grams"]],"bakers_pct":null,"component":null},{"name":"banana purée","amounts":[["600","grams"]],"bakers_pct":null,"component":null},{"name":"mandarin purée","amounts":[["250","grams"]],"bakers_pct":null,"component":null},{"name":"lemon juice","amounts":[["125","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine the first measurement of sucrose (1) and stabilizer.","Heat water to 50˚C/120˚F. Whisk in the stabilizer mixture, and then the remaining sucrose (2), dextrose, and invert sugar and bring just to a boil. Remove from heat.","Chill and allow syrup to mature.","Combine measured base syrup with fruit purées and juice and briefly blend with an immersion blender. Process in batch freezer; extract the mix at -5˚C/23˚F.","Transfer finished sorbet to blast chiller to harden at minimum of -18˚C/0˚F. Alternatively, transfer to PacoJet canisters and freeze; process as needed."]', '[]', 'PA_Mod_01_Instructor.pdf', 288);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Banana Citrus Sorbet', 'Frozen Desserts', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 73, NULL, NULL, '[]', '[{"name":"sucrose (1)","amounts":[["30","grams"]],"bakers_pct":null,"component":null},{"name":"sorbet stabilizer","amounts":[["4","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["500","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose (2)","amounts":[["200","grams"]],"bakers_pct":null,"component":null},{"name":"invert sugar","amounts":[["90","grams"]],"bakers_pct":null,"component":null},{"name":"glucose powder","amounts":[["20","grams"]],"bakers_pct":null,"component":null},{"name":"banana purée","amounts":[["600","grams"]],"bakers_pct":null,"component":null},{"name":"lemon juice","amounts":[["125","grams"]],"bakers_pct":null,"component":null},{"name":"mandarin purée","amounts":[["250","grams"]],"bakers_pct":null,"component":null}]', '[["1819","grams"]]', '["Whisk the first measurement of sugar (1) and stabilizer."]', '[]', 'Pastry_Module_3_Course_6.pdf', 233);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Basil Ice Cream', 'Frozen Desserts', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 19, NULL, NULL, '[]', '[{"name":"whole milk","amounts":[["550","grams"]],"bakers_pct":null,"component":null},{"name":"nonfat dry milk powder","amounts":[["35","grams"]],"bakers_pct":null,"component":null},{"name":"heavy cream (36% fat)","amounts":[["230","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose","amounts":[["140","grams"]],"bakers_pct":null,"component":null},{"name":"dextrose","amounts":[["20","grams"]],"bakers_pct":null,"component":null},{"name":"invert sugar","amounts":[["20","grams"]],"bakers_pct":null,"component":null},{"name":"ice cream stabilizer","amounts":[["4","grams"]],"bakers_pct":null,"component":null},{"name":"basil leaves, blanched","amounts":[["25","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Place the milk, nonfat milk powder, and cream in a sauce pan over medium heat. Add the sucrose, dextrose, invert sugar, and stabilizer. Heat, while whisking, to 85°C/185°F.","Remove from heat and homogenize with an immersion blender. Chill in an ice water bath. Allow the mix to mature at least 12 hours if possible.","Blend the basil into a portion of the base mix using a high speed blender. Process in batch freezer; extract the mix at -5˚C/23˚F. Alternatively, transfer to PacoJet canisters and freeze; process as needed."]', '[]', 'PA_Mod_01_Instructor.pdf', 317);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Basque Tart, Olive Oil Ice Cream, Almond, Apricot Basque Tart Dough', 'Frozen Desserts', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 71, NULL, NULL, '[]', '[{"name":"butter, softened","amounts":[["270","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["5","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose","amounts":[["200","grams"]],"bakers_pct":null,"component":null},{"name":"almond flour","amounts":[["140","grams"]],"bakers_pct":null,"component":null},{"name":"egg yolks","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"AP flour","amounts":[["270","grams"]],"bakers_pct":null,"component":null},{"name":"baking powder","amounts":[["5","grams"]],"bakers_pct":null,"component":null}]', '[["990","grams"]]', '["Combine the butter, sucrose and salt in the bowl of the stand mixer; cream the mixture with the paddle attachment. Add the almond flour, and then slowly add egg yolks one at a time until mixed, scraping down the bowl between each addition. Lastly add flour and baking powder. Mix until just combined.","Refrigerate and rest a minimum one hour. Roll or sheet the dough to a thickness of 3mm (1/8\"); cut equal number of discs with a 12cm (4 ½”) and 8cm (3'') and line prepared 8cm (3”) rings. Deposit vanilla custard and then top with the smaller disc and seal."]', '[]', 'Pastry_Module_3_Course_6.pdf', 140);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Biscuit Coulant Chocolat Coffee Ice Cream', 'Frozen Desserts', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 71, NULL, NULL, '[]', '[{"name":"whole milk","amounts":[["518","grams"]],"bakers_pct":null,"component":null},{"name":"coffee, ground","amounts":[["20","grams"]],"bakers_pct":null,"component":null},{"name":"dry nonfat milk powder","amounts":[["38","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose (1)","amounts":[["85","grams"]],"bakers_pct":null,"component":null},{"name":"glucose powder","amounts":[["30","grams"]],"bakers_pct":null,"component":null},{"name":"invert sugar","amounts":[["20","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose (2)","amounts":[["30","grams"]],"bakers_pct":null,"component":null},{"name":"ice cream stabilizer","amounts":[["3","grams"]],"bakers_pct":null,"component":null},{"name":"instant coffee","amounts":[["8","grams"]],"bakers_pct":null,"component":null},{"name":"egg yolk","amounts":[["30","grams"]],"bakers_pct":null,"component":null},{"name":"heavy cream","amounts":[["200","grams"]],"bakers_pct":null,"component":null}]', '[["982","grams"]]', '["Place the milk and ground coffee in a sauce pan. Whisk in the dry milk to rehydrate and add first measurement of sucrose (1), glucose, and invert sugar. Bring to a boil. Remove from heat and allow to stand five minutes. Strain.","Meanwhile, combine the second measurement of sucrose (2), stabilizer, and instant coffee. Whisk into egg yolks.","Temper hot milk into yolk mixture. Return to low heat and cook, stirring constantly to 85˚C/185˚F."]', '[]', 'Pastry_Module_3_Course_6.pdf', 156);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Black Currant Ice Cream', 'Frozen Desserts', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 19, NULL, NULL, '[]', '[{"name":"whole milk","amounts":[["375","grams"]],"bakers_pct":null,"component":null},{"name":"nonfat dry milk powder","amounts":[["60","grams"]],"bakers_pct":null,"component":null},{"name":"heavy cream (36% fat)","amounts":[["75","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose","amounts":[["120","grams"]],"bakers_pct":null,"component":null},{"name":"glucose powder","amounts":[["20","grams"]],"bakers_pct":null,"component":null},{"name":"invert sugar","amounts":[["25","grams"]],"bakers_pct":null,"component":null},{"name":"ice cream stabilizer","amounts":[["5","grams"]],"bakers_pct":null,"component":null},{"name":"black currant purée","amounts":[["320","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Place the milk, nonfat milk powder, and cream in a sauce pan over medium heat. Add the sucrose, glucose, invert sugar and stabilizer. Heat, while whisking, to 85°C/185°F.","Remove from heat and homogenize with an immersion blender. Chill in an ice water bath. Allow the mix to mature at least 12 hours if possible.","Thoroughly blend the base mix and black currant purée. Process in batch freezer; extract the mix at -5˚C/23˚F. Alternatively, transfer to PacoJet canisters and freeze; process as needed."]', '[]', 'PA_Mod_01_Instructor.pdf', 316);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Blackberry Sorbet', 'Frozen Desserts', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 18, NULL, NULL, '[]', '[{"name":"sucrose (1)","amounts":[["25","grams"]],"bakers_pct":null,"component":null},{"name":"sorbet stabilizer","amounts":[["5","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["470","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose (2)","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"dextrose","amounts":[["30","grams"]],"bakers_pct":null,"component":null},{"name":"glucose powder","amounts":[["64","grams"]],"bakers_pct":null,"component":null},{"name":"blackberry purée","amounts":[["750","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine the first measurement of sucrose (1) and stabilizer.","Heat water to 50˚C/120˚F. Whisk in the stabilizer mixture, and then the remaining sucrose (2), dextrose, and glucose and bring just to a boil. Remove from heat.","Chill and allow syrup to mature.","Combine the base syrup with fruit purée and briefly blend with an immersion blender. Process in batch freezer; extract the mix at -5˚C/23˚F.","Transfer finished sorbet to blast chiller to harden at minimum of -18˚C/0˚F. Alternatively, transfer to PacoJet canisters and freeze; process as needed."]', '[]', 'PA_Mod_01_Instructor.pdf', 287);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Bulk Sorbet Base (Acidic Fruit)', 'Frozen Desserts', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 18, NULL, NULL, '[]', '[{"name":"sucrose (1)","amounts":[["50","grams"]],"bakers_pct":null,"component":null},{"name":"sorbet stabilizer","amounts":[["8","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["555","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose (2)","amounts":[["265","grams"]],"bakers_pct":null,"component":null},{"name":"dextrose","amounts":[["132","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine the first measurement of sucrose (1) and stabilizer.","Heat water to 50˚C/120˚F. Whisk in the stabilizer mixture, and then the remaining sucrose (2) and dextrose and bring just to a boil. Remove from heat.","Chill and allow syrup to mature at least 4 hours.","Combine measured base syrup with fruit purée (and additional water, if necessary) and briefly blend with an immersion blender. Process in batch freezer; extract the mix at"]', '[]', 'PA_Mod_01_Instructor.pdf', 279);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Bulk Sorbet Base (Sweet Fruit)', 'Frozen Desserts', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 18, NULL, NULL, '[]', '[{"name":"sucrose (1)","amounts":[["50","grams"]],"bakers_pct":null,"component":null},{"name":"sorbet stabilizer","amounts":[["8","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["380","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose (2)","amounts":[["350","grams"]],"bakers_pct":null,"component":null},{"name":"dextrose","amounts":[["52","grams"]],"bakers_pct":null,"component":null},{"name":"glucose powder","amounts":[["160","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine the first measurement of sucrose (1) and stabilizer.","Heat water to 50˚C/120˚F. Whisk in the stabilizer mixture, and then the remaining sucrose (2), dextrose, and glucose and bring just to a boil. Remove from heat.","Chill and allow syrup to mature at least 4 hours.","Combine measured base syrup with fruit purée (and additional water, if necessary) and briefly blend with an immersion blender. Process in batch freezer; extract the mix at"]', '[]', 'PA_Mod_01_Instructor.pdf', 280);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Caramel Crepe Cake, Roasted Pineapple, Banana-Citrus Sorbet Crepe', 'Frozen Desserts', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 73, NULL, NULL, '[]', '[{"name":"AP flour","amounts":[["170","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose","amounts":[["40","grams"]],"bakers_pct":null,"component":null},{"name":"fine sea salt","amounts":[["5","grams"]],"bakers_pct":null,"component":null},{"name":"whole eggs","amounts":[["150","grams"]],"bakers_pct":null,"component":null},{"name":"egg yolks","amounts":[["60","grams"]],"bakers_pct":null,"component":null},{"name":"vegetable oil","amounts":[["70","grams"]],"bakers_pct":null,"component":null},{"name":"whole milk","amounts":[["370","grams"]],"bakers_pct":null,"component":null},{"name":"dark rum","amounts":[["30","grams"]],"bakers_pct":null,"component":null}]', '[["895","grams"]]', '["Combine and sift sucrose, flour, and salt. Whisk together the whole eggs and yolks.","Add dry ingredients in to the eggs in two additions, mixing just until incorporated. Slowly add the vegetable oil, followed by the milk and rum.","Chill and allow to rest for several hours; strain if necessary.","Cook one-ounce portioned crepe batter in small non-stick pans. Cool, wrap, and reserve for assembly."]', '[]', 'Pastry_Module_3_Course_6.pdf', 231);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Caramel Ice Cream', 'Frozen Desserts', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 19, NULL, NULL, '[]', '[{"name":"sucrose","amounts":[["140","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["","as needed"]],"bakers_pct":null,"component":null},{"name":"heavy cream (36% fat)","amounts":[["220","grams"]],"bakers_pct":null,"component":null},{"name":"whole milk","amounts":[["570","grams"]],"bakers_pct":null,"component":null},{"name":"nonfat dry milk powder","amounts":[["34","grams"]],"bakers_pct":null,"component":null},{"name":"dextrose","amounts":[["20","grams"]],"bakers_pct":null,"component":null},{"name":"invert sugar","amounts":[["20","grams"]],"bakers_pct":null,"component":null},{"name":"ice cream stabilizer","amounts":[["4","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["2","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Place the sugar and water to cover in a medium sauce pan. Cook over medium heat to a medium dark caramel. Remove from heat and gradually add the cream.","Whisk in the milk and nonfat milk powder and return to medium heat. Add the, dextrose, invert sugar, stabilizer, and salt. Heat, while whisking, to 85°C/185°F.","Remove from heat and homogenize with an immersion blender. Chill in an ice water bath. Allow the mix to mature at least 12 hours if possible.","Process in batch freezer; extract the mix at -5˚C/23˚F. Alternatively, transfer to PacoJet canisters and freeze; process as needed."]', '[]', 'PA_Mod_01_Instructor.pdf', 318);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Champagne Granite', 'Frozen Desserts', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 18, NULL, NULL, '[]', '[{"name":"sucrose","amounts":[["150","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["350","grams"]],"bakers_pct":null,"component":null},{"name":"Champagne or sparkling wine","amounts":[["750","grams"]],"bakers_pct":null,"component":null},{"name":"gelatin sheet, hydrated (optional)","amounts":[["1","piece"]],"bakers_pct":null,"component":null}]', NULL, '["Combine the sucrose and water and bring to a boil.","Add the sparkling wine (and gelatin, if used); strain.","Pour into shallow pans and begin to freeze, stirring every fifteen minutes with a fork.","Once the proper ice consistency is achieved, place granité in covered containers and store in the freezer."]', '[]', 'PA_Mod_01_Instructor.pdf', 278);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Chocolate Ice Cream “A”', 'Frozen Desserts', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 19, NULL, NULL, '[]', '[{"name":"whole milk","amounts":[["560","grams"]],"bakers_pct":null,"component":null},{"name":"nonfat dry milk powder","amounts":[["45","grams"]],"bakers_pct":null,"component":null},{"name":"heavy cream (36% fat)","amounts":[["170","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose","amounts":[["140","grams"]],"bakers_pct":null,"component":null},{"name":"glucose powder","amounts":[["40","grams"]],"bakers_pct":null,"component":null},{"name":"ice cream stabilizer","amounts":[["5","grams"]],"bakers_pct":null,"component":null},{"name":"cocoa powder (20-22% fat)","amounts":[["40","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Place the milk, nonfat milk powder, and cream in a sauce pan over medium heat. Add the sucrose, glucose, stabilizer, and cocoa. Heat, while whisking, to 85°C/185°F.","Remove from heat and homogenize with an immersion blender. Chill in an ice water bath. Allow the mix to mature at least 12 hours if possible","Process in batch freezer; extract the mix at -5˚C/23˚F. Alternatively, transfer to PacoJet canisters and freeze; process as needed."]', '[]', 'PA_Mod_01_Instructor.pdf', 309);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Chocolate Ice Cream “B”', 'Frozen Desserts', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 19, NULL, NULL, '[]', '[{"name":"whole milk","amounts":[["600","grams"]],"bakers_pct":null,"component":null},{"name":"nonfat dry milk powder","amounts":[["34","grams"]],"bakers_pct":null,"component":null},{"name":"heavy cream (36% fat)","amounts":[["65","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose","amounts":[["55","grams"]],"bakers_pct":null,"component":null},{"name":"invert sugar","amounts":[["60","grams"]],"bakers_pct":null,"component":null},{"name":"ice cream stabilizer","amounts":[["4","grams"]],"bakers_pct":null,"component":null},{"name":"dark chocolate (74%)","amounts":[["185","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Place the milk, nonfat milk powder, and cream in a sauce pan over medium heat. Add the sucrose, invert sugar, and stabilizer. Heat, while whisking, to 85°C/185°F.","Remove from heat, add the chocolate and homogenize with an immersion blender. Chill in an ice water bath. Allow the mix to mature at least 12 hours if possible.","Process in batch freezer; extract the mix at -5˚C/23˚F. Alternatively, transfer to PacoJet canisters and freeze; process as needed."]', '[]', 'PA_Mod_01_Instructor.pdf', 310);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Chocolate Peanut Tart Praline Citrus Sorbet', 'Frozen Desserts', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 73, NULL, NULL, '[]', '[{"name":"sucrose (1)","amounts":[["63","grams"]],"bakers_pct":null,"component":null},{"name":"sorbet stabilizer","amounts":[["4","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["590","grams"]],"bakers_pct":null,"component":null},{"name":"glucose syrup","amounts":[["84","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose (2)","amounts":[["190","grams"]],"bakers_pct":null,"component":null},{"name":"orange juice","amounts":[["84","grams"]],"bakers_pct":null,"component":null},{"name":"lemon juice","amounts":[["168","grams"]],"bakers_pct":null,"component":null},{"name":"praline paste","amounts":[["255","grams"]],"bakers_pct":null,"component":null}]', '[["1438","grams"]]', '["Whisk together the first measurement of sucrose (1) and stabilizer.","Heat water to 50˚C/120˚F. Whisk in stabilizer mixture, then the remaining sucrose (2) and glucose, bring to a boil for about 30 seconds. Remove from heat and chill; allow syrup to mature for at least 4 hours.","Combine juices, praline paste and syrup and process in batch freezer; extract the mix at -5˚C/23˚F."]', '[]', 'Pastry_Module_3_Course_6.pdf', 209);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Cinnamon Ice Cream', 'Frozen Desserts', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 19, NULL, NULL, '[]', '[{"name":"whole milk","amounts":[["550","grams"]],"bakers_pct":null,"component":null},{"name":"nonfat dry milk powder","amounts":[["35","grams"]],"bakers_pct":null,"component":null},{"name":"heavy cream (36% fat)","amounts":[["230","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose (1)","amounts":[["50","grams"]],"bakers_pct":null,"component":null},{"name":"dextrose","amounts":[["20","grams"]],"bakers_pct":null,"component":null},{"name":"invert sugar","amounts":[["20","grams"]],"bakers_pct":null,"component":null},{"name":"ice cream stabilizer","amounts":[["4","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose (2)","amounts":[["90","grams"]],"bakers_pct":null,"component":null},{"name":"cinnamon, ground","amounts":[["2","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Place the milk, nonfat milk powder, and cream in a sauce pan over medium heat. Add the sucrose (1), dextrose, invert sugar, and stabilizer. Heat, while whisking, to"]', '[]', 'PA_Mod_01_Instructor.pdf', 321);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Cocoa Sorbet', 'Frozen Desserts', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 18, NULL, NULL, '[]', '[{"name":"sucrose (1)","amounts":[["50","grams"]],"bakers_pct":null,"component":null},{"name":"sorbet stabilizer","amounts":[["4","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["670","grams"]],"bakers_pct":null,"component":null},{"name":"nonfat milk powder","amounts":[["20","grams"]],"bakers_pct":null,"component":null},{"name":"cocoa powder","amounts":[["20","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose (2)","amounts":[["95","grams"]],"bakers_pct":null,"component":null},{"name":"invert sugar","amounts":[["50","grams"]],"bakers_pct":null,"component":null},{"name":"unsweetened chocolate, chopped","amounts":[["100","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine the first measurement of sucrose (1) and stabilizer.","Heat water to 50˚C/120˚F. Whisk in the stabilizer mixture, and then the milk powder, cocoa powder, remaining sucrose (2), and invert sugar and bring just to a boil. Remove from heat. Blend in the unsweetened chocolate with an immersion blender.","Chill and allow syrup to mature at least 4 hours.","Process in batch freezer; extract the mix at -5˚C/23˚F.","Transfer finished sorbet to blast chiller to harden at minimum of -18˚C/0˚F. Alternatively, transfer to PacoJet canisters and freeze; process as needed."]', '[]', 'PA_Mod_01_Instructor.pdf', 289);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Coconut Sorbet', 'Frozen Desserts', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 18, NULL, NULL, '[]', '[{"name":"sucrose (1)","amounts":[["30","grams"]],"bakers_pct":null,"component":null},{"name":"sorbet stabilizer","amounts":[["5","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["550","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose (2)","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"glucose powder","amounts":[["110","grams"]],"bakers_pct":null,"component":null},{"name":"coconut purée","amounts":[["750","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine the first measurement of sucrose (1) and stabilizer.","Heat water to 50˚C/120˚F. Whisk in the stabilizer mixture, and then the remaining sucrose (2) and glucose and bring just to a boil. Remove from heat.","Chill and allow syrup to mature.","Combine base syrup with fruit purée and briefly blend with an immersion blender. Process in batch freezer; extract the mix at -5˚C/23˚F.","Transfer finished sorbet to blast chiller to harden at minimum of -18˚C/0˚F. Alternatively, transfer to PacoJet canisters and freeze; process as needed"]', '[]', 'PA_Mod_01_Instructor.pdf', 283);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Coffee Granite', 'Frozen Desserts', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 18, NULL, NULL, '[]', '[{"name":"sucrose","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["250","grams"]],"bakers_pct":null,"component":null},{"name":"strong brewed coffee","amounts":[["750","grams"]],"bakers_pct":null,"component":null},{"name":"coffee extract","amounts":[["10","grams"]],"bakers_pct":null,"component":null},{"name":"gelatin sheet, hydrated (optional)","amounts":[["1","piece"]],"bakers_pct":null,"component":null}]', NULL, '["Combine the sucrose and water and bring to a boil.","Add the coffee and extract (and gelatin, if used); strain.","Pour into shallow pans and begin to freeze, stirring every fifteen minutes with a fork.","Once the proper ice consistency is achieved, place granité in covered containers and store in the freezer."]', '[]', 'PA_Mod_01_Instructor.pdf', 276);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Coffee Ice Cream', 'Frozen Desserts', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 19, NULL, NULL, '[]', '[{"name":"whole milk","amounts":[["550","grams"]],"bakers_pct":null,"component":null},{"name":"nonfat dry milk powder","amounts":[["35","grams"]],"bakers_pct":null,"component":null},{"name":"heavy cream (36% fat)","amounts":[["230","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose","amounts":[["140","grams"]],"bakers_pct":null,"component":null},{"name":"dextrose","amounts":[["20","grams"]],"bakers_pct":null,"component":null},{"name":"invert sugar","amounts":[["20","grams"]],"bakers_pct":null,"component":null},{"name":"ice cream stabilizer","amounts":[["4","grams"]],"bakers_pct":null,"component":null},{"name":"coffee extract","amounts":[["35","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Place the milk, nonfat milk powder, and cream in a sauce pan over medium heat. Add the sucrose, dextrose, invert sugar, and stabilizer. Heat, while whisking, to 85°C/185°F.","Remove from heat add the coffee extract; homogenize with an immersion blender. Chill in an ice water bath. Allow the mix to mature at least 12 hours if possible","Process in batch freezer; extract the mix at -5˚C/23˚F. Alternatively, transfer to PacoJet canisters and freeze; process as needed."]', '[]', 'PA_Mod_01_Instructor.pdf', 320);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Custard Base (10% Milk Fat)', 'Frozen Desserts', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 19, NULL, NULL, '[]', '[{"name":"whole milk","amounts":[["430","grams"]],"bakers_pct":null,"component":null},{"name":"nonfat dry milk powder","amounts":[["50","grams"]],"bakers_pct":null,"component":null},{"name":"heavy cream (36% fat)","amounts":[["245","grams"]],"bakers_pct":null,"component":null},{"name":"dextrose","amounts":[["22","grams"]],"bakers_pct":null,"component":null},{"name":"invert sugar","amounts":[["21","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose","amounts":[["130","grams"]],"bakers_pct":null,"component":null},{"name":"ice cream stabilizer","amounts":[["2","grams"]],"bakers_pct":null,"component":null},{"name":"egg yolks","amounts":[["100","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Place the milk, nonfat milk powder, and cream in a sauce pan over medium heat. Add the dextrose, and invert sugar. Meanwhile, whisk the sucrose and stabilizer into the egg yolks.","Carefully temper the warm base into the egg yolk mixture and continue to heat, while whisking, to 85°C/185°F.","Remove from heat and homogenize with an immersion blender. Chill in an ice water bath. Allow the mix to mature at least 12 hours if possible.","Process in batch freezer; extract the mix at -5˚C/23˚F. Alternatively, transfer to PacoJet canisters and freeze; process as needed."]', '[]', 'PA_Mod_01_Instructor.pdf', 308);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Dark Chocolate Cremeux Coconut Sorbet', 'Frozen Desserts', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 73, NULL, NULL, '[]', '[{"name":"sucrose (1)","amounts":[["20","grams"]],"bakers_pct":null,"component":null},{"name":"ice cream stabilizer","amounts":[["3","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["365","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose (2)","amounts":[["150","grams"]],"bakers_pct":null,"component":null},{"name":"glucose powder","amounts":[["75","grams"]],"bakers_pct":null,"component":null},{"name":"coconut purée","amounts":[["500","grams"]],"bakers_pct":null,"component":null}]', '[["1113","grams"]]', '["Whisk the first measurement of sucrose (1) and stabilizer.","Heat water to 50˚C/120˚F. Whisk in stabilizer mixture, then remaining sucrose (2) and glucose powder, bring to just to a boil. Remove from heat and chill; allow syrup to mature for at least 4 hours if possible.","Combine purée and syrup and process in batch freezer; extract the mix at -"]', '[]', 'Pastry_Module_3_Course_6.pdf', 217);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Earl Grey Tea Granite', 'Frozen Desserts', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 18, NULL, NULL, '[]', '[{"name":"sucrose","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["250","grams"]],"bakers_pct":null,"component":null},{"name":"Earl Grey tea infusion*","amounts":[["750","grams"]],"bakers_pct":null,"component":null},{"name":"orange zest, grated","amounts":[["5","grams"]],"bakers_pct":null,"component":null},{"name":"lemon juice","amounts":[["10","grams"]],"bakers_pct":null,"component":null},{"name":"gelatin sheet, hydrated (optional)","amounts":[["1","piece"]],"bakers_pct":null,"component":null}]', NULL, '["Combine the sucrose and water and bring to a boil.","Add the infusion, orange zest, and lemon juice (and gelatin, if used); strain.","Pour into shallow pans and begin to freeze, stirring every fifteen minutes with a fork.","Once the proper ice consistency is achieved, place granité in covered containers and store in the freezer."]', '["*For the tea infusion, infuse 12g loose Earl Grey tea into 800g of boiled water."]', 'PA_Mod_01_Instructor.pdf', 278);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Exotic Fruit Granite', 'Frozen Desserts', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 18, NULL, NULL, '[]', '[{"name":"sucrose","amounts":[["85","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["300","grams"]],"bakers_pct":null,"component":null},{"name":"passion fruit purée","amounts":[["150","grams"]],"bakers_pct":null,"component":null},{"name":"mango purée","amounts":[["180","grams"]],"bakers_pct":null,"component":null},{"name":"pineapple purée","amounts":[["150","grams"]],"bakers_pct":null,"component":null},{"name":"gelatin sheet, hydrated (optional)","amounts":[["1","piece"]],"bakers_pct":null,"component":null}]', NULL, '["Combine the sucrose and water and bring to a boil.","Add the fruit purées (and gelatin, if used); strain.","Pour into shallow pans and begin to freeze, stirring every fifteen minutes with a fork.","Once the proper ice consistency is achieved, place granité in covered containers and store in the freezer."]', '[]', 'PA_Mod_01_Instructor.pdf', 277);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Frozen Chocolate Parfait', 'Frozen Desserts', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 20, NULL, NULL, '[]', '[{"name":"whole milk","amounts":[["210","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose","amounts":[["170","grams"]],"bakers_pct":null,"component":null},{"name":"egg yolks","amounts":[["170","grams"]],"bakers_pct":null,"component":null},{"name":"dark chocolate, melted","amounts":[["150","grams"]],"bakers_pct":null,"component":null},{"name":"heavy cream, whipped","amounts":[["340","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Make a Crème Anglaise by placing the milk in a sauce pan and bring just to boil; meanwhile, whisk together the egg yolks and sucrose. Temper the milk into the yolk mixture and return to low heat and gently cook to 85°C/185°F or until nappe.","Remove from heat and transfer to the bowl of a stand mixer and whip until cool.","Fold a small amount of whipped cream into the melted chocolate, followed by half of the whipped Anglaise mixture. Gently fold in the remaining Anglaise mixture and the remaining whipped cream.","Transfer to prepared molds and freeze."]', '[]', 'PA_Mod_01_Instructor.pdf', 331);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Frozen Ginger Parfait, Passion Fruit Sorbet, Meringue Frozen Ginger Parfait', 'Frozen Desserts', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 73, NULL, NULL, '[]', '[{"name":"ginger, peeled, and thinly sliced","amounts":[["120","grams"]],"bakers_pct":null,"component":null},{"name":"heavy cream","amounts":[["200","grams"]],"bakers_pct":null,"component":null},{"name":"whole milk","amounts":[["150","grams"]],"bakers_pct":null,"component":null},{"name":"gelatin sheets, bloomed","amounts":[["2","each"]],"bakers_pct":null,"component":null},{"name":"egg yolk","amounts":[["120","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose","amounts":[["120","grams"]],"bakers_pct":null,"component":null}]', '[["710","grams"]]', '["Place the ginger in a saucepan and cover with cold water. Bring to a boil and drain.","Divide the ginger evenly between the cream and the milk and allow to infuse, chilled, at least 12 hours if possible","Transfer the milk mixture to a saucepan and bring to a boil. Meanwhile, combine the egg yolks and sugar in a medium mixing bowl.","Strain and then temper the hot milk into the yolk mixture, return to low heat, and continue to cook just until slightly thickened. Add the gelatin.","Transfer the anglaise to a mixer bowl and whip at high speed until cool to the touch.","Strain the cream and whip to soft peaks. Fold into the whipped anglaise and deposit into low 8cm (3”) ring molds. Freeze."]', '[]', 'Pastry_Module_3_Course_6.pdf', 223);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Grapefruit Tarragon Granite', 'Frozen Desserts', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 18, NULL, NULL, '[]', '[{"name":"tarragon leaves","amounts":[["10","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose","amounts":[["90","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["250","grams"]],"bakers_pct":null,"component":null},{"name":"grapefruit juice","amounts":[["750","grams"]],"bakers_pct":null,"component":null},{"name":"lemon juice","amounts":[["10","grams"]],"bakers_pct":null,"component":null},{"name":"gelatin sheet, hydrated (optional)","amounts":[["1","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine the sucrose and water and bring to a boil. Remove from heat, add the tarragon, cover, and infuse for 15 minutes.","Add the grapefruit and lemon juice (and gelatin, if used); strain.","Pour into shallow pans and begin to freeze, stirring every fifteen minutes with a fork.","Once the proper ice consistency is achieved, place granité in covered containers and store in the freezer."]', '[]', 'PA_Mod_01_Instructor.pdf', 277);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Hazelnut Ice Cream', 'Frozen Desserts', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 19, NULL, NULL, '[]', '[{"name":"whole milk","amounts":[["560","grams"]],"bakers_pct":null,"component":null},{"name":"nonfat dry milk powder","amounts":[["45","grams"]],"bakers_pct":null,"component":null},{"name":"heavy cream (36% fat)","amounts":[["128","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose","amounts":[["115","grams"]],"bakers_pct":null,"component":null},{"name":"dextrose","amounts":[["25","grams"]],"bakers_pct":null,"component":null},{"name":"glucose powder","amounts":[["30","grams"]],"bakers_pct":null,"component":null},{"name":"ice cream stabilizer","amounts":[["5","grams"]],"bakers_pct":null,"component":null},{"name":"hazelnut paste (100%)","amounts":[["90","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["2","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Place the milk, nonfat milk powder, and cream in a sauce pan over medium heat. Add the sucrose, dextrose, glucose, and stabilizer. Heat, while whisking, to 85°C/185°F.","Remove from heat, add hazelnut paste and salt; homogenize with an immersion blender. Chill in an ice water bath. Allow the mix to mature at least 12 hours if possible.","Process in batch freezer; extract the mix at -5˚C/23˚F. Alternatively, transfer to PacoJet canisters and freeze; process as needed."]', '[]', 'PA_Mod_01_Instructor.pdf', 312);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Hazelnut Praline Semifreddo', 'Frozen Desserts', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 20, NULL, NULL, '[]', '[{"name":"heavy cream (1)","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"hazelnut praline paste","amounts":[["275","grams"]],"bakers_pct":null,"component":null},{"name":"egg whites","amounts":[["70","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose","amounts":[["60","grams"]],"bakers_pct":null,"component":null},{"name":"heavy cream, whipped (2)","amounts":[["275","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Heat the first measurement of cream (1) until just warmed; add the praline paste and whisk until smooth.","Combine the egg whites and sucrose in a KitchenAid bowl and heat over a double boiler, whisking constantly, to 55°C/130°F. Whip to medium peaks and cool.","Fold one third of meringue into the praline cream mixture before folding in remaining whites, folding until thoroughly combined. until smooth. Fold in the whipped cream.","Transfer to prepared molds and freeze."]', '[]', 'PA_Mod_01_Instructor.pdf', 332);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Honey Ice Cream', 'Frozen Desserts', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 19, NULL, NULL, '[]', '[{"name":"whole milk","amounts":[["540","grams"]],"bakers_pct":null,"component":null},{"name":"nonfat dry milk powder","amounts":[["40","grams"]],"bakers_pct":null,"component":null},{"name":"heavy cream (36% fat)","amounts":[["230","grams"]],"bakers_pct":null,"component":null},{"name":"honey","amounts":[["80","grams"]],"bakers_pct":null,"component":null},{"name":"glucose powder","amounts":[["40","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose","amounts":[["45","grams"]],"bakers_pct":null,"component":null},{"name":"ice cream stabilizer","amounts":[["5","grams"]],"bakers_pct":null,"component":null},{"name":"egg yolks","amounts":[["40","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Place the milk, nonfat milk powder, and cream in a sauce pan over medium heat. Add the honey, and glucose. Meanwhile, whisk the sucrose and stabilizer into the egg yolks.","Carefully temper the warm base into the egg yolk mixture and continue to heat, while whisking, to 85°C/185°F.","Remove from heat and homogenize with an immersion blender. Chill in an ice water bath. Allow the mix to mature at least 12 hours if possible.","Process in batch freezer; extract the mix at -5˚C/23˚F. Alternatively, transfer to PacoJet canisters and freeze; process as needed."]', '[]', 'PA_Mod_01_Instructor.pdf', 319);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Honey Pistachio Parfait', 'Frozen Desserts', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 20, NULL, NULL, '[]', '[{"name":"egg whites","amounts":[["70","grams"]],"bakers_pct":null,"component":null},{"name":"honey","amounts":[["140","grams"]],"bakers_pct":null,"component":null},{"name":"heavy cream","amounts":[["500","grams"]],"bakers_pct":null,"component":null},{"name":"caramelized pistachios, crushed","amounts":[["150","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Prepare an Italian-style meringue by bringing the honey to a boil and pouring into the whipping egg whites.","When cool, fold in the whipped cream and crushed nuts.","Transfer to prepared molds. Freeze. Suggested combinations of components for final dessert presentations:  Vanilla Ice Cream, Caramel Ice Cream, Chocolate Sauce, Tuile  Chocolate Ice Cream, Vanilla Ice Cream, Caramel Sauce, Caramelized Rice  Passion Fruit Sorbet, Honey Ice Cream, Passion Fruit Coulis, Caramelized Pistachio  Pistachio Ice Cream, Raspberry Ice Cream, Raspberry Coulis, Meringue Buttons  Black Currant Ice Cream, Basil Ice Cream, Lemon Curd, Meringue Buttons  Vanilla Ice Cream, Cinnamon Ice Cream, Red Wine Caramel, Caramelized Rice  Mango Ice Cream, Coconut Sorbet, Pineapple Coconut Anglaise, Pizzelle  Coffee Ice Cream, Hazelnut Ice Cream, Chocolate Shell, Pizzelle"]', '[]', 'PA_Mod_01_Instructor.pdf', 333);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Honey Semifreddo', 'Frozen Desserts', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 71, NULL, NULL, '[]', '[{"name":"egg whites","amounts":[["105","grams"]],"bakers_pct":null,"component":null},{"name":"honey","amounts":[["240","grams"]],"bakers_pct":null,"component":null},{"name":"heavy cream whipped to soft peaks","amounts":[["750","grams"]],"bakers_pct":null,"component":null}]', '[["1095","grams"]]', '["Prepare an Italian meringue by bringing the honey just to a boil and pouring into the whipping egg whites.","Fold in whipped cream and pipe into to prepared molds, filling roughly halfway. Insert one piece of the molded lemon sorbet and top with additional semifreddo and seal the mold with a disc of the almond sponge. Freeze."]', '[]', 'Pastry_Module_3_Course_6.pdf', 151);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Honey-Lemon Semifreddo Lemon Sorbet', 'Frozen Desserts', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 71, NULL, NULL, '[]', '[{"name":"sucrose (1)","amounts":[["30","grams"]],"bakers_pct":null,"component":null},{"name":"sorbet stabilizer","amounts":[["3","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["450","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose (2)","amounts":[["180","grams"]],"bakers_pct":null,"component":null},{"name":"dry nonfat milk powder","amounts":[["10","grams"]],"bakers_pct":null,"component":null},{"name":"glucose powder","amounts":[["40","grams"]],"bakers_pct":null,"component":null},{"name":"invert sugar","amounts":[["20","grams"]],"bakers_pct":null,"component":null},{"name":"lemon juice","amounts":[["250","grams"]],"bakers_pct":null,"component":null}]', '[["993","grams"]]', '["Whisk together first measurement of sucrose (1) and stabilizer.","Heat the water to 50˚C/120˚F. Whisk in stabilizer mixture, then remaining sucrose (2), milk powder, glucose, and invert sugar; bring just to a boil. Remove from heat and chill; allow syrup to mature for at least 4 hours if possible.","Combine the lemon juice and syrup and process in batch freezer; extract the mix at -5˚C/23˚F.","Pipe the lemon sorbet into small hemisphere molds and place in blast freezer."]', '[]', 'Pastry_Module_3_Course_6.pdf', 149);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Lemon Granite', 'Frozen Desserts', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 18, NULL, NULL, '[]', '[{"name":"sucrose","amounts":[["150","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["350","grams"]],"bakers_pct":null,"component":null},{"name":"lemon juice","amounts":[["650","grams"]],"bakers_pct":null,"component":null},{"name":"gelatin sheet, hydrated (optional)","amounts":[["1","piece"]],"bakers_pct":null,"component":null}]', NULL, '["Combine the sucrose and water and bring to a boil.","Add the lemon juice (and gelatin, if used); strain.","Pour into shallow pans and begin to freeze, stirring every fifteen minutes with a fork.","Once the proper ice consistency is achieved, place granité in covered containers and store in the freezer."]', '[]', 'PA_Mod_01_Instructor.pdf', 276);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Malt Milk Chocolate Ice Cream', 'Frozen Desserts', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 19, NULL, NULL, '[]', '[{"name":"whole milk","amounts":[["465","grams"]],"bakers_pct":null,"component":null},{"name":"nonfat dry milk powder","amounts":[["20","grams"]],"bakers_pct":null,"component":null},{"name":"heavy cream (36% fat)","amounts":[["175","grams"]],"bakers_pct":null,"component":null},{"name":"malted milk powder","amounts":[["75","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose","amounts":[["90","grams"]],"bakers_pct":null,"component":null},{"name":"ice cream stabilizer","amounts":[["4","grams"]],"bakers_pct":null,"component":null},{"name":"egg yolks","amounts":[["90","grams"]],"bakers_pct":null,"component":null},{"name":"milk chocolate (31%)","amounts":[["55","grams"]],"bakers_pct":null,"component":null},{"name":"dark chocolate (74%)","amounts":[["25","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Place the milk, nonfat milk powder, and cream in a sauce pan over medium heat. Add the malt powder. Meanwhile, whisk the sucrose and stabilizer into the egg yolks.","Carefully temper the warm base into the egg yolk mixture and continue to heat, while whisking, to 85°C/185°F.","Remove from heat and add the chocolates; homogenize with an immersion blender. Chill in an ice water bath. Allow the mix to mature at least 12 hours if possible.","Process in batch freezer; extract the mix at -5˚C/23˚F. Alternatively, transfer to PacoJet canisters and freeze; process as needed."]', '[]', 'PA_Mod_01_Instructor.pdf', 311);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Mandarin Sorbet', 'Frozen Desserts', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 71, NULL, NULL, '[]', '[{"name":"sucrose (1)","amounts":[["40","grams"]],"bakers_pct":null,"component":null},{"name":"sorbet stabilizer","amounts":[["5","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["245","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose (2)","amounts":[["160","grams"]],"bakers_pct":null,"component":null},{"name":"glucose powder","amounts":[["50","grams"]],"bakers_pct":null,"component":null},{"name":"mandarin purée","amounts":[["1000","grams"]],"bakers_pct":null,"component":null}]', '[["1500","grams"]]', '["Whisk together the first measurement of sucrose (1) and stabilizer.","Heat water to 50˚C/ 120˚F. Whisk in the stabilizer mixture, then the remaining sucrose (2) and glucose powder and bring to a boil for about 30 seconds. Remove from heat, chill, and allow syrup to mature.","Combine syrup and purée and process in batch freezer; extract the mix at -"]', '[]', 'Pastry_Module_3_Course_6.pdf', 167);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Mango Cheese Parfait', 'Frozen Desserts', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 73, NULL, NULL, '[]', '[{"name":"gelatin sheets, bloomed","amounts":[["2","each"]],"bakers_pct":null,"component":null},{"name":"water, cold","amounts":[["25","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose","amounts":[["75","grams"]],"bakers_pct":null,"component":null},{"name":"fine sea salt","amounts":[["1","gram"]],"bakers_pct":null,"component":null},{"name":"butter, softened","amounts":[["65","grams"]],"bakers_pct":null,"component":null},{"name":"cream cheese, softened","amounts":[["150","grams"]],"bakers_pct":null,"component":null},{"name":"crème fraiche","amounts":[["35","grams"]],"bakers_pct":null,"component":null},{"name":"mango purée","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"lime juice","amounts":[["10","grams"]],"bakers_pct":null,"component":null},{"name":"heavy cream, whipped","amounts":[["165","grams"]],"bakers_pct":null,"component":null}]', '[["1429","grams"]]', '["Bloom the gelatin in full measurement of cold water. Gently heat to dissolve when needed.","In a mixer bowl, combine the sucrose, salt, and butter, creaming the mixture well. Slowly add the cream cheese, occasionally scraping down the sides of the bowl. Follow with the addition of the crème fraiche, mango purée, lime juice, and dissolved gelatin.","Fold into the whipped cream and portion into 5cm (2”) ring molds arranged on a flat acetate-lined sheet pan; top each mold with the previously baked coconut sablée. Freeze."]', '[]', 'Pastry_Module_3_Course_6.pdf', 237);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Mango Cheese Parfait Coconut Sablee', 'Frozen Desserts', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 73, NULL, NULL, '[]', '[{"name":"butter, softened","amounts":[["75","grams"]],"bakers_pct":null,"component":null},{"name":"coconut oil, softened","amounts":[["50","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose","amounts":[["80","grams"]],"bakers_pct":null,"component":null},{"name":"dry coconut, finely ground","amounts":[["25","grams"]],"bakers_pct":null,"component":null},{"name":"egg yolk","amounts":[["55","grams"]],"bakers_pct":null,"component":null},{"name":"dark rum","amounts":[["5","grams"]],"bakers_pct":null,"component":null},{"name":"fine sea salt","amounts":[["3","grams"]],"bakers_pct":null,"component":null},{"name":"baking powder","amounts":[["5","grams"]],"bakers_pct":null,"component":null},{"name":"AP flour","amounts":[["180","grams"]],"bakers_pct":null,"component":null}]', '[["478","grams"]]', '["In a mixer bowl fitted with the paddle attachment, cream together butter, coconut oil, sucrose, and dry coconut.","Slowly add egg yolks, followed by the rum, scraping down the bowl after each addition.","Add flour, salt and baking powder, mixing just until combined. Chill.","Roll or sheet dough thin and cut 4cm discs. Transfer to a parchment or Silpat-lined sheet pan and bake at 150˚C/300˚F for 10-12 minutes."]', '[]', 'Pastry_Module_3_Course_6.pdf', 236);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Mango Ice Cream', 'Frozen Desserts', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 19, NULL, NULL, '[]', '[{"name":"whole milk","amounts":[["335","grams"]],"bakers_pct":null,"component":null},{"name":"nonfat dry milk powder","amounts":[["70","grams"]],"bakers_pct":null,"component":null},{"name":"heavy cream (36% fat)","amounts":[["80","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose","amounts":[["125","grams"]],"bakers_pct":null,"component":null},{"name":"glucose powder","amounts":[["20","grams"]],"bakers_pct":null,"component":null},{"name":"invert sugar","amounts":[["15","grams"]],"bakers_pct":null,"component":null},{"name":"ice cream stabilizer","amounts":[["5","grams"]],"bakers_pct":null,"component":null},{"name":"mango purée","amounts":[["350","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Place the milk, nonfat milk powder, and cream in a sauce pan over medium heat. Add the sucrose, glucose, invert sugar and stabilizer. Heat, while whisking, to 85°C/185°F.","Remove from heat and homogenize with an immersion blender. Chill in an ice water bath. Allow the mix to mature at least 12 hours if possible.","Thoroughly blend the base mix and mango purée. Process in batch freezer; extract the mix at -5˚C/23˚F. Alternatively, transfer to PacoJet canisters and freeze; process as needed."]', '[]', 'PA_Mod_01_Instructor.pdf', 315);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Melon Sorbet', 'Frozen Desserts', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 18, NULL, NULL, '[]', '[{"name":"sucrose (1)","amounts":[["40","grams"]],"bakers_pct":null,"component":null},{"name":"sorbet stabilizer","amounts":[["5","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["270","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose (2)","amounts":[["140","grams"]],"bakers_pct":null,"component":null},{"name":"glucose powder","amounts":[["45","grams"]],"bakers_pct":null,"component":null},{"name":"melon purée","amounts":[["1000","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine the first measurement of sucrose (1) and stabilizer.","Heat water to 50˚C/120˚F. Whisk in the stabilizer mixture, and then the remaining sucrose (2) and glucose and bring just to a boil. Remove from heat.","Chill and allow syrup to mature.","Combine base syrup with fruit purée and briefly blend with an immersion blender. Process in batch freezer; extract the mix at -5˚C/23˚F.","Transfer finished sorbet to blast chiller to harden at minimum of -18˚C/0˚F. Alternatively, transfer to PacoJet canisters and freeze; process as needed."]', '[]', 'PA_Mod_01_Instructor.pdf', 282);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Olive Oil Ice Cream', 'Frozen Desserts', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 71, NULL, NULL, '[]', '[{"name":"whole milk","amounts":[["625","grams"]],"bakers_pct":null,"component":null},{"name":"dry nonfat milk powder","amounts":[["80","grams"]],"bakers_pct":null,"component":null},{"name":"heavy cream (36% fat)","amounts":[["250","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose","amounts":[["115","grams"]],"bakers_pct":null,"component":null},{"name":"glucose powder","amounts":[["115","grams"]],"bakers_pct":null,"component":null},{"name":"invert sugar","amounts":[["25","grams"]],"bakers_pct":null,"component":null},{"name":"ice cream stabilizer","amounts":[["5","grams"]],"bakers_pct":null,"component":null},{"name":"egg yolks","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"extra virgin olive oil","amounts":[["125","grams"]],"bakers_pct":null,"component":null}]', '[["1440","grams"]]', '["Combine the sucrose and ice cream stabilizer and set aside.","Combine the milk, cream, and milk powder and begin heating.","Add the sucrose and stabilizer, glucose, invert sugar and egg yolk at Heat base to 85˚C/185˚F and hold for two minutes.","Cool base to 4˚C/40˚F. At approx. 65˚C/150˚F add olive oil and homogenize base with a handheld immersion blender for approximately 45 seconds. Mature base at 4˚C/40˚F for 12-16 hours if possible.","Process in a batch freezer to temperature of -5˚C/23˚F and extract. Transfer finished ice cream to blast chiller to harden at minimum of -18˚C/0˚F."]', '[]', 'Pastry_Module_3_Course_6.pdf', 142);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Orange Liquor Souffle Glace', 'Frozen Desserts', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 20, NULL, NULL, '[]', '[{"name":"egg yolks","amounts":[["200","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose","amounts":[["200","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["40","grams"]],"bakers_pct":null,"component":null},{"name":"heavy cream, whipped","amounts":[["250","grams"]],"bakers_pct":null,"component":null},{"name":"orange zest","amounts":[["2","grams"]],"bakers_pct":null,"component":null},{"name":"orange liquor","amounts":[["30","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Place the egg yolks in a stand mixer fitted with the whip attachment; meanwhile, combine the sucrose and water in a sauce pan and cook to 115°C/240°F while whipping the egg yolks.","Remove the syrup from heat and slowly pour into the whipping yolks; continue to whip until cool.","Fold into the whip cream; fold in the orange zest and Grand Marnier. Transfer to prepared molds and freeze."]', '[]', 'PA_Mod_01_Instructor.pdf', 330);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Passion Fruit Sorbet', 'Frozen Desserts', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 18, NULL, NULL, '[]', '[{"name":"sucrose (1)","amounts":[["38","grams"]],"bakers_pct":null,"component":null},{"name":"sorbet stabilizer","amounts":[["10","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["625","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose (2)","amounts":[["350","grams"]],"bakers_pct":null,"component":null},{"name":"glucose powder","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"passion fruit purée","amounts":[["750","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine the first measurement of sucrose (1) and stabilizer.","Heat water to 50˚C/120˚F. Whisk in the stabilizer mixture, and then the remaining sucrose (2), and glucose and bring just to a boil. Remove from heat.","Chill and allow syrup to mature.","Combine base syrup with fruit purée and briefly blend with an immersion blender. Process in batch freezer; extract the mix at -5˚C/23˚F.","Transfer finished sorbet to blast chiller to harden at minimum of -18˚C/0˚F. Alternatively, transfer to PacoJet canisters and freeze; process as needed."]', '[]', 'PA_Mod_01_Instructor.pdf', 286);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Pistachio Ice Cream', 'Frozen Desserts', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 19, NULL, NULL, '[]', '[{"name":"whole milk","amounts":[["495","grams"]],"bakers_pct":null,"component":null},{"name":"nonfat dry milk powder","amounts":[["43","grams"]],"bakers_pct":null,"component":null},{"name":"heavy cream (36% fat)","amounts":[["220","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose","amounts":[["90","grams"]],"bakers_pct":null,"component":null},{"name":"dextrose","amounts":[["25","grams"]],"bakers_pct":null,"component":null},{"name":"glucose powder","amounts":[["30","grams"]],"bakers_pct":null,"component":null},{"name":"ice cream stabilizer","amounts":[["5","grams"]],"bakers_pct":null,"component":null},{"name":"pistachio paste (100%)","amounts":[["50","grams"]],"bakers_pct":null,"component":null},{"name":"pistachio paste (sweetened)","amounts":[["40","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["2","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Place the milk, nonfat milk powder, and cream in a sauce pan over medium heat. Add the sucrose, dextrose, glucose, and stabilizer. Heat, while whisking, to 85°C/185°F.","Remove from heat, add pistachio pastes and salt; homogenize with an immersion blender. Chill in an ice water bath. Allow the mix to mature at least 12 hours if possible.","Process in batch freezer; extract the mix at -5˚C/23˚F. Alternatively, transfer to PacoJet canisters and freeze; process as needed."]', '[]', 'PA_Mod_01_Instructor.pdf', 313);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('RECIPES and EXECRCISES BASIC GRANITE', 'Frozen Desserts', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 18, NULL, NULL, '[]', '[{"name":"sucrose","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["250","grams"]],"bakers_pct":null,"component":null},{"name":"fruit juice or purée","amounts":[["750","grams"]],"bakers_pct":null,"component":null},{"name":"lemon juice","amounts":[["10","grams"]],"bakers_pct":null,"component":null},{"name":"gelatin sheet, hydrated (optional)","amounts":[["1","sheet"]],"bakers_pct":null,"component":null}]', NULL, '["Combine the sucrose and water and bring to a boil.","Add the base fruit and lemon juice (and gelatin, if used); strain.","Pour into shallow pans and begin to freeze, stirring every fifteen minutes with a fork.","Once the proper ice consistency is achieved, place granité in covered containers and store in the freezer"]', '[]', 'PA_Mod_01_Instructor.pdf', 275);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('RECIPES and EXECRCISES WHITE BASE (6% MILK FAT)', 'Frozen Desserts', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 19, NULL, NULL, '[]', '[{"name":"whole milk","amounts":[["635","grams"]],"bakers_pct":null,"component":null},{"name":"nonfat dry milk powder","amounts":[["50","grams"]],"bakers_pct":null,"component":null},{"name":"heavy cream (36% fat)","amounts":[["110","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose","amounts":[["160","grams"]],"bakers_pct":null,"component":null},{"name":"dextrose","amounts":[["20","grams"]],"bakers_pct":null,"component":null},{"name":"invert sugar","amounts":[["20","grams"]],"bakers_pct":null,"component":null},{"name":"ice cream stabilizer","amounts":[["5","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Place the milk, nonfat milk powder, and cream in a sauce pan over medium heat. Add the sucrose, dextrose, invert sugar, and stabilizer. Heat, while whisking, to 85°C/185°F.","Remove from heat and homogenize with an immersion blender. Chill in an ice water bath. Allow the mix to mature at least 12 hours if possible.","Process in batch freezer; extract the mix at -5˚C/23˚F. Alternatively, transfer to PacoJet canisters and freeze; process as needed."]', '[]', 'PA_Mod_01_Instructor.pdf', 305);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Raspberry Ice Cream', 'Frozen Desserts', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 19, NULL, NULL, '[]', '[{"name":"whole milk","amounts":[["305","grams"]],"bakers_pct":null,"component":null},{"name":"nonfat dry milk powder","amounts":[["65","grams"]],"bakers_pct":null,"component":null},{"name":"heavy cream (36% fat)","amounts":[["80","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose","amounts":[["90","grams"]],"bakers_pct":null,"component":null},{"name":"glucose powder","amounts":[["25","grams"]],"bakers_pct":null,"component":null},{"name":"invert sugar","amounts":[["30","grams"]],"bakers_pct":null,"component":null},{"name":"ice cream stabilizer","amounts":[["5","grams"]],"bakers_pct":null,"component":null},{"name":"raspberry purée","amounts":[["400","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Place the milk, nonfat milk powder, and cream in a sauce pan over medium heat. Add the sucrose, glucose, invert sugar and stabilizer. Heat, while whisking, to 85°C/185°F.","Remove from heat and homogenize with an immersion blender. Chill in an ice water bath. Allow the mix to mature at least 12 hours if possible.","Thoroughly blend the base mix and raspberry purée. Process in batch freezer; extract the mix at -5˚C/23˚F. Alternatively, transfer to PacoJet canisters and freeze; process as needed."]', '[]', 'PA_Mod_01_Instructor.pdf', 314);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Strawberry Sorbet', 'Frozen Desserts', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 18, NULL, NULL, '[]', '[{"name":"sucrose (1)","amounts":[["60","grams"]],"bakers_pct":null,"component":null},{"name":"sorbet stabilizer","amounts":[["8","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["300","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose (2)","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"glucose powder","amounts":[["75","grams"]],"bakers_pct":null,"component":null},{"name":"invert sugar","amounts":[["25","grams"]],"bakers_pct":null,"component":null},{"name":"strawberry purée","amounts":[["1000","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine the first measurement of sucrose (1) and stabilizer.","Heat water to 50˚C/120˚F. Whisk in the stabilizer mixture, and then the remaining sucrose (2), glucose, and invert sugar and bring just to a boil. Remove from heat.","Chill and allow syrup to mature.","Combine base syrup with fruit purée and briefly blend with an immersion blender. Process in batch freezer; extract the mix at -5˚C/23˚F.","Transfer finished sorbet to blast chiller to harden at minimum of -18˚C/0˚F. Alternatively, transfer to PacoJet canisters and freeze; process as needed."]', '[]', 'PA_Mod_01_Instructor.pdf', 284);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Vanilla Ice Cream (6% Fat)', 'Frozen Desserts', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 73, 'Total Yield 1000 grams', '1000 grams', '[]', '[{"name":"whole milk","amounts":[["635","grams"]],"bakers_pct":null,"component":null},{"name":"nonfat dry milk powder","amounts":[["50","grams"]],"bakers_pct":null,"component":null},{"name":"heavy cream (36% fat)","amounts":[["110","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose","amounts":[["160","grams"]],"bakers_pct":null,"component":null},{"name":"dextrose","amounts":[["20","grams"]],"bakers_pct":null,"component":null},{"name":"invert sugar","amounts":[["20","grams"]],"bakers_pct":null,"component":null},{"name":"ice cream stabilizer","amounts":[["5","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Place the milk, nonfat milk powder, cream, and vanilla in a sauce pan over medium heat. Add the sucrose, dextrose, invert sugar, and stabilizer. Heat, while whisking, to 85°C/185°F.","Remove from heat and homogenize with an immersion blender. Chill in an ice water bath. Allow the mix to mature at least 12 hours.","Process in batch freezer; extract the mix at -5˚C/23˚F."]', '[]', 'Pastry_Module_3_Course_6.pdf', 215);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('WHITE BASE (14% MILK FAT) g oz', 'Frozen Desserts', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 19, NULL, NULL, '[]', '[{"name":"whole milk","amounts":[["450","grams"]],"bakers_pct":null,"component":null},{"name":"nonfat dry milk powder","amounts":[["30","grams"]],"bakers_pct":null,"component":null},{"name":"heavy cream (36% fat)","amounts":[["350","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose","amounts":[["130","grams"]],"bakers_pct":null,"component":null},{"name":"dextrose","amounts":[["20","grams"]],"bakers_pct":null,"component":null},{"name":"invert sugar","amounts":[["20","grams"]],"bakers_pct":null,"component":null},{"name":"ice cream stabilizer","amounts":[["4","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Place the milk, nonfat milk powder, and cream in a sauce pan over medium heat. Add the sucrose, dextrose, invert sugar, and stabilizer. Heat, while whisking, to 85°C/185°F.","Remove from heat and homogenize with an immersion blender. Chill in an ice water bath. Allow the mix to mature at least 12 hours if possible.","Process in batch freezer; extract the mix at -5˚C/23˚F. Alternatively, transfer to PacoJet canisters and freeze; process as needed."]', '[]', 'PA_Mod_01_Instructor.pdf', 307);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('White Base (10% Milk Fat)', 'Frozen Desserts', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 19, NULL, NULL, '[]', '[{"name":"whole milk","amounts":[["550","grams"]],"bakers_pct":null,"component":null},{"name":"nonfat dry milk powder","amounts":[["35","grams"]],"bakers_pct":null,"component":null},{"name":"heavy cream (36% fat)","amounts":[["230","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose","amounts":[["140","grams"]],"bakers_pct":null,"component":null},{"name":"dextrose","amounts":[["20","grams"]],"bakers_pct":null,"component":null},{"name":"invert sugar","amounts":[["20","grams"]],"bakers_pct":null,"component":null},{"name":"ice cream stabilizer","amounts":[["4","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Place the milk, nonfat milk powder, and cream in a sauce pan over medium heat. Add the sucrose, dextrose, invert sugar, and stabilizer. Heat, while whisking, to 85°C/185°F.","Remove from heat and homogenize with an immersion blender. Chill in an ice water bath. Allow the mix to mature at least 12 hours if possible.","Process in batch freezer; extract the mix at -5˚C/23˚F. Alternatively, transfer to PacoJet canisters and freeze; process as needed."]', '[]', 'PA_Mod_01_Instructor.pdf', 306);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Yuzu Parfait', 'Frozen Desserts', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 71, NULL, NULL, '[]', '[{"name":"whole eggs","amounts":[["200","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose","amounts":[["300","grams"]],"bakers_pct":null,"component":null},{"name":"yuzu (or other citrus) purée","amounts":[["170","grams"]],"bakers_pct":null,"component":null},{"name":"gelatin sheets, bloomed","amounts":[["4","sheets"]],"bakers_pct":null,"component":null},{"name":"butter, unsalted","amounts":[["170","grams"]],"bakers_pct":null,"component":null},{"name":"heavy cream ,whipped to soft peak","amounts":[["170","grams"]],"bakers_pct":null,"component":null}]', '[["1010","grams"]]', '["In a heavy saucepan, whisk together the eggs and sucrose, and then add the yuzu purée.","On medium heat, bring mixture just to a boil, stirring constantly. Remove from heat and add the gelatin.","Allow the mixture to cool 35˚C/95˚F and emulsify the butter into the base.","Once cooled, fold into whipped cream.","Pipe the mousse into silicon ‘stone'' molds, filling approximately halfway. Insert a piece of the frozen pistachio cream into each mold and top with additional mousse to fill the mold completely. Freeze"]', '[]', 'Pastry_Module_3_Course_6.pdf', 165);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Yuzu Parfait Pistachio Cream', 'Frozen Desserts', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 71, NULL, NULL, '[]', '[{"name":"whole milk","amounts":[["250","grams"]],"bakers_pct":null,"component":null},{"name":"heavy cream","amounts":[["250","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose","amounts":[["50","grams"]],"bakers_pct":null,"component":null},{"name":"egg yolks","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"sheet gelatin, bloomed","amounts":[["3","sheets"]],"bakers_pct":null,"component":null},{"name":"pistachio paste, sweetened","amounts":[["50","grams"]],"bakers_pct":null,"component":null}]', '[["700","grams"]]', '["In a saucepan, combine milk, cream, and sucrose. Bring to a boil.","Remove from heat and carefully whisk in egg yolks. Return to low heat and cook, stirring, to 85ºC/185ºF.","Remove from heat, add gelatin, and blend in the pistachio paste. Strain through a chinois.","Portion into small hemisphere molds and place in blast freezer."]', '[]', 'Pastry_Module_3_Course_6.pdf', 164);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Apfelstrudel (Apple Strudel)', 'Laminated & Phyllo Doughs', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 42, NULL, NULL, '[]', '[{"name":"butter","amounts":[["115","grams"]],"bakers_pct":null,"component":null},{"name":"Golden Delicious apples (10)","amounts":[["2230","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["170","grams"]],"bakers_pct":null,"component":null},{"name":"lemon zest","amounts":[["2","grams"]],"bakers_pct":null,"component":null},{"name":"cinnamon","amounts":[["3","grams"]],"bakers_pct":null,"component":null},{"name":"raisins","amounts":[["85","grams"]],"bakers_pct":null,"component":null},{"name":"walnuts","amounts":[["85","grams"]],"bakers_pct":null,"component":null},{"name":"melted butter","amounts":[["170","grams"]],"bakers_pct":null,"component":null},{"name":"fine dry breadcrumbs","amounts":[["60","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Peel, halve and core the apples. Cut each half in 5 or 6 slices toss with the remaining filling ingredients, except the walnuts, in a wide pan. Cover and cook over medium heat about 15 minutes, until the apples are swimming in water. Uncover, lower heat and cook until the juices have evaporated, about 20 minutes. Stir in the walnuts and cool the filling.","Brush melted butter on to the stretched strudel dough, reserving a little butter for the outside of the strudel. Sprinkle the dough with the narrow ends of the dough.","Roll the strudel, folding in the ends as you roll.","Transfer the strudel to a half-sheet pan lined with parchment. Bend the strudel into a horseshoe shape. Butter the outside of the strudel and bake it at 400 degrees about 40 minutes. If the strudel is beginning to take on too much color, lower the temperature to 350 degrees and cover the strudel loosely with aluminum foil.","Cool the strudel on the pan, and dust the strudel lightly with confectioners'' sugar before serving."]', '["For the dough"]', 'Pastry_Module_2_Course_4.pdf', 93);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Apple Strip', 'Laminated & Phyllo Doughs', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 45, NULL, NULL, '[]', '[{"name":"puff pastry","amounts":[["440","grams"]],"bakers_pct":null,"component":null},{"name":"Almond Frangipane","amounts":[["440","grams"]],"bakers_pct":null,"component":null},{"name":"melted butter","amounts":[["30","grams"]],"bakers_pct":null,"component":null},{"name":"apricot glaze","amounts":[["60","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Roll the puff pastry into a long strip.","Spread the Almond Frangipane evenly down the center of the strip, leaving a border.","Arrange sliced apples over the frangipane.","Fold and crimp the pastry edges up around the filling to enclose it.","Brush the pastry with melted butter.","Bake at 375 F until the pastry is puffed and golden and the apples are tender.","Brush warm apricot glaze over the top to finish.","Cool before slicing."]', '[]', 'Pastry_Module_2_Course_4.pdf', 118);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Baklava', 'Laminated & Phyllo Doughs', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 47, NULL, NULL, '[]', '[{"name":"walnuts","amounts":[["115","grams"]],"bakers_pct":null,"component":null},{"name":"almonds","amounts":[["115","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["115","grams"]],"bakers_pct":null,"component":null},{"name":"ground cinnamon","amounts":[["1","gram"]],"bakers_pct":null,"component":null},{"name":"clarified butter","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"phyllo dough","amounts":[["24","sheets"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["340","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["355","grams"]],"bakers_pct":null,"component":null},{"name":"honey","amounts":[["85","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Grind walnuts, almonds, sugar and cinnamon together, until finely processed.","Open package of phyllo dough, and cut entire package in half through the width (making two short rectangles).","Brush one half-piece lightly with melted clarified butter.","Spread 2 tablespoons of filling evenly over phyllo and drizzle the filling with clarified butter.","Fold in edges to cover filling, and then roll. Brush top with clarified butter."]', '[]', 'Pastry_Module_2_Course_4.pdf', 134);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Bourbon Mille Feuille, Lemon, Vanilla Ice Cream Vanilla Pastry Cream', 'Laminated & Phyllo Doughs', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 73, NULL, NULL, '[]', '[{"name":"corn starch","amounts":[["50","grams"]],"bakers_pct":null,"component":null},{"name":"whole milk (1)","amounts":[["50","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose (1)","amounts":[["62","grams"]],"bakers_pct":null,"component":null},{"name":"whole eggs","amounts":[["50","grams"]],"bakers_pct":null,"component":null},{"name":"egg yolks","amounts":[["80","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["1","gram"]],"bakers_pct":null,"component":null},{"name":"whole milk (2)","amounts":[["495","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose (2)","amounts":[["6.2","grams"]],"bakers_pct":null,"component":null},{"name":"butter, unsalted","amounts":[["60","grams"]],"bakers_pct":null,"component":null}]', '[["911","grams"]]', '["Whisk the corn starch into the first measurement of milk (1) in a medium- sized mixing bowl, followed by the first measurement of sucrose (1), the whole eggs, egg yolks and salt.","Combine the remaining milk (2), sucrose (2), and vanilla in a sauce pan; bring to a boil.","Remove from heat and temper the warm milk mixture into the corn starch mixture. Return to heat and cook over medium heat, whisking constantly, just to a boil. Remove from heat (remove the scraped vanilla pod) and whisk"]', '[]', 'Pastry_Module_3_Course_6.pdf', 213);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Butter (Beurrage)', 'Laminated & Phyllo Doughs', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 50, NULL, NULL, '["Small Batch"]', '[{"name":"butter","amounts":[["440","grams"]],"bakers_pct":null,"component":null},{"name":"flour","amounts":[["55","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Assemble mise-en-place (12 points)","Prepare Detrempe (12 points)","Prepare Beurrage (12 points)","Form Paton (12 points)","Rolling dough (16 points)","First double turn (12 points)","Second double turn (12 points)","Finish last two double turns after quiz (12 points)"]', '[]', 'Pastry_Module_2_Course_4.pdf', 160);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Classic Puff Pastry Dough (Detrempe)', 'Laminated & Phyllo Doughs', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 43, NULL, NULL, '["Small Batch","Large Batch"]', '[{"name":"all purpose flour","amounts":[["330","grams"],["660","grams"]],"bakers_pct":"75.00","component":null},{"name":"cake flour","amounts":[["110","grams"],["220","grams"]],"bakers_pct":"25.00","component":null},{"name":"salt","amounts":[["9","grams"],["18","grams"]],"bakers_pct":"2.05","component":null},{"name":"sugar","amounts":[["6","grams"],["12","grams"]],"bakers_pct":"1.36","component":null},{"name":"very cold water","amounts":[["220","grams"],["440","grams"]],"bakers_pct":"50.00","component":null},{"name":"soft butter","amounts":[["110","grams"],["220","grams"]],"bakers_pct":"25.00","component":null}]', NULL, '["Sift the all-purpose flour and cake flour together; add the salt and sugar and combine.","Rub the soft butter into the flour mixture until evenly distributed and sandy in texture.","Make a well in the center and add the very cold water all at once.","Mix just until the dough comes together into a smooth, cohesive mass; stop as soon as it clears the bowl and do not overwork or develop the gluten.","Turn the dough out and gather into a smooth rectangle or disk.","Wrap tightly and refrigerate at least 30 to 60 minutes to relax and firm before rolling in the butter block for lamination."]', '[]', 'Pastry_Module_2_Course_4.pdf', 108);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Coques', 'Laminated & Phyllo Doughs', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 46, NULL, NULL, '[]', '[{"name":"puff pastry","amounts":[["440","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["330","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Allow dough to rest in the refrigerator about 1 hour."]', '[]', 'Pastry_Module_2_Course_4.pdf', 129);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Croissant Dough', 'Laminated & Phyllo Doughs', 'Module 2', 'Course 3', 'Breads & Yeast Doughs', 34, NULL, NULL, '[]', '[{"name":"water","amounts":[["350","grams"]],"bakers_pct":null,"component":null},{"name":"milk","amounts":[["300","grams"]],"bakers_pct":null,"component":null},{"name":"SAF yeast","amounts":[["15","grams"]],"bakers_pct":null,"component":null},{"name":"(optional) starter","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["55","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["25","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"all purpose flour","amounts":[["1100","grams"]],"bakers_pct":null,"component":null},{"name":"butter","amounts":[["484","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["350","grams"]],"bakers_pct":null,"component":null},{"name":"milk","amounts":[["300","grams"]],"bakers_pct":null,"component":null},{"name":"SAF yeast","amounts":[["15","grams"]],"bakers_pct":null,"component":null},{"name":"(optional) starter","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["55","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["25","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"whole wheat flour","amounts":[["150","grams"]],"bakers_pct":null,"component":null},{"name":"all purpose flour","amounts":[["950","grams"]],"bakers_pct":null,"component":null},{"name":"butter","amounts":[["484","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Add all ingredients except butter together in bowl.","Mix on low speed with dough hook attachment until it all comes together.","Knead on floured table a little but not too much. Shape into square roughly 8 X 8 and wrap in plastic.","Let rest in refrigerator. Whole Wheat Croissant Use Either Starter or Water NOT BOTH","Add all ingredients except butter together in bowl.","Mix on low speed with dough hook attachment until it all comes together.","Knead on floured table a little but not too much. Shape into square roughly 8 X 8 and wrap in plastic.","Let rest in refrigerator. Butter for Laminating:","Flour parchment paper","Chop butter lengthwise into roughly 115 gram (4 ounce) pieces.","Flour the butter lightly and cover with paper.","Beat with rolling pin to soften and flatten. Try to shape it into rectangle.","Make sure the butter is roughly 2/3 the size of the dough.","Roll out dough to form rectangle. Don''t let the dough get too wide,","Brush off excess flour with a brush and mark about 2/3 of the dough.","Fold 1/3 of the dough over. Brush off flour and fold the other 1/3","Rotate the dough 90° and flour it up. Hit the ends to seal the dough","Brush off the flour and double turn. Sealing the two ends when you","Roll it out a little and cover with plastic wrap. Let rest in fridge","Repeat the double turn. Flour the dough and triple wrap in plastic."]', '[]', 'Pastry_Module_2_Course_3.pdf', 124);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Danish Dough', 'Laminated & Phyllo Doughs', 'Module 2', 'Course 3', 'Breads & Yeast Doughs', 34, NULL, NULL, '[]', '[{"name":"whole milk","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"SAF yeast","amounts":[["10","grams"]],"bakers_pct":null,"component":null},{"name":"all purpose flour","amounts":[["570","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["55","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["7","grams"]],"bakers_pct":null,"component":null},{"name":"butter","amounts":[["340","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Determine the correct size of dough for tête mold by rounding a piece of","Oil small classic brioche molds well.","1-2-3-4 dough shaping method. Cover with one hand and roll into a ball.","Turn on side and roll into width of hand. Dip the side of your hand in flour","Stand the dough upright with the head on top.","Use first two fingers from each hand and place them under the head.","Place in prepared molds. Place in proof box for about an hour until double","Egg wash tops and bake."]', '[]', 'Pastry_Module_2_Course_3.pdf', 126);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Galaktoboureko', 'Laminated & Phyllo Doughs', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 47, NULL, NULL, '[]', '[{"name":"milk","amounts":[["975","grams"]],"bakers_pct":null,"component":null},{"name":"semolina","amounts":[["140","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"eggs (5)","amounts":[["250","grams"]],"bakers_pct":null,"component":null},{"name":"clarified butter","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"Phyllo dough","amounts":[["16","sheets"]],"bakers_pct":null,"component":null}]', NULL, '["Heat ¾ of milk in sauce pan with vanilla bean","Combine remaining milk with semolina, sugar and eggs and set aside.","When milk and vanilla come to a boil, make a liaison with milk and semolina mixture.","Continue to cook mixture until it is thickened."]', '[]', 'Pastry_Module_2_Course_4.pdf', 135);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Machine Puff Pastry 20-Quart Machine Dough (Detrempe)', 'Laminated & Phyllo Doughs', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 44, NULL, NULL, '[]', '[{"name":"All-purpose flour","amounts":[["2640","grams"]],"bakers_pct":"75.00","component":null},{"name":"cake flour","amounts":[["880","grams"]],"bakers_pct":"25.00","component":null},{"name":"salt","amounts":[["72","grams"]],"bakers_pct":"2.05","component":null},{"name":"sugar","amounts":[["48","grams"]],"bakers_pct":"1.36","component":null},{"name":"very cold water","amounts":[["1760","grams"]],"bakers_pct":"50.00","component":null},{"name":"soft butter","amounts":[["880","grams"]],"bakers_pct":"25.00","component":null}]', NULL, '["Combine the all-purpose flour, cake flour, salt, and sugar in the bowl of a 20-quart mixer fitted with the hook attachment.","Add the soft butter and mix on low speed until worked evenly into the dry ingredients and the mixture looks sandy.","Add the very cold water and mix on low speed just until the dough comes together into a smooth, cohesive mass and clears the bowl.","Stop mixing as soon as the dough comes together; do not overmix or allow the dough to warm.","Remove the dough, divide, and shape into rectangles.","Wrap tightly and refrigerate until firm before laminating with the butter block."]', '[]', 'Pastry_Module_2_Course_4.pdf', 114);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Mille Feuille Layers', 'Laminated & Phyllo Doughs', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 73, NULL, NULL, '[]', '[{"name":"frozen puff pastry sheets","amounts":[["2","each"]],"bakers_pct":null,"component":null},{"name":"10x","amounts":[["","as needed"]],"bakers_pct":null,"component":null}]', NULL, '["Roll out Puff pastry layers thinly and sprinkle lightly with 10X. Bake between parchment and straight half sheet pans until fully baked."]', '[]', 'Pastry_Module_3_Course_6.pdf', 216);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Mozzarella and Prosciutto Turnovers', 'Laminated & Phyllo Doughs', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 43, '9. Yield: about 30 turnovers.', NULL, '[]', '[{"name":"shredded mozzarella","amounts":[["60","grams"]],"bakers_pct":null,"component":null},{"name":"minced prosciutto","amounts":[["60","grams"]],"bakers_pct":null,"component":null},{"name":"chopped flat-leaved parsley","amounts":[["7","grams"]],"bakers_pct":null,"component":null},{"name":"freshly ground black pepper","amounts":[["","as needed"]],"bakers_pct":null,"component":null}]', NULL, '["Stir together the cheese, prosciutto, parsley and pepper.","Egg-wash dough lightly and divide filling among disks of dough, placing it off- center.","Fold over disks of dough and seal well with fingertips. Seal with tines of fork, dipping fork in flour to prevent sticking.","Egg-wash tops of turnovers and bake at 375 degrees about 20 minutes until well colored and crisp.","Cool the pastries on the pans and reheat for service."]', '[]', 'Pastry_Module_2_Course_4.pdf', 102);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Optional Danish Fillings Pastry Cream', 'Laminated & Phyllo Doughs', 'Module 2', 'Course 3', 'Breads & Yeast Doughs', 35, NULL, NULL, '["Large Batch","Medium Batch","Small Batch"]', '[{"name":"milk","amounts":[["1960","grams"],["980","grams"],["490","grams"]],"bakers_pct":null,"component":null},{"name":"cornstarch","amounts":[["200","grams"],["100","grams"],["50","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["452","grams"],["226","grams"],["113","grams"]],"bakers_pct":null,"component":null},{"name":"eggs","amounts":[["200","grams"],["100","grams"],["50","grams"]],"bakers_pct":null,"component":null},{"name":"yolks","amounts":[["280","grams"],["140","grams"],["70","grams"]],"bakers_pct":null,"component":null},{"name":"butter","amounts":[["220","grams"],["110","grams"],["55","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla","amounts":[["24","grams"],["12","grams"],["6","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Dissolve cornstarch in 1/8 of the milk.","Combine the remaining milk with the sugar in a rondeau or saucepan; bring to a boil.","Whisk whole eggs, then yolks into cornstarch mixture.","Pour 1/3 of the boiling milk into the egg mixture, whisking. Return the remaining milk mixture to a boil.","Whisk the egg mixture into the boiling milk, whisking until the pastry cream thickens and returns to a boil. Boil, whisking, about 1 minute.","Remove from heat and beat in the butter and vanilla.","Pour the cream into a stainless steel pan. Press plastic wrap directly on the surface, and poke holes to vent. Chill immediatel"]', '[]', 'Pastry_Module_2_Course_3.pdf', 135);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Paillettes', 'Laminated & Phyllo Doughs', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 46, NULL, NULL, '[]', '[{"name":"puff pastry","amounts":[["440","grams"]],"bakers_pct":null,"component":null},{"name":"grated parmesan","amounts":[["110","grams"]],"bakers_pct":null,"component":null},{"name":"paprika","amounts":[["5","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Roll the puff pastry into a rectangle about 1/8 inch thick.","Combine the grated parmesan and paprika.","Sprinkle the cheese mixture evenly over one half of the dough.","Fold the other half of the dough over the cheese to enclose it, and roll gently to seal and adhere the layers.","Cut into strips about 1/2 inch wide.","Twist each strip several times and place on a parchment-lined sheet pan, pressing the ends down to secure.","Bake at 375 F until golden brown and crisp.","Cool on the pan before serving."]', '[]', 'Pastry_Module_2_Course_4.pdf', 127);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Palmiers', 'Laminated & Phyllo Doughs', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 46, NULL, NULL, '[]', '[{"name":"puff pastry","amounts":[["440","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["330","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Cut into 1/4-inch-thick slices. Dip surface that will go against pan in sugar.","Bake at 375 degrees for about 15 minutes, or until golden brown."]', '[]', 'Pastry_Module_2_Course_4.pdf', 126);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Parmesan and Paprika Palmiers', 'Laminated & Phyllo Doughs', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 43, NULL, NULL, '[]', '[{"name":"grated Parmesan cheese","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["3","grams"]],"bakers_pct":null,"component":null},{"name":"sweet Hungarian paprika","amounts":[["7","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Strew evenly with cheese, salt and paprika.","Fold each long end 1/3 of the way in toward the center. Repeat folds, folding to center, and then fold in half at center line. Wrap in plastic and chill until firm."]', '[]', 'Pastry_Module_2_Course_4.pdf', 106);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Plum and Cheese Strudel', 'Laminated & Phyllo Doughs', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 42, NULL, NULL, '[]', '[{"name":"white bread","amounts":[["115","grams"]],"bakers_pct":null,"component":null},{"name":"milk, scalded","amounts":[["120","grams"]],"bakers_pct":null,"component":null},{"name":"cream cheese","amounts":[["455","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["115","grams"]],"bakers_pct":null,"component":null},{"name":"egg yolks (3)","amounts":[["50","grams"]],"bakers_pct":null,"component":null},{"name":"farmer cheese or ricotta","amounts":[["455","grams"]],"bakers_pct":null,"component":null},{"name":"sour cream","amounts":[["115","grams"]],"bakers_pct":null,"component":null},{"name":"melted butter","amounts":[["55","grams"]],"bakers_pct":null,"component":null},{"name":"grated lemon zest","amounts":[["2","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla extract","amounts":[["8","grams"]],"bakers_pct":null,"component":null},{"name":"red plums, rinsed, halved, pitted & sliced","amounts":[["860","grams"]],"bakers_pct":null,"component":null},{"name":"melted butter","amounts":[["170","grams"]],"bakers_pct":null,"component":null},{"name":"fine dry breadcrumbs","amounts":[["60","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Trim the crusts from the bread, soak it in the milk, and force it through a strainer. Force the cheese through a strainer over the bread. Set aside. Beat the cream cheese to lighten it then beat in the sugar and the yolks. Stir in the farmer cheese, the bread, and all other ingredients except the plums.","Stretch the strudel dough. Brush melted butter on to the strudel dough, reserving a little butter for the outside of the strudel. Sprinkle the dough with the breadcrumbs.","Spread the filling over 1/3 of the dough and scatter on the plums. Roll dough up, taking care to fold in the sides to prevent the filling from leaking out.","Transfer the strudel to a half-sheet pan lined with parchment. Bend the strudel into a horseshoe shape. Butter the outside of the strudel and","Bake it at 375 degrees about 40 minutes. If the strudel is beginning to"]', '["For the dough"]', 'Pastry_Module_2_Course_4.pdf', 95);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Praline Feuillete', 'Laminated & Phyllo Doughs', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 64, '(two 10” discs) Yield 463 grams', '463 grams', '[]', '[{"name":"semisweet chocolate","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"milk chocolate","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"praline paste","amounts":[["70","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["3","grams"]],"bakers_pct":null,"component":null},{"name":"Feuilletine","amounts":[["190","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Melt the semisweet and milk chocolate together gently over a bain-marie, stirring until smooth.","Stir in the praline paste and salt until fully smooth and combined.","Fold in the Feuilletine flakes just until evenly coated, taking care not to crush them.","Divide the mixture between sheets of parchment or acetate and spread thinly into two 10-inch discs.","Chill until firm and set before using."]', '[]', 'Pastry_Module_3_Course_6.pdf', 36);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Quick Puff Pastry Dough', 'Laminated & Phyllo Doughs', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 42, NULL, NULL, '[]', '[{"name":"all-purpose flour","amounts":[["330","grams"]],"bakers_pct":"75.00","component":null},{"name":"cake flour","amounts":[["110","grams"]],"bakers_pct":"25.00","component":null},{"name":"cold butter","amounts":[["495","grams"]],"bakers_pct":"112.50","component":null},{"name":"salt","amounts":[["6","grams"]],"bakers_pct":"1.36","component":null},{"name":"lemon juice or distilled white vinegar","amounts":[["14","grams"]],"bakers_pct":"3.18","component":null},{"name":"ice water","amounts":[["220","grams"]],"bakers_pct":"50.00","component":null}]', NULL, '["Combine the flours in a bowl and stir well to mix. Rub 55 grams of butter into the flours until it disappears and is cool and powdery. Set aside."]', '[]', 'Pastry_Module_2_Course_4.pdf', 99);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Rectangular Mille Feuille', 'Laminated & Phyllo Doughs', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 46, NULL, NULL, '[]', '[{"name":"puff pastry(1/2 small batch)","amounts":[["640","grams"]],"bakers_pct":null,"component":null},{"name":"flavored pastry cream","amounts":[["680","grams"]],"bakers_pct":null,"component":null},{"name":"heavy cream, whipped to soft peaks","amounts":[["475","grams"]],"bakers_pct":null,"component":null},{"name":"melted dark chocolate","amounts":[["120","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Bake at 350 degrees for 30 minutes, turning dough often and watching its progress. Remove dough from oven and cool between the pans to prevent warping. Assembly","Stir the cold pastry cream to soften slightly. Fold the whipped cream into the pastry cream. and reserving scraps.","Place first strip on cardboard; spread with 1/3 of the pastry cream. Top with second strip; spread with another 1/3 pastry cream; top with third strip and spread with remaining pastry cream. Top with last strip. Place cardboard over stacked pastry; press down to adhere interior together and to ensure that it is straight.","Cover top of pastry with vanilla fondant and finish with chocolate. Spread sides evenly with any pastry cream that flows out; adhere crumbs to sides."]', '[]', 'Pastry_Module_2_Course_4.pdf', 124);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Roquefort and Spinach Strudel', 'Laminated & Phyllo Doughs', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 43, NULL, NULL, '[]', '[{"name":"milk","amounts":[["120","grams"]],"bakers_pct":null,"component":null},{"name":"butter","amounts":[["55","grams"]],"bakers_pct":null,"component":null},{"name":"unbleached, al- purpose flour","amounts":[["70","grams"]],"bakers_pct":null,"component":null},{"name":"eggs (2)","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"salt, pepper and nutmeg","amounts":[["","as needed"]],"bakers_pct":null,"component":null},{"name":"Roquefort, crumbled","amounts":[["115","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine the milk and butter in a saucepan and bring to a boil.","Add the flour all at once and stir vigorously over low heat until the mixture forms a smooth ball and pulls away from the sides of the pan.","Transfer to a mixer and beat on low speed briefly to cool slightly.","Add the eggs gradually, beating well after each addition until the paste is smooth and glossy.","Season the paste with salt, pepper, and nutmeg.","Spread the paste thinly and evenly on a parchment-lined sheet pan.","Bake at 375 F until set, dry, and lightly golden.","While still warm and pliable, scatter sautéed spinach and crumbled Roquefort evenly over the surface.","Roll up jelly-roll style to enclose the filling; place seam-side down.","Return to the oven briefly to set and heat through.","Cool slightly, then slice and serve."]', '[]', 'Pastry_Module_2_Course_4.pdf', 104);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Sacristains', 'Laminated & Phyllo Doughs', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 46, NULL, NULL, '["2-inches"]', '[{"name":"puff pastry","amounts":[["440","grams"]],"bakers_pct":null,"component":null},{"name":"ground almonds","amounts":[["110","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["110","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Roll the puff pastry into a rectangle about 1/8 inch thick.","Combine the ground almonds and sugar.","Sprinkle the almond-sugar mixture evenly over the dough, pressing gently to adhere.","Cut into strips about 1/2 inch wide.","Twist each strip several times and place on a parchment-lined sheet pan.","Bake at 375 F until golden brown and crisp.","Cool on the pan before serving."]', '[]', 'Pastry_Module_2_Course_4.pdf', 126);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Smoked Salmon Mille Feuille', 'Laminated & Phyllo Doughs', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 43, NULL, NULL, '[]', '[{"name":"soft cream cheese","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"soft butter","amounts":[["115","grams"]],"bakers_pct":null,"component":null},{"name":"finely grated lemon zest","amounts":[["6","grams"]],"bakers_pct":null,"component":null},{"name":"salt and pepper","amounts":[["","as needed"]],"bakers_pct":null,"component":null},{"name":"fresh chives, finely sliced","amounts":[["6","grams"]],"bakers_pct":null,"component":null},{"name":"smoked salmon, sliced thin","amounts":[["170","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Dock the dough well and place on a paper-lined pan. Cover dough with another piece of paper and pan and bake at 350 degrees about 30 minutes, turning dough often and watching its progress as it becomes golden. Remove dough from oven and cool between the pans to prevent warping.","While the dough is baking, prepare the filling. Beat together cream cheese and butter until smooth and light. Beat in lemon zest, salt and pepper. Stir in chives. each piece with half the filling.","Arrange the salmon to cover one of the pieces, and then invert the remaining piece onto the first piece, covering the salmon. Slide onto a pan and press to adhere. Refrigerate until firm, about 1 hour."]', '[]', 'Pastry_Module_2_Course_4.pdf', 103);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Spanikopita', 'Laminated & Phyllo Doughs', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 47, NULL, NULL, '[]', '[{"name":"spinach","amounts":[["450","grams"]],"bakers_pct":null,"component":null},{"name":"olive oil","amounts":[["40","grams"]],"bakers_pct":null,"component":null},{"name":"scallions","amounts":[["200","grams"]],"bakers_pct":null,"component":null},{"name":"dill","amounts":[["3","grams"]],"bakers_pct":null,"component":null},{"name":"ricotta","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"eggs(3)","amounts":[["150","grams"]],"bakers_pct":null,"component":null},{"name":"feta cheese, broken into large pieces","amounts":[["450","grams"]],"bakers_pct":null,"component":null},{"name":"clarified butter","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"Phyllo dough","amounts":[["48","sheets"]],"bakers_pct":null,"component":null}]', NULL, '["Wash, drain and chop spinach, scallions and dill.","Sauté spinach in olive oil, until wilted. Add scallions and dill and continue to sauté briefly. Cool and drain off excess liquid.","Place spinach, scallions and dill in a large bowl and add the ricotta, eggs and broken feta. Stir well to mix.","Open package of phyllo dough, and cut entire package in half through the length (making two long rectangles). Brush one rectangular piece lightly with melted clarified butter and place second sheet on top, brushing again with clarified butter.","Place approximately one ounce of filling in lower right hand corner of phyllo dough. Fold dough in half to cover filling and make a long narrow rectangle. Fold filling upward twice, and then begin folding as you would a flag, creating triangular pieces.","Arrange on parchment lined pan, brush with melted clarified butter and bake at 350 until golden."]', '[]', 'Pastry_Module_2_Course_4.pdf', 133);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Strudelteig Strudel Dough', 'Laminated & Phyllo Doughs', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 42, NULL, NULL, '[]', '[{"name":"high gluten or bread flour","amounts":[["397","grams"]],"bakers_pct":"100.00","component":null},{"name":"salt","amounts":[["7","grams"]],"bakers_pct":"1.76","component":null},{"name":"eggs (2)","amounts":[["100","grams"]],"bakers_pct":"25.19","component":null},{"name":"oil","amounts":[["14","grams"]],"bakers_pct":"3.53","component":null},{"name":"Total liquid","amounts":[["300","grams"]],"bakers_pct":"75.57","component":null}]', NULL, '["Combine the flour and salt in a mixing bowl. Beat the eggs and oil with a whisk. Add enough warm water to make a total of 300 grams.","Stir the liquid into the flour with a rubber spatula, making sure that no flour sticks to the side of the bowl. The dough should be fairly soft.","Turn the dough out on a lightly floured surface and begin to develop the gluten. Pick the dough up and slam it against the surface forcefully. Fold the dough back on itself, and pick it up again from the side, detaching it from the surface with a bench scraper. Repeat this motion 100 times, until the dough is smooth and elastic.","Oil a small bowl, place the dough in the bowl and turn the dough over, so that the top is oiled. Press plastic wrap against the surface of the dough and rest the dough at room temperature about 1 hour, longer if possible. Refrigerate the dough if it is to be held more than half a day. If the dough was refrigerated, let it come to room temperature before proceeding."]', '[]', 'Pastry_Module_2_Course_4.pdf', 91);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Topfen Strudel', 'Laminated & Phyllo Doughs', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 42, NULL, NULL, '[]', '[{"name":"white bread","amounts":[["115","grams"]],"bakers_pct":null,"component":null},{"name":"milk","amounts":[["120","grams"]],"bakers_pct":null,"component":null},{"name":"yellow raisins","amounts":[["140","grams"]],"bakers_pct":null,"component":null},{"name":"eggs (3)","amounts":[["150","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["115","grams"]],"bakers_pct":null,"component":null},{"name":"farmer cheese","amounts":[["910","grams"]],"bakers_pct":null,"component":null},{"name":"sour cream","amounts":[["170","grams"]],"bakers_pct":null,"component":null},{"name":"melted butter","amounts":[["55","grams"]],"bakers_pct":null,"component":null},{"name":"lemon zest, grated","amounts":[["2","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla extract","amounts":[["26","grams"]],"bakers_pct":null,"component":null},{"name":"melted butter","amounts":[["170","grams"]],"bakers_pct":null,"component":null},{"name":"fine dry breadcrumbs","amounts":[["60","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Trim the crusts from the bread, soak it in the milk, and force it through a strainer. Force the cheese through a strainer over the bread. Set aside. Bring the raisins to a boil in water and drain them. Set aside. Beat the eggs with the sugar until light and stir in the cheese, the bread, raisins, and all other ingredients.","Butter and crumb the dough and spread the filling over 1/3 of the strudel dough and roll it up, taking care to fold in the sides to prevent the filling from leaking out.","Transfer the strudel to a half-sheet pan lined with parchment. Bend the strudel into a horseshoe shape. Butter the outside of the strudel and bake it at 375 degrees about 40 minutes. If the strudel is beginning to take on too much color, lower the temperature to 350 degrees and cover the strudel loosely with aluminum foil.","Cool the strudel on the pan, and dust the strudel lightly with confectioners'' sugar before serving"]', '["For the dough"]', 'Pastry_Module_2_Course_4.pdf', 94);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Tresses', 'Laminated & Phyllo Doughs', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 46, NULL, NULL, '["1-inch cutter"]', '[{"name":"puff pastry","amounts":[["440","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["330","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Allow dough to rest in the refrigerator about 1 hour.","Cut into ¾ -inch wide strips. Braid 3 at a time.","Place 1 ½ inches apart on paper-lined pan.","Bake at 375 degrees for about 15 minutes, or until golden brown."]', '[]', 'Pastry_Module_2_Course_4.pdf', 128);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Tyrolean Strudel', 'Laminated & Phyllo Doughs', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 42, NULL, NULL, '[]', '[{"name":"milk","amounts":[["490","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["115","grams"]],"bakers_pct":null,"component":null},{"name":"egg yolks (6)","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"all-purpose flour","amounts":[["43","grams"]],"bakers_pct":null,"component":null},{"name":"butter","amounts":[["55","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla extract","amounts":[["8","grams"]],"bakers_pct":null,"component":null},{"name":"yellow raisins","amounts":[["115","grams"]],"bakers_pct":null,"component":null},{"name":"currants or dark raisins","amounts":[["115","grams"]],"bakers_pct":null,"component":null},{"name":"diced pitted dates","amounts":[["115","grams"]],"bakers_pct":null,"component":null},{"name":"diced dried figs","amounts":[["115","grams"]],"bakers_pct":null,"component":null},{"name":"coarsely chopped walnut pieces","amounts":[["115","grams"]],"bakers_pct":null,"component":null},{"name":"egg whites (6)","amounts":[["220","grams"]],"bakers_pct":null,"component":null},{"name":"melted butter","amounts":[["170","grams"]],"bakers_pct":null,"component":null},{"name":"fine dry breadcrumbs","amounts":[["60","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Bring the milk to a boil with half the sugar in a non-aluminum saucepan. Whisk the yolks in a bowl and beat in the remaining sugar. Sift in the flour and stir it in. Beat 1/3 of the boiling milk into the yolk mixture, and then return the remaining milk to a boil. Beat the yolk mixture into the boiling milk and continue beating until the cream thickens and returns to a boil. Cook the cream about 1 minute, beating constantly. Remove from heat and beat in the butter and vanilla.","Pour the cream into a clean, dry bowl and press plastic wrap against the surface. Refrigerate until cold.","Stir the dried fruit and walnuts into the cold pastry cream. Beat the egg whites until they hold a soft peak and fold into the filling.","Brush the strudel dough with melted butter, reserving a little butter for the outside of the strudel. Sprinkle the dough with the breadcrumbs. Spread the filling in half the dough and roll up the strudel, folding in the ends while rolling.","Transfer the strudel to a half-sheet pan lined with parchment. Bend the"]', '["For the dough"]', 'Pastry_Module_2_Course_4.pdf', 97);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Baked Meringue', 'Meringues & Soufflés', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 73, NULL, NULL, '[]', '[{"name":"egg whites","amounts":[["120","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose","amounts":[["200","grams"]],"bakers_pct":null,"component":null}]', '[["320","grams"]]', '["Begin whipping egg whites in mixer on medium speed. Slowly add sucrose in a few additions until firm peaks are achieved.","Transfer to a pastry fitted with a medium-sized straight plain tip and pipe small buttons onto a Silpat-lined sheet pan and dry in an oven at 93˚C/200˚F.","Store in an air-tight container. ASSEMBLY grams milk chocolate décor candied ginger, diced","Unmold each ginger parfait onto a cooled sucrée disc. Top with a scoop or quenelle of the passion fruit sorbet, meringue, candied ginger, and milk chocolate décor. Finish the plate with the passion fruit caramel."]', '[]', 'Pastry_Module_3_Course_6.pdf', 226);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Chocolate Meringue', 'Meringues & Soufflés', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 14, NULL, NULL, '[]', '[{"name":"egg whites","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"confectioners'' sugar","amounts":[["170","grams"]],"bakers_pct":null,"component":null},{"name":"cocoa powder","amounts":[["55","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine egg whites and salt in mixing bowl.","Whip on medium speed until risen in volume and whites begin to hold shape around the whisk.","Add the sugar in a slow stream, beating until desired peak.","Fold in the combined and sifted confectioners'' sugar and cocoa powder by hand.","Pipe as instructed. Bake at 300 F."]', '[]', 'PA_Mod_01_Instructor.pdf', 224);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Chocolate Meringue', 'Meringues & Soufflés', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 64, 'Yield 472 grams', '472 grams', '[]', '[{"name":"egg whites","amounts":[["157","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["157","grams"]],"bakers_pct":null,"component":null},{"name":"10X","amounts":[["120","grams"]],"bakers_pct":null,"component":null},{"name":"cocoa powder","amounts":[["38","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine egg whites and salt in mixing bowl.","Whip on medium speed until risen in volume and whites begin to hold shape around the whisk.","Add the sugar in a slow stream, beating until stiff peak.","Sift the 10X and cocoa powder and fold in by hand.","Pipe in very thin lines (quickly from a distance from the tray to ensure thin lines) utilizing an 801plain tip. Bake at 300 F. until dried. Once meringue is baked and cooled, utilize on the side of the entremet."]', '["Utilize chocolate decorations or other decorations for the top."]', 'Pastry_Module_3_Course_6.pdf', 38);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Coconut Souffle', 'Meringues & Soufflés', 'Module 1', 'Course 2', 'Baking Techniques & Ingredients Pt 2', 15, NULL, NULL, '[]', '[{"name":"all-purpose flour","amounts":[["55","grams"]],"bakers_pct":null,"component":null},{"name":"coconut milk","amounts":[["450","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["115","grams"]],"bakers_pct":null,"component":null},{"name":"(about one large) eggs","amounts":[["50","grams"]],"bakers_pct":null,"component":null},{"name":"yolks","amounts":[["70","grams"]],"bakers_pct":null,"component":null},{"name":"unsweetened coconut","amounts":[["115","grams"]],"bakers_pct":null,"component":null},{"name":"egg whites","amounts":[["165","grams"]],"bakers_pct":null,"component":null},{"name":"granulated sugar","amounts":[["70","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Whisk flour into 100 grams of the coconut milk and set aside.","Combine the remaining coconut milk with the sugar in a small saucepan; bring to a boil.","Whisk whole eggs and yolks into flour milk mixture. Temper, by pouring 1/3 of the boiling milk into the egg mixture, whisking. Return the remaining milk mixture to a boil. Whisk the egg mixture into the boiling milk, whisking until the (pastry) cream thickens and returns to a boil.","Boil the pastry cream and continue whisking for 1 minute. Remove from heat and beat in the unsweetened coconut.","Pour the cream into a stainless steel pan. Press plastic wrap directly on the surface. Chill immediately over ice or as instructed.","When cooled, whip whites until frothy and gradually add the remaining sugar; continue whipping until soft peaks are formed.","Fold whites into coconut pastry cream mixture and place into prepared molds.","Bake at 350 degrees for approximately 20 minutes."]', '[]', 'Pastry_Module_1_Course_2.pdf', 52);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Cofee & Pecan Petit Gateaux Pecan Dacquoise Pecan Caramel Coffee Crème Coffee Mousse Pecan Dacquoise', 'Meringues & Soufflés', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 68, '(one 1/2 sheet pan) Yield 850 grams', '850 grams', '[]', '[{"name":"pecans","amounts":[["125","grams"]],"bakers_pct":null,"component":null},{"name":"AP flour","amounts":[["50","grams"]],"bakers_pct":null,"component":null},{"name":"almond flour","amounts":[["125","grams"]],"bakers_pct":null,"component":null},{"name":"sugar (1)","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"egg whites","amounts":[["250","grams"]],"bakers_pct":null,"component":null},{"name":"sugar (2)","amounts":[["200","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Grind pecans and flour together in a Robot Coupe until fine. Combine with the almond flour and sugar (1) and set aside.","Make an ordinary meringue with the egg whites and sugar (2) and whip to firm peaks.","Gently fold the dry ingredients into the meringue.","Spread onto parchment lined sheet pan and dust with confectio10X.","Bake at 375 F. for 8-10 minutes or until golden brown and set.","Once cooled, invert onto parchment lined half sheet pan and trim to fit in a sheet pan extender."]', '[]', 'Pastry_Module_3_Course_6.pdf', 102);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Flavoring for Flour-Based Souffle Mocha Flavoring', 'Meringues & Soufflés', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 15, NULL, NULL, '[]', '[{"name":"freshly brewed espresso","amounts":[["60","grams"]],"bakers_pct":null,"component":null},{"name":"brandy","amounts":[["14","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Add espresso and brandy to Flour-Based Soufflé at step 5."]', '[]', 'PA_Mod_01_Instructor.pdf', 232);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Flour-Based Chocolate Souffle', 'Meringues & Soufflés', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 15, NULL, NULL, '[]', '[{"name":"milk","amounts":[["365","grams"]],"bakers_pct":null,"component":null},{"name":"flour","amounts":[["43","grams"]],"bakers_pct":null,"component":null},{"name":"softened butter","amounts":[["43","grams"]],"bakers_pct":null,"component":null},{"name":"bittersweet chocolate, finely chopped","amounts":[["170","grams"]],"bakers_pct":null,"component":null},{"name":"yolks","amounts":[["70","grams"]],"bakers_pct":null,"component":null},{"name":"liqueur","amounts":[["28","grams"]],"bakers_pct":null,"component":null},{"name":"egg whites","amounts":[["165","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["55","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Bring milk to a boil.","Separately, mix butter and flour to a paste.","Add paste to boiling milk over low flame gradually and stir until base thickens and returns to a boil.","Remove from heat. Turn into a bowl. (If not using immediately cover with plastic wrap and refrigerate. Warm over simmering water to 100 degrees before using.)","While stirring, add chocolate all at once TO MELT COMPETELY.","Gradually add yolks to mixture, then liqueur.","Allow base to cool.","Whip egg whites to a very light peak. Add sugar gradually while continuing to whip to a soft peak, (making a French meringue).","Stir 1/4 of the whipped whites into the base.","Fold in the remaining 3/4 of the whites.","Place batter in eight 4- or 5-ounce buttered and sugared ramekins and bake at 400 degrees for approximately 15 minutes."]', '["Note: This soufflé recipe is part of your practical exam on Lesson 23"]', 'PA_Mod_01_Instructor.pdf', 230);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Flour-Based Souffle', 'Meringues & Soufflés', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 15, NULL, NULL, '[]', '[{"name":"milk","amounts":[["245","grams"]],"bakers_pct":null,"component":null},{"name":"softened butter","amounts":[["43","grams"]],"bakers_pct":null,"component":null},{"name":"flour","amounts":[["43","grams"]],"bakers_pct":null,"component":null},{"name":"yolks","amounts":[["70","grams"]],"bakers_pct":null,"component":null},{"name":"egg whites","amounts":[["165","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["70","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Bring milk to a boil.","Mix butter and flour to a paste.","Add paste to milk over low flame gradually and stir until base thickens and returns to a boil.","Remove from heat. Turn into a bowl. (If not using immediately cover with plastic wrap and refrigerate. Warm over simmering water to 100 degrees before using.)","While stirring, gradually add FLAVORING (as assigned in the next page) to mixture.","Gradually add yolks to mixture.","Allow base to cool.","Whip egg whites to a very light peak. For sweet soufflés add sugar slowly while continuing to whip to a soft peak; for savory soufflés, whip whites without sugar.","Stir 1/4 of the whipped whites into the base.","Fold in the remaining 3/4 of the whites.","Place batter in eight 4- or 5-ounce buttered and sugared ramekins for sweet soufflés or buttered and Parmesan cheese ramekins for savory soufflés. Bake at 400 degrees for approximately 15 minutes."]', '[]', 'PA_Mod_01_Instructor.pdf', 231);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('French (Ordinary) Meringue', 'Meringues & Soufflés', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 14, NULL, NULL, '[]', '[{"name":"egg whites","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"granulated or confectioners'' sugar","amounts":[["225","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine egg whites and salt in mixing bowl.","Whip on medium speed until risen in volume and whites begin to hold shape around the whisk.","Add the sugar in a slow stream, beating until desired peak.","Fold in the second sugar by hand. Pipe as instructed. Bake at 225 F."]', '[]', 'PA_Mod_01_Instructor.pdf', 224);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('French Macarons', 'Meringues & Soufflés', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 56, '(80 halves, 40 sandwiched 1” macaroons) Yield 601 grams', '601 grams', '[]', '[{"name":"almond flour","amounts":[["165","grams"]],"bakers_pct":null,"component":null},{"name":"10x","amounts":[["165","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["150","grams"]],"bakers_pct":null,"component":null},{"name":"powdered egg white","amounts":[["5","grams"]],"bakers_pct":null,"component":null},{"name":"whisked egg whites, aged 2 days (refrigerated)","amounts":[["115","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Pulse the almond flour, 10x and salt in the bowl of a food processor 4 times for 4 seconds each. Sift.","Whisk the powdered egg whites and granulated sugar in an electric mixer bowl. Whisk in the aged egg whites, and whisk at medium-high speed until glossy stiff peaks form (about 11 minutes).","Fold the dry ingredients into the meringue until the mixture falls back into the bowl, with no stiffness, in one continuous drip. Add the coloring until just incorporated."]', '[]', 'Pastry_Module_3_Course_5.pdf', 84);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Honey Meringue', 'Meringues & Soufflés', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 71, NULL, NULL, '[]', '[{"name":"honey","amounts":[["230","grams"]],"bakers_pct":null,"component":null},{"name":"egg whites","amounts":[["120","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose","amounts":[["20","grams"]],"bakers_pct":null,"component":null}]', '[["370","grams"]]', '["Place the honey in a small sauce pan and begin to heat.","Place egg whites and sugar in a KitchenAid mixer bowl with whip attachment and start to mix on medium speed. Bring honey to boil and continue cooking to ; remove from heat and slowly pour the honey into egg whites. Continue to whip until cool and stiff.","Transfer the meringue into a pastry bag fitted with a medium plain tip and pipe spiked mounds onto each of the unmolded honey parfait hemispheres. Return to freezer. Lightly caramelize the meringue with a blowtorch before serving."]', '[]', 'Pastry_Module_3_Course_6.pdf', 151);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Italian Meringue Buttercream', 'Meringues & Soufflés', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 11, NULL, NULL, '[]', '[{"name":"Italian Meringue","amounts":[["1","batch"]],"bakers_pct":null,"component":null},{"name":"butter, pieces","amounts":[["675","grams"]],"bakers_pct":null,"component":null}]', NULL, '["After meringue is whipped until cold and stiff, switch to the paddle attachment of the mixer if desired.","Add the butter while continuing to beat until all the butter is incorporated.","Beat until smooth.","Flavor the Italian Meringue buttercream at this point by adding flavorings of your choice."]', '[]', 'PA_Mod_01_Instructor.pdf', 198);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Italian Meringue Italian Meringue', 'Meringues & Soufflés', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 11, NULL, NULL, '[]', '[{"name":"water","amounts":[["115","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["340","grams"]],"bakers_pct":null,"component":null},{"name":"egg whites","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"salt (optional)","amounts":[["1","gram"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["110","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Pour water and 340 grams of sugar into a small saucepan. Stir to combine.","Place the pan over low to medium heat.","Meanwhile, place the egg whites and salt in a Kitchen Aid bowl.","When the sugar syrup comes to a boil, begin whipping the egg whites. Whip whites until white and frothy. Gradually add the 110 grams of sugar to the whipping egg whites.","When the sugar syrup reaches 240° F, add sugar syrup in a slow stream to the whites while they are whipping. Be careful not to pour the sugar onto the whisk, but rather down the side of the bowl while it is whipping.","Whip until cooled."]', '[]', 'PA_Mod_01_Instructor.pdf', 197);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Lime Meringue', 'Meringues & Soufflés', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 73, NULL, NULL, '[]', '[{"name":"sucrose","amounts":[["75","grams"]],"bakers_pct":null,"component":null},{"name":"Versawhip (soy protein)","amounts":[["2.5","grams"]],"bakers_pct":null,"component":null},{"name":"xanthan gum","amounts":[["0.5","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"lime juice","amounts":[["30","grams"]],"bakers_pct":null,"component":null}]', '[["208","grams"]]', '["Combine the sucrose, Versawhip, and xanthan gum and blend into the liquids with an immersion blender. Chill for one hour.","Transfer to the bowl of an electric stand mixer and whip to a slightly firm peak."]', '[]', 'Pastry_Module_3_Course_6.pdf', 220);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Meringue Buttons', 'Meringues & Soufflés', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 19, NULL, NULL, '[]', '[{"name":"egg whites","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose","amounts":[["135","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Begin whipping egg whites in mixer on medium speed. Slowly add sucrose in a few additions until firm peaks are achieved.","Apply as desired and dry in a convection oven, low fan, between 82°C/180°F and"]', '[]', 'PA_Mod_01_Instructor.pdf', 324);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Pecan Dacquoise Layer', 'Meringues & Soufflés', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 68, '(one half sheet pan)Yield 712 grams', '712 grams', '[]', '[{"name":"pecans","amounts":[["130","grams"]],"bakers_pct":null,"component":null},{"name":"coconut, unsweetened","amounts":[["217","grams"]],"bakers_pct":null,"component":null},{"name":"tapioca starch","amounts":[["14","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["4","grams"]],"bakers_pct":null,"component":null},{"name":"canola oil","amounts":[["15","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla extract","amounts":[["9","grams"]],"bakers_pct":null,"component":null},{"name":"dark rum","amounts":[["8","grams"]],"bakers_pct":null,"component":null},{"name":"egg whites","amounts":[["170","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["145","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine the pecans and all the dry ingredients in a Robot Coupe until the pecans are ground to fine flour. Set aside.","Combine all the liquid ingredients in one bowl. Set aside.","Meanwhile whip egg whites and sugar to make an ordinary meringue and whip until soft peak.","Add the dry ingredients and liquids alternately into the meringue.","Spread the meringue onto a parchment lined (1/2) sheet pan.","Bake at 350 F. Once cooled, cut cake to fit into oval flexi molds."]', '[]', 'Pastry_Module_3_Course_6.pdf', 99);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Pistachio Souffle', 'Meringues & Soufflés', 'Module 1', 'Course 2', 'Baking Techniques & Ingredients Pt 2', 15, NULL, NULL, '[]', '[{"name":"all-purpose flour","amounts":[["55","grams"]],"bakers_pct":null,"component":null},{"name":"milk","amounts":[["490","grams"]],"bakers_pct":null,"component":null},{"name":"granulated sugar","amounts":[["115","grams"]],"bakers_pct":null,"component":null},{"name":"(about one large) eggs","amounts":[["50","grams"]],"bakers_pct":null,"component":null},{"name":"yolks","amounts":[["70","grams"]],"bakers_pct":null,"component":null},{"name":"pistachio paste","amounts":[["115","grams"]],"bakers_pct":null,"component":null},{"name":"chopped blanched pistachios","amounts":[["115","grams"]],"bakers_pct":null,"component":null},{"name":"egg whites","amounts":[["165","grams"]],"bakers_pct":null,"component":null},{"name":"granulated sugar","amounts":[["70","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Whisk flour into 100 grams of the milk and set aside.","Combine the remaining milk with the sugar in a small saucepan; bring to a boil.","Whisk eggs and yolks into flour milk mixture. Temper, by pouring 1/3 of the boiling milk into the egg mixture, whisking. Return the remaining milk mixture to a boil. Whisk the egg mixture into the boiling milk, whisking until the pastry cream thickens and returns to a boil.","Boil the pastry cream and continue whisking for 1 minute. Remove from heat and beat in the pistachio paste and chopped pistachios.","Pour the cream into a stainless steel pan. Press plastic wrap directly on the surface. Chill immediately over ice or as instructed.","When cooled, whip whites until frothy and gradually add the remaining sugar, continue whipping until soft peaks are formed.","Fold whites into pistachio pastry cream mixture and place into prepared molds.","Bake at 350 degrees for approximately 20 minutes."]', '[]', 'Pastry_Module_1_Course_2.pdf', 50);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Praline Souffle', 'Meringues & Soufflés', 'Module 1', 'Course 2', 'Baking Techniques & Ingredients Pt 2', 15, NULL, NULL, '[]', '[{"name":"all-purpose flour","amounts":[["55","grams"]],"bakers_pct":null,"component":null},{"name":"milk","amounts":[["490","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["115","grams"]],"bakers_pct":null,"component":null},{"name":"(about one large) eggs","amounts":[["50","grams"]],"bakers_pct":null,"component":null},{"name":"yolks","amounts":[["70","grams"]],"bakers_pct":null,"component":null},{"name":"praline paste","amounts":[["115","grams"]],"bakers_pct":null,"component":null},{"name":"chopped toasted hazelnuts","amounts":[["115","grams"]],"bakers_pct":null,"component":null},{"name":"egg whites","amounts":[["165","grams"]],"bakers_pct":null,"component":null},{"name":"granulated sugar","amounts":[["70","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Whisk flour into 100 grams of the milk and set aside.","Combine the remaining milk with the sugar in a small saucepan; bring to a boil.","Whisk eggs and yolks into flour milk mixture. Temper, by pouring 1/3 of the boiling milk into the egg mixture, whisking. Return the remaining milk mixture to a boil. Whisk the egg mixture into the boiling milk, whisking until the (pastry) cream thickens and returns to a boil.","Boil the pastry cream and continue whisking for 1 minute. Remove from heat and beat in the praline paste and chopped hazelnuts.","Pour the cream into a stainless steel pan. Press plastic wrap directly on the surface. Chill immediately over ice or as instructed.","When cooled, whip whites until frothy and gradually add the remaining sugar, continue whipping until soft peaks are formed.","Fold whites into praline pastry cream mixture and place into prepared molds.","Bake at 350 degrees for approximately 20 minutes."]', '[]', 'Pastry_Module_1_Course_2.pdf', 51);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Succes Meringue Layers', 'Meringues & Soufflés', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 14, NULL, NULL, '[]', '[{"name":"sugar","amounts":[["175","grams"]],"bakers_pct":null,"component":null},{"name":"almond flour","amounts":[["87","grams"]],"bakers_pct":null,"component":null},{"name":"hazelnut flour","amounts":[["87","grams"]],"bakers_pct":null,"component":null},{"name":"cornstarch","amounts":[["28.5","grams"]],"bakers_pct":null,"component":null},{"name":"egg whites","amounts":[["175","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["175","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine the (first) sugar, the almond flour, hazelnut flour and cornstarch in a bowl and mix to combine.","Combine egg whites and salt in a kitchen aid bowl. Whip on medium speed until soft peaks form.","Gradually add the (second) sugar.","Continue whipping until stiff peaks form.","By hand, fold ¼ of the whipped whites into the almond/hazelnut mixture to lighten. Then fold in the rest of the whipped whites until just incorporated.","Pipe into cookie size spiral disks on a parchment paper-lined sheet pan with a","Bake at 300 degrees for about 25 minutes, or until set."]', '[]', 'PA_Mod_01_Instructor.pdf', 225);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Swiss Meringue', 'Meringues & Soufflés', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 14, NULL, NULL, '[]', '[{"name":"egg whites","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["450","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine well, the egg whites, salt and sugar in a Kitchen Aid mixing bowl. Then place over simmering water.","While over the hot water bath, stir with a hand whip until the egg whites are hot (approximately 130-140° F) and all the sugar is dissolved.","Remove from the heat and place on the mixer.","Whip until cool and stiff."]', '["Optional: Add 675 grams of butter to finished meringue to make buttercream"]', 'PA_Mod_01_Instructor.pdf', 226);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Swiss Meringue Butter Cream', 'Meringues & Soufflés', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 74, NULL, NULL, '[]', '[{"name":"egg whites","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose","amounts":[["150","grams"]],"bakers_pct":null,"component":null},{"name":"butter, room temperature","amounts":[["500","grams"]],"bakers_pct":null,"component":null}]', '[["750","grams"]]', '["Combine egg whites and sugar in a bowl and heat over a double boiler to approximately 130˚F/55°C, or until the sugar has completely dissolved.","Transfer the egg whites to the bowl of an electric stand mixer and whip until cool.","Add butter in small amounts while whipping until fully incorporated."]', '[]', 'Pastry_Module_3_Course_6.pdf', 244);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Swiss Meringue Buttercream', 'Meringues & Soufflés', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 66, 'Yield 2,040 grams', '2,040 grams', '[]', '[{"name":"egg whites","amounts":[["340","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["680","grams"]],"bakers_pct":null,"component":null},{"name":"butter","amounts":[["1020","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine egg whites and sugar in mixing bowl. Stir well with whisk and then place over simmering water.","Heat, while whisking, until egg whites are hot to the touch (approximately 140 ºF) and all the sugar is dissolved.","Remove from the heat and place bowl on mixer. Whisk until cool and stiff.","After meringue is cool and stiff, switch to the paddle attachment of the mixer if desired.","Add the butter, gradually; continue beating until all there are no lumps of butter and the mixture is completely smooth.","Flavor as desired when needed. Suggested flavors: Vanilla, Almond, Praline, Coffee"]', '[]', 'Pastry_Module_3_Course_6.pdf', 58);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Biscuit Mixing Method', 'Mixing Methods', NULL, NULL, NULL, NULL, NULL, NULL, '[]', '[]', NULL, '["Whip the egg yolks with a portion of the sugar until pale, thick, and at ribbon stage (it should hold a ribbon shape briefly when trailed across the surface). Set aside.","In a separate, clean bowl, whip the egg whites, adding the remaining sugar gradually, to make an ordinary (French) meringue at soft-to-medium peak — don''t overwhip it stiff and dry.","Fold the meringue into the ribboned yolks in stages, folding only about three-quarters of the way together.","Finish folding while sifting in the flour (and any nut flour or cocoa) at the same time, so the last few folds combine the dry ingredients and the two egg mixtures together in one motion.","If melted butter is used, fold it in last, once the mixture is almost fully combined, so it doesn''t deflate the foam any more than necessary.","Spread or pipe immediately onto parchment and bake in a hot oven for a short time — biscuit bakes fast and can dry out if left in too long."]', '["The defining move is separating the eggs and whipping yolks and whites independently, unlike the [[Genoise Mixing Method|Genoise Mixing]], which whips whole eggs together — this gives biscuit sponges (biscuit cuillère, biscuit joconde, dacquoise-style biscuits) a slightly coarser, more open crumb that’s ideal for piping ladyfingers or rolling.","Used in this cookbook for: [[Biscuit Cuillere]], [[Chocolate Biscuit]], [[Pecan Biscuit]], and [[Walnut Biscuit]].","Biscuit Joconde is a nut-flour variant that whips whole eggs into an almond-flour paste first and folds in the meringue afterward — same family, reordered steps."]', NULL, NULL);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Chiffon Mixing Method', 'Mixing Methods', NULL, NULL, NULL, NULL, NULL, NULL, '[]', '[]', NULL, '["Whisk together the dry ingredients (flour, part of the sugar, baking powder, salt) in one bowl.","In another bowl, whisk together the liquid ingredients — vegetable oil, egg yolks, water or other liquid, and any flavoring.","Whisk the liquid ingredients into the dry ingredients until smooth; this forms the base batter, which is essentially a lean, oil-based cake batter with no leavening power of its own yet.","Separately, whip the egg whites with the remaining sugar and a little salt to make an ordinary meringue at soft peak.","Fold the meringue into the base batter in two or three additions, scraping the bottom of the bowl each time, until no white streaks remain.","Pour into an ungreased tube pan (traditionally) or prepared loaf/cake pans and bake; chiffon cakes are usually cooled upside down in the pan so the delicate structure doesn''t collapse under its own weight."]', '["A hybrid of the [[One-Stage Mixing Method|One-Stage Mixing]] (for the oil/yolk base) and a whipped-meringue foam — oil keeps the crumb moist and tender while the whipped whites do all of the lifting.","Used in this cookbook for: [[Vanilla Chiffon Cake]], [[Chocolate Cinnamon Chiffon Cake]], and [[Walnut Chiffon Cake]].","Because oil (not solid fat) is used, chiffon cakes stay soft even cold from the fridge — solid-fat batters firm up when chilled, oil-based ones don’t."]', NULL, NULL);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Creaming Dough Mixing Method', 'Mixing Methods', NULL, NULL, NULL, NULL, NULL, NULL, '[]', '[]', NULL, '["Beat softened (room-temperature) butter and sugar together with the paddle attachment until smooth and creamy — there''s no need to whip in as much air as for a cake batter, just an even, lump-free base.","Add the flour(s), and any eggs, egg yolks, or flavoring called for, and mix only until just combined, scraping the bottom of the bowl so no pockets of unmixed flour or butter remain.","Gather the dough, flatten into a disk, wrap, and chill thoroughly — the dough will be soft after mixing since the butter was worked at room temperature rather than kept cold.","Roll out cold; because the fat is fully creamed in rather than left in pieces, this dough rolls, cuts, and shapes more like a cookie dough than a pie crust and holds crisp, sharp edges well after baking."]', '["Unlike the Flaky and Mealy Dough Methods, the fat here is fully emulsified into the flour from the start (like the [[Creaming Method]] for cakes) rather than cut in as solid pieces — the result is a short, sandy-tender, cookie-like dough rather than a flaky or mealy one.","Used in this cookbook for: [[Pate Sablee|Pâte Sablée]], [[Almond Pate Sucree|Almond Pâte Sucrée]], [[Breton Dough]], [[Lemon Pound Loaf Cake]], [[Sour Cherry Crumbcake Squares]], and [[Apple Walnut Muffins]].","Note this course’s terminology can differ from other pastry references, some of which describe pâte sucrée as the creamed dough and pâte sablée as the cut-in one — follow the specific recipe’s mixing method note on this site rather than assuming by name alone."]', NULL, NULL);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Creaming Method', 'Mixing Methods', NULL, NULL, NULL, NULL, NULL, NULL, '[]', '[]', NULL, '["Have the butter and any solid fat at cool room temperature (about 65–68°F) — pliable but not soft or greasy.","Beat the butter and sugar together on medium speed with the paddle attachment until light in color and fluffy, 3–5 minutes. This is the step that matters most: the sugar crystals cut tiny air cells into the fat, and those cells are what leaven the cake in the oven.","Add eggs a little at a time (one at a time for whole eggs), beating well and scraping down after each addition so the mixture stays emulsified instead of curdling.","Add the sifted dry ingredients and the liquid (milk, buttermilk, etc.) alternately in 3–4 additions, starting and ending with the dry ingredients. Mix only until each addition is just combined — overmixing after the flour goes in develops gluten and toughens the cake.","Scrape the bowl well, give it one final short mix to even out the batter, and pan it immediately."]', '["Produces a taller, more open crumb than the two-stage/high-ratio method, but takes longer and is more sensitive to overmixing.","Used in this cookbook for: [[Basic Yellow Cake]], [[Chocolate Cake]], [[Yellow Buttermilk Cake]], [[Coconut Cake]], [[Chocolate Cupcakes]], [[Basic Sugar Cookie]], [[Chocolate Chip Cookies]], [[Spritz Cookies]], [[Tres Leches Cake]], [[Basque Cake]], and [[Apple Quick Bread]].","If the batter looks curdled after the eggs go in, it usually means the butter or eggs were too cold — warm the bowl slightly or add a spoonful of the measured flour to bring it back together."]', NULL, NULL);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Flaky Dough Mixing Method', 'Mixing Methods', NULL, NULL, NULL, NULL, NULL, NULL, '[]', '[]', NULL, '["Start with cold fat (butter, shortening, or a blend) cut into small cubes, and cold liquid held in reserve.","Cut the fat into the flour (and salt/sugar) using a pastry blender, your fingertips, or the mixer''s paddle on low speed, stopping while the pieces of fat are still pea-to-almond sized — you want visible flecks of fat, not a uniform crumb.","Add the cold liquid gradually, tossing or mixing gently, adding only enough for the dough to just come together — it should still look shaggy and a little dry, not smooth.","Gather the dough, pat it into a disk without kneading it, wrap, and chill thoroughly before rolling.","Roll and use as needed; the large, intact pieces of cold fat melt in the oven and release steam, separating the dough into the distinct flaky layers this method is named for."]', '["Best for top crusts, lattice tops, turnovers, and any pastry you want visibly flaky and shattering rather than crumbly.","Used in this cookbook for: [[Pate Brisee|Pâte Brisée]], [[Sour Cream Dough]], [[Galette Dough]], [[Biscuits]], and [[Shortcakes]].","Keeping everything cold (fat, liquid, even the bowl) is the whole method — if the fat softens and blends in too far, you lose the flakiness and end up with a mealy dough instead."]', NULL, NULL);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Genoise Mixing Method', 'Mixing Methods', NULL, NULL, NULL, NULL, NULL, NULL, '[]', '[]', NULL, '["Whisk whole eggs, sugar, and a pinch of salt together in the mixer bowl, then set the bowl over a pan of barely simmering water (a bain-marie).","Whisk constantly by hand while the mixture warms to just lukewarm (about body temperature) and the sugar fully dissolves — don''t let it get hot enough to scramble the eggs.","Move the bowl to the mixer and whip on high speed until the mixture has cooled back to room temperature and tripled in volume, reaching the “ribbon stage” (it falls off the whisk in a slowly dissolving ribbon).","Sift the flour a second time directly over the whipped eggs, then fold it in quickly but gently with a rubber spatula, scraping to the bottom of the bowl each pass so no dry flour hides there.","Finish by folding in cooled melted butter (if used) just until incorporated, then spread or pan immediately — the foam starts losing volume the moment folding stops."]', '["A whole-egg foam method: all of the leavening is whipped-in air, with no chemical leavener and (unlike Genoise Mousseline) no separate meringue.","Used in this cookbook for: [[Plain Genoise]], [[Chocolate Genoise Cake]], and the sponge layer in [[Strawberry Fraisier|Strawbery Fraisier]].","Warming the eggs before whipping lets them hold far more air than whipping cold — skipping the bain-marie step is the most common cause of a dense genoise."]', NULL, NULL);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Genoise Mousseline Mixing Method', 'Mixing Methods', NULL, NULL, NULL, NULL, NULL, NULL, '[]', '[]', NULL, '["Whisk the eggs and sugar together over a bain-marie until the sugar dissolves and the mixture feels warm, exactly as in the plain Genoise Method.","Transfer to the mixer and whip on medium-high speed until thickened and increased in volume — it doesn''t need to fully cool and triple the way a classic genoise does before you move on.","While the eggs whip, melt the butter and combine it with any flavoring liquid (rum, coffee, etc.), and sift the dry ingredients.","As soon as the egg foam has thickened enough, sift the dry ingredients directly over it while folding gently, then fold in the warm butter mixture just until no streaks remain.","Spread the batter thinly and bake right away, since it holds less air than a fully-whipped genoise and deflates faster."]', '["A lighter-touch variant of the [[Genoise Mixing Method|Genoise Mixing]] — the eggs are whipped to a looser, less-set foam and the butter is folded in as a separate warm mixture rather than added cold at the very end.","Used in this cookbook for the [[Chocolate Genoise Mousseline]] layer in the Milk Chocolate Coconut entremet.","Bakes thin (sheet-pan) rather than in a deep cake pan — it’s built to be cut into entremet layers, not stand alone."]', NULL, NULL);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('High-Ratio (Two-Stage) Mixing Method', 'Mixing Methods', NULL, NULL, NULL, NULL, NULL, NULL, '[]', '[]', NULL, '["Combine all of the dry ingredients (flour, sugar, leavener, salt) with the emulsified shortening or softened butter in the mixer bowl fitted with the paddle.","Mix on low speed until the fat has coated the flour and the mixture looks sandy, then increase to medium speed and beat until light — this is stage one, and it''s what waterproofs the flour''s protein and keeps the eventual crumb tender.","With the mixer running, add about half of the combined liquid ingredients (eggs, milk, flavorings). Mix until no streaks of fat remain, then continue mixing for about two more minutes to build the batter''s structure.","Add the remaining liquid in a slow, steady stream with the mixer still running, then mix for a further two minutes. The finished batter should be thin enough to pour, not scrape, into the pan.","Scrape down, pour into prepared pans, and bake right away."]', '["Requires a recipe with a \"high ratio\" of sugar and liquid to flour (sugar ≥ 100% of flour weight) and an emulsified shortening — it was developed specifically for that combination and won’t work with a lean, low-sugar formula.","Used in this cookbook for: [[Basic Vanilla Cake]], [[Basic Chocolate Cupcake]], [[Basic White Cupcake]], [[Bourbon Pecan Pound Cake]], and [[High-Ratio Fresh Ginger Pound Cake with Lemon Glaze]].","Trades some of the height you get from the [[Creaming Method]] for a very fine, velvety, moist crumb and a longer shelf life."]', NULL, NULL);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Mealy Dough Mixing Method', 'Mixing Methods', NULL, NULL, NULL, NULL, NULL, NULL, '[]', '[]', NULL, '["Start with cold fat cut into the flour, exactly as for the Flaky Dough Method, but keep working it — by pastry blender, fingertips, or paddle — until the mixture looks like coarse cornmeal or sand, with no pea-sized pieces left.","Add the cold liquid gradually, mixing only until the dough just comes together into a cohesive mass.","Gather into a disk, wrap, and chill before rolling.","Roll and dock or blind-bake as the recipe calls for; because the fat is worked in so finely, this dough won''t puff into distinct layers, but it also won''t let liquid filling soak through it the way a flakier dough can."]', '["The finer the fat is worked in, the more thoroughly it coats the flour’s protein, which both blocks gluten development (for a tender, short bite) and blocks moisture (for a crust that resists getting soggy).","Used in this cookbook for: [[Pate Sucree|Pâte Sucrée]], [[Pasta Frolla]], [[Dark Linzer Dough]] and [[Light Linzer Dough]], [[Shirley O. Corriher’s Biscuits|Shirley O. Corriher''s Biscuits]], and the base for [[Scones]] (plain, [[Currant Tea Scones|currant]], [[Chocolate Chunk Scones|chocolate chunk]], [[Lemon Cornmeal Scones|lemon-cornmeal]], and [[Rock Scones|rock]] scones).","Reach for this method for bottom crusts under wet or custardy fillings, and for any dough (like scones) where a short, tender crumb matters more than visible layers."]', NULL, NULL);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Modified Creaming Method', 'Mixing Methods', NULL, NULL, NULL, NULL, NULL, NULL, '[]', '[]', NULL, '["Cream the butter and the first portion of sugar until light and smooth, then beat in the egg yolks gradually until pale and fully incorporated.","Fold in any nut flour, ground nuts, or breadcrumbs called for in the base.","Separately, whip the egg whites to soft peaks and add the second portion of sugar to make an ordinary (French) meringue.","Lighten the creamed base with about a quarter of the meringue first, stirring it in fully, then gently fold in the remaining meringue in two additions — fold just until no streaks remain to keep as much air as possible.","Pan and bake immediately; this batter deflates faster than a straight creaming-method batter because so much of its lift comes from the whipped whites."]', '["A hybrid of the [[Creaming Method]] and a whipped-egg-foam method — richer and more tender than a plain sponge, lighter than a straight creamed cake.","Used in this cookbook for: [[Klimt-Torte]] and [[Lemon Ricotta Sponge]].","Because the structure leans on the meringue, fold gently and bake right away — letting the batter sit deflates it."]', NULL, NULL);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('One-Stage Mixing Method', 'Mixing Methods', NULL, NULL, NULL, NULL, NULL, NULL, '[]', '[]', NULL, '["Whisk together the wet ingredients (eggs, oil, buttermilk, melted butter, purees like carrot or banana) in the mixer bowl.","Sift the dry ingredients together separately, then add them all at once to the wet ingredients.","Mix on low speed just until combined — there''s no creaming, no ribbon stage, and no separate egg-foam step, so this is the fastest of the mixing methods.","Fold in any mix-ins (nuts, grated vegetables, chocolate chips) by hand or on the lowest speed.","Pan and bake immediately."]', '["Also called the \"muffin method\" outside this curriculum — it’s built for oil-based batters (rather than solid-fat batters) where there’s no fat to cream in the first place.","Used in this cookbook for: [[Carrot Cake Layer]], [[Gluten-Free Vanilla Loaf Cake]], [[Salted Chocolate Cake]], [[Chocolate “Brownie” Entremet Cake]], and [[Brown Sugar Mixture]].","Overmixing is the main risk — stop as soon as the streaks of flour disappear, or the cake turns rubbery and tunnels."]', NULL, NULL);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Pain de Gênes Mixing Method', 'Mixing Methods', NULL, NULL, NULL, NULL, NULL, NULL, '[]', '[]', NULL, '["Cream the almond paste (or almond/pistachio paste) with butter and sugar on the paddle attachment, beating until completely smooth — any lumps of paste will stay lumps in the baked cake, so take the time here.","Add the eggs gradually, beating well after each addition; continue beating past that point until the mixture reaches ribbon stage (thick, pale, and holding a trail when the whisk is lifted).","Sift the flour (and baking powder, salt, or starch if used) separately.","Fold the sifted dry ingredients into the emulsified egg-and-nut-paste base.","If using melted butter separately (rather than creaming all the butter in step 1), temper a small amount of the batter into it first, then fold that back into the remaining batter so the butter incorporates evenly instead of pooling.","Spread thinly on a lined sheet pan and bake — pain de gênes bakes flatter and denser than a genoise, so don''t expect the same rise."]', '["Almond-paste-based cousin of the [[Genoise Mixing Method|Genoise Mixing]]: the emulsion of almond paste and egg replaces most of the whipped-air structure, so the cake is moister and denser than a classic genoise.","Used in this cookbook for: [[Almond Pear Cake]] and the [[Pistachio Pain De Gene]] layer in Lemon Strawberry Pistachio Cake.","Good almond paste (smooth, not gritty, not overly stiff) matters more here than in almost any other mixing method — it can’t be creamed smooth if it starts out dry or grainy."]', NULL, NULL);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Pâte à Bombe Method', 'Mixing Methods', NULL, NULL, NULL, NULL, NULL, NULL, '[]', '[]', NULL, '["Cook sugar and water to soft-ball stage (about 118–121°C / 245–250°F) in a small saucepan, washing down the sides of the pan with a wet pastry brush to prevent crystallization.","While the syrup cooks, whip egg yolks (whole eggs, for some variations) in a stand mixer on medium speed until light, pale, and frothy.","Once the syrup is at temperature, reduce the mixer to medium-low and pour the hot syrup into the whipping yolks in a thin, steady stream, aiming between the whisk and the side of the bowl so it doesn''t splash onto the whisk and spin off as threads.","Increase to medium-high speed and continue whipping until the mixture has roughly doubled in volume and the outside of the bowl has cooled to just warm — this can take several minutes.","Use the pâte à bombe right away as the aerating base for mousses, buttercreams, parfaits, or semifreddo, folding it into whipped cream, softened butter, or other components while it''s still light and mousse-like."]', '["The egg-yolk counterpart to Italian meringue — hot syrup pasteurizes the yolks and whips them into a stable, long-lasting foam without cooking them into scrambled egg.","Used in this cookbook as the base for glaze/mousse preparations such as the [[Glaze]] recipe (orange-chocolate mousse base).","Pour the syrup carefully and slowly — too fast, and it seizes into hard threads instead of emulsifying into the yolks; splashed onto the moving whisk, it flings out as unusable strands."]', NULL, NULL);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Apricot–Thyme Miroir', 'Mousses & Entremets', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 63, '(two 6” cakes, 2” high) Yield 1,240 grams', '1,240 grams', '[]', '[{"name":"Vanilla Biscuit","amounts":[["1","half sheet"]],"bakers_pct":null,"component":null},{"name":"gelatin sheets","amounts":[["7.5","sheets"]],"bakers_pct":null,"component":null},{"name":"heavy cream","amounts":[["525","grams"]],"bakers_pct":null,"component":null},{"name":"apricot puree","amounts":[["675","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["38","grams"]],"bakers_pct":null,"component":null},{"name":"fresh thyme leaves- chopped fine","amounts":[["2","grams"]],"bakers_pct":null,"component":null},{"name":"gelatin sheets","amounts":[["3.75","sheets"]],"bakers_pct":null,"component":null},{"name":"apricot puree","amounts":[["188","grams"]],"bakers_pct":null,"component":null},{"name":"apple jelly","amounts":[["188","grams"]],"bakers_pct":null,"component":null},{"name":"nappage at end)","amounts":[["1","grams"]],"bakers_pct":null,"component":null},{"name":"Stock Syrup- vanilla","amounts":[["","as needed"]],"bakers_pct":null,"component":null}]', NULL, '["Line a 6-inch entremet ring with acetate and set the Vanilla Biscuit in the base; brush generously with vanilla Stock Syrup.","Soak the 7.5 sheets of gelatin in cold water until soft.","Warm one-third of the apricot purée (about 225g) with the sugar and chopped thyme, stirring until the sugar dissolves and the mixture is hot.","Remove from heat, squeeze excess water from the bloomed gelatin, and whisk it into the warm purée until fully dissolved.","Stir in the remaining cold apricot purée to bring the mixture down in temperature.","Whip the heavy cream to soft peak.","Fold the whipped cream into the apricot mixture in two additions until smooth and homogenous.","Pour the mousse over the prepared biscuit within the ring; smooth the top and freeze until fully set.","For the mirror glaze, soak the 3.75 sheets of gelatin in cold water.","Gently warm the apricot purée with the apple jelly, stirring until the jelly is melted and the mixture is smooth.","Remove from heat, squeeze excess water from the gelatin, and whisk it in until dissolved.","Stir in the nappage and strain the glaze for a smooth finish.","Cool the glaze to just warm (90-95°F) — it should not be hot to the touch.","Pour the glaze evenly over the frozen mousse to coat completely; return to the freezer to set the glaze before unmolding."]', '["Note: To make candied thyme branches, dip thyme, holding from the base of the stalk very briefly in"]', 'Pastry_Module_3_Course_6.pdf', 25);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Banana Mousse', 'Mousses & Entremets', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 68, 'Yield 1,368 grams', '1,368 grams', '[]', '[{"name":"heavy cream (1)","amounts":[["560","grams"]],"bakers_pct":null,"component":null},{"name":"gelatin sheets","amounts":[["6","each"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["76","grams"]],"bakers_pct":null,"component":null},{"name":"heavy cream (2)","amounts":[["190","grams"]],"bakers_pct":null,"component":null},{"name":"egg yolks","amounts":[["80","grams"]],"bakers_pct":null,"component":null},{"name":"banana puree","amounts":[["400","grams"]],"bakers_pct":null,"component":null},{"name":"cinnamon","amounts":[["2","grams"]],"bakers_pct":null,"component":null},{"name":"milk chocolate, melted","amounts":[["60","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Whip the heavy cream (1) to a soft peak and set aside refrigerated.","Bloom the gelatin sheets and set aside.","Make a caramel from the sugar and stop the cooking by adding the heavy cream (2). Return the caramel to the heat if necessary to re-melt the caramel.","Remove the caramel from the heat and add the bloomed gelatin.","Temper the egg yolks with all of the caramel mixture. Add the banana puree, cinnamon and melted milk chocolate. Cool the mixture until it is cooled enough to fold in the heavy cream.","Fold in the heavy cream."]', '[]', 'Pastry_Module_3_Course_6.pdf', 115);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Blood Orange- Cinnamon Miroir', 'Mousses & Entremets', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 63, '(two 6” cakes, 2” high) Yield 1,615 grams', '1,615 grams', '[]', '[{"name":"Vanilla Biscuit","amounts":[["1","half sheet"]],"bakers_pct":null,"component":null},{"name":"gelatin sheets","amounts":[["16.5","sheets"]],"bakers_pct":null,"component":null},{"name":"heavy cream","amounts":[["700","grams"]],"bakers_pct":null,"component":null},{"name":"blood orange puree","amounts":[["900","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["12.5","grams"]],"bakers_pct":null,"component":null},{"name":"cinnamon","amounts":[["2.5","grams"]],"bakers_pct":null,"component":null},{"name":"gelatin sheets","amounts":[["8","sheets"]],"bakers_pct":null,"component":null},{"name":"blood orange puree","amounts":[["250","grams"]],"bakers_pct":null,"component":null},{"name":"apricot nappage","amounts":[["250","grams"]],"bakers_pct":null,"component":null},{"name":"Stock Syrup- vanilla","amounts":[["","as needed"]],"bakers_pct":null,"component":null}]', NULL, '["Line a 6-inch entremet ring with acetate and set the Vanilla Biscuit in the base; brush generously with vanilla Stock Syrup.","Soak the 16.5 sheets of gelatin in cold water until soft.","Warm one-third of the blood orange purée (about 300g) with the sugar and cinnamon, stirring until the sugar dissolves and the mixture is hot.","Remove from heat, squeeze excess water from the bloomed gelatin, and whisk it into the warm purée until fully dissolved.","Stir in the remaining cold blood orange purée to bring the mixture down in temperature.","Whip the heavy cream to soft peak.","Fold the whipped cream into the blood orange mixture in two additions until smooth and homogenous.","Pour the mousse over the prepared biscuit within the ring; smooth the top and freeze until fully set.","For the mirror glaze, soak the 8 sheets of gelatin in cold water.","Gently warm the blood orange purée with the apricot nappage, stirring until melted and smooth.","Remove from heat, squeeze excess water from the gelatin, and whisk it in until dissolved.","Cool the glaze to just warm (90-95°F) — it should not be hot to the touch.","Pour the glaze evenly over the frozen mousse to coat completely; return to the freezer to set the glaze before unmolding."]', '[]', 'Pastry_Module_3_Course_6.pdf', 26);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Blueberry- Lemon Miroir', 'Mousses & Entremets', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 63, '(two 6” cakes, 2” high) Yield 1,390 grams', '1,390 grams', '[]', '[{"name":"Vanilla Biscuit","amounts":[["1","half sheet"]],"bakers_pct":null,"component":null},{"name":"gelatin sheets","amounts":[["9.5","sheets"]],"bakers_pct":null,"component":null},{"name":"heavy cream","amounts":[["675","grams"]],"bakers_pct":null,"component":null},{"name":"blueberry puree","amounts":[["675","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["37","grams"]],"bakers_pct":null,"component":null},{"name":"gelatin sheets","amounts":[["3.75","sheets"]],"bakers_pct":null,"component":null},{"name":"blueberry puree","amounts":[["217","grams"]],"bakers_pct":null,"component":null},{"name":"currant jelly","amounts":[["217","grams"]],"bakers_pct":null,"component":null},{"name":"Stock Syrup- lemon","amounts":[["","as needed"]],"bakers_pct":null,"component":null}]', NULL, '["Line a 6-inch entremet ring with acetate and set the Vanilla Biscuit in the base; brush generously with lemon Stock Syrup.","Soak the 9.5 sheets of gelatin in cold water until soft.","Warm one-third of the blueberry purée (about 225g) with the sugar, stirring until the sugar dissolves and the mixture is hot.","Remove from heat, squeeze excess water from the bloomed gelatin, and whisk it into the warm purée until fully dissolved.","Stir in the remaining cold blueberry purée to bring the mixture down in temperature.","Whip the heavy cream to soft peak.","Fold the whipped cream into the blueberry mixture in two additions until smooth and homogenous.","Pour the mousse over the prepared biscuit within the ring; smooth the top and freeze until fully set.","For the mirror glaze, soak the 3.75 sheets of gelatin in cold water.","Gently warm the blueberry purée with the currant jelly, stirring until the jelly is melted and the mixture is smooth.","Remove from heat, squeeze excess water from the gelatin, and whisk it in until dissolved.","Cool the glaze to just warm (90-95°F) — it should not be hot to the touch.","Pour the glaze evenly over the frozen mousse to coat completely; return to the freezer to set the glaze before unmolding."]', '[]', 'Pastry_Module_3_Course_6.pdf', 27);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Caramel Mousse', 'Mousses & Entremets', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 62, NULL, NULL, '[]', '[{"name":"heavy cream (1)","amounts":[["300","grams"]],"bakers_pct":null,"component":null},{"name":"gelatin","amounts":[["4.5","sheets"]],"bakers_pct":null,"component":null},{"name":"milk","amounts":[["150","grams"]],"bakers_pct":null,"component":null},{"name":"heavy cream (2)","amounts":[["150","grams"]],"bakers_pct":null,"component":null},{"name":"sugar (1)","amounts":[["180","grams"]],"bakers_pct":null,"component":null},{"name":"egg yolks","amounts":[["90","grams"]],"bakers_pct":null,"component":null},{"name":"sugar (2)","amounts":[["120","grams"]],"bakers_pct":null,"component":null},{"name":"Maldon sea salt","amounts":[["3","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Whip heavy cream (1) to soft peak; reserve refrigerated.","Soak the gelatin sheets in cold water.","Warm the milk and heavy cream (2) together; keep warm.","In a heavy saucepan, melt sugar (1) over medium heat, swirling occasionally, until it reaches a deep amber caramel.","Off heat, carefully whisk in the warm milk-cream mixture in stages (the caramel will bubble vigorously); return to heat and stir until smooth.","Whisk egg yolks with sugar (2) until pale.","Temper the yolks by gradually whisking in the hot caramel-cream mixture.","Return the mixture to the pan and cook over low heat, stirring constantly, until it thickens to nappe consistency (coats the back of a spoon).","Remove from heat; squeeze excess water from the gelatin and whisk it in until dissolved.","Stir in the Maldon salt.","Strain the caramel anglaise and cool to room temperature.","Fold in the whipped cream in two additions until fully incorporated.","Pour into molds and chill/freeze until set."]', '[]', 'Pastry_Module_3_Course_5.pdf', 196);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Charlotte Royale Biscuit Layers Raspberry Mousse Biscuit Layers', 'Mousses & Entremets', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 66, '(two half sheet pans)Yield 1,016 grams', '1,016 grams', '[]', '[{"name":"whole eggs","amounts":[["360","grams"]],"bakers_pct":null,"component":null},{"name":"egg yolks","amounts":[["216","grams"]],"bakers_pct":null,"component":null},{"name":"sugar (1)","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"cake flour","amounts":[["83","grams"]],"bakers_pct":null,"component":null},{"name":"cornstarch","amounts":[["50","grams"]],"bakers_pct":null,"component":null},{"name":"egg whites","amounts":[["153","grams"]],"bakers_pct":null,"component":null},{"name":"sugar (2)","amounts":[["45","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla extract","amounts":[["9","grams"]],"bakers_pct":null,"component":null}]', NULL, '["In a KitchenAid mixing bowl combine the eggs, yolks and the sugar (1).","Warm over double boiler until sugar is dissolved and mixture is warm.","Whip until ribboned.","Once ribboned, add the sifted flour and corn starch and vanilla extract. Whip for 1 more minute at high speed until light and fluffy.","Separately, make an ordinary meringue from the egg whites and sugar (2) and whip to a soft peak.","Fold together both mixes just until combined.","Spread evenly onto flat parchment lined half sheet pans.","Bake in a 375 F. convection oven for 8-10 minutes."]', '[]', 'Pastry_Module_3_Course_6.pdf', 60);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Chocolate Mirror Glaze', 'Mousses & Entremets', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 64, 'Yields 622 grams', '622 grams', '[]', '[{"name":"gelatin","amounts":[["5","sheets"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["285","grams"]],"bakers_pct":null,"component":null},{"name":"cocoa powder","amounts":[["78","grams"]],"bakers_pct":null,"component":null},{"name":"heavy cream","amounts":[["82","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["142","grams"]],"bakers_pct":null,"component":null},{"name":"semisweet chocolate","amounts":[["35","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Bloom gelatin sheets.","Sift together the sugar and cocoa powder, then whisk them together with the water and heavy cream in a pot. Bring to a boil.","Remove from the heat and pour over the chocolate. Stir until combined.","Add the bloomed gelatin and stir until dissolved. Strain mixture through a chinois","The glaze is ready to use when it reaches 85 F."]', '[]', 'Pastry_Module_3_Course_6.pdf', 37);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Chocolate Mousse', 'Mousses & Entremets', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 68, '(12 flexi mold domes) Yield 1,430 grams', '1,430 grams', '[]', '[{"name":"heavy cream (1)","amounts":[["680","grams"]],"bakers_pct":null,"component":null},{"name":"semi-sweet chocolate","amounts":[["330","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"egg yolks","amounts":[["160","grams"]],"bakers_pct":null,"component":null},{"name":"heavy cream (2)","amounts":[["160","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Whip cream (1) to soft peak and reserve in refrigerator.","Melt chocolate and set aside.","Whisk sugar, egg yolks and heavy cream (2) over double boiler until thickened.","Remove from heat, fold in melted chocolate into yolk mixture.","Cool to room temperature, and then fold in reserved whipped cream.","Pipe a layer into dome molds, making sure to line the mold completely with an even layer, (approximately 110g per mold).","Freeze immediately."]', '[]', 'Pastry_Module_3_Course_6.pdf', 110);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Chocolate “Brownie” Entremet Cake', 'Mousses & Entremets', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 64, '(two 10” cakes) Yield 635 grams', '635 grams', '[]', '[{"name":"unsweetened chocolate, finely","amounts":[["115","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["240","grams"]],"bakers_pct":null,"component":null},{"name":"eggs","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"vegetable oil","amounts":[["110","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla extract","amounts":[["7","grams"]],"bakers_pct":null,"component":null},{"name":"sour cream","amounts":[["120","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["450","grams"]],"bakers_pct":null,"component":null},{"name":"AP flour","amounts":[["170","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["3","grams"]],"bakers_pct":null,"component":null},{"name":"baking soda","amounts":[["4","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Melt finely chopped chocolate over a hot water bath and then combine with water. Whisk until smooth and set aside.","In a bowl, whisk the eggs, oil, vanilla and sour cream until smooth. Then, combine with melted chocolate mixture.","In a large bowl, combine sugar, flour, salt and baking soda and whisk together to combine.","Gradually pour the wet ingredients into the dry ingredients while whisking to ensure there are no lumps.","Portion the batter into two (10”) pans that have been sprayed and parchment lined. Bake at 325 F. until slightly firm.","Cool in freezer as soon as possible."]', '["Utilize the One Step mixing method"]', 'Pastry_Module_3_Course_6.pdf', 34);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Coconut-Lime & Chocolate Miroir', 'Mousses & Entremets', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 63, '(two 6” cakes, 2” high) Yield 1,258.75 grams', '1,258.75 grams', '[]', '[{"name":"Chocolate Biscuit","amounts":[["1","half sheet"]],"bakers_pct":null,"component":null},{"name":"gelatin sheets","amounts":[["9.75","sheets"]],"bakers_pct":null,"component":null},{"name":"heavy cream","amounts":[["525","grams"]],"bakers_pct":null,"component":null},{"name":"coconut puree","amounts":[["675","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["55","grams"]],"bakers_pct":null,"component":null},{"name":"gelatin sheets","amounts":[["3.75","sheets"]],"bakers_pct":null,"component":null},{"name":"coconut puree","amounts":[["187","grams"]],"bakers_pct":null,"component":null},{"name":"apple jelly","amounts":[["187","grams"]],"bakers_pct":null,"component":null},{"name":"Stock Syrup- rum","amounts":[["","as needed"]],"bakers_pct":null,"component":null}]', NULL, '["Line a 6-inch entremet ring with acetate and set the Chocolate Biscuit in the base; brush generously with rum Stock Syrup.","Soak the 9.75 sheets of gelatin in cold water until soft.","Warm one-third of the coconut purée (about 225g) with the sugar, stirring until the sugar dissolves and the mixture is hot.","Remove from heat, squeeze excess water from the bloomed gelatin, and whisk it into the warm purée until fully dissolved.","Stir in the remaining cold coconut purée to bring the mixture down in temperature.","Whip the heavy cream to soft peak.","Fold the whipped cream into the coconut mixture in two additions until smooth and homogenous.","Pour the mousse over the prepared biscuit within the ring; smooth the top and freeze until fully set.","For the mirror glaze, soak the 3.75 sheets of gelatin in cold water.","Gently warm the coconut purée with the apple jelly, stirring until the jelly is melted and the mixture is smooth.","Remove from heat, squeeze excess water from the gelatin, and whisk it in until dissolved.","Cool the glaze to just warm (90-95°F) — it should not be hot to the touch.","Pour the glaze evenly over the frozen mousse to coat completely; return to the freezer to set the glaze before unmolding."]', '[]', 'Pastry_Module_3_Course_6.pdf', 30);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Coffee Mousse', 'Mousses & Entremets', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 68, '(one 1/2 sheet pan)Yield 1,648 grams', '1,648 grams', '[]', '[{"name":"heavy cream","amounts":[["625","grams"]],"bakers_pct":null,"component":null},{"name":"gelatin powder","amounts":[["6","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["30","grams"]],"bakers_pct":null,"component":null},{"name":"heavy cream","amounts":[["338","grams"]],"bakers_pct":null,"component":null},{"name":"whole milk","amounts":[["338","grams"]],"bakers_pct":null,"component":null},{"name":"ground coffee","amounts":[["35","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla beans","amounts":[["1","each"]],"bakers_pct":null,"component":null},{"name":"egg yolks","amounts":[["150","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["125","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Whip cream to soft peak and reserve in refrigerator.","Bloom gelatin powder with the 30 grams of water and set aside.","Boil the next four ingredients, cover with plastic wrap and steep for 10 minutes.","After 10 minutes, strain the boiled mixture through a chinois and add more heavy cream if necessary to get a total of 675 grams.","Return mixture to a boil and make an anglaise with the egg yolks and sugar.","Remove from heat and add the bloomed gelatin.","Strain and allow to cool over an ice bath and then fold in whipped cream.","Pour onto cake frame on top of the coffee creme and freeze in the blast freezer or freeze overnight."]', '[]', 'Pastry_Module_3_Course_6.pdf', 106);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Dark Chocolate & Raspberry Mousse', 'Mousses & Entremets', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 62, NULL, NULL, '[]', '[{"name":"heavy cream","amounts":[["475","grams"]],"bakers_pct":null,"component":null},{"name":"semisweet chocolate","amounts":[["280","grams"]],"bakers_pct":null,"component":null},{"name":"water (1)","amounts":[["90","grams"]],"bakers_pct":null,"component":null},{"name":"egg yolks","amounts":[["120","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["85","grams"]],"bakers_pct":null,"component":null},{"name":"water (2)","amounts":[["60","grams"]],"bakers_pct":null,"component":null},{"name":"raspberry jam","amounts":[["160","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Whip the heavy cream to soft peak; set aside refrigerated.","Melt the semisweet chocolate with water (1) over a bain-marie, stirring until smooth; keep warm.","Combine sugar and water (2) in a saucepan and cook to soft-ball stage (240°F/116°C).","Begin whipping the egg yolks in a mixer.","With the mixer running, stream in the hot syrup and whip on high speed until pale, thick, and cooled to room temperature (pâte à bombe).","Fold the pâte à bombe into the warm melted chocolate until smooth.","Fold in the whipped cream in two additions until fully incorporated.","Gently ripple the raspberry jam through the mousse, leaving visible streaks rather than blending fully.","Pour into molds and freeze/chill until set."]', '[]', 'Pastry_Module_3_Course_5.pdf', 187);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Five Spice Milk Chocolate Mousse', 'Mousses & Entremets', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 62, NULL, NULL, '[]', '[{"name":"heavy cream","amounts":[["420","grams"]],"bakers_pct":null,"component":null},{"name":"gelatin","amounts":[["3","sheets"]],"bakers_pct":null,"component":null},{"name":"crème Anglaise","amounts":[["250","grams"]],"bakers_pct":null,"component":null},{"name":"five spice powder","amounts":[["3.7","grams"]],"bakers_pct":null,"component":null},{"name":"milk chocolate (melted)","amounts":[["380","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Whip the heavy cream to soft peak; set aside refrigerated.","Soak the gelatin in cold water.","Warm the crème anglaise with the five spice powder.","Remove from heat, squeeze excess water from the gelatin, and stir it into the warm crème anglaise until dissolved.","Gradually whisk the warm crème anglaise into the melted milk chocolate in thirds, stirring until smooth and glossy after each addition.","Cool the mixture to about body temperature.","Fold in the whipped cream in two additions until homogenous.","Pour into molds and chill/freeze until set."]', '[]', 'Pastry_Module_3_Course_5.pdf', 190);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Lemon Mousse', 'Mousses & Entremets', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 68, 'Yield 1,232 grams', '1,232 grams', '[]', '[{"name":"heavy cream","amounts":[["460","grams"]],"bakers_pct":null,"component":null},{"name":"gelatin sheets","amounts":[["6","sheets"]],"bakers_pct":null,"component":null},{"name":"Italian Meringue","amounts":[["125","grams"]],"bakers_pct":null,"component":null},{"name":"lemon juice","amounts":[["92","grams"]],"bakers_pct":null,"component":null},{"name":"lemon cream (previous recipe)","amounts":[["555","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Whip cream until soft peak and set aside refrigerated.","Bloom gelatin and set aside.","Meanwhile, make the Italian meringue and set aside125 grams that is needed for the recipe.","Heat the lemon juice and add the bloomed gelatin.","Add the lemon cream to the gelatin mixture and stir until combined.","With a whisk, fold the Italian meringue into the lemon cream gently making sure it is smooth.","Fold in the whipped cream."]', '[]', 'Pastry_Module_3_Course_6.pdf', 96);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Mandarin Gelee', 'Mousses & Entremets', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 5, NULL, NULL, '[]', '[{"name":"sheet gelatin","amounts":[["2.25","sheet"]],"bakers_pct":null,"component":null},{"name":"mandarin purée","amounts":[["200","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["60","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Bloom the gelatin in cold water until bloomed.","Combine the mandarin purée and sugar in a small saucepan; heat until the sucrose has dissolved.","Remove from heat and add the bloomed gelatin; stir until dissolved.","Cool slightly and deposit a thin layer onto the previously set panna cotta. Chill to further set."]', '[]', 'PA_Mod_01_Instructor.pdf', 171);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Milk Chocolate Mousse', 'Mousses & Entremets', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 68, 'Yield 841.5 grams', '841.5 grams', '[]', '[{"name":"heavy cream","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"gelatin","amounts":[["4.5","sheets"]],"bakers_pct":null,"component":null},{"name":"egg yolks","amounts":[["90","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["90","grams"]],"bakers_pct":null,"component":null},{"name":"milk powder","amounts":[["30","grams"]],"bakers_pct":null,"component":null},{"name":"glucose","amounts":[["9","grams"]],"bakers_pct":null,"component":null},{"name":"heavy cream","amounts":[["90","grams"]],"bakers_pct":null,"component":null},{"name":"milk chocolate","amounts":[["300","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["3","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Whip heavy cream to soft peak, set aside.","Bloom gelatin, set aside.","Combine the remaining pate a bombe ingredients in a pot, whisk until mixture reaches 179 F.","Remove gelatin from water and add to the hot pate a bomb and stir until dissolved.","Transfer to a KitchenAid bowl and whip until cooled.","In a large bowl, make a ganache with boiled heavy cream, milk chocolate and salt, making sure it is well emulsified.","Fold cooled pate a bombe into the ganache in three stages.","Fold in whipped cream."]', '[]', 'Pastry_Module_3_Course_6.pdf', 89);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Orange White Chocolate Mousse', 'Mousses & Entremets', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 62, NULL, NULL, '[]', '[{"name":"heavy cream","amounts":[["475","grams"]],"bakers_pct":null,"component":null},{"name":"gelatin sheets","amounts":[["6","sheets"]],"bakers_pct":null,"component":null},{"name":"white chocolate","amounts":[["280","grams"]],"bakers_pct":null,"component":null},{"name":"orange juice","amounts":[["90","grams"]],"bakers_pct":null,"component":null},{"name":"egg yolks","amounts":[["120","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["90","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["60","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Whip the heavy cream to soft peak; set aside refrigerated.","Soak the gelatin in cold water.","Melt the white chocolate over a bain-marie; keep warm.","Warm the orange juice, remove from heat, squeeze excess water from the gelatin, and stir it into the juice until dissolved.","Gradually whisk the warm orange juice into the melted white chocolate until smooth and fully emulsified.","Combine the sugar and water in a saucepan and cook to soft-ball stage (240°F/116°C).","Whip the egg yolks while streaming in the hot syrup; whip until thick, pale, and cooled (pâte à bombe).","Fold the pâte à bombe into the white chocolate-orange mixture.","Fold in the whipped cream in two additions until fully incorporated.","Pour into molds and chill/freeze until set."]', '[]', 'Pastry_Module_3_Course_5.pdf', 185);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Peanut Butter & Jelly Mousse', 'Mousses & Entremets', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 62, NULL, NULL, '[]', '[{"name":"crème Anglaise","amounts":[["500","grams"]],"bakers_pct":null,"component":null},{"name":"peanut butter","amounts":[["88","grams"]],"bakers_pct":null,"component":null},{"name":"gelatin","amounts":[["5","sheets"]],"bakers_pct":null,"component":null},{"name":"whipped cream","amounts":[["350","grams"]],"bakers_pct":null,"component":null},{"name":"grape jelly","amounts":[["240","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Soak the gelatin in cold water.","Warm the crème anglaise and whisk in the peanut butter until completely smooth.","Remove from heat, squeeze excess water from the gelatin, and stir it in until dissolved.","Cool the peanut butter anglaise to room temperature.","Fold in the whipped cream in two additions until fully incorporated.","Spoon half of the mousse into molds.","Add a layer or swirl of grape jelly over the mousse.","Top with the remaining mousse, covering the jelly completely.","Chill/freeze until fully set."]', '[]', 'Pastry_Module_3_Course_5.pdf', 194);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Pineapple Gelee', 'Mousses & Entremets', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 5, NULL, NULL, '[]', '[{"name":"sheet gelatin","amounts":[["2.5","sheets"]],"bakers_pct":null,"component":null},{"name":"pineapple purée","amounts":[["185","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["60","grams"]],"bakers_pct":null,"component":null},{"name":"dark rum","amounts":[["12","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Bloom the gelatin in cold water until bloomed.","Combine the pineapple purée and sugar in a small saucepan and heat just until the sucrose has dissolved.","Remove from heat and add bloomed gelatin, followed by the rum; stir until dissolved.","Cool slightly and deposit a thin layer onto the previously set panna cotta. Chill to further set."]', '[]', 'PA_Mod_01_Instructor.pdf', 170);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Pistachio Cherry Mousse', 'Mousses & Entremets', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 62, NULL, NULL, '[]', '[{"name":"crème Anglaise","amounts":[["500","grams"]],"bakers_pct":null,"component":null},{"name":"pistachio paste","amounts":[["25","grams"]],"bakers_pct":null,"component":null},{"name":"kirsch liquor","amounts":[["6","grams"]],"bakers_pct":null,"component":null},{"name":"gelatin","amounts":[["7.5","sheets"]],"bakers_pct":null,"component":null},{"name":"heavy cream","amounts":[["350","grams"]],"bakers_pct":null,"component":null},{"name":"Amarena cherries, drained","amounts":[["200","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Soak the gelatin in cold water.","Warm the crème anglaise and whisk in the pistachio paste until smooth.","Remove from heat, squeeze excess water from the gelatin, and stir it in until dissolved.","Stir in the kirsch.","Cool the pistachio anglaise to room temperature.","Whip the heavy cream to soft peak.","Fold the whipped cream into the pistachio mixture in two additions until homogenous.","Fold in the drained Amarena cherries.","Pour into molds and chill/freeze until set."]', '[]', 'Pastry_Module_3_Course_5.pdf', 192);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Pomegranate Gelee', 'Mousses & Entremets', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 5, NULL, NULL, '[]', '[{"name":"sheet gelatin","amounts":[["2","sheets"]],"bakers_pct":null,"component":null},{"name":"pomegranate juice","amounts":[["250","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["55","grams"]],"bakers_pct":null,"component":null},{"name":"balsamic vinegar","amounts":[["2","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Bloom the gelatin in cold water until bloomed.","Combine the pomegranate juice and sugar in a small saucepan; heat until the sucrose has dissolved.","Remove from heat and add the bloomed gelatin and balsamic vinegar; stir until dissolved.","Cool slightly and deposit a thin layer onto the previously set panna cotta. Chill to further set."]', '[]', 'PA_Mod_01_Instructor.pdf', 171);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Raspberry & Chocolate Miroir', 'Mousses & Entremets', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 63, '(two 6” cakes, 2” high) Yield 1,237 grams', '1,237 grams', '[]', '[{"name":"Chocolate Biscuit","amounts":[["1","half sheet"]],"bakers_pct":null,"component":null},{"name":"gelatin sheets","amounts":[["7.5","sheets"]],"bakers_pct":null,"component":null},{"name":"heavy cream","amounts":[["525","grams"]],"bakers_pct":null,"component":null},{"name":"raspberry puree","amounts":[["675","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["37","grams"]],"bakers_pct":null,"component":null},{"name":"gelatin sheets","amounts":[["3.75","sheets"]],"bakers_pct":null,"component":null},{"name":"raspberry puree","amounts":[["187","grams"]],"bakers_pct":null,"component":null},{"name":"currant jelly","amounts":[["187","grams"]],"bakers_pct":null,"component":null},{"name":"Stock Syrup- Framboise","amounts":[["","as needed"]],"bakers_pct":null,"component":null}]', NULL, '["Line a 6-inch entremet ring with acetate and set the Chocolate Biscuit in the base; brush generously with Framboise Stock Syrup.","Soak the 7.5 sheets of gelatin in cold water until soft.","Warm one-third of the raspberry purée (about 225g) with the sugar, stirring until the sugar dissolves and the mixture is hot.","Remove from heat, squeeze excess water from the bloomed gelatin, and whisk it into the warm purée until fully dissolved.","Stir in the remaining cold raspberry purée to bring the mixture down in temperature.","Whip the heavy cream to soft peak.","Fold the whipped cream into the raspberry mixture in two additions until smooth and homogenous.","Pour the mousse over the prepared biscuit within the ring; smooth the top and freeze until fully set.","For the mirror glaze, soak the 3.75 sheets of gelatin in cold water.","Gently warm the raspberry purée with the currant jelly, stirring until the jelly is melted and the mixture is smooth.","Remove from heat, squeeze excess water from the gelatin, and whisk it in until dissolved.","Cool the glaze to just warm (90-95°F) — it should not be hot to the touch.","Pour the glaze evenly over the frozen mousse to coat completely; return to the freezer to set the glaze before unmolding."]', '[]', 'Pastry_Module_3_Course_6.pdf', 28);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Raspberry Mousse', 'Mousses & Entremets', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 66, 'Yield 1,118 grams', '1,118 grams', '[]', '[{"name":"gelatin","amounts":[["4.5","sheets"]],"bakers_pct":null,"component":null},{"name":"heavy cream","amounts":[["560","grams"]],"bakers_pct":null,"component":null},{"name":"raspberry puree","amounts":[["240","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["130","grams"]],"bakers_pct":null,"component":null},{"name":"yolks","amounts":[["120","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["68","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Bloom the gelatin and set aside.","Whip the heavy cream to soft peak and set aside refrigerated.","Heat the raspberry puree and sugar together until the sugar is dissolved. Remove from the heat; allow to cool slightly and mix in the bloomed gelatin. Allow this mixture to cool before use.","While the puree is cooling, mix the yolks and sugar in the bowl of a KitchenAid mixer and place over a bain marie and whip until thick and the sugar dissolved. Remove from the heat and whip on a mixer until ribboned and cooled.","Add the cooled raspberry puree mixture to the ribboned eggs and mix until cool enough to fold in the whipped cream.","Fold in the whipped cream quickly and all at once. Charlotte Assembly:","Unmold biscuit onto parchment that has been lightly sprinkled with 10X.","Spread one half sheet of biscuit evenly with 200 grams of seedless raspberry jam and roll into a tight roulade. Freeze until solid so that ¼” thick slices can be","Fill with raspberry mousse. *Note the next instructions before filling the mold","Cut 6” cake disc from remaining (1/2) sheet cake (or larger depending on bowl","Freeze overnight or place in a blast freezer before unmolding.","Glaze with nappage if desired."]', '[]', 'Pastry_Module_3_Course_6.pdf', 61);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Raspberry Verrine Raspberry Gelee', 'Mousses & Entremets', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 71, NULL, NULL, '[]', '[{"name":"raspberry purée","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"raspberries, fresh","amounts":[["75","grams"]],"bakers_pct":null,"component":null},{"name":"invert sugar","amounts":[["40","grams"]],"bakers_pct":null,"component":null},{"name":"gelatin sheets, bloomed","amounts":[["2.5","each"]],"bakers_pct":null,"component":null}]', '[["350","grams"]]', '["Combine the raspberry purée and fresh raspberries in a sauce pan. Bring to a simmer.","Whisk in the gelatin and invert sugar. Deposit as instructed into serving dishes and chill to set."]', '[]', 'Pastry_Module_3_Course_6.pdf', 153);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Red Wine Gelee', 'Mousses & Entremets', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 5, NULL, NULL, '[]', '[{"name":"sheet gelatin","amounts":[["3.75","sheets"]],"bakers_pct":null,"component":null},{"name":"red wine","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["37","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Bloom the gelatin in cold water until bloomed.","Combine the red wine and sugar in a small saucepan and bring to a boil; reduce heat and continue to simmer for several minutes until the mixture has reduced slightly, to a weight of approximately 225g.","Remove from heat and add bloomed gelatin; stir until dissolved.","Cool slightly and deposit a thin layer onto the previously set panna cotta. Chill to further set."]', '[]', 'PA_Mod_01_Instructor.pdf', 170);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Sour Cherry & Chocolate Miroir', 'Mousses & Entremets', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 63, '(two 6” cakes, 2” high) Yield 1,410 grams', '1,410 grams', '[]', '[{"name":"Chocolate Biscuit","amounts":[["1","half sheet"]],"bakers_pct":null,"component":null},{"name":"gelatin","amounts":[["9.75","sheets"]],"bakers_pct":null,"component":null},{"name":"heavy cream","amounts":[["675","grams"]],"bakers_pct":null,"component":null},{"name":"sour cherry puree","amounts":[["675","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["60","grams"]],"bakers_pct":null,"component":null},{"name":"gelatin sheets","amounts":[["3.75","sheets"]],"bakers_pct":null,"component":null},{"name":"cherry puree","amounts":[["187","grams"]],"bakers_pct":null,"component":null},{"name":"currant jelly","amounts":[["187","grams"]],"bakers_pct":null,"component":null},{"name":"Stock Syrup- cherry juice","amounts":[["","as needed"]],"bakers_pct":null,"component":null}]', NULL, '["Line a 6-inch entremet ring with acetate and set the Chocolate Biscuit in the base; brush generously with cherry-juice Stock Syrup.","Soak the 9.75 sheets of gelatin in cold water until soft.","Warm one-third of the sour cherry purée (about 225g) with the sugar, stirring until the sugar dissolves and the mixture is hot.","Remove from heat, squeeze excess water from the bloomed gelatin, and whisk it into the warm purée until fully dissolved.","Stir in the remaining cold sour cherry purée to bring the mixture down in temperature.","Whip the heavy cream to soft peak.","Fold the whipped cream into the cherry mixture in two additions until smooth and homogenous.","Pour the mousse over the prepared biscuit within the ring; smooth the top and freeze until fully set.","For the mirror glaze, soak the 3.75 sheets of gelatin in cold water.","Gently warm the cherry purée with the currant jelly, stirring until the jelly is melted and the mixture is smooth.","Remove from heat, squeeze excess water from the gelatin, and whisk it in until dissolved.","Cool the glaze to just warm (90-95°F) — it should not be hot to the touch.","Pour the glaze evenly over the frozen mousse to coat completely; return to the freezer to set the glaze before unmolding."]', '[]', 'Pastry_Module_3_Course_6.pdf', 29);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Strawberry Gelee', 'Mousses & Entremets', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 68, 'Yield: 585 grams', '585 grams', '[]', '[{"name":"gelatin sheets","amounts":[["6","sheets"]],"bakers_pct":null,"component":null},{"name":"lemon juice","amounts":[["40","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["40","grams"]],"bakers_pct":null,"component":null},{"name":"strawberry puree","amounts":[["500","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Bloom gelatin.","In a small sauce pan heat the lemon juice with the sugar to dissolve and add the bloomed gelatin and stir to melt.","Temper the gelatin mixture with some of the strawberry puree to make sure the gelatin is not setting and then pour the gelatin base into the remaining puree and stir to incorporate.","Allow gelee to cool before pouring onto ½ sheet pan flexi mold frame.","Put in blast freezer or freeze overnight until ready to assemble the cake."]', '[]', 'Pastry_Module_3_Course_6.pdf', 94);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Apple Cranberry Pie', 'Pies & Tarts', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 40, NULL, NULL, '[]', '[{"name":"Pâte Sucrée or Sour Cream Dough","amounts":[["600","grams"]],"bakers_pct":null,"component":null},{"name":"firm, tart apples (5 large)","amounts":[["1125","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["170","grams"]],"bakers_pct":null,"component":null},{"name":"cranberries, rinsed and drained","amounts":[["170","grams"]],"bakers_pct":null,"component":null},{"name":"all-purpose flour","amounts":[["15","grams"]],"bakers_pct":null,"component":null},{"name":"cinnamon","amounts":[["2","grams"]],"bakers_pct":null,"component":null},{"name":"grated lemon zest","amounts":[["2","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Roll half the dough and line the pie pan; trim overhang and chill.","Peel, core and slice apples into wedges.","Toss apples with sugar, cranberries, flour, cinnamon and lemon zest.","Fill the lined shell with the apple-cranberry mixture, mounding slightly in the center.","Roll remaining dough and top the pie (full round or lattice); seal and crimp the edges.","Cut vents in the top crust if using a full round.","Chill the filled pie until the dough is firm.","Bake until the crust is golden brown and the filling is bubbling through the vents, tenting with foil if the edges brown too quickly.","Cool completely on a rack before slicing."]', '[]', 'Pastry_Module_2_Course_4.pdf', 75);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Apple Crumb Pie', 'Pies & Tarts', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 40, NULL, NULL, '["9-inch pie"]', '[{"name":"Pâte Sucrée or Sour Cream Dough","amounts":[["300","grams"]],"bakers_pct":null,"component":null},{"name":"Golden Delicious apples (5 large)","amounts":[["1125","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["200","grams"]],"bakers_pct":null,"component":null},{"name":"all-purpose flour","amounts":[["40","grams"]],"bakers_pct":null,"component":null},{"name":"cinnamon","amounts":[["2","grams"]],"bakers_pct":null,"component":null},{"name":"lemon zest","amounts":[["2","grams"]],"bakers_pct":null,"component":null},{"name":"crumb topping","amounts":[["450","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Roll the dough and line the pie pan; trim and crimp the edge, then chill.","Peel, core and slice apples into wedges.","Toss apples with sugar, flour, cinnamon and lemon zest.","Fill the shell with the apple mixture, mounding slightly in the center.","Cover the apples generously and evenly with the crumb topping.","Bake until the topping is golden brown and the apples are tender when pierced, tenting with foil if the topping browns too quickly.","Cool completely before slicing."]', '[]', 'Pastry_Module_2_Course_4.pdf', 74);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Apple Pie', 'Pies & Tarts', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 40, NULL, NULL, '[]', '[{"name":"Pâte Sucrée or Sour Cream Dough","amounts":[["500","grams"]],"bakers_pct":null,"component":null},{"name":"cooked apple filling","amounts":[["1200","grams"]],"bakers_pct":null,"component":null},{"name":"butter","amounts":[["30","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Roll half the dough and line the pie pan; chill.","Fill the shell with the cooked apple filling, spreading evenly.","Dot the filling with butter.","Roll the remaining dough and top the pie (full round or lattice); seal and crimp the edges.","Cut vents in the top crust if using a full round.","Chill the filled pie until the dough is firm.","Bake until the crust is golden brown and the filling bubbles through the vents.","Cool completely on a rack before slicing."]', '[]', 'Pastry_Module_2_Course_4.pdf', 74);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Apple Tart', 'Pies & Tarts', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 47, NULL, NULL, '[]', '[{"name":"granulated sugar","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["60","grams"]],"bakers_pct":null,"component":null},{"name":"lemon juice","amounts":[["5","grams"]],"bakers_pct":null,"component":null},{"name":"unsalted butter","amounts":[["115","grams"]],"bakers_pct":null,"component":null},{"name":"Gluten Free Flaky Pie Crust, above","amounts":[["1","batch"]],"bakers_pct":null,"component":null}]', NULL, '["Peel, core, halve and slice the apples, keeping halves intact; set aside","Combine sugar, water and lemon juice in a sauté pan with a 10-inch. Bring to a boil and cook syrup to a light caramel. Add butter off the heat.","Arrange apple halves in pan, rounded sides face down, crowding together. If there are any leftover halves, separate slices to form a layer over the halves in the pan.","Cook, covered over medium heat for about 15 minutes or until apples are tender.","Uncover. Allow syrup in the pan to reduce until thick. Cool."]', '[]', 'Pastry_Module_2_Course_4.pdf', 139);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Apple Walnut Lattice Tart', 'Pies & Tarts', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 39, NULL, NULL, '[]', '[{"name":"Pâte Sucrée","amounts":[["1150","grams"]],"bakers_pct":null,"component":null},{"name":"Walnut Frangipane","amounts":[["680","grams"]],"bakers_pct":null,"component":null},{"name":"Golden Delicious apples (8 large)","amounts":[["1800","grams"]],"bakers_pct":null,"component":null},{"name":"butter, melted","amounts":[["55","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["115","grams"]],"bakers_pct":null,"component":null},{"name":"ground cinnamon","amounts":[["2","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Roll 700 grams of the dough on a floured surface and line a buttered 12- x 18- inch pan with it. Chill the dough-lined pan. Reserve the remaining pound of dough in the refrigerator.","Prepare the Walnut Frangipane and spread it evenly on the dough.","Peel, core and slice the apples and fan them out on the filling. Paint the apples with the butter and sprinkle evenly with the cinnamon and sugar."]', '[]', 'Pastry_Module_2_Course_4.pdf', 56);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Apricot Cognac Tart', 'Pies & Tarts', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 39, NULL, NULL, '[]', '[{"name":"Pâte Sucrée","amounts":[["680","grams"]],"bakers_pct":null,"component":null},{"name":"Pastry Cream","amounts":[["680","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla extract","amounts":[["13","grams"]],"bakers_pct":null,"component":null},{"name":"toasted ground almonds","amounts":[["115","grams"]],"bakers_pct":null,"component":null},{"name":"Cognac","amounts":[["55","grams"]],"bakers_pct":null,"component":null},{"name":"apricots","amounts":[["1350","grams"]],"bakers_pct":null,"component":null},{"name":"apricot glaze","amounts":[["340","grams"]],"bakers_pct":null,"component":null},{"name":"toasted sliced almonds","amounts":[["55","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Prepare the dough and chill it. Roll the dough on a floured surface and","Beat the pastry cream to soften it and beat in the vanilla, toasted ground almonds and one ounce of Cognac.","Rinse, halve and stone the apricots. Spread the almond pastry cream evenly on the dough and arrange the apricot halves on it, cut side down. Bake the tart at 350 degrees about 30 - 40 minutes. Cool the tart.","Combine Apricot Glaze and remaining ounce of Cognac. Brush the glaze evenly over the cooled tart. Strew with the sliced almond"]', '[]', 'Pastry_Module_2_Course_4.pdf', 55);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Banana Walnut Tart', 'Pies & Tarts', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 39, NULL, NULL, '[]', '[{"name":"Pâte Sucrée","amounts":[["340","grams"]],"bakers_pct":null,"component":null},{"name":"2 bananas","amounts":[["240","grams"]],"bakers_pct":null,"component":null},{"name":"Walnut Frangipane","amounts":[["340","grams"]],"bakers_pct":null,"component":null},{"name":"walnut pieces, chopped and sifted","amounts":[["115","grams"]],"bakers_pct":null,"component":null},{"name":"dark rum","amounts":[["28","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Roll the Pâte Sucrée and line the tart pan; blind-bake the shell until lightly golden and let cool.","Spread the Walnut Frangipane evenly in the baked shell.","Peel and slice the bananas; toss gently with the dark rum.","Arrange the banana slices over the frangipane.","Scatter the chopped walnut pieces over the top.","Bake until the frangipane is puffed, set and golden brown.","Cool completely before unmolding and slicing."]', '[]', 'Pastry_Module_2_Course_4.pdf', 62);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Bistro Apple Tart', 'Pies & Tarts', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 47, NULL, NULL, '[]', '[{"name":"Gluten Free Flaky Pie Crust, above","amounts":[["1","batch"]],"bakers_pct":null,"component":null},{"name":"melted butter","amounts":[["60","grams"]],"bakers_pct":null,"component":null},{"name":"granulated sugar","amounts":[["60","grams"]],"bakers_pct":null,"component":null},{"name":"cinnamon","amounts":[["3","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Slice apple thinly and fan in concentric circle over dough.","Brush with melted butter and sprinkle with cinnamon sugar.","Bake at 375°F for about 20 minutes until the dough is cooked through and apples are tender."]', '[]', 'Pastry_Module_2_Course_4.pdf', 140);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Blueberry Pie', 'Pies & Tarts', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 40, NULL, NULL, '[]', '[{"name":"Pâte Sucrée or Sour Cream Dough","amounts":[["300","grams"]],"bakers_pct":null,"component":null},{"name":"blueberries, divided","amounts":[["600","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["140","grams"]],"bakers_pct":null,"component":null},{"name":"cornstarch","amounts":[["28","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["30","grams"]],"bakers_pct":null,"component":null},{"name":"butter","amounts":[["55","grams"]],"bakers_pct":null,"component":null},{"name":"lemon zest","amounts":[["2","grams"]],"bakers_pct":null,"component":null},{"name":"Crumb Topping (optional)","amounts":[["450","grams"]],"bakers_pct":null,"component":null},{"name":"dough for lattice (optional)","amounts":[["300","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Roll the dough and line the pie pan; chill.","Whisk the cornstarch and water together to make a slurry.","In a saucepan, cook a portion of the blueberries with the sugar and lemon zest over medium heat until the berries release their juices.","Stir in the cornstarch slurry and cook until the mixture thickens and turns glossy.","Remove from heat and fold in the remaining raw blueberries; cool slightly.","Fill the shell with the blueberry mixture and dot with butter.","Top with a lattice of rolled dough, or cover with the crumb topping, per the desired finish.","Bake until the filling is bubbling and the crust or topping is golden brown.","Cool completely to allow the filling to set before slicing."]', '[]', 'Pastry_Module_2_Course_4.pdf', 76);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Blueberry and Walnut Tart', 'Pies & Tarts', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 39, NULL, NULL, '[]', '[{"name":"Pâte Sucrée","amounts":[["340","grams"]],"bakers_pct":null,"component":null},{"name":"blueberries","amounts":[["450","grams"]],"bakers_pct":null,"component":null},{"name":"Walnut Frangipane","amounts":[["340","grams"]],"bakers_pct":null,"component":null},{"name":"Apricot Glaze","amounts":[["115","grams"]],"bakers_pct":null,"component":null},{"name":"ground walnuts","amounts":[["55","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Roll the Pâte Sucrée and line the tart pan; blind-bake the shell until lightly golden and let cool.","Spread the Walnut Frangipane evenly in the baked shell.","Scatter the blueberries evenly over the frangipane.","Bake until the frangipane is set, puffed and golden brown.","Cool slightly, then brush the warm tart with Apricot Glaze.","Finish by pressing ground walnuts around the edge of the tart.","Cool completely before unmolding and slicing."]', '[]', 'Pastry_Module_2_Course_4.pdf', 60);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Breton Dough', 'Pies & Tarts', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 48, NULL, NULL, '[]', '[{"name":"butter","amounts":[["455","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["455","grams"]],"bakers_pct":null,"component":null},{"name":"yolks (8)","amounts":[["135","grams"]],"bakers_pct":null,"component":null},{"name":"lemon zest, grated","amounts":[["2","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla","amounts":[["8","grams"]],"bakers_pct":null,"component":null},{"name":"flour","amounts":[["795","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Prepare using Creaming Dough Mixing Method.","Use immediately. This dough is very soft."]', '[]', 'Pastry_Module_2_Course_4.pdf', 143);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Cannoli', 'Pies & Tarts', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 48, NULL, NULL, '[]', '[{"name":"all-purpose flour","amounts":[["370","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["43","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["6","grams"]],"bakers_pct":null,"component":null},{"name":"cinnamon","amounts":[["3","grams"]],"bakers_pct":null,"component":null},{"name":"butter or lard","amounts":[["43","grams"]],"bakers_pct":null,"component":null},{"name":"large egg (1)","amounts":[["50","grams"]],"bakers_pct":null,"component":null},{"name":"egg yolk (1)","amounts":[["17","grams"]],"bakers_pct":null,"component":null},{"name":"dry white wine or dry vermouth","amounts":[["120","grams"]],"bakers_pct":null,"component":null},{"name":"ricotta impastata","amounts":[["900","grams"]],"bakers_pct":null,"component":null},{"name":"confectioners'' sugar","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla extract","amounts":[["4","grams"]],"bakers_pct":null,"component":null},{"name":"cinnamon","amounts":[["1","gram"]],"bakers_pct":null,"component":null},{"name":"chopped semisweet chocolate","amounts":[["28","grams"]],"bakers_pct":null,"component":null},{"name":"chopped candied orange peel","amounts":[["28","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine the flour, sugar, salt and cinnamon in a medium mixing bowl.","Rub the lard or butter by hand until it is finely incorporated.","Whisk the egg, yolk and wine together and use a large rubber spatula to stir the liquid into the flour mixture. Continue stirring until all the flour is evenly moistened, and then scrape the dough out onto a floured surface.","Knead the dough briefly by folding it over onto itself repeatedly until it becomes too firm and elastic to knead further. Use a bench scraper or a knife to divide the dough into 3 pieces. Flour 1 piece and pass it through the widest setting on a pasta machine.","Fold the dough in thirds and pass it through again from the open side. Repeat until the dough is smooth and elastic and no longer shreds as you are putting it through the machine.","Fold the dough in thirds again, wrap in plastic wrap and repeat with the remaining two pieces of dough.","After all the pieces have been passed through the machine, fold each in thirds again, wrap them in plastic wrap and refrigerate them for at least an hour or as long as overnight before continuing.","To form the cannoli shells, remove the dough from the refrigerator and flour 1 piece.","Use a plain round cutter or a stiff cardboard pattern and the point of a pairing knife","Cut straight down without twisting the utter, which would seal the cut edge of the","Roll over 1 disk of dough with a rolling pin to make it slightly oval. Position 1","Draw the other edge of the dough disk up to meet the first one and overlap them","In a large Dutch oven, heat the oil to 375 degrees. Fry 3 or 4 cannoli at a time to a","Use an oven mitt to grasp the end of the tube and use a towel or several","Repeat with remaining pieces of dough and tubes. If you have only a few tubes","While the shells are cooling, prepare the filling.","Place the ricotta in the bowl of an electric mixer. Using the paddle attachment","Beat in the confectioner''s sugar and continue beating just until it is absorbed.","Beat in the vanilla and cinnamon. Remove the bowl from the mixer and use a"]', '[]', 'Pastry_Module_2_Course_4.pdf', 146);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Citrus-Cornmeal Breton Cookies', 'Pies & Tarts', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 56, 'Yield 1,255 grams', '1,255 grams', '[]', '[{"name":"egg yolks","amounts":[["150","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["300","grams"]],"bakers_pct":null,"component":null},{"name":"butter, softened","amounts":[["300","grams"]],"bakers_pct":null,"component":null},{"name":"orange zest","amounts":[["3","grams"]],"bakers_pct":null,"component":null},{"name":"lemon zest","amounts":[["3","grams"]],"bakers_pct":null,"component":null},{"name":"lime zest","amounts":[["3","grams"]],"bakers_pct":null,"component":null},{"name":"AP flour","amounts":[["375","grams"]],"bakers_pct":null,"component":null},{"name":"cornmeal","amounts":[["94","grams"]],"bakers_pct":null,"component":null},{"name":"baking powder","amounts":[["23","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["4","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Whip yolks and sugar to heavy ribbon.","Switch to paddle and add butter.","Add citrus zests and dry ingredients and mix until smooth.","Scoop dough with medium or large cookie scoop and freeze.","Cut frozen scoops into quarters. Bake with cut side facing up at 350F."]', '[]', 'Pastry_Module_3_Course_5.pdf', 103);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Dark Linzer Dough', 'Pies & Tarts', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 41, NULL, NULL, '[]', '[{"name":"flour","amounts":[["225","grams"]],"bakers_pct":"61.64","component":null},{"name":"sugar","amounts":[["170","grams"]],"bakers_pct":"46.58","component":null},{"name":"baking powder","amounts":[["4","grams"]],"bakers_pct":"1.10","component":null},{"name":"cinnamon","amounts":[["4","grams"]],"bakers_pct":"1.10","component":null},{"name":"butter","amounts":[["170","grams"]],"bakers_pct":"46.58","component":null},{"name":"egg (1)","amounts":[["50","grams"]],"bakers_pct":"13.70","component":null},{"name":"yolk (1)","amounts":[["17","grams"]],"bakers_pct":"4.66","component":null}]', NULL, '["Prepare using Mealy Dough Mixing Method.","Scrape dough out of bowl. Do not refrigerate before using. Dough will be very soft."]', '[]', 'Pastry_Module_2_Course_4.pdf', 86);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Galette Dough', 'Pies & Tarts', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 38, NULL, NULL, '[]', '[{"name":"all-purpose flour","amounts":[["595","grams"]],"bakers_pct":"100.00","component":null},{"name":"salt","amounts":[["6","grams"]],"bakers_pct":"1.01","component":null},{"name":"sugar","amounts":[["28","grams"]],"bakers_pct":"4.71","component":null},{"name":"butter","amounts":[["453","grams"]],"bakers_pct":"76.13","component":null},{"name":"eggs (4)","amounts":[["200","grams"]],"bakers_pct":"33.61","component":null},{"name":"water","amounts":[["55","grams"]],"bakers_pct":"9.24","component":null}]', NULL, '["Prepare using Flaky Dough Mixing Method."]', '[]', 'Pastry_Module_2_Course_4.pdf', 47);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Galette Fillings Apple Cinnamon Filling', 'Pies & Tarts', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 40, NULL, NULL, '[]', '[{"name":"Granny Smith apples (6 large)","amounts":[["1350","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["115","grams"]],"bakers_pct":null,"component":null},{"name":"butter","amounts":[["55","grams"]],"bakers_pct":null,"component":null},{"name":"dark rum","amounts":[["55","grams"]],"bakers_pct":null,"component":null},{"name":"lemon juice","amounts":[["15","grams"]],"bakers_pct":null,"component":null},{"name":"cinnamon","amounts":[["1","gram"]],"bakers_pct":null,"component":null}]', NULL, '["Peel, core, and halve the apples.","Cut each half into 5 wedges.","Combine apple slices with remaining ingredients in a heavy saucepan over medium heat.","Cover; cook 10 minutes. Uncover; lower heat, cook until liquid evaporates. Cool."]', '[]', 'Pastry_Module_2_Course_4.pdf', 70);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Gluten Free Flaky Pie Crust', 'Pies & Tarts', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 47, NULL, NULL, '[]', '[{"name":"brown rice flour","amounts":[["142","grams"]],"bakers_pct":null,"component":null},{"name":"potato starch","amounts":[["58","grams"]],"bakers_pct":null,"component":null},{"name":"tapioca starch","amounts":[["16","grams"]],"bakers_pct":null,"component":null},{"name":"sweet rice flour","amounts":[["16","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["3","grams"]],"bakers_pct":null,"component":null},{"name":"granulated sugar","amounts":[["4","grams"]],"bakers_pct":null,"component":null},{"name":"cold unsalted butter","amounts":[["86","grams"]],"bakers_pct":null,"component":null},{"name":"egg(1)","amounts":[["50","grams"]],"bakers_pct":null,"component":null},{"name":"cider vinegar","amounts":[["15","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["45","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Mix all dry ingredients in the bowl of a standing mixer fitted with a paddle attachment to combine well.","Add cold butter to the bowl in large pieces and mix briefly.","Combine liquid ingredients. Add all at once to the mixer and beat until dough is formed.","Wrap dough and chill until ready to use. Dough can be used right away.","When ready to use, roll on parchment or between two pieces of parchment. Invert into a pan and peel away parchment. If rolling directly on the bench, make sure to use a gluten free starch","Bake at 375° F until a deep golden color."]', '[]', 'Pastry_Module_2_Course_4.pdf', 138);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Grigliata Umbra', 'Pies & Tarts', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 39, NULL, NULL, '[]', '[{"name":"Pâte Sucrée","amounts":[["1150","grams"]],"bakers_pct":null,"component":null},{"name":"tart apples","amounts":[["2250","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["90","grams"]],"bakers_pct":null,"component":null},{"name":"ground cinnamon","amounts":[["3","grams"]],"bakers_pct":null,"component":null},{"name":"cocoa powder","amounts":[["3","grams"]],"bakers_pct":null,"component":null},{"name":"walnuts, chopped","amounts":[["170","grams"]],"bakers_pct":null,"component":null},{"name":"pine nuts","amounts":[["55","grams"]],"bakers_pct":null,"component":null},{"name":"golden raisins","amounts":[["85","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Peel, core, and grate the apples coarsely by hand or in a food processor fitted with the metal blade. Combine with the sugar and water in a non-reactive saucepan that has a tight-fitting lid. Place over medium heat. When the mixture begins to simmer, lower the heat, cover the pan, and cook 5 minutes, until the apples are swimming in water. Uncover, add the remaining filling ingredients, and cook over low heat, stirring often, about 15 to 20 minutes, until the filling is reduced to a thick paste. Cool the filling in a bowl at room temperature, stirring occasionally.","Roll 700 grams of the dough on a floured surface and line a buttered 12- x 18- inch pan with it. Chill the dough-lined pan until the dough is firm, about 30 minutes. Reserve the remaining pound of dough in the refrigerator.","Spread the cooled filling evenly over the dough.. Roll the remaining dough the strips on the filling, 4 in each direction, to make a \"grill,\" or perpendicular lattice. Trim away the excess dough at the edges. Bake the grigliata at 350 degrees for about 35 minutes, until the pastry is baked through. Cool in the pan on a rack.","For the glaze, place the apple jelly in a small saucepan and bring to a boil over low heat, stirring occasionally. Reduce the glaze until it is sticky. Brush on the filling and cool a few minutes to allow the glaze to set. Cut the grigliata into 3-"]', '[]', 'Pastry_Module_2_Course_4.pdf', 57);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Light Linzer Dough', 'Pies & Tarts', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 41, NULL, NULL, '[]', '[{"name":"all purpose flour","amounts":[["225","grams"]],"bakers_pct":"61.64","component":null},{"name":"sugar","amounts":[["170","grams"]],"bakers_pct":"46.58","component":null},{"name":"baking powder","amounts":[["4","grams"]],"bakers_pct":"1.10","component":null},{"name":"butter","amounts":[["170","grams"]],"bakers_pct":"46.58","component":null},{"name":"egg (1)","amounts":[["50","grams"]],"bakers_pct":"13.70","component":null},{"name":"yolk (1)","amounts":[["17","grams"]],"bakers_pct":"4.66","component":null},{"name":"lemon zest, grated","amounts":[["2","grams"]],"bakers_pct":"0.55","component":null},{"name":"vanilla extract","amounts":[["4","grams"]],"bakers_pct":"1.10","component":null}]', NULL, '["Prepare using Mealy Dough Mixing Method.","Scrape dough out of bowl. Do not refrigerate before using. Dough will be very soft."]', '[]', 'Pastry_Module_2_Course_4.pdf', 86);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Linzer Cookies', 'Pies & Tarts', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 56, 'Yield 1,090 grams', '1,090 grams', '[]', '[{"name":"butter","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"egg yolks","amounts":[["40","grams"]],"bakers_pct":null,"component":null},{"name":"lemon zest","amounts":[["4","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla extract","amounts":[["15","grams"]],"bakers_pct":null,"component":null},{"name":"almond extract","amounts":[["5","grams"]],"bakers_pct":null,"component":null},{"name":"hazelnut flour","amounts":[["285","grams"]],"bakers_pct":null,"component":null},{"name":"AP flour","amounts":[["285","grams"]],"bakers_pct":null,"component":null},{"name":"cinnamon","amounts":[["4","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["2","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Cream butter and sugar.","Add yolks, zest and extracts and mix until combined, scraping down the sides as needed.","Add dry ingredients and scrape from the bottom just until combined. Chill dough for use.","Roll dough out and use a round cookie cutter to cut out the cookies. Cut a hole in the center of half the cookies only.","Bake both cookies at 350ºF.","Spread preserves on the solid cookies and sift 10x on the other half of the cookies with the holes cut out. Then sandwich together."]', '["Utilize the Creaming mixing method."]', 'Pastry_Module_3_Course_5.pdf', 99);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Pastiera Napoletana', 'Pies & Tarts', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 39, NULL, NULL, '["9-inch Pan"]', '[{"name":"Pasta Frolla","amounts":[["455","grams"]],"bakers_pct":null,"component":null},{"name":"hulled white wheat kernels","amounts":[["115","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["3","grams"]],"bakers_pct":null,"component":null},{"name":"butter","amounts":[["28","grams"]],"bakers_pct":null,"component":null},{"name":"ricotta","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["55","grams"]],"bakers_pct":null,"component":null},{"name":"eggs(2)","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"orange flower water","amounts":[["5","grams"]],"bakers_pct":null,"component":null},{"name":"candied orange peel, rinsed and chopped","amounts":[["55","grams"]],"bakers_pct":null,"component":null},{"name":"pastry cream","amounts":[["225","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Soak the wheat overnight in water if possible. Drain and rinse the wheat and until tender, about 2 hours. Add water as necessary to keep the wheat from drying out and sticking. Cool the wheat and refrigerate until needed.","To assemble the filling, beat ricotta to soften it. Beat in the sugar. Beat in eggs, orange flower water and candied orange peel. Stir in the cooked wheat and the pastry cream."]', '[]', 'Pastry_Module_2_Course_4.pdf', 63);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Peach Pie', 'Pies & Tarts', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 40, NULL, NULL, '[]', '[{"name":"all-purpose flour","amounts":[["115","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["42","grams"]],"bakers_pct":null,"component":null},{"name":"freshly grated nutmeg","amounts":[["1","gram"]],"bakers_pct":null,"component":null},{"name":"crushed sliced almonds","amounts":[["55","grams"]],"bakers_pct":null,"component":null},{"name":"melted butter","amounts":[["85","grams"]],"bakers_pct":null,"component":null},{"name":"Pâte Sucrée or Sour Cream Dough","amounts":[["300","grams"]],"bakers_pct":null,"component":null},{"name":"ripe yellow-fleshed freestone peaches (4 large or 6medium)","amounts":[["900","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["115","grams"]],"bakers_pct":null,"component":null},{"name":"all-purpose flour","amounts":[["15","grams"]],"bakers_pct":null,"component":null},{"name":"almond extract","amounts":[["2","grams"]],"bakers_pct":null,"component":null},{"name":"cold butter","amounts":[["28","grams"]],"bakers_pct":null,"component":null}]', NULL, '["To make the topping, combine the flour, sugar, and nutmeg in a mixing bowl; stir well to combine and stir in the sliced almonds. Stir in the melted butter evenly. Set aside for 5 minutes. Break into crumbs and set aside until ready to use."]', '[]', 'Pastry_Module_2_Course_4.pdf', 77);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Pear and Walnut Tart', 'Pies & Tarts', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 39, NULL, NULL, '[]', '[{"name":"Pâte Sucrée","amounts":[["340","grams"]],"bakers_pct":null,"component":null},{"name":"Walnut Frangipane","amounts":[["340","grams"]],"bakers_pct":null,"component":null},{"name":"apricot glaze","amounts":[["115","grams"]],"bakers_pct":null,"component":null},{"name":"ground walnuts","amounts":[["55","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Roll the Pâte Sucrée and line the tart pan; blind-bake the shell until lightly golden and let cool.","Spread the Walnut Frangipane evenly in the baked shell.","Peel, core and thinly slice the pears; arrange over the frangipane in a decorative pattern.","Bake until the frangipane is set, puffed and golden brown and the pears are tender.","Cool slightly, then brush the warm tart with apricot glaze.","Finish by pressing ground walnuts around the edge of the tart.","Cool completely before unmolding and slicing."]', '[]', 'Pastry_Module_2_Course_4.pdf', 61);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Pecan Pie', 'Pies & Tarts', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 40, NULL, NULL, '[]', '[{"name":"Pâte Sucrée","amounts":[["300","grams"]],"bakers_pct":null,"component":null},{"name":"pecan halves","amounts":[["340","grams"]],"bakers_pct":null,"component":null},{"name":"dark corn syrup","amounts":[["330","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["170","grams"]],"bakers_pct":null,"component":null},{"name":"butter","amounts":[["115","grams"]],"bakers_pct":null,"component":null},{"name":"eggs (3)","amounts":[["150","grams"]],"bakers_pct":null,"component":null},{"name":"Bourbon","amounts":[["28","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Roll the Pâte Sucrée and line the pie pan, crimping the edge; chill.","Scatter the pecan halves evenly over the bottom of the shell.","Whisk together the corn syrup, sugar, melted butter, eggs and Bourbon until smooth.","Pour the syrup mixture over the pecans, allowing them to float to the surface.","Bake until the filling is set around the edges with a slight jiggle in the center, tenting the edges with foil if the crust browns too quickly.","Cool completely on a rack before slicing, allowing the filling to fully set."]', '[]', 'Pastry_Module_2_Course_4.pdf', 78);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Pizza Rustica Alla Napoletana', 'Pies & Tarts', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 39, NULL, NULL, '[]', '[{"name":"one 12-inch pan","amounts":[["2","pounds"],["900","grams"]],"bakers_pct":null,"component":null},{"name":"ricotta","amounts":[["900","grams"]],"bakers_pct":null,"component":null},{"name":"eggs(6)","amounts":[["300","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["2","grams"]],"bakers_pct":null,"component":null},{"name":"freshly ground pepper","amounts":[["2","grams"]],"bakers_pct":null,"component":null},{"name":"grated Pecorino Romano","amounts":[["28","grams"]],"bakers_pct":null,"component":null},{"name":"mozzarella, coarsely grated","amounts":[["450","grams"]],"bakers_pct":null,"component":null},{"name":"sweet dried sausage, peeled and diced","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"prosciutto, shredded","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"chopped parsley","amounts":[["14","grams"]],"bakers_pct":null,"component":null}]', NULL, '["For the filling, place ricotta in a bowl and stir smooth with a rubber spatula. Stir in eggs one at a time; stir in remaining filling ingredients in order.","Divide the Pasta Frolla into 2 pieces. Roll 1 of the pieces thinly to line a 12- inch straight-sided cake pan. Pour in filling and smooth top. Roll the and salt together and paint dough strips with egg wash. Arrange six strips on filling. Arrange remaining strips at a 45-degree angle to the first ones. Press strips at rim of pan to adhere and trim away excess dough even with top of pan.","Bake at 350 degrees for about 45 minutes, until the filling is set and the dough is baked through. Cool in the pan on a rack. Serve at room temperature. Refrigerate leftovers."]', '[]', 'Pastry_Module_2_Course_4.pdf', 64);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Raspberry Almond Tart', 'Pies & Tarts', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 39, NULL, NULL, '[]', '[{"name":"Pâte Sucrée","amounts":[["340","grams"]],"bakers_pct":null,"component":null},{"name":"Almond Frangipane","amounts":[["340","grams"]],"bakers_pct":null,"component":null},{"name":"Raspberries","amounts":[["625","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Roll the Pâte Sucrée and line the tart pan; blind-bake the shell until lightly golden and let cool.","Spread the Almond Frangipane evenly in the baked shell.","Scatter the raspberries evenly over the frangipane.","Bake until the frangipane is set, puffed and golden brown.","Cool completely before unmolding and slicing."]', '[]', 'Pastry_Module_2_Course_4.pdf', 58);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Rhubarb Cheese Tart with Crumb Topping', 'Pies & Tarts', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 39, NULL, NULL, '[]', '[{"name":"Pâte Sucrée","amounts":[["680","grams"]],"bakers_pct":null,"component":null},{"name":"fresh rhubarb","amounts":[["1800","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["450","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["900","grams"]],"bakers_pct":null,"component":null},{"name":"cream cheese","amounts":[["170","grams"]],"bakers_pct":null,"component":null},{"name":"heavy cream","amounts":[["180","grams"]],"bakers_pct":null,"component":null},{"name":"egg yolks","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["85","grams"]],"bakers_pct":null,"component":null},{"name":"orange zest","amounts":[["6","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Prepare the dough and chill it. Roll the dough on a floured surface and small hotel pan.","Bring the sugar and water to a boil and pour it over the rhubarb. Allow the rhubarb to cool in the syrup and chill. Drain the rhubarb on paper towels.","Arrange the rhubarb on the dough. Beat the cream cheese until it is light and beat in the remaining ingredients in order.","Pour the cheese custard over the rhubarb and strew the surface with the crumbs.","Bake the tart at 350 degrees 30 - 40 minutes. Cool the tart and dust it with confectioners'' sugar."]', '[]', 'Pastry_Module_2_Course_4.pdf', 54);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Sfogliatelle Napoletane', 'Pies & Tarts', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 48, NULL, NULL, '[]', '[{"name":"unbleached, all-purpose flour","amounts":[["400","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["6","grams"]],"bakers_pct":null,"component":null},{"name":"warm water","amounts":[["175","grams"]],"bakers_pct":null,"component":null},{"name":"lard","amounts":[["55","grams"]],"bakers_pct":null,"component":null},{"name":"unsalted butter","amounts":[["55","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["235","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["115","grams"]],"bakers_pct":null,"component":null},{"name":"semolina","amounts":[["115","grams"]],"bakers_pct":null,"component":null},{"name":"ricotta","amounts":[["340","grams"]],"bakers_pct":null,"component":null},{"name":"egg yolks (2)","amounts":[["34","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla extract","amounts":[["8","grams"]],"bakers_pct":null,"component":null},{"name":"cinnamon","amounts":[["1","gram"]],"bakers_pct":null,"component":null},{"name":"finely chopped candied orange peel","amounts":[["85","grams"]],"bakers_pct":null,"component":null}]', NULL, '["For the dough, combine the flour and salt in a mixing bowl and stir in the water. The dough will be very dry. Scrape the contents of the bowl onto the work surface and press and knead the dough together so that all the dry bits are through the widest setting of the pasta machine to work the dough smooth. Fold the dough in half every time after passing it through the machine and change the direction of inserting the dough occasionally. After passing the dough through about 12 or 15 times, it should be smooth. Knead the dough into a ball, wrap in plastic wrap and allow to rest in the refrigerator about 2 hours.","For the filling, combine the water and sugar in a saucepan. Bring to a boil and sift the semolina over the boiling water gradually, stirring constantly to avoid lumps. Lower the heat and cook, for a minute or two stirring often, until very smooth and thick. Press the ricotta through a fine sieve or puree it in the food processor and stir into the cooked semolina mixture. Cook several minutes longer, stirring often. Remove from the heat and stir in the yolks, vanilla, cinnamon and candied orange peel. Scrape the filling into a shallow bowl or glass pie pan and press plastic wrap against the surface. Refrigerate until cold. The filling will become very firm.","Combine the lard and butter in a bowl and beat by machine until well mixed and soft. Flour the dough and divide it into 4 pieces. Flour each piece of dough and pass through the pasta machine at the widest setting. Make sure the dough emerges in a neat, rectangular strip as wide as the opening of the machine. If the dough is uneven, fold it over on itself so that it is as wide as the opening and","Place one of the strips of dough on a lightly floured surface and paint it with the","Preheat the oven to 400 degrees and set a rack in the middle level. Line 2 half-"]', '[]', 'Pastry_Module_2_Course_4.pdf', 149);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Tart Tatin Apples', 'Pies & Tarts', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 7, NULL, NULL, '["6” cake"]', '[{"name":"apples, golden delicious","amounts":[["8","each"]],"bakers_pct":null,"component":null},{"name":"sugar (measure 2x separately)","amounts":[["115","grams"]],"bakers_pct":null,"component":null},{"name":"butter (measure 2x separately)","amounts":[["115","grams"]],"bakers_pct":null,"component":null},{"name":"frozen puff pastry","amounts":[["","as needed"]],"bakers_pct":null,"component":null}]', NULL, '["Peel, core and cut apples evenly into 4th''s and set aside.","Caramelize first 115 grams of sugar to a light golden color. Add only half of the apples (as it may crowd the pan and cause the apples to steam if you add too many), and first115 grams of butter and combine to stop the caramel from darkening.","Sauté the apples in the caramel until cooked. The apples should be well colored but still be slightly firm as they will be further baked in the oven. Place them on a tray to cool.","Repeat these steps with the other half of the apples and the second sugar and butter.","When the apple slices are cool enough to handle, place a layer very tightly,","Cut the frozen puff pastry to fit the top of the 6” cake pan and place on top of the","Once removed from the oven, allow the Tart Tatin to sit for several minutes and"]', '[]', 'PA_Mod_01_Instructor.pdf', 155);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Tarte Croustade Pate Croustade', 'Pies & Tarts', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 71, NULL, NULL, '[]', '[{"name":"fine sea salt","amounts":[["4","grams"]],"bakers_pct":null,"component":null},{"name":"AP flour","amounts":[["250","grams"]],"bakers_pct":null,"component":null},{"name":"water, warm","amounts":[["50","grams"]],"bakers_pct":null,"component":null},{"name":"butter, melted","amounts":[["150","grams"]],"bakers_pct":null,"component":null},{"name":"egg yolk","amounts":[["60","grams"]],"bakers_pct":null,"component":null}]', '[["514","grams"]]', '["Thoroughly combine salt and flour in mixer bowl.","Separately, combine water and butter; add egg yolks.","Add liquid mixture to flour in three additions, mixing to produce a homogenous dough.","Portion into four flat rectangles and rest for at least two hours, chilled.","Roll to 1mm thickness and cut rectangles measuring 6cm by 10cm.","Gently transfer cut rectangles to stainless steel tube molds and then tightly wrap in foil (24cm in length). Bake at 150˚C/300˚F for approximately16 minutes."]', '[]', 'Pastry_Module_3_Course_6.pdf', 145);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Thanksgiving Day Pumpkin Pie', 'Pies & Tarts', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 40, NULL, NULL, '[]', '[{"name":"Pâte Sucrée","amounts":[["300","grams"]],"bakers_pct":null,"component":null},{"name":"canned pumpkin","amounts":[["425","grams"]],"bakers_pct":null,"component":null},{"name":"eggs (2)","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"yolks (2)","amounts":[["34","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["170","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["3","grams"]],"bakers_pct":null,"component":null},{"name":"ground cinnamon","amounts":[["3","grams"]],"bakers_pct":null,"component":null},{"name":"ground ginger","amounts":[["1","gram"]],"bakers_pct":null,"component":null},{"name":"freshly grated nutmeg","amounts":[["1","gram"]],"bakers_pct":null,"component":null},{"name":"half and half","amounts":[["300","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Roll the Pâte Sucrée and line the pie pan, crimping the edge; chill.","Whisk together the pumpkin, eggs, yolks, sugar, salt, cinnamon, ginger and nutmeg until smooth.","Whisk in the half and half until fully incorporated.","Pour the filling into the chilled shell.","Bake until the filling is set around the edges with a slight jiggle in the center.","Cool completely before slicing."]', '[]', 'Pastry_Module_2_Course_4.pdf', 79);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Almond Dentelle', 'Plated Dessert Components', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 71, NULL, NULL, '[]', '[{"name":"AP flour","amounts":[["105","grams"]],"bakers_pct":null,"component":null},{"name":"almond flour","amounts":[["80","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["1","grams"]],"bakers_pct":null,"component":null},{"name":"orange juice","amounts":[["75","grams"]],"bakers_pct":null,"component":null},{"name":"butter, softened","amounts":[["110","grams"]],"bakers_pct":null,"component":null}]', '[["691","grams"]]', '["In a stand mixer bowl, combine the flour, sucrose, almond flour, and salt using the paddle attachment.","Add the orange juice, followed by the melted butter.","Mix until thoroughly incorporated. Chill and rest, refrigerated, until the dough is firm.","Using a small spoon or scoop, portion and roll small balls of dough (approximately 10-20g each); place them on a Silpat-lined sheet pan, allowing ample room for spreading.","Bake at 150°C/300°F until golden, but not excessively browned, approximately 10-15 minutes. Remove from the oven, allow to cool one to two minutes, and then trim each dentelle cookie with an appropriate sized ring cutter. Allow to cool and store in a covered container."]', '[]', 'Pastry_Module_3_Course_6.pdf', 143);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Apricot Puree', 'Plated Dessert Components', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 71, NULL, NULL, '[]', '[{"name":"apricot purée","amounts":[["250","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose","amounts":[["20","grams"]],"bakers_pct":null,"component":null},{"name":"xanthan gum","amounts":[["0.5","grams"]],"bakers_pct":null,"component":null}]', '[["270","grams"]]', '["Combine all ingredients (discard or use the scraped vanilla pod for another use) and blend well. Strain and chill."]', '[]', 'Pastry_Module_3_Course_6.pdf', 144);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Apricot Sphere', 'Plated Dessert Components', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 71, '(Yield: approximately 36 filled almost to the top)', NULL, '[]', '[{"name":"apricot purée","amounts":[["200","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose (1)","amounts":[["20","grams"]],"bakers_pct":null,"component":null},{"name":"calcium lactate","amounts":[["5","grams"]],"bakers_pct":null,"component":null},{"name":"water, warm (1)","amounts":[["1000","grams"]],"bakers_pct":null,"component":null},{"name":"sodium alginate","amounts":[["7","grams"]],"bakers_pct":null,"component":null},{"name":"sodium citrate","amounts":[["2","grams"]],"bakers_pct":null,"component":null},{"name":"water (2)","amounts":[["600","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose (2)","amounts":[["550","grams"]],"bakers_pct":null,"component":null}]', '[["1150","grams"]]', '["Thoroughly blend the apricot purée, sucrose (1), and calcium lactate. Deposit into silicon dome molds and freeze.","Thoroughly blend the warm water (1), sodium alginate, and sodium citrate in a blender. Transfer to a nine pan and allow to stand at room temperature for at least one hour or overnight.","Combine the water (2) and sucrose (2) in a small sauce pan and bring just to a boil. Transfer to a shallow pan and cool to room temperature.","Drop frozen apricot purée into the alginate bath and set, about 5 minutes. Carefully transfer to a water rinse, and then to the syrup solution."]', '[]', 'Pastry_Module_3_Course_6.pdf', 155);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Avocado Puree', 'Plated Dessert Components', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 71, NULL, NULL, '[]', '[{"name":"avocado pulp","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose","amounts":[["50","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["50","grams"]],"bakers_pct":null,"component":null},{"name":"lime juice","amounts":[["10","grams"]],"bakers_pct":null,"component":null}]', '[["210","grams"]]', '["Combine all the ingredients and thoroughly puree with a blender. Transfer to a squeeze bottle.","Prepare close to the time needed, to avoid browning of the avocado purée."]', '[]', 'Pastry_Module_3_Course_6.pdf', 139);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Banana, Chocolate and Walnut Dome Walnut Biscuit Praline Krispy Chocolate Cream Insert Banana Mousse Caramel Bananas Walnut Biscuit', 'Plated Dessert Components', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 68, '(one 1/2 sheet) Yield 720 grams', '720 grams', '[]', '[{"name":"AP flour","amounts":[["50","grams"]],"bakers_pct":null,"component":null},{"name":"walnuts, finely ground","amounts":[["200","grams"]],"bakers_pct":null,"component":null},{"name":"yolks","amounts":[["110","grams"]],"bakers_pct":null,"component":null},{"name":"brown sugar","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"egg whites","amounts":[["160","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["100","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine the flour and walnuts and set aside.","Whip the yolks and brown sugar to ribbon.","Separately, make a French meringue with the egg whites and sugar and whip to soft peak.","Fold the meringue into the yolks three quarters of the way and finish the folding by adding in the flour and walnuts.","Spread onto parchment lined half sheet pan.","Bake at 375 F. for approximately 10-15 minutes until set.","Allow cake to cool and place in the freezer."]', '["Utilize the biscuit mixing method"]', 'Pastry_Module_3_Course_6.pdf', 113);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Basil Foam', 'Plated Dessert Components', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 71, NULL, NULL, '[]', '[{"name":"skim milk","amounts":[["250","grams"]],"bakers_pct":null,"component":null},{"name":"basil, blanched","amounts":[["5","grams"]],"bakers_pct":null,"component":null},{"name":"granulated sugar","amounts":[["25","grams"]],"bakers_pct":null,"component":null},{"name":"soy lecithin","amounts":[["2","grams"]],"bakers_pct":null,"component":null}]', '[["282","grams"]]', '["Combine all the ingredients in a blender until pureed. Cover and reserve in the refrigerator until ready to use.","For plating, puree the basil foam with an immersion blender and spoon the foam onto the plate."]', '[]', 'Pastry_Module_3_Course_6.pdf', 138);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Basil Seeds', 'Plated Dessert Components', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 71, NULL, NULL, '[]', '[{"name":"water","amounts":[["25","grams"]],"bakers_pct":null,"component":null},{"name":"granulated sugar","amounts":[["25","grams"]],"bakers_pct":null,"component":null},{"name":"fresh grapefruit juice, strained","amounts":[["120","grams"]],"bakers_pct":null,"component":null},{"name":"basil seeds","amounts":[["25","grams"]],"bakers_pct":null,"component":null}]', '[["195","grams"]]', '["Combine water and sugar in a sauce pan and cook over medium heat just until the sugar has dissolved.","Remove from the heat and add the grapefruit juice and basil seeds.","Chill and allow to hydrate about 1 hour."]', '[]', 'Pastry_Module_3_Course_6.pdf', 138);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Brown Sugar Mixture', 'Plated Dessert Components', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 69, '(two 9” loaf pans) Yield 1,629.25 grams', '1,629.25 grams', '[]', '[{"name":"dark brown sugar","amounts":[["40","grams"]],"bakers_pct":null,"component":null},{"name":"cinnamon","amounts":[["4","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine the first 5 (dry) ingredients and mix to combine. Set aside.","Combine the next six ingredients and mix to combine. Then add to the dry ingredients.","Pan mixture into two (9”) loaf pans which have been sprayed and lined with parchment up the sides.","Make a cut down the center top of each batter and add half of the combined brown sugar mixture to each loaf and swirl with a fork to marble through the top.","Bake at 350 F. for approximately 50 minutes."]', '["Utilize the One Step method:"]', 'Pastry_Module_3_Course_6.pdf', 128);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Caramel Bananas', 'Plated Dessert Components', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 68, NULL, NULL, '[]', '[{"name":"sugar","amounts":[["340","grams"]],"bakers_pct":null,"component":null},{"name":"lemon juice","amounts":[["5","grams"]],"bakers_pct":null,"component":null},{"name":"water, warm","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"bananas","amounts":[["8","each"]],"bakers_pct":null,"component":null}]', NULL, '["Make a dry caramel from the sugar and lemon juice.","Stop the caramel from cooking by adding the water. Heat again if necessary to fully melt the caramel.","Separately, slice the bananas very thinly, evenly and diagonally. Place the bananas in a hotel pan and pour the caramel over the bananas. Allow to cool. Drain for use. Assemble as illustrated in a fleximold domed mold: Shingled Caramel Bananas Banana Mousse Chocolate Cream Insert Praline Crispy Walnut Biscuit"]', '[]', 'Pastry_Module_3_Course_6.pdf', 116);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Caramel Decorations', 'Plated Dessert Components', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 69, NULL, NULL, '[]', '[{"name":"sugar","amounts":[["200","grams"]],"bakers_pct":null,"component":null},{"name":"lemon juice, optional","amounts":[["3","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine the sugar and lemon juice in a sauté pan.","Place the pan over medium heat to begin melting the sugar,","When the sugar begins to caramelize, stir the uncaramelized sugar into the caramelized sugar so the sugar melts and caramelizes evenly.","Lower the heat when most of the sugar has melted so all the sugar crystals dissolve into the caramel without the caramel getting too dark.","Cook the caramel until it is a light golden color.","On a silpat, carefully use a spoon to form, drizzle, or manipulate caramel into desired decoration. Cool until set.","Reheat caramel if needed."]', '[]', 'Pastry_Module_3_Course_6.pdf', 125);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Caramelized Cashews', 'Plated Dessert Components', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 68, 'Yield 287 grams', '287 grams', '[]', '[{"name":"whole cashews","amounts":[["200","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose","amounts":[["65","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["22","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Roast cashews at 150˚C/300°F oven for approximately 10 minutes, or until thoroughly toasted, and reserve warm.","Cook the sucrose, scraped vanilla bean and water to 115°C/240°.","Add cashews to the sugar mixture and continue to cook, stirring constantly. The sugar will begin to crystallize. Continue to stir to coat the cashews completely.","Reduce heat and continue to stir until cashews are coated with caramelized sugar.","Pour caramelized cashews onto a parchment lined sheet pan, separate the nuts if necessary, and allow to cool completely."]', '[]', 'Pastry_Module_3_Course_6.pdf', 88);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Caramelized Hazelnuts', 'Plated Dessert Components', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 71, 'Total Yield 600 grams', '600 grams', '[]', '[{"name":"whole hazelnuts","amounts":[["425","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose","amounts":[["130","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["45","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Roast almonds at 150˚C/300°F oven for approximately 10 minutes, or until thoroughly toasted, and reserve warm.","Cook the sucrose, scraped vanilla bean and water to 115°C/240°.","Add hazelnuts to the sugar mixture and continue to cook, stirring constantly. The sugar will begin to crystallize. Continue to stir to coat the hazelnuts completely.","Reduce heat and continue to stir until hazelnuts are coated with caramelized sugar.","Pour caramelized hazelnuts onto a parchment lined sheet pan, separate the nuts if necessary, and allow to cool completely."]', '[]', 'Pastry_Module_3_Course_6.pdf', 146);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Caramelized Pecans', 'Plated Dessert Components', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 68, 'Yield 287 grams', '287 grams', '[]', '[{"name":"pecans halves","amounts":[["200","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["65","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["22","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Roast pecans and reserve warm.","Cook the sugar, scraped vanilla bean and water to 240°F.","Add pecans to the sugar mixture and continue to cook, stirring constantly. The sugar will begin to crystallize. Continue to stir to coat the pecans completely.","Reduce heat and continue to stir until pecans are coated with caramelized sugar.","Pour caramelized pecans onto a parchment lined sheet pan, separate the nuts if necessary, and allow to cool completely."]', '[]', 'Pastry_Module_3_Course_6.pdf', 105);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Caramelized Pistachios', 'Plated Dessert Components', 'Module 1', 'Course 2', 'Baking Techniques & Ingredients Pt 2', 19, NULL, NULL, '[]', '[{"name":"pistachios","amounts":[["450","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["45","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose","amounts":[["180","grams"]],"bakers_pct":null,"component":null},{"name":"butter","amounts":[["23","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Gently warm the pistachios in a low oven. Place sucrose in a medium sauté pan and moisten with water.","Over medium heat, cook sucrose until nearly all water has evaporated and but before it begins to color.","Add the pistachios and stir to coat with sugar.","Continue cooking and stirring as sugar crystallizes. Sugar will begin to melt and caramelize.","When most of the sugar has re-melted and coated the nuts, remove from heat and stir in the butter, gently yet thoroughly. Transfer to a Silpat to cool and store in sealed containers."]', '[]', 'Pastry_Module_1_Course_2.pdf', 149);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Caramelized Rice', 'Plated Dessert Components', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 19, NULL, NULL, '[]', '[{"name":"sucrose","amounts":[["240","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["60","grams"]],"bakers_pct":null,"component":null},{"name":"rice cereal","amounts":[["200","grams"]],"bakers_pct":null,"component":null},{"name":"butter","amounts":[["20","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Place sucrose in a medium sauté pan and moisten with water.","Over medium heat, cook sucrose until nearly all water has evaporated and but before it begins to color.","Add cereal and gently stir to coat with sugar.","Continue cooking and stirring as sugar crystallizes. Sugar will begin to melt and caramelize."]', '[]', 'PA_Mod_01_Instructor.pdf', 324);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Caramelized Rice Cereal', 'Plated Dessert Components', 'Module 1', 'Course 2', 'Baking Techniques & Ingredients Pt 2', 19, NULL, NULL, '[]', '[{"name":"sucrose","amounts":[["240","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["60","grams"]],"bakers_pct":null,"component":null},{"name":"rice cereal","amounts":[["200","grams"]],"bakers_pct":null,"component":null},{"name":"butter","amounts":[["20","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Place sucrose in a medium sauté pan and moisten with water.","Over medium heat, cook sucrose until nearly all water has evaporated and but before it begins to color.","Add cereal and gently stir to coat with sugar.","Continue cooking and stirring as sugar crystallizes. Sugar will begin to melt and caramelize.","When most of the sugar has re-melted and coated the cereal, remove from heat and stir in the butter, gently yet thoroughly. Transfer to a Silpat to cool and store in sealed containers."]', '[]', 'Pastry_Module_1_Course_2.pdf', 148);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Chocolate Glacage', 'Plated Dessert Components', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 68, 'Yield 2,001 grams', '2,001 grams', '[]', '[{"name":"gelatin sheets","amounts":[["10","sheets"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["544","grams"]],"bakers_pct":null,"component":null},{"name":"coconut milk","amounts":[["1087","grams"]],"bakers_pct":null,"component":null},{"name":"cocoa powder","amounts":[["254","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Bloom gelatin in cold water and set aside.","Bring sugar and coconut milk to a boil.","Whisk in cocoa powder and bloomed gelatin to boiled mixture.","Strain and reserve. Allow to cool before glazing panna cotta. Assemble as illustrated: Chocolate Glacage Maple Panna Cotta ( 1/2 way ) Pecan Dacqouise Maple Panna Cotta ( 1/2 way ) Pecan Biscuit"]', '[]', 'Pastry_Module_3_Course_6.pdf', 101);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Crystallized or Caramelized Almonds', 'Plated Dessert Components', 'Module 4', 'Course 7', 'Chocolate & Confections', 76, NULL, NULL, '[]', '[{"name":"whole almonds","amounts":[["425","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose","amounts":[["130","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["45","grams"]],"bakers_pct":null,"component":null},{"name":"dark chocolate, tempered","amounts":[["120","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Roast almonds at 150˚C/300°F oven for approximately 10 minutes, or until thoroughly toasted, and reserve warm.","Cook the sucrose, scraped vanilla bean and water to 115°C/240°.","Add almonds to the sugar mixture and continue to cook, stirring constantly. The sugar will begin to crystallize. Continue to stir to coat the almonds completely.","Alternatively, if desired to coat the almonds with caramel, reduce heat and continue to stir until almonds are coated with caramelized sugar.","Pour crystallized or caramelized almonds onto a parchment lined sheet pan, separate the nuts if necessary, and allow to cool completely.","Place the nuts into a chilled mixing bowl, set into a lager bowl filled with ice. Slowly pour the tempered chocolate into the nuts, stirring vigorously to evenly coat.","Just as the chocolate coating begins to set, rapidly sift cocoa powder or confectioners'' sugar onto the nuts while stirring, until well coated and separated."]', '[]', 'Pastry_Module_4_Course_7.pdf', 29);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Lemon Fluid Gel', 'Plated Dessert Components', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 73, NULL, NULL, '[]', '[{"name":"water","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"agar","amounts":[["3","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"lemon juice","amounts":[["125","grams"]],"bakers_pct":null,"component":null}]', '[["328","grams"]]', '["Combine water and agar in a small sauce pan. Gently bring to a boil; reduce heat while maintaining a simmer for two minutes.","Remove from heat and whisk in the sucrose and lemon juice. Allow to cool and set.","Process in blender until smooth. Transfer to a squeeze bottle."]', '[]', 'Pastry_Module_3_Course_6.pdf', 210);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Mango Pearls', 'Plated Dessert Components', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 73, NULL, NULL, '[]', '[{"name":"mango purée","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"lime juice","amounts":[["25","grams"]],"bakers_pct":null,"component":null},{"name":"lime juice","amounts":[["75","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["150","grams"]],"bakers_pct":null,"component":null},{"name":"agar","amounts":[["3","grams"]],"bakers_pct":null,"component":null},{"name":"locust bean gum","amounts":[["0.4","grams"]],"bakers_pct":null,"component":null},{"name":"vegetable oil, cold","amounts":[["750","grams"]],"bakers_pct":null,"component":null}]', '[["478","grams"]]', '["Combine the mango purée, lime juice, and sucrose; warm slightly to dissolve the sugar. Reserve warm.","Combine the water, agar, and locust bean gum in a small sauce pan.","Bring this mixture to a boil, whisking occasionally, and then reduce heat and gently simmer for 1 minute.","Remove from heat and incorporate into the mango base. Transfer to a squeeze bottle.","Drop the mixture into cold vegetable oil, allowing 5-10 minutes to set; drain."]', '[]', 'Pastry_Module_3_Course_6.pdf', 219);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Milk Chocolate Coconut Chocolate Genoise Mousseline Coconut Caramel Pressed Coconut Caremelized Cashews Milk Chocolate Mousse Chocolate Genoise Mousseline', 'Plated Dessert Components', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 68, '(one 1/2 sheet)Yield 1,099 grams', '1,099 grams', '[]', '[{"name":"eggs","amounts":[["550","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["315","grams"]],"bakers_pct":null,"component":null},{"name":"AP flour","amounts":[["84","grams"]],"bakers_pct":null,"component":null},{"name":"cocoa powder","amounts":[["84","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["4","grams"]],"bakers_pct":null,"component":null},{"name":"butter, melted","amounts":[["31","grams"]],"bakers_pct":null,"component":null},{"name":"spiced rum","amounts":[["31","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine the eggs and the sugar and whisk over a bain marie until the sugar is dissolved and warm.","Whip eggs and sugar on medium high speed until thickened for a genoise.","While the eggs are whipping, combine the melted butter and rum and set aside.","Sift the dry ingredients together and set aside.","When the egg mixture has thickened enough, sift the dry ingredients into the whipped eggs while folding carefully."]', '["Utilize the Genoise Mousseline mixing method"]', 'Pastry_Module_3_Course_6.pdf', 85);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Passion Fruit Gel', 'Plated Dessert Components', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 74, NULL, NULL, '[]', '[{"name":"water","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"agar","amounts":[["3","grams"]],"bakers_pct":null,"component":null},{"name":"sucrose","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"passion fruit purée","amounts":[["125","grams"]],"bakers_pct":null,"component":null}]', '[["328","grams"]]', '["Combine water and agar in a small sauce pan. Gently bring to a boil; reduce heat while maintaining a simmer for two minutes.","Remove from heat and whisk in the sucrose and passion fruit purée. Allow to cool and set.","Process in blender until smooth. Transfer to a squeeze bottle."]', '[]', 'Pastry_Module_3_Course_6.pdf', 276);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Peanut Butter Powder', 'Plated Dessert Components', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 73, NULL, NULL, '[]', '[{"name":"natural peanut butter","amounts":[["120","grams"]],"bakers_pct":null,"component":null},{"name":"N-Zorbit (tapioca maltodextrin)","amounts":[["75","grams"]],"bakers_pct":null,"component":null}]', '[["195","grams"]]', '["Place peanut butter into the work bowl of a food processor. Slowly incorporate the maltodextrin, pulsing the machine until a powdery consistency is achieved.","Transfer to a dry covered container."]', '[]', 'Pastry_Module_3_Course_6.pdf', 211);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Pecan Maple Petit Gauteux (Gluten Free, Dairy Free) Pecan Biscuit Pecan Dacquoise Layer Maple Panna Cotta Chocolate Glacage Pecan Biscuit', 'Plated Dessert Components', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 68, '( one ½ sheet) Yield 670 grams', '670 grams', '[]', '[{"name":"bittersweet chocolate","amounts":[["120","grams"]],"bakers_pct":null,"component":null},{"name":"shortening (dairy free)","amounts":[["120","grams"]],"bakers_pct":null,"component":null},{"name":"pecans","amounts":[["56","grams"]],"bakers_pct":null,"component":null},{"name":"brown rice flour","amounts":[["36","grams"]],"bakers_pct":null,"component":null},{"name":"potato starch","amounts":[["12","grams"]],"bakers_pct":null,"component":null},{"name":"tapioca starch","amounts":[["6","grams"]],"bakers_pct":null,"component":null},{"name":"egg yolks","amounts":[["80","grams"]],"bakers_pct":null,"component":null},{"name":"egg whites","amounts":[["120","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["120","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Melt chocolate over double boiler and add shortening, stir to combine and allow mixture to cool.","Combine the pecans and the dry ingredients in a Robot Coupe, process until pecans are chopped into fine flour.","Whip egg yolks until ribbon.","Separately, make an ordinary meringue with egg whites and sugar.","Fold together meringue and yolks, fold in dry ingredients and melted chocolate mixture.","Spread mixture onto parchment lined half sheet pan and bake at 350 F.","Once cooled, cut cake into ovals to fit oval shaped flexi mold."]', '["Utilize the Biscuit mixing method"]', 'Pastry_Module_3_Course_6.pdf', 98);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Praline Krispy', 'Plated Dessert Components', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 68, '(one 1/2 sheet) Yields 585 grams', '585 grams', '[]', '[{"name":"white chocolate","amounts":[["85","grams"]],"bakers_pct":null,"component":null},{"name":"hazelnut praline","amounts":[["350","grams"]],"bakers_pct":null,"component":null},{"name":"feuilletine","amounts":[["150","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Melt chocolate, stir in praline paste.","Gently mix in feuilletine.","Spread onto the cooled walnut biscuit.","Put in fridge to set, cut into circles to fit the base of the dome fleximolds."]', '[]', 'Pastry_Module_3_Course_6.pdf', 114);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Pressed Coconut', 'Plated Dessert Components', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 68, 'Yield 330 grams', '330 grams', '[]', '[{"name":"coconut milk","amounts":[["52","grams"]],"bakers_pct":null,"component":null},{"name":"corn syrup","amounts":[["81","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["71","grams"]],"bakers_pct":null,"component":null},{"name":"orange, zest","amounts":[["1","each"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["1","grams"]],"bakers_pct":null,"component":null},{"name":"unsweetened coconut","amounts":[["125","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine the first 5 ingredients into a pot and bring to a boil.","Add the coconut and lower the heat to the lowest setting.","Stir often with a rubber spatula, making sure nothing sticks to the bottom.","Cook until the mixture forms a dough and does not stick to your fingers.","Roll in between two pieces of parchment paper until very thin.","Freeze until firm."]', '[]', 'Pastry_Module_3_Course_6.pdf', 87);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Strawberry Puree', 'Plated Dessert Components', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 73, NULL, NULL, '[]', '[{"name":"fresh strawberries, cleaned and trimmed","amounts":[["250","grams"]],"bakers_pct":null,"component":null},{"name":"simple syrup","amounts":[["50","grams"]],"bakers_pct":null,"component":null}]', '[["300.5","grams"]]', '["Combine the strawberries, syrup, and xanthan gum and process in a blender; strain through a fine mesh sieve. Chill."]', '[]', 'Pastry_Module_3_Course_6.pdf', 208);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('White Chocolate Pate a Glace', 'Plated Dessert Components', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 68, 'Yield: 150 grams', '150 grams', '[]', '[{"name":"white chocolate","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"shortening","amounts":[["50","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Melt the white chocolate and shortening together gently over a double boiler or in the microwave in short bursts.","Stir until completely smooth.","Use warm as a dipping or glazing coating."]', '[]', 'Pastry_Module_3_Course_6.pdf', 96);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Apple Quick Bread', 'Quick Breads & Scones', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 69, '(two 10” pans) Yield 1,849.5 grams', '1,849.5 grams', '[]', '[{"name":"butter","amounts":[["170","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["425","grams"]],"bakers_pct":null,"component":null},{"name":"AP flour","amounts":[["400","grams"]],"bakers_pct":null,"component":null},{"name":"baking powder","amounts":[["11","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["1","gram"]],"bakers_pct":null,"component":null},{"name":"whole eggs","amounts":[["250","grams"]],"bakers_pct":null,"component":null},{"name":"orange juice","amounts":[["85","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla","amounts":[["6.5","grams"]],"bakers_pct":null,"component":null},{"name":"apples (peeled, cored and cut into thin slices)","amounts":[["750","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["50","grams"]],"bakers_pct":null,"component":null},{"name":"cinnamon","amounts":[["1","grams"]],"bakers_pct":null,"component":null}]', NULL, '["In a KitchenAid bowl with a paddle, cream the butter and sugar.","Add the dry ingredients (which have been mixed together well), and the liquid ingredients on top of the dry. Mix all ingredients together until just combined. lined pans and spread evenly.","On top of the batter, spread all of the apples which has been liberally tossed with the cinnamon sugar.","Place the other half of the batter on top of the apples and spread to cover (The batter will barely cover the apples but will expand during baking).","Bake at 350 F."]', '["Utilize the Creaming method:"]', 'Pastry_Module_3_Course_6.pdf', 129);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Apple Walnut Muffins', 'Quick Breads & Scones', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 51, '(approximately 12 muffins)Yield 1,005 grams', '1,005 grams', '[]', '[{"name":"butter","amounts":[["85","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["156","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["1","gram"]],"bakers_pct":null,"component":null},{"name":"lemon zest","amounts":[["2","grams"]],"bakers_pct":null,"component":null},{"name":"AP flour","amounts":[["285","grams"]],"bakers_pct":null,"component":null},{"name":"baking powder","amounts":[["12","grams"]],"bakers_pct":null,"component":null},{"name":"cinnamon","amounts":[["2","grams"]],"bakers_pct":null,"component":null},{"name":"apples (peeled, diced)","amounts":[["170","grams"]],"bakers_pct":null,"component":null},{"name":"walnuts (chopped)","amounts":[["140","grams"]],"bakers_pct":null,"component":null},{"name":"milk","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"eggs","amounts":[["50","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla","amounts":[["2","grams"]],"bakers_pct":null,"component":null}]', NULL, '["In a KitchenAid mixer with a paddle, cream the butter with the sugar, salt and lemon zest until lightened. Scrape the bowl and the paddle several times to make sure there are no lumps of butter.","Combine the dry ingredients together in a bowl, then add the apples and walnuts and toss to coat.","Whisk together the wet ingredients.","Add the dry ingredients and the liquid ingredients to the creamed butter/ sugar. Mix until just combined, making sure to scrape from the bottom.","Place the batter 2/3 full in 12 paper muffin cups and cover with muffin crumb topping on the previous page if desired.","Bake at 350 F."]', '["Utilize the Creaming Dough mixing method:"]', 'Pastry_Module_3_Course_5.pdf', 36);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Banana Nut Bread', 'Quick Breads & Scones', 'Module 3', 'Course 6', 'Cakes, Fillings & Icings Pt 2', 69, NULL, NULL, '[]', '[{"name":"AP flour","amounts":[["654","grams"]],"bakers_pct":null,"component":null},{"name":"baking powder","amounts":[["13","grams"]],"bakers_pct":null,"component":null},{"name":"sea salt","amounts":[["10","grams"]],"bakers_pct":null,"component":null},{"name":"cinnamon","amounts":[["5.5","grams"]],"bakers_pct":null,"component":null},{"name":"ground cloves","amounts":[["2.5","grams"]],"bakers_pct":null,"component":null},{"name":"bananas, ripe, mashed","amounts":[["350","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["480","grams"]],"bakers_pct":null,"component":null},{"name":"butter, melted and cooled","amounts":[["320","grams"]],"bakers_pct":null,"component":null},{"name":"eggs","amounts":[["256","grams"]],"bakers_pct":null,"component":null},{"name":"walnuts, chopped","amounts":[["160","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla extract","amounts":[["16","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Whisk together the mashed banana, sugar, melted butter, eggs, and vanilla extract.","In a separate bowl, combine the flour, baking powder, salt, cinnamon, and cloves.","Fold the dry ingredients into the wet ingredients just until combined.","Fold in the chopped walnuts.","Divide the batter into prepared loaf pan(s).","Bake at 350 F until a tester inserted in the center comes out clean."]', '[]', 'Pastry_Module_3_Course_6.pdf', 128);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Biscuits', 'Quick Breads & Scones', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 36, NULL, NULL, '[]', '[{"name":"Self-Rising Cake flour","amounts":[["455","grams"]],"bakers_pct":null,"component":null},{"name":"butter","amounts":[["170","grams"]],"bakers_pct":null,"component":null},{"name":"milk, buttermilk* or cream","amounts":[["245","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["3","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Prepare using Flaky Dough Mixing Method. Gradually stir in milk, adding only enough to make a soft dough.","Flour work surface and scrape dough onto it. Knead lightly several times to make dough smooth, without over-mixing, adding extra flour if the dough is too soft or sticky. Cut with a round cutter and transfer to paper-lined pan. Dust tops of biscuits with flour or paint with milk.","Bake at 450 degrees about 10 minutes, until well risen, a deep golden and baked through. Serve immediately or cool and reheat at 350 degrees before serving. Variation: Cheese Biscuits Add 200 grams grated sharp cheddar cheese, mixing it in well, before adding the liquid to the biscuit dough. Variation: Chive and Cheese Biscuits Add 200 grams grated sharp cheddar cheese and 55 grams finely chopped chives, mixing it in well, before adding the liquid to the biscuit dough. beginning to mix."]', '["*When using buttermilk, add 2 grams baking soda to the dry ingredients before"]', 'Pastry_Module_2_Course_4.pdf', 27);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Blueberry Muffins Leavening Exercise', 'Quick Breads & Scones', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 8, 'Yield: 12 muffins', NULL, '[]', '[{"name":"butter","amounts":[["115","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["255","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["3","grams"]],"bakers_pct":null,"component":null},{"name":"eggs","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"all-purpose flour","amounts":[["285","grams"]],"bakers_pct":null,"component":null},{"name":"milk","amounts":[["120","grams"]],"bakers_pct":null,"component":null},{"name":"blueberries, rinsed, drained & dried","amounts":[["100","grams"]],"bakers_pct":null,"component":null}]', NULL, '["In a Kitchen Aid mixer with a paddle, cream the butter with the sugar and salt until lightened. Scrape the bowl and the paddle several times to make sure there are no lumps of butter.","Beat in the eggs, gradually, until smooth.","Mix the flour and baking powder together well and stir into the batter alternating with the milk, scraping again to ensure the batter is well mixed.","Fold in the remaining berries whole so as not to crush the berries.","Deposit the entire batter into twelve muffin pans lined with paper cups.","Bake muffins at 375 degrees. Cool the muffins in the pan.  No chemical leavening  2x baking powder  3x baking powder  4x baking powder  Substitute baking soda for baking powder  2x baking soda"]', '["*Alternate leavening assigned by instructor:"]', 'PA_Mod_01_Instructor.pdf', 101);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Cherry Lemon Scones', 'Quick Breads & Scones', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 3, NULL, NULL, '[]', '[{"name":"all purpose flour","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"yellow cornmeal","amounts":[["140","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["70","grams"]],"bakers_pct":null,"component":null},{"name":"baking powder","amounts":[["14","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["6","grams"]],"bakers_pct":null,"component":null},{"name":"lemon zest","amounts":[["2","grams"]],"bakers_pct":null,"component":null},{"name":"butter (cubed)","amounts":[["70","grams"]],"bakers_pct":null,"component":null},{"name":"dried cherries","amounts":[["140","grams"]],"bakers_pct":null,"component":null},{"name":"egg","amounts":[["50","grams"]],"bakers_pct":null,"component":null},{"name":"milk","amounts":[["120","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla extract","amounts":[["8","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine the first 6 ingredients in a Kitchen Aid bowl and mix to combine using the paddle attachment.","Add the butter and mix just until the butter disappears. Then add the dried cherries and mix just until combined.","Add the 3 liquid ingredients and mix until just combined.","Place the dough on a lightly floured surface.","Divide dough into 70 gram pieces and shape round. Egg wash and sprinkle sugar on top.","Bake at 400 degrees for about 15 minutes. Variation: Substitute dried apricot or other dried fruit for the cherries."]', '[]', 'PA_Mod_01_Instructor.pdf', 49);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Chocolate Chunk Scones', 'Quick Breads & Scones', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 36, NULL, NULL, '[]', '[{"name":"all purpose flour","amounts":[["340","grams"]],"bakers_pct":null,"component":null},{"name":"cocoa powder","amounts":[["28","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["115","grams"]],"bakers_pct":null,"component":null},{"name":"baking powder","amounts":[["14","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["3","grams"]],"bakers_pct":null,"component":null},{"name":"butter","amounts":[["85","grams"]],"bakers_pct":null,"component":null},{"name":"coarsely chopped semisweet chocolate","amounts":[["170","grams"]],"bakers_pct":null,"component":null},{"name":"egg","amounts":[["50","grams"]],"bakers_pct":null,"component":null},{"name":"buttermilk or milk","amounts":[["185","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Prepare using Mealy Dough Mixing Method, adding chocolate before adding liquid. Divide each disk into four wedges.","Bake at 450 degrees for about 10 to 15 minutes."]', '[]', 'Pastry_Module_2_Course_4.pdf', 34);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Corn Muffins', 'Quick Breads & Scones', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 4, '*Note: make sure to record the corn muffin yield for use in worksheets to follow.', NULL, '[]', '[{"name":"all purpose flour","amounts":[["432","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["230","grams"]],"bakers_pct":null,"component":null},{"name":"cornmeal","amounts":[["155","grams"]],"bakers_pct":null,"component":null},{"name":"dry milk","amounts":[["31","grams"]],"bakers_pct":null,"component":null},{"name":"baking powder","amounts":[["22","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["6","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["340","grams"]],"bakers_pct":null,"component":null},{"name":"vegetable, corn or canola oil","amounts":[["30","grams"]],"bakers_pct":null,"component":null},{"name":"light corn syrup","amounts":[["32","grams"]],"bakers_pct":null,"component":null},{"name":"melted butter","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"whole eggs","amounts":[["160","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla extract","amounts":[["1.5","grams"]],"bakers_pct":null,"component":null}]', NULL, '["In a bowl, combine well the first 6 (dry) ingredients.","Gradually add the next 6 (liquid) ingredients which have been combined and mixed well.","Mix just until thoroughly combined.","Place the batter 2/3 full in paper muffin cups and bake at 350 F."]', '[]', 'PA_Mod_01_Instructor.pdf', 59);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Corn Muffins', 'Quick Breads & Scones', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 51, 'Yield 1,665 grams', '1,665 grams', '[]', '[{"name":"AP flour","amounts":[["432","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["230","grams"]],"bakers_pct":null,"component":null},{"name":"cornmeal","amounts":[["155","grams"]],"bakers_pct":null,"component":null},{"name":"dry milk","amounts":[["31","grams"]],"bakers_pct":null,"component":null},{"name":"baking powder","amounts":[["22","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["6","grams"]],"bakers_pct":null,"component":null},{"name":"water","amounts":[["340","grams"]],"bakers_pct":null,"component":null},{"name":"vegetable, corn or canola oil","amounts":[["30","grams"]],"bakers_pct":null,"component":null},{"name":"light corn syrup","amounts":[["32","grams"]],"bakers_pct":null,"component":null},{"name":"melted butter","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"whole eggs","amounts":[["160","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla extract","amounts":[["1.5","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Cover ears of corn with husks in salted, cool water and bring to a boil.","Remove corn from water and remove husks.","Cut kernels from cob and reserve.","In a bowl, combine well the first 6 (dry) ingredients","Combine the next 6 (liquid) ingredients in a bowl and mix well.","Mix the wet ingredients into the dry until just thoroughly combined.","Add corn kernels and mix until just combined.","Place the batter 2/3 full in paper muffin cups and bake at 350 F."]', '["Utilize the One Step mixing method."]', 'Pastry_Module_3_Course_5.pdf', 31);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Cranberry Orange Crumb Muffins Mmmmmmmuffmuffins Muffins', 'Quick Breads & Scones', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 51, '(approximately 12 muffins ) Yield 1,014 grams', '1,014 grams', '[]', '[{"name":"mMMMMMMMMMMMMMMMMMMM butter","amounts":[["115","grams"]],"bakers_pct":null,"component":null},{"name":"MMMMMMMMMM MMMMMMM MUFF Msugar","amounts":[["255","grams"]],"bakers_pct":null,"component":null},{"name":"MUFFINS salt","amounts":[["3","grams"]],"bakers_pct":null,"component":null},{"name":"eggs","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"AP flour","amounts":[["285","grams"]],"bakers_pct":null,"component":null},{"name":"baking powder","amounts":[["8","grams"]],"bakers_pct":null,"component":null},{"name":"milk","amounts":[["120","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla extract","amounts":[["3","grams"]],"bakers_pct":null,"component":null},{"name":"frozen cranberries","amounts":[["125","grams"]],"bakers_pct":null,"component":null}]', NULL, '["In a KitchenAid mixer with a paddle, cream the butter with the sugar, salt and orange zest until lightened. Scrape the bowl and the paddle several times to make sure there are no lumps of butter.","Add the eggs gradually and mix until smooth, wiping down the sides of the bowl as needed","Mix the flour and baking powder together well and stir into the batter, alternating with the milk, scraping again to ensure the batter is well mixed.","Fold in the cranberries making sure not to crush them too much.","Place the batter 2/3 full in 12 paper muffin cups and cover with all of the muffin crumb topping in the following recipe.","Bake at 350 F."]', '["Utilize the Creaming Dough mixing method:"]', 'Pastry_Module_3_Course_5.pdf', 34);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Crumble Topping', 'Quick Breads & Scones', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 2, NULL, NULL, '[]', '[{"name":"sugar","amounts":[["125","grams"]],"bakers_pct":null,"component":null},{"name":"butter","amounts":[["125","grams"]],"bakers_pct":null,"component":null},{"name":"high gluten flour","amounts":[["125","grams"]],"bakers_pct":null,"component":null},{"name":"almond flour","amounts":[["95","grams"]],"bakers_pct":null,"component":null},{"name":"fine sea salt","amounts":[["1","gram"]],"bakers_pct":null,"component":null}]', NULL, '["Place all of the ingredients into a large mixing bowl and mix by hand until a loose, pebble-like texture is achieved; reserve chilled.","Place the cooked apple filling into individual-sized serving dishes or one large, shallow baking dish as instructed.","Liberally cover the surface of the apple filling with the crumble topping and place in a pre-heated 176˚C/350˚F oven. Bake until the crumble topping is crisp and golden brown, about 15 to 30 minutes, depending upon the size and dimensions of the baking dish.","Remove from the oven and cool briefly before serving."]', '[]', 'PA_Mod_01_Instructor.pdf', 35);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Currant Tea Scones', 'Quick Breads & Scones', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 36, NULL, NULL, '[]', '[{"name":"unbleached, all-purpose flour","amounts":[["910","grams"]],"bakers_pct":null,"component":null},{"name":"cake flour","amounts":[["455","grams"]],"bakers_pct":null,"component":null},{"name":"baking powder","amounts":[["55","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["12","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["170","grams"]],"bakers_pct":null,"component":null},{"name":"butter","amounts":[["170","grams"]],"bakers_pct":null,"component":null},{"name":"currants","amounts":[["170","grams"]],"bakers_pct":null,"component":null},{"name":"milk","amounts":[["490","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Prepare using Mealy Dough Mixing Method, adding currants before adding liquid.","Form a smooth dough. Knead lightly once or twice to complete mixing. to paper-lined pan and egg wash tops carefully. Allow wash to dry and apply a second coat.","Bake scones at 425 degrees about 10 to 15 minutes, being careful that they do not color too deeply, until they are firm but not dry."]', '[]', 'Pastry_Module_2_Course_4.pdf', 31);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Gluten-Free Flour Blend', 'Quick Breads & Scones', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 52, 'Yield: 599 grams', '599 grams', '[]', '[{"name":"white rice flour","amounts":[["340","grams"]],"bakers_pct":null,"component":null},{"name":"brown rice flour","amounts":[["106","grams"]],"bakers_pct":null,"component":null},{"name":"potato starch","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"tapioca starch","amounts":[["42.5","grams"]],"bakers_pct":null,"component":null},{"name":"nonfat milk","amounts":[["10.5","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Whisk all ingredients together until well combined."]', '[]', 'Pastry_Module_3_Course_5.pdf', 55);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Jordan Marsh Blueberry Muffins', 'Quick Breads & Scones', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 4, 'Yield grams', NULL, '[]', '[{"name":"butter","amounts":[["115","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["255","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["3","grams"]],"bakers_pct":null,"component":null},{"name":"eggs","amounts":[["100","grams"]],"bakers_pct":null,"component":null},{"name":"all-purpose flour","amounts":[["115","grams"]],"bakers_pct":null,"component":null},{"name":"baking powder","amounts":[["8","grams"]],"bakers_pct":null,"component":null},{"name":"milk","amounts":[["120","grams"]],"bakers_pct":null,"component":null},{"name":"blueberries, rinsed, drained & dried","amounts":[["350","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Cream the butter with the sugar and salt until light. Beat in the eggs, one at a time, until smooth. Mix the flour and baking powder together well and stir into the batter alternating with the milk or buttermilk.","Crush 1/4 of the berries and stir into the batter; fold in the remaining berries whole.","Deposit the batter into twelve muffin pans lined with paper cups. Sprinkle tops of muffins with sugar, or crumb topping, below.","Bake muffins at 375 degrees about 30 minutes, until well risen and deep golden. Cool the muffins in the pan."]', '[]', 'PA_Mod_01_Instructor.pdf', 64);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Lemon Cornmeal Scones', 'Quick Breads & Scones', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 36, NULL, NULL, '[]', '[{"name":"all-purpose flour","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"yellow cornmeal","amounts":[["140","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["70","grams"]],"bakers_pct":null,"component":null},{"name":"baking powder","amounts":[["14","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["6","grams"]],"bakers_pct":null,"component":null},{"name":"butter","amounts":[["70","grams"]],"bakers_pct":null,"component":null},{"name":"dried cherries","amounts":[["140","grams"]],"bakers_pct":null,"component":null},{"name":"egg","amounts":[["50","grams"]],"bakers_pct":null,"component":null},{"name":"milk","amounts":[["120","grams"]],"bakers_pct":null,"component":null},{"name":"lemon zest","amounts":[["2","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla extract","amounts":[["8","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Prepare using Mealy Dough Mixing Method, adding dried cherries before adding liquid. Divide each disk into four wedges.","Bake at 450 degrees for about 10 to 15 minutes."]', '[]', 'Pastry_Module_2_Course_4.pdf', 33);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Rock Scones', 'Quick Breads & Scones', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 36, NULL, NULL, '["Small Batch","Large Batch"]', '[{"name":"unbleached, all-purpose flour","amounts":[["340","grams"],["680","grams"]],"bakers_pct":null,"component":null},{"name":"cake flour","amounts":[["115","grams"],["230","grams"]],"bakers_pct":null,"component":null},{"name":"baking powder","amounts":[["21","grams"],["42","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["3","grams"],["6","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["140","grams"],["280","grams"]],"bakers_pct":null,"component":null},{"name":"butter","amounts":[["130","grams"],["260","grams"]],"bakers_pct":null,"component":null},{"name":"currants","amounts":[["55","grams"],["110","grams"]],"bakers_pct":null,"component":null},{"name":"golden raisins","amounts":[["55","grams"],["110","grams"]],"bakers_pct":null,"component":null},{"name":"rinsed, diced candied orange peel","amounts":[["55","grams"],["110","grams"]],"bakers_pct":null,"component":null},{"name":"eggs","amounts":[["50","grams"],["150","grams"]],"bakers_pct":null,"component":null},{"name":"yolk","amounts":[["17","grams"]],"bakers_pct":null,"component":null},{"name":"milk","amounts":[["245","grams"],["490","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Prepare using Mealy Dough Mixing Method, adding currants, raisins, and candied orange before adding liquid.","Whisk eggs and milk together and stir into flour and butter mixture to form a rough dough.","Divide dough into scant 2-ounce pieces and roll between palms gently to round.","Bake scones at 450 degrees about 10 to 15 minutes, being careful that they do not color too deeply, or until they are firm, but not dry."]', '[]', 'Pastry_Module_2_Course_4.pdf', 32);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Scones', 'Quick Breads & Scones', 'Module 1', 'Course 1-2', 'Baking Techniques & Ingredients', 4, 'Yield 2,100 grams', '2,100 grams', '[]', '[{"name":"all-purpose flour","amounts":[["680","grams"]],"bakers_pct":null,"component":null},{"name":"cake flour","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"baking powder","amounts":[["43","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["7","grams"]],"bakers_pct":null,"component":null},{"name":"butter","amounts":[["140","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["140","grams"]],"bakers_pct":null,"component":null},{"name":"dark raisins","amounts":[["140","grams"]],"bakers_pct":null,"component":null},{"name":"eggs","amounts":[["205","grams"]],"bakers_pct":null,"component":null},{"name":"milk","amounts":[["520","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Combine flours, baking powder and salt in a bowl.","Beat butter and sugar together until soft and light. Scrape into flour mixture and rub in evenly. Add optional raisins, if used.","Whisk eggs and milk together and stir into flour and butter mixture to form smooth dough.","Cut the dough into 70 gram units with plastic scraper or bench scraper. Egg wash evenly, allow wash to dry several minutes, then wash again.","Bake scones at 450 degrees about 10 to 15 minutes, being careful that they do not color too deeply, or until they are firm, but not dry."]', '[]', 'PA_Mod_01_Instructor.pdf', 66);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Scones', 'Quick Breads & Scones', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 36, NULL, NULL, '[]', '[{"name":"unbleached, all-purpose flour","amounts":[["680","grams"]],"bakers_pct":null,"component":null},{"name":"cake flour","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"baking powder","amounts":[["42","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["9","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["140","grams"]],"bakers_pct":null,"component":null},{"name":"butter","amounts":[["140","grams"]],"bakers_pct":null,"component":null},{"name":"dark raisins (optional)","amounts":[["140","grams"]],"bakers_pct":null,"component":null},{"name":"eggs","amounts":[["250","grams"]],"bakers_pct":null,"component":null},{"name":"milk","amounts":[["490","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Prepare using Mealy Dough Mixing Method, adding raisins before adding liquid. paper-lined pans and mark in quarters with plastic scraper or bench scraper. Egg wash evenly, allow wash to dry several minutes, and then wash again.","Bake scones at 450 degrees about 10 to 15 minutes, being careful that they do not color too deeply, until they are firm but not dry."]', '[]', 'Pastry_Module_2_Course_4.pdf', 30);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Shirley O. Corriher''S Biscuits', 'Quick Breads & Scones', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 36, NULL, NULL, '[]', '[{"name":"self-rising cake flour","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"baking powder","amounts":[["4","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["55","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["3","grams"]],"bakers_pct":null,"component":null},{"name":"shortening","amounts":[["42","grams"]],"bakers_pct":null,"component":null},{"name":"cream","amounts":[["150","grams"]],"bakers_pct":null,"component":null},{"name":"buttermilk","amounts":[["245","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Prepare using Mealy Dough Mixing Method.","After adding the cream, add enough buttermilk so the mixture looks likes cottage cheese.","Using a large ice cream scoop, drop biscuits into bowl of flour to coat them. the biscuits to rise and not to spread.","Bake at 425 degrees for approximately 20 minutes, until golden and cooked through."]', '[]', 'Pastry_Module_2_Course_4.pdf', 28);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Shortcakes', 'Quick Breads & Scones', 'Module 2', 'Course 4', 'Pies, Tarts & Laminated Doughs', 36, NULL, NULL, '[]', '[{"name":"all purpose flour","amounts":[["400","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["55","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["2","grams"]],"bakers_pct":null,"component":null},{"name":"baking powder","amounts":[["28","grams"]],"bakers_pct":null,"component":null},{"name":"butter (cold, cut into pieces)","amounts":[["115","grams"]],"bakers_pct":null,"component":null},{"name":"heavy cream","amounts":[["240","grams"]],"bakers_pct":null,"component":null},{"name":"milk","amounts":[["120","grams"]],"bakers_pct":null,"component":null},{"name":"eggs","amounts":[["50","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Prepare using the Flaky Dough Mixing Method","Combine the dry ingredients in the bowl of a standing mixer.","Add butter, and mix with a paddle attachment until the butter is pea size pieces.","Add the liquid ingredients and mix until just combined.","Roll on a lightly floured surface until dough is about ¾ inch thick.","Bake at 375° F until lightly colored."]', '[]', 'Pastry_Module_2_Course_4.pdf', 29);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Sour Cherry Crumbcake Squares', 'Quick Breads & Scones', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 51, '(1/2 sheet pan) Yield 1,572 grams', '1,572 grams', '[]', '[{"name":"butter, softened","amounts":[["225","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["340","grams"]],"bakers_pct":null,"component":null},{"name":"vanilla extract","amounts":[["9","grams"]],"bakers_pct":null,"component":null},{"name":"eggs","amounts":[["150","grams"]],"bakers_pct":null,"component":null},{"name":"AP flour","amounts":[["370","grams"]],"bakers_pct":null,"component":null},{"name":"baking powder","amounts":[["8","grams"]],"bakers_pct":null,"component":null},{"name":"egg yolks","amounts":[["60","grams"]],"bakers_pct":null,"component":null},{"name":"milk","amounts":[["60","grams"]],"bakers_pct":null,"component":null},{"name":"sour cherries, thawed and well drained","amounts":[["350","grams"]],"bakers_pct":null,"component":null},{"name":"light brown sugar","amounts":[["70","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["70","grams"]],"bakers_pct":null,"component":null},{"name":"AP flour","amounts":[["280","grams"]],"bakers_pct":null,"component":null},{"name":"butter","amounts":[["170","grams"]],"bakers_pct":null,"component":null},{"name":"cinnamon","amounts":[["1","grams"]],"bakers_pct":null,"component":null}]', NULL, '["Butter a half sheet pan and line the bottom with parchment. 2 . In a KitchenAid bowl, beat the butter, sugar and vanilla until soft and light. 3 . Add the eggs gradually until well incorporated. Mix together the flour and baking powder and stir into the batter alternating with the yolks and milk, making sure not to over mix. 4 . Spread the batter evenly in the prepared pan and scatter the sour cherries evenly over the batter.","Place all of the ingredients into a mixing bowl and mix by hand or machine until a","Liberally cover the surface with the crumb topping and bake in a 350˚F oven."]', '["Utilize the Creaming Dough mixing method:"]', 'Pastry_Module_3_Course_5.pdf', 37);
INSERT INTO recipes (title, category, module, course, course_name, lesson, yield, yield_num, batch_cols, ingredients, total, steps, notes, source_pdf, source_page) VALUES ('Zucchini Loaves', 'Quick Breads & Scones', 'Module 3', 'Course 5', 'Cakes, Fillings & Icings Pt 1', 51, 'Yield 2,206.2 grams', '2,206.2 grams', '[]', '[{"name":"whole eggs","amounts":[["200","grams"]],"bakers_pct":null,"component":null},{"name":"sugar","amounts":[["450","grams"]],"bakers_pct":null,"component":null},{"name":"vegetable or canola oil","amounts":[["320","grams"]],"bakers_pct":null,"component":null},{"name":"AP flour","amounts":[["320","grams"]],"bakers_pct":null,"component":null},{"name":"baking powder","amounts":[["8.5","grams"]],"bakers_pct":null,"component":null},{"name":"cinnamon","amounts":[["5.5","grams"]],"bakers_pct":null,"component":null},{"name":"baking soda","amounts":[["5.8","grams"]],"bakers_pct":null,"component":null},{"name":"salt","amounts":[["6.4","grams"]],"bakers_pct":null,"component":null},{"name":"zucchini (grated)","amounts":[["455","grams"]],"bakers_pct":null,"component":null},{"name":"walnuts (chopped)","amounts":[["115","grams"]],"bakers_pct":null,"component":null}]', NULL, '["In a bowl, whisk together the first 3 ingredients","Combine the next 5 (dry) ingredients in a bowl and mix well.","Add the wet ingredients into the dry and mix until just combined.","Add the zucchini and chopped walnuts and mix until incorporated.","Place the batter approximately 2/3 full (about 220 grams) in paper lined loaf pans and bake at 350 F."]', '["Utilize the One Step mixing method."]', 'Pastry_Module_3_Course_5.pdf', 30);
